let db = {};

// Keep legacy localStorage write for cache/offline resilience
function saveDBLocal() {
  try { localStorage.setItem(STORE_KEY, JSON.stringify(db)); } catch(e) {}
}

// Debounced API push
let _saveTimer = null;
function saveDB() {
  saveDBLocal(); // always write locally immediately
  clearTimeout(_saveTimer);
  _saveTimer = setTimeout(pushDBToAPI, 400);
}

async function pushDBToAPI() {
  if (!_authToken) return;
  try {
    await apiPost('/import', {
      contacts:   db.contacts   || [],
      companies:  db.companies  || [],
      deals:      db.deals      || [],
      activities: db.activities || [],
      tasks:      db.tasks      || [],
      invoices:   db.invoices   || [],
      products:   db.products   || [],
      settings:   db.settings   || {},
    });
  } catch(err) {
    // Non-fatal — local cache is still intact
    console.warn('API sync failed:', err.message);
  }
}

async function loadDBFromAPI() {
  try {
    const [companies, contacts, deals, activities, tasks, invoices, products, settings, sequences, proposals, smartLists, docLinks, competitorEntries, campaigns, subscriptions] = await Promise.all([
      apiGet('/companies'),
      apiGet('/contacts'),
      apiGet('/deals'),
      apiGet('/activities'),
      apiGet('/tasks'),
      apiGet('/invoices'),
      apiGet('/products'),
      apiGet('/settings'),
      apiGet('/sequences'),
      apiGet('/proposals'),
      apiGet('/smart-lists'),
      apiGet('/doc-links'),
      apiGet('/competitor-entries'),
      apiGet('/campaigns'),
      apiGet('/subscriptions'),
    ]);

    db.companies         = companies;
    db.contacts          = contacts;
    db.deals             = deals;
    db.activities        = activities;
    db.tasks             = tasks;
    db.invoices          = invoices;
    db.products          = products;
    db.sequences         = sequences;
    db.proposals         = proposals;
    db.smartLists        = smartLists;
    db.documents         = docLinks;
    db.competitorEntries = competitorEntries;
    db.campaigns         = campaigns;
    db.subscriptions     = subscriptions || [];
    db.meetings          = db.meetings || [];

    // Flatten settings into db.settings
    db.settings = settings || {};
    db.settings.pipelineStages   = db.settings.pipelineStages   || null;
    db.settings.emailTemplates   = db.settings.emailTemplates   || [];
    db.settings.playbooks        = db.settings.playbooks        || [];
    db.settings.invoiceSettings  = db.settings.invoiceSettings  || { nextNumber: 1001, prefix: 'INV-' };
    db.settings.profile          = db.settings.profile          || {};

    saveDBLocal(); // update local cache
    console.log(`✅ Loaded from API: ${contacts.length} contacts, ${deals.length} deals, ${companies.length} companies, ${docLinks.length} docs, ${competitorEntries.length} competitors, ${campaigns.length} campaigns`);
  } catch(err) {
    console.error('Failed to load from API:', err);
    // Fallback to local cache
    const raw = localStorage.getItem(STORE_KEY);
    if (raw) {
      db = JSON.parse(raw);
      toast('Using cached data (API unreachable)', 'warning');
    }
  }
}

// Legacy loadDB — now just a sync wrapper (called from init, but init is now async)
function loadDB() {
  // Tries local cache for immediate render; API load happens in init()
  try {
    const raw = localStorage.getItem(STORE_KEY);
    if (raw) {
      db = JSON.parse(raw);
    } else {
      db = { companies:[], contacts:[], deals:[], activities:[], tasks:[], settings:{pipelineStages:null, emailTemplates:[], playbooks:[], invoiceSettings:{nextNumber:1001,prefix:'INV-'}, profile:{}}, invoices:[], products:[], smartLists:[], sequences:[], proposals:[] };
    }
    db.companies  = db.companies  || [];
    db.contacts   = db.contacts   || [];
    db.deals      = db.deals      || [];
    db.activities = db.activities || [];
    db.tasks      = db.tasks      || [];
    db.settings   = db.settings   || { pipelineStages: null, emailTemplates: [] };
    db.settings.emailTemplates  = db.settings.emailTemplates  || [];
    db.settings.playbooks       = db.settings.playbooks       || [];
    db.products          = db.products          || [];
    db.invoices          = db.invoices          || [];
    db.smartLists        = db.smartLists        || [];
    db.sequences         = db.sequences         || [];
    db.proposals         = db.proposals         || [];
    db.documents         = db.documents         || [];
    db.competitorEntries = db.competitorEntries || [];
    db.campaigns         = db.campaigns         || [];
    db.meetings          = db.meetings          || [];
    db.subscriptions     = db.subscriptions     || [];
  } catch(e) {
    db = { companies:[], contacts:[], deals:[], activities:[], tasks:[], settings:{pipelineStages:null, emailTemplates:[], playbooks:[]}, invoices:[], products:[], smartLists:[], sequences:[], proposals:[] };
  }
}

// ── Utilities ──────────────────────────────────────────────────────────────
function uid() { return Math.random().toString(36).slice(2) + Date.now().toString(36); }

function formatCurrency(v) {
  if (v >= 1000000) return '$' + (v/1000000).toFixed(1) + 'M';
  if (v >= 1000)    return '$' + (v/1000).toFixed(0) + 'K';
  return '$' + v;
}

function formatDate(iso) {
  if (!iso) return '—';
  const d = new Date(iso);
  return d.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
}

function timeAgo(ts) {
  const diff = Date.now() - (typeof ts === 'string' ? new Date(ts).getTime() : ts);
  const mins = Math.floor(diff / 60000);
  if (mins < 1) return 'just now';
  if (mins < 60) return `${mins}m ago`;
  const hrs = Math.floor(mins / 60);
  if (hrs < 24) return `${hrs}h ago`;
  const days = Math.floor(hrs / 24);
  if (days < 30) return `${days}d ago`;
  return `${Math.floor(days / 30)}mo ago`;
}

function daysInStage(movedAt) {
  const diff = Date.now() - (typeof movedAt === 'string' ? new Date(movedAt).getTime() : movedAt);
  return Math.floor(diff / 86400000);
}

function initials(name) { return (name || '').split(' ').map(w => w[0]).join('').slice(0,2).toUpperCase(); }

function esc(str) {
  return String(str || '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

function companyName(id) { const c = db.companies.find(c => c.id === id); return c ? c.name : id || ''; }
function contactName(id) { const c = db.contacts.find(c => c.id === id); return c ? c.name : id || ''; }
function getContactDeals(contactId) { return db.deals.filter(d => d.contact === contactId); }
function getCompanyContacts(companyId) { return db.contacts.filter(c => c.company === companyId); }
function getCompanyDeals(companyId) { return db.deals.filter(d => d.company === companyId); }
function getContactActivities(contactId) { return db.activities.filter(a => a.contactId === contactId).sort((a,b) => new Date(b.date) - new Date(a.date)); }
function getDealActivities(dealId) { return db.activities.filter(a => a.dealId === dealId).sort((a,b) => new Date(b.date) - new Date(a.date)); }

function stageClass(stage) {
  const map = { 'Lead':'stage-lead', 'Qualified':'stage-qualified', 'Prospect':'stage-prospect', 'Customer':'stage-customer', 'Churned':'stage-churned' };
  return map[stage] || 'stage-lead';
}

