  const company     = deal.company ? db.companies.find(c => c.id === deal.company) : null;
  const dealTasks   = (db.tasks || []).filter(t => t.dealId === id && t.status === 'Open');
  const days        = daysInStage(deal.movedAt || deal.createdAt);
