// ── Dashboard ──────────────────────────────────────────────────────────────
function renderDashboard() {
  const openDeals    = db.deals.filter(d => d.stage !== 'Won' && d.stage !== 'Lost');
  const pipelineValue= openDeals.reduce((s,d) => s + (d.value||0), 0);
  const thisWeek     = Date.now() - 7 * 86400000;
  const actThisWeek  = db.activities.filter(a => new Date(a.date).getTime() > thisWeek).length;
  const weightedValue= db.deals.reduce((s,d) => s + (d.value||0) * getDealEffectiveProbability(d), 0);
  const todayStr     = new Date().toISOString().slice(0, 10);
  const overdueTasks = (db.tasks||[]).filter(t => t.status === 'Open' && t.dueDate < todayStr).length;

  document.getElementById('stat-contacts').textContent        = db.contacts.length;
  document.getElementById('stat-open-deals').textContent      = openDeals.length;
  document.getElementById('stat-pipeline-value').textContent  = formatCurrency(pipelineValue);
  document.getElementById('stat-activities').textContent      = actThisWeek;
  document.getElementById('stat-weighted-pipeline').textContent = formatCurrency(Math.round(weightedValue));
  document.getElementById('stat-overdue-tasks').textContent   = overdueTasks;

  const overdueCard  = document.getElementById('stat-card-overdue');
  const overdueDelta = document.getElementById('stat-overdue-delta');
  const overdueVal   = document.getElementById('stat-overdue-tasks');
  if (overdueTasks > 0) {
    overdueCard.style.borderColor = 'rgba(239,68,68,0.35)';
    overdueDelta.textContent = overdueTasks === 1 ? '1 past due' : `${overdueTasks} past due`;
    overdueDelta.className = 'stat-delta down';
    overdueVal.style.color = 'var(--red)';
  } else {
    overdueCard.style.borderColor = '';
    overdueDelta.textContent = 'All caught up';
    overdueDelta.className = 'stat-delta up';
    overdueVal.style.color = '';
  }

  updateTasksBadge();
  updateNotificationBell();
  renderInsightsPanel();
  updateDashboardInvoiceStats();
  renderGoalProgress();
  injectForecastPanel();
  renderPipelineForecast();

  const recentContacts = [...db.contacts].sort((a,b) => b.createdAt - a.createdAt).slice(0,6);
  document.getElementById('recent-contacts-list').innerHTML = recentContacts.length ? recentContacts.map(c => `
    <div class="recent-contact-row" onclick="showContactDetail('${c.id}')">
      <div class="avatar">${esc(initials(c.name))}</div>
      <div>
        <div class="contact-mini-name">${esc(c.name)}</div>
        <div class="contact-mini-company">${esc(companyName(c.company))} &middot; ${esc(c.title||'')}</div>
      </div>
      <span class="contact-mini-time">${timeAgo(c.createdAt)}</span>
    </div>`).join('') : '<div class="empty-state"><div class="empty-state-title">No contacts yet</div></div>';

  const recentActs = [...db.activities].sort((a,b) => new Date(b.date) - new Date(a.date)).slice(0,8);
  document.getElementById('dashboard-activity-feed').innerHTML = recentActs.length ? recentActs.map(a => `
    <div class="activity-item">
      <div class="activity-icon ${activityTypeClass(a.type)}">${activityIconSVG(a.type)}</div>
      <div class="activity-content">
        <div class="activity-header">
          <span class="activity-type" style="color:${activityTypeColor(a.type)}">${esc(a.type)}</span>
          <span class="activity-contact">${esc(contactName(a.contactId))}</span>
          <span class="activity-time">${timeAgo(new Date(a.date).getTime())}</span>
        </div>
        <div class="activity-note">${esc(a.note)}</div>
      </div>
    </div>`).join('') : '<div class="empty-state"><div class="empty-state-title">No activities yet</div></div>';

  const stages  = getDealStages().filter(s => s !== 'Lost');
  const maxVal  = Math.max(...stages.map(s => db.deals.filter(d=>d.stage===s).reduce((sum,d)=>sum+(d.value||0),0)), 1);
  document.getElementById('pipeline-summary').innerHTML = stages.map(s => {
    const deals = db.deals.filter(d => d.stage === s);
    const val   = deals.reduce((sum,d) => sum+(d.value||0),0);
    const pct   = Math.round(val / maxVal * 100);
    const col   = getStageColor(s);
    return `
      <div class="pipeline-row">
        <span class="pipeline-row-label" style="color:${col}">${esc(s)}</span>
        <div class="pipeline-row-bar-wrap"><div class="pipeline-row-bar" style="width:${pct}%;background:${col}"></div></div>
        <span class="pipeline-row-count">${deals.length}</span>
        <span class="pipeline-row-value">${formatCurrency(val)}</span>
      </div>`;
  }).join('');
}

// ── Contacts ───────────────────────────────────────────────────────────────
let contactSearch = '';
let contactStageFilter = '';
let contactTagFilter = '';
let contactSort = { col: 'name', dir: 'asc' };
let bulkSelected = new Set();

function renderContacts() {
  let contacts = [...db.contacts];
  if (contactSearch) {
    const q = contactSearch.toLowerCase();
    contacts = contacts.filter(c =>
      c.name.toLowerCase().includes(q) ||
      (c.email||'').toLowerCase().includes(q) ||
      (c.phone||'').toLowerCase().includes(q) ||
      companyName(c.company).toLowerCase().includes(q) ||
      (c.tags||[]).join(' ').toLowerCase().includes(q)
    );
  }
  if (contactStageFilter) contacts = contacts.filter(c => c.stage === contactStageFilter);
  if (contactTagFilter)   contacts = contacts.filter(c => (c.tags||[]).includes(contactTagFilter));
  // Health filter (Phase 15)
  const healthFilterEl = document.getElementById('contacts-health-filter');
  const contactHealthFilter = healthFilterEl ? healthFilterEl.value : '';
  if (contactHealthFilter) {
    contacts = contacts.filter(c => {
      const score = calcHealthScore(c);
      if (contactHealthFilter === 'scored') return score !== null;
      const l = healthLabel(score);
      return l === contactHealthFilter;
    });
  }

  contacts.sort((a,b) => {
    let av, bv;
    switch(contactSort.col) {
      case 'name':         av = a.name; bv = b.name; break;
      case 'company':      av = companyName(a.company); bv = companyName(b.company); break;
      case 'stage':        av = a.stage; bv = b.stage; break;
      case 'lastActivity': av = a.lastActivity||0; bv = b.lastActivity||0; break;
      case 'health':       av = calcHealthScore(a) ?? -1; bv = calcHealthScore(b) ?? -1; break;
      default: av = a.name; bv = b.name;
    }
    if (av < bv) return contactSort.dir === 'asc' ? -1 : 1;
    if (av > bv) return contactSort.dir === 'asc' ? 1 : -1;
    return 0;
  });

  const allTags = [...new Set(db.contacts.flatMap(c => c.tags||[]))].sort();
  document.getElementById('contacts-tag-filter').innerHTML =
    `<option value="">All Tags</option>` + allTags.map(t => `<option value="${esc(t)}" ${contactTagFilter===t?'selected':''}>${esc(t)}</option>`).join('');
  document.getElementById('contacts-count').textContent = contacts.length + ' contacts';

  const tbody = document.getElementById('contacts-tbody');
  tbody.innerHTML = contacts.length ? contacts.map(c => `
    <tr onclick="showContactDetail('${c.id}')">
      <td onclick="event.stopPropagation()" style="padding:8px 10px;width:36px">
        <input type="checkbox" class="contact-checkbox" data-id="${c.id}" onchange="toggleBulkSelect('${c.id}')" ${bulkSelected.has(c.id)?'checked':''} />
      </td>
      <td class="td-name">
        <div style="display:flex;align-items:center;gap:8px">
          <div class="avatar">${esc(initials(c.name))}</div>
          <span>${esc(c.name)}</span>
        </div>
      </td>
      <td class="td-email">${esc(companyName(c.company))}</td>
      <td class="td-email">${esc(c.email||'')}</td>
      <td class="td-muted">${esc(c.phone||'')}</td>
      <td><span class="stage-pill ${stageClass(c.stage)}">${esc(c.stage)}</span></td>
      <td class="td-muted">${c.lastActivity ? timeAgo(c.lastActivity) : '—'}</td>
      <td><div class="tags-cell">${(c.tags||[]).slice(0,3).map(t => `<span class="tag">${esc(t)}</span>`).join('')}</div></td>
      <td class="td-muted">${esc(c.owner||'')}</td>
      <td class="td-muted">${c.leadSource ? `<span class="tag" style="background:rgba(99,102,241,0.12);color:#818cf8;border-color:rgba(99,102,241,0.2)">${esc(c.leadSource)}</span>` : '—'}</td>
      <td>${(s => s !== null ? `<span class="health-badge health-${healthLabel(s)}">${s}</span>` : '')(calcHealthScore(c))}</td>
    </tr>`).join('') : `<tr><td colspan="11"><div class="empty-state"><div class="empty-state-title">No contacts found</div><div class="empty-state-sub">Try adjusting your search or filters</div></div></td></tr>`;

  // Inject lead score badges
  document.querySelectorAll('#contacts-tbody tr').forEach(tr => {
    const onclick = tr.getAttribute('onclick') || '';
    const idMatch = onclick.match(/showContactDetail\('([^']+)'\)/);
    if (!idMatch) return;
    const c = db.contacts.find(c => c.id === idMatch[1]);
    if (!c) return;
    const score = calcLeadScore(c);
    const nameCell = tr.querySelector('.td-name span');
    if (nameCell && !nameCell.querySelector('.lead-score-badge')) {
      nameCell.insertAdjacentHTML('afterend', leadScoreBadge(score));
    }
  });
  // Sync select-all checkbox state
  const allCB = document.getElementById('contact-select-all');
  if (allCB) {
    const visibleIds = contacts.map(c => c.id);
    const allChecked = visibleIds.length > 0 && visibleIds.every(id => bulkSelected.has(id));
    allCB.checked = allChecked;
    allCB.indeterminate = !allChecked && visibleIds.some(id => bulkSelected.has(id));
  }
  updateBulkBar();
}

function toggleBulkSelect(id) {
  if (bulkSelected.has(id)) bulkSelected.delete(id);
  else bulkSelected.add(id);
  updateBulkBar();
  // Sync select-all checkbox
  const allCB = document.getElementById('contact-select-all');
  if (allCB) {
    const visibleIds = [...document.querySelectorAll('.contact-checkbox')].map(cb => cb.dataset.id);
    const allChecked = visibleIds.length > 0 && visibleIds.every(id => bulkSelected.has(id));
    allCB.checked = allChecked;
    allCB.indeterminate = !allChecked && visibleIds.some(id => bulkSelected.has(id));
  }
}

function toggleSelectAll() {
  const allCB = document.getElementById('contact-select-all');
  const visibleIds = [...document.querySelectorAll('.contact-checkbox')].map(cb => cb.dataset.id);
  if (allCB.checked) {
    visibleIds.forEach(id => bulkSelected.add(id));
  } else {
    visibleIds.forEach(id => bulkSelected.delete(id));
  }
  renderContacts();
}

function updateBulkBar() {
  const bar = document.getElementById('bulk-action-bar');
  const cnt = document.getElementById('bulk-count');
  if (!bar) return;
  if (bulkSelected.size > 0) {
    bar.classList.add('visible');
    cnt.textContent = `${bulkSelected.size} selected`;
    // Sync bulk-stage-select with current stages
    const sel = document.getElementById('bulk-stage-select');
    if (sel) {
      const current = sel.value;
      sel.innerHTML = `<option value="">Update Stage...</option>` + CONTACT_STAGES.map(s => `<option value="${s}" ${s===current?'selected':''}>${s}</option>`).join('');
    }
  } else {
    bar.classList.remove('visible');
  }
}

function bulkUpdateStage() {
  const stage = document.getElementById('bulk-stage-select').value;
  if (!stage) { toast('Select a stage first', 'error'); return; }
  let count = 0;
  bulkSelected.forEach(id => {
    const c = db.contacts.find(x => x.id === id);
    if (c) { c.stage = stage; count++; }
  });
  saveDB();
  clearBulkSelection();
  renderContacts();
  toast(`Updated ${count} contact${count!==1?'s':''} to ${stage}`, 'success');
}

function bulkAssignOwner() {
  const owner = document.getElementById('bulk-owner-input').value.trim();
  if (!owner) { toast('Enter an owner first', 'error'); return; }
  let count = 0;
  bulkSelected.forEach(id => {
    const c = db.contacts.find(x => x.id === id);
    if (c) { c.owner = owner; count++; }
  });
  saveDB();
  clearBulkSelection();
  renderContacts();
  toast(`Assigned ${owner} to ${count} contact${count!==1?'s':''}`, 'success');
}

function bulkDeleteSelected() {
  const count = bulkSelected.size;
  if (!confirm(`Delete ${count} contact${count!==1?'s':''}? This cannot be undone.`)) return;
  db.contacts = db.contacts.filter(c => !bulkSelected.has(c.id));
  saveDB();
  clearBulkSelection();
  renderContacts();
  toast(`Deleted ${count} contact${count!==1?'s':''}`, 'info');
}

function clearBulkSelection() {
  bulkSelected.clear();
  updateBulkBar();
  renderContacts();
}

function editContactModal(id) {
  const c = db.contacts.find(x => x.id === id);
  if (!c) return;
  openContactModal(c);
}

function openContactModal(contact = null) {
  const isEdit = !!contact;
  document.getElementById('modal-contact-title').textContent = isEdit ? 'Edit Contact' : 'Add Contact';
  document.getElementById('contact-form-id').value           = isEdit ? contact.id : '';
  document.getElementById('contact-form-name').value         = isEdit ? contact.name : '';
  document.getElementById('contact-form-email').value        = isEdit ? (contact.email||'') : '';
  document.getElementById('contact-form-phone').value        = isEdit ? (contact.phone||'') : '';
  document.getElementById('contact-form-title').value        = isEdit ? (contact.title||'') : '';
  document.getElementById('contact-form-stage').value        = isEdit ? (contact.stage||'Lead') : 'Lead';
  document.getElementById('contact-form-owner').value        = isEdit ? (contact.owner||'') : '';
  document.getElementById('contact-form-notes').value        = isEdit ? (contact.notes||'') : '';
  const lsEl = document.getElementById('contact-form-lead-source');
  if (lsEl) lsEl.value = isEdit ? (contact.leadSource||'') : '';

  const sel = document.getElementById('contact-form-company');
  sel.innerHTML = `<option value="">No Company</option>` + db.companies.map(c => `<option value="${c.id}" ${isEdit && contact.company===c.id?'selected':''}>${esc(c.name)}</option>`).join('');

  contactModalTags = isEdit ? [...(contact.tags||[])] : [];
  renderContactModalTags();

  document.getElementById('btn-delete-contact').style.display = isEdit ? 'inline-flex' : 'none';
  document.getElementById('btn-delete-contact').onclick = () => deleteContact(contact.id);

  if (isEdit) {
    const acts = getContactActivities(contact.id);
    document.getElementById('contact-activities-section').style.display = 'block';
    document.getElementById('contact-activities-list').innerHTML = acts.length ? acts.map(a => `
      <div class="activity-log-entry">
        <div class="activity-icon ${activityTypeClass(a.type)}" style="width:24px;height:24px;border-radius:5px">${activityIconSVG(a.type)}</div>
        <div>
          <div style="font-weight:500;color:var(--text)">${esc(a.type)} <span style="color:var(--text-muted);font-weight:400">&middot; ${formatDate(a.date)}</span></div>
          <div style="color:var(--text-dim);margin-top:2px">${esc(a.note)}</div>
        </div>
      </div>`).join('') : '<div style="color:var(--text-muted);font-size:12px;padding:8px 0">No activities logged yet.</div>';
    document.getElementById('btn-log-activity-from-contact').onclick = () => {
      closeModal('modal-contact');
      openActivityModal(contact.id);
    };
  } else {
    document.getElementById('contact-activities-section').style.display = 'none';
  }
  openModal('modal-contact');
}

let contactModalTags = [];
function renderContactModalTags() {
  const wrap  = document.getElementById('contact-tags-wrap');
  const input = document.getElementById('contact-tags-input');
  wrap.querySelectorAll('.tag').forEach(t => t.remove());
  contactModalTags.map(t => {
    const span = document.createElement('span');
    span.className = 'tag';
    span.innerHTML = `${esc(t)} <button class="tag-remove" onclick="removeContactTag('${esc(t)}')" type="button"><svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg></button>`;
    wrap.insertBefore(span, input);
  });
}
function removeContactTag(tag) { contactModalTags = contactModalTags.filter(t => t !== tag); renderContactModalTags(); }

function saveContact() {
  const id   = document.getElementById('contact-form-id').value;
  const name = document.getElementById('contact-form-name').value.trim();
  if (!name) { toast('Name is required', 'error'); return; }

  const email = document.getElementById('contact-form-email').value.trim();

  // Duplicate email check (new contacts only)
  if (!id && email) {
    const dup = db.contacts.find(c => c.email && c.email.toLowerCase() === email.toLowerCase());
    if (dup) {
      if (!confirm(`A contact with email "${email}" already exists (${dup.name}). Add anyway?`)) return;
    }
  }

  const data = {
    name,
    email,
    phone:      document.getElementById('contact-form-phone').value.trim(),
    company:    document.getElementById('contact-form-company').value,
    title:      document.getElementById('contact-form-title').value.trim(),
    stage:      document.getElementById('contact-form-stage').value,
    owner:      document.getElementById('contact-form-owner').value.trim(),
    notes:      document.getElementById('contact-form-notes').value.trim(),
    tags:       [...contactModalTags],
    leadSource: document.getElementById('contact-form-lead-source')?.value || '',
    lastActivity: Date.now(),
  };

  if (id) {
    const idx = db.contacts.findIndex(c => c.id === id);
    if (idx !== -1) { db.contacts[idx] = { ...db.contacts[idx], ...data }; toast('Contact updated', 'success'); }
  } else {
    db.contacts.push({ id: uid(), createdAt: Date.now(), ...data });
    toast('Contact added', 'success');
  }

  saveDB();
  closeModal('modal-contact');
  renderContacts();
  if (currentView === 'dashboard') renderDashboard();
}

function deleteContact(id) {
  if (!confirm('Delete this contact? This cannot be undone.')) return;
  db.contacts = db.contacts.filter(c => c.id !== id);
  saveDB();
  closeModal('modal-contact');
  renderContacts();
  toast('Contact deleted', 'info');
}

// ── Companies ──────────────────────────────────────────────────────────────
let companySearch = '';

function renderCompanies() {
  let companies = [...db.companies];
  if (companySearch) {
    const q = companySearch.toLowerCase();
    companies = companies.filter(c => c.name.toLowerCase().includes(q) || (c.industry||'').toLowerCase().includes(q));
  }
  document.getElementById('companies-count').textContent = companies.length + ' companies';

  const tbody = document.getElementById('companies-tbody');
  tbody.innerHTML = companies.length ? companies.map(co => {
    const contactCount = getCompanyContacts(co.id).length;
    const dealValue    = getCompanyDeals(co.id).filter(d => d.stage !== 'Lost').reduce((s,d) => s+(d.value||0),0);
    return `
      <tr onclick="showCompanyDetail('${co.id}')">
        <td class="td-name">
          <div style="display:flex;align-items:center;gap:8px">
            <div class="avatar" style="background:rgba(59,130,246,0.12);color:#3b82f6;border-radius:4px">${esc(initials(co.name))}</div>
            <div>
              <div>${esc(co.name)}</div>
              ${co.city ? `<div style="font-size:11px;color:var(--text-muted)">${esc(co.city)}</div>` : ''}
            </div>
          </div>
        </td>
        <td><span class="company-industry">${esc(co.industry||'')}</span></td>
        <td class="td-email"><a href="https://${esc(co.website||'')}" target="_blank" onclick="event.stopPropagation()" style="color:var(--accent-hover);text-decoration:none">${esc(co.website||'—')}</a></td>
        <td class="td-muted">${esc(co.phone||'')}</td>
        <td class="td-muted" style="text-align:center">${contactCount}</td>
        <td><span style="color:var(--green);font-weight:600">${dealValue ? formatCurrency(dealValue) : '—'}</span></td>
      </tr>`;
  }).join('') : `<tr><td colspan="6"><div class="empty-state"><div class="empty-state-title">No companies found</div></div></td></tr>`;
}

function editCompanyModal(id) {
  const c = db.companies.find(x => x.id === id);
  if (!c) return;
  openCompanyModal(c);
}

function openCompanyModal(company = null) {
  const isEdit = !!company;
  document.getElementById('modal-company-title').textContent  = isEdit ? 'Edit Company' : 'Add Company';
  document.getElementById('company-form-id').value            = isEdit ? company.id : '';
  document.getElementById('company-form-name').value          = isEdit ? company.name : '';
  document.getElementById('company-form-industry').value      = isEdit ? (company.industry||'') : '';
  document.getElementById('company-form-website').value       = isEdit ? (company.website||'') : '';
  document.getElementById('company-form-phone').value         = isEdit ? (company.phone||'') : '';
  document.getElementById('company-form-address').value       = isEdit ? (company.address||'') : '';
  document.getElementById('company-form-city').value          = isEdit ? (company.city||'') : '';
  document.getElementById('company-form-notes').value         = isEdit ? (company.notes||'') : '';

  document.getElementById('btn-delete-company').style.display = isEdit ? 'inline-flex' : 'none';
  document.getElementById('btn-delete-company').onclick = () => deleteCompany(company.id);

  if (isEdit) {
    const contacts = getCompanyContacts(company.id);
    document.getElementById('company-contacts-section').style.display = 'block';
    document.getElementById('company-contacts-list').innerHTML = contacts.length
      ? contacts.map(c => `<span class="tag tag-accent" style="margin:2px;cursor:pointer" onclick="closeModal('modal-company');showContactDetail('${c.id}')">${esc(c.name)}</span>`).join('')
      : '<span style="color:var(--text-muted);font-size:12px">No linked contacts.</span>';
  } else {
    document.getElementById('company-contacts-section').style.display = 'none';
  }
  openModal('modal-company');
}

function saveCompany() {
  const id   = document.getElementById('company-form-id').value;
  const name = document.getElementById('company-form-name').value.trim();
  if (!name) { toast('Company name is required', 'error'); return; }

  const data = {
    name,
    industry: document.getElementById('company-form-industry').value,
    website:  document.getElementById('company-form-website').value.trim().replace(/^https?:\/\//,''),
    phone:    document.getElementById('company-form-phone').value.trim(),
    address:  document.getElementById('company-form-address').value.trim(),
    city:     document.getElementById('company-form-city').value.trim(),
    notes:    document.getElementById('company-form-notes').value.trim(),
  };

  if (id) {
    const idx = db.companies.findIndex(c => c.id === id);
    if (idx !== -1) { db.companies[idx] = { ...db.companies[idx], ...data }; toast('Company updated', 'success'); }
  } else {
    db.companies.push({ id: uid(), createdAt: Date.now(), ...data });
    toast('Company added', 'success');
  }
  saveDB();
  closeModal('modal-company');
  renderCompanies();
}

function deleteCompany(id) {
  if (!confirm('Delete this company? Linked contacts will be unlinked.')) return;
  db.companies = db.companies.filter(c => c.id !== id);
  db.contacts.forEach(c => { if (c.company === id) c.company = ''; });
  saveDB();
  closeModal('modal-company');
  renderCompanies();
  toast('Company deleted', 'info');
}

// ── Pipeline ───────────────────────────────────────────────────────────────
let dragDealId = null;
let dragSourceStage = null;

function renderPipeline() {
  const board  = document.getElementById('pipeline-board');
  const stages = getDealStages();
  board.innerHTML = '';

  stages.forEach(stage => {
    const deals    = db.deals.filter(d => d.stage === stage);
    const totalVal = deals.reduce((s,d) => s+(d.value||0), 0);
    const color    = getStageColor(stage);
    const isLost   = stage.toLowerCase() === 'lost';
    const isWon    = stage.toLowerCase() === 'won';

    const col = document.createElement('div');
    col.className = `kanban-col${isLost?' col-lost':''}${isWon?' col-won':''}`;
    col.dataset.stage = stage;

    col.innerHTML = `
      <div class="kanban-col-header">
        <div class="kanban-col-dot" style="${getStageDotStyle(stage)}"></div>
        <div>
          <div class="kanban-col-title">${esc(stage)}</div>
          ${totalVal ? `<div class="kanban-col-value">${formatCurrency(totalVal)}</div>` : ''}
        </div>
        <span class="kanban-col-count">${deals.length}</span>
      </div>
      <div class="kanban-cards" id="cards-${stage.replace(/\s/g,'-')}"
        ondragover="event.preventDefault();this.classList.add('drag-over')"
        ondragleave="this.classList.remove('drag-over')"
        ondrop="dropDeal(event,'${esc(stage)}')"
      >${deals.map(d => renderDealCard(d)).join('')}</div>
      <div class="kanban-col-footer">
        <button class="kanban-add-btn" onclick="openDealModal(null,'${esc(stage)}')">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round"><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg>
          Add Deal
        </button>
      </div>`;
    board.appendChild(col);
  });
}

function renderDealCard(d) {
  const days    = daysInStage(d.movedAt || d.createdAt);
  const prob    = getStageProbability(d.stage);
  const probPct = Math.round(prob * 100);
  const isCold   = d.stage !== 'Won' && d.stage !== 'Lost' && days >= 14;
  const todayStr = new Date().toISOString().slice(0,10);
  const isPastDue = d.closeDate && d.closeDate < todayStr && d.stage !== 'Won' && d.stage !== 'Lost';

  // Phase 20: SLA check
  const slaStatus = (_dealsSLAStatus || {})[d.id];
  const slaBreached = slaStatus?.slaBreached;
  const slaBadge = slaBreached
    ? `<span class="sla-warning-badge" title="SLA exceeded: ${slaStatus.daysInStage.toFixed(1)} days (limit: ${slaStatus.slaLimit}d)">SLA</span>`
    : '';

  // Phase 20: Checklist progress
  const clProg = (_checklistProgressCache || {})[d.id];
  const clHtml = clProg && clProg.total > 0 ? `
    <div style="margin-top:5px">
      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:2px">
        <span style="font-size:9px;color:var(--text-muted)">Checklist ${clProg.done}/${clProg.total}</span>
        <span style="font-size:9px;color:${clProg.progress===100?'var(--green)':'var(--text-muted)'}">${clProg.progress}%</span>
      </div>
      <div style="height:3px;background:var(--surface2);border-radius:2px">
        <div style="height:100%;width:${clProg.progress}%;background:${clProg.progress===100?'var(--green)':'var(--accent)'};border-radius:2px"></div>
      </div>
    </div>` : '';

  return `
    <div class="deal-card${isCold?' deal-card-cold':''}" draggable="true"
      ondragstart="startDrag(event,'${d.id}','${esc(d.stage)}')"
      ondragend="endDrag(event)"
      onclick="showDealDetail('${d.id}')">
      <div style="display:flex;align-items:flex-start;justify-content:space-between;gap:4px;margin-bottom:2px">
        <div class="deal-card-name">${esc(d.name)}${slaBadge}</div>
        <span class="deal-prob-badge" title="Win probability">${probPct}%</span>
      </div>
      <div class="deal-card-company">${esc(companyName(d.company))}</div>
      <div class="deal-card-footer">
        <span class="deal-card-value">${formatCurrency(d.value||0)}</span>
        <div class="owner-dot">${esc(d.owner||'?')}</div>
      </div>
      <div class="deal-card-days" style="${isCold||isPastDue?'color:var(--red)':''}">
        ${isPastDue ? 'Overdue close · ' : isCold ? 'Cold — ' : ''}${days === 0 ? 'Today' : `${days}d in stage`}
      </div>
      ${isPastDue ? `<div style="font-size:9px;color:var(--red);font-weight:600;margin-top:2px">Closed ${formatDate(d.closeDate)}</div>` : ''}
      ${clHtml}
    </div>`;
}

function startDrag(e, dealId, stage) {
  dragDealId = dealId; dragSourceStage = stage;
  e.target.classList.add('dragging');
  e.dataTransfer.effectAllowed = 'move';
}
function endDrag(e) {
  e.target.classList.remove('dragging');
  document.querySelectorAll('.drag-over').forEach(el => el.classList.remove('drag-over'));
}
function dropDeal(e, targetStage) {
  e.preventDefault();
  e.currentTarget.classList.remove('drag-over');
  if (!dragDealId || dragSourceStage === targetStage) return;
  const deal = db.deals.find(d => d.id === dragDealId);
  if (!deal) return;
  deal.stage   = targetStage;
  deal.movedAt = Date.now();
  saveDB();
  renderPipeline();
  toast(`Moved to ${targetStage}`, 'success');
  dragDealId = null;
}

function openDealModal(id, defaultStage) {
  if (!defaultStage) defaultStage = getDealStages()[0] || 'To Contact';
  const deal   = id ? db.deals.find(d => d.id === id) : null;
  const isEdit = !!deal;

  document.getElementById('modal-deal-title').textContent  = isEdit ? 'Edit Deal' : 'Add Deal';
  document.getElementById('deal-form-id').value            = isEdit ? deal.id : '';
  document.getElementById('deal-form-name').value          = isEdit ? deal.name : '';
  document.getElementById('deal-form-value').value         = isEdit ? deal.value : '';
  document.getElementById('deal-form-owner').value         = isEdit ? (deal.owner||'') : 'AW';
  document.getElementById('deal-form-closedate').value     = isEdit ? (deal.closeDate||'') : '';
  document.getElementById('deal-form-notes').value         = isEdit ? (deal.notes||'') : '';

  // Populate stage dropdown dynamically
  const stageSel = document.getElementById('deal-form-stage');
  stageSel.innerHTML = getDealStages().map(s => `<option value="${esc(s)}" ${(isEdit ? deal.stage : defaultStage)===s?'selected':''}>${esc(s)}</option>`).join('');

  const cSel = document.getElementById('deal-form-company');
  cSel.innerHTML = `<option value="">No Company</option>` + db.companies.map(c => `<option value="${c.id}" ${isEdit && deal.company===c.id?'selected':''}>${esc(c.name)}</option>`).join('');

  const pSel = document.getElementById('deal-form-contact');
  pSel.innerHTML = `<option value="">No Contact</option>` + db.contacts.map(c => `<option value="${c.id}" ${isEdit && deal.contact===c.id?'selected':''}>${esc(c.name)}</option>`).join('');

  document.getElementById('btn-delete-deal').style.display = isEdit ? 'inline-flex' : 'none';
  document.getElementById('btn-delete-deal').onclick = () => deleteDeal(deal.id);

  // Recurring revenue fields (Phase 6)
  const rvEl = document.getElementById('deal-form-recurring-value');
  const rtEl = document.getElementById('deal-form-recurring-type');
  if (rvEl) rvEl.value = isEdit ? (deal.recurringValue||'') : '';
  if (rtEl) rtEl.value = isEdit ? (deal.recurringType||'') : '';

  // Win/Loss reason (Phase 10)
  const reasonEl = document.getElementById('deal-form-win-loss-reason');
  if (reasonEl) reasonEl.value = isEdit ? (deal.winLossReason||'') : '';
  toggleWinLossReason(isEdit ? deal.stage : (defaultStage || ''));

  // Lead Source (Phase 16)
  const dlsEl = document.getElementById('deal-form-lead-source');
  if (dlsEl) dlsEl.value = isEdit ? (deal.leadSource||'') : '';

  openModal('modal-deal');
}

// saveDeal — defined below with recurring field support

function deleteDeal(id) {
  if (!confirm('Delete this deal?')) return;
  db.deals = db.deals.filter(d => d.id !== id);
  saveDB();
  closeModal('modal-deal');
  navigate('pipeline');
  toast('Deal deleted', 'info');
}

// ── Pipeline Settings ──────────────────────────────────────────────────────
let pipelineSettingsTemp = [];

function openPipelineSettings() {
  // Deep-copy current stages
  const stages = getDealStages();
  pipelineSettingsTemp = stages.map(name => ({
    name,
    color:       getStageColor(name),
    probability: getStageProbability(name),
  }));
  renderPipelineSettingsStages();
  openModal('modal-pipeline-settings');
}

function renderPipelineSettingsStages() {
  const container = document.getElementById('pipeline-settings-stages');
  container.innerHTML = pipelineSettingsTemp.map((s, i) => {
    const dealsInStage = db.deals.filter(d => d.stage === s.name).length;
    return `
      <div class="pipeline-stage-row" id="pss-row-${i}">
        <input type="color" class="stage-color-swatch" value="${s.color}" onchange="pipelineSettingsTemp[${i}].color=this.value;document.getElementById('pss-row-${i}').style.borderLeft='3px solid '+this.value" style="border-left:3px solid ${s.color}" />
        <input type="text" class="form-input" value="${esc(s.name)}" oninput="pipelineSettingsTemp[${i}].name=this.value" style="flex:1;font-size:12px" placeholder="Stage name" />
        <span style="font-size:11px;color:var(--text-muted);white-space:nowrap">Win %</span>
        <input type="number" class="form-input stage-prob-input" value="${Math.round(s.probability*100)}" min="0" max="100" oninput="pipelineSettingsTemp[${i}].probability=Math.min(1,Math.max(0,parseInt(this.value)||0)/100)" placeholder="%" />
        <button class="btn btn-ghost btn-xs stage-row-move" onclick="movePipelineSettingStage(${i},-1)" title="Move up">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" width="12" height="12"><polyline points="18 15 12 9 6 15"/></svg>
        </button>
        <button class="btn btn-ghost btn-xs stage-row-move" onclick="movePipelineSettingStage(${i},1)" title="Move down">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" width="12" height="12"><polyline points="6 9 12 15 18 9"/></svg>
        </button>
        <button class="btn btn-ghost btn-xs" onclick="deletePipelineSettingStage(${i})" ${dealsInStage>0?`title="Cannot delete — ${dealsInStage} deal(s) in stage" disabled`:'title="Delete stage"'} style="${dealsInStage>0?'opacity:0.3;cursor:not-allowed':''}">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" width="12" height="12"><polyline points="3,6 5,6 21,6"/><path d="M19,6l-1,14a2,2,0,0,1-2,2H8a2,2,0,0,1-2-2L5,6"/></svg>
        </button>
      </div>`;
  }).join('');
}

function addPipelineSettingStage() {
  pipelineSettingsTemp.push({ name: 'New Stage', color: '#6366f1', probability: 0.10 });
  renderPipelineSettingsStages();
}

function deletePipelineSettingStage(idx) {
  pipelineSettingsTemp.splice(idx, 1);
  renderPipelineSettingsStages();
}

function movePipelineSettingStage(idx, dir) {
  const newIdx = idx + dir;
  if (newIdx < 0 || newIdx >= pipelineSettingsTemp.length) return;
  [pipelineSettingsTemp[idx], pipelineSettingsTemp[newIdx]] = [pipelineSettingsTemp[newIdx], pipelineSettingsTemp[idx]];
  renderPipelineSettingsStages();
}

function savePipelineSettings() {
  // Validate — no empty names
  if (pipelineSettingsTemp.some(s => !s.name.trim())) { toast('All stages must have a name', 'error'); return; }
  if (pipelineSettingsTemp.length < 2) { toast('Need at least 2 stages', 'error'); return; }
  db.settings.pipelineStages = pipelineSettingsTemp.map(s => ({ ...s, name: s.name.trim() }));
  saveDB();
  closeModal('modal-pipeline-settings');
  renderPipeline();
  toast('Pipeline stages saved', 'success');
}

// ── Activities ─────────────────────────────────────────────────────────────
let actTypeFilter = '';
let actDateFilter = '';

function renderActivities() {
  let acts = [...db.activities].sort((a,b) => new Date(b.date) - new Date(a.date));
  if (actTypeFilter) acts = acts.filter(a => a.type === actTypeFilter);
  if (actDateFilter) {
    const now = new Date();
    if (actDateFilter === 'today')  { const dd = new Date(now.setHours(0,0,0,0)); acts = acts.filter(a => new Date(a.date) >= dd); }
    if (actDateFilter === 'week')   { const dd = new Date(Date.now() - 7*86400000); acts = acts.filter(a => new Date(a.date) >= dd); }
    if (actDateFilter === 'month')  { const dd = new Date(Date.now() - 30*86400000); acts = acts.filter(a => new Date(a.date) >= dd); }
  }
  document.getElementById('activities-count').textContent = acts.length + ' activities';
  const feed = document.getElementById('activities-feed');
  feed.innerHTML = acts.length ? acts.map(a => `
    <div class="activity-item">
      <div class="activity-icon ${activityTypeClass(a.type)}">${activityIconSVG(a.type)}</div>
      <div class="activity-content">
        <div class="activity-header">
          <span class="activity-type" style="color:${activityTypeColor(a.type)}">${esc(a.type)}</span>
          <span class="activity-contact">${esc(contactName(a.contactId))}</span>
          ${a.dealId ? `<span class="tag tag-blue" style="font-size:9px">${esc(db.deals.find(d=>d.id===a.dealId)?.name||'')}</span>` : ''}
          <span class="activity-time">${timeAgo(new Date(a.date).getTime())}</span>
        </div>
        <div class="activity-note">${esc(a.note)}</div>
        <div style="font-size:11px;color:var(--text-muted);margin-top:3px">${formatDate(a.date)}</div>
      </div>
      <button class="btn btn-ghost btn-sm" onclick="deleteActivity('${a.id}')" title="Delete">
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><polyline points="3,6 5,6 21,6"/><path d="M19,6l-1,14a2,2,0,0,1-2,2H8a2,2,0,0,1-2-2L5,6"/><path d="M10,11v6"/><path d="M14,11v6"/></svg>
      </button>
    </div>`).join('') : `<div class="empty-state"><div class="empty-state-title">No activities found</div><div class="empty-state-sub">Log a call, email, or meeting to get started</div></div>`;
}

function openActivityModal(preContactId = null, preDealId = null) {
  document.getElementById('activity-form-id').value    = '';
  document.getElementById('activity-form-type').value  = 'Note';
  document.getElementById('activity-form-note').value  = '';
  document.getElementById('activity-form-date').value  = new Date().toISOString().slice(0,10);
  document.getElementById('email-template-picker').style.display = 'none';

  const cSel = document.getElementById('activity-form-contact');
  cSel.innerHTML = `<option value="">No Contact</option>` + db.contacts.map(c => `<option value="${c.id}" ${preContactId===c.id?'selected':''}>${esc(c.name)}</option>`).join('');

  const dSel = document.getElementById('activity-form-deal');
  dSel.innerHTML = `<option value="">No Deal</option>` + db.deals.filter(d => d.stage!=='Lost').map(d => `<option value="${d.id}" ${preDealId===d.id?'selected':''}>${esc(d.name)}</option>`).join('');

  openModal('modal-activity');
}

function saveActivity() {
  const note = document.getElementById('activity-form-note').value.trim();
  if (!note) { toast('Note is required', 'error'); return; }
  const contactId = document.getElementById('activity-form-contact').value;
  const dateVal   = document.getElementById('activity-form-date').value;
  const act = {
    id:        uid(),
    type:      document.getElementById('activity-form-type').value,
    contactId,
    dealId:    document.getElementById('activity-form-deal').value || null,
    note,
    date:      dateVal ? new Date(dateVal).toISOString() : new Date().toISOString(),
    createdAt: Date.now(),
  };
  db.activities.push(act);
  if (contactId) {
    const c = db.contacts.find(x => x.id === contactId);
    if (c) c.lastActivity = Date.now();
  }
  saveDB();
  closeModal('modal-activity');
  renderActivities();
  if (currentView === 'dashboard')     renderDashboard();
  if (currentView === 'contacts')      renderContacts();
  if (currentView === 'contact-detail') renderContactDetail(contactId);
  if (currentView === 'deal-detail' && act.dealId) renderDealDetail(act.dealId);
  toast('Activity logged', 'success');
}

function deleteActivity(id) {
  db.activities = db.activities.filter(a => a.id !== id);
  saveDB();
  renderActivities();
  toast('Activity deleted', 'info');
}

// ── Tasks ──────────────────────────────────────────────────────────────────
function updateTasksBadge() {
  const todayStr = new Date().toISOString().slice(0, 10);
  const overdue  = (db.tasks||[]).filter(t => t.status === 'Open' && t.dueDate < todayStr).length;
  const badge    = document.getElementById('nav-tasks-badge');
  if (badge) {
    if (overdue > 0) { badge.style.display = ''; badge.textContent = overdue; badge.style.background = 'rgba(239,68,68,0.2)'; badge.style.color = 'var(--red)'; }
    else badge.style.display = 'none';
  }
  updateNotificationBell();
}

function renderTasks() {
  const tasks    = db.tasks || [];
  const todayStr = new Date().toISOString().slice(0, 10);
  const overdue  = tasks.filter(t => t.status === 'Open' && t.dueDate && t.dueDate < todayStr);
  const dueToday = tasks.filter(t => t.status === 'Open' && t.dueDate === todayStr);
  const upcoming = tasks.filter(t => t.status === 'Open' && (!t.dueDate || t.dueDate > todayStr));
  const done     = tasks.filter(t => t.status === 'Done');

  const openCount = overdue.length + dueToday.length + upcoming.length;
  document.getElementById('tasks-count').textContent = openCount + ' open' + (done.length ? `, ${done.length} done` : '');
  updateTasksBadge();

  function taskItemHTML(t) {
    const isDone    = t.status === 'Done';
    const isOverdue = !isDone && t.dueDate && t.dueDate < todayStr;
    const isToday   = !isDone && t.dueDate === todayStr;
    const contact   = t.contactId ? db.contacts.find(c => c.id === t.contactId) : null;
    const deal      = t.dealId    ? db.deals.find(d => d.id === t.dealId)       : null;
    return `
      <div class="task-item${isDone?' done':''}">
        <div class="task-priority ${(t.priority||'medium').toLowerCase()}"></div>
        <div style="flex:1;min-width:0">
          <div class="task-title${isDone?' done':''}">${esc(t.title)}</div>
          <div class="task-meta" style="margin-top:3px">
            ${t.dueDate ? `<span class="task-due ${isOverdue?'overdue':isToday?'today':'upcoming'}">${isOverdue?'Overdue · ':isToday?'Today · ':''}${formatDate(t.dueDate)}</span>` : ''}
            ${contact ? `<span style="color:var(--text-dim)"> · <a href="#" onclick="event.preventDefault();showContactDetail('${contact.id}')" style="color:var(--accent-hover);text-decoration:none">${esc(contact.name)}</a></span>` : ''}
            ${deal    ? `<span class="tag tag-blue" style="font-size:9px;cursor:pointer" onclick="showDealDetail('${deal.id}')">${esc(deal.name)}</span>` : ''}
            <span class="tag ${t.priority==='High'?'tag-red':t.priority==='Low'?'tag-blue':'tag-yellow'}" style="font-size:9px">${esc(t.priority||'Medium')}</span>
          </div>
        </div>
        ${!isDone ? `<button class="btn btn-ghost btn-xs" onclick="markTaskDone('${t.id}');renderTasks()" title="Mark done">Done</button>` : `<span style="font-size:10px;color:var(--text-muted)">Done</span>`}
        <button class="btn btn-ghost btn-xs" onclick="deleteTask('${t.id}')" title="Delete task" style="opacity:0.5;padding:2px 4px">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" width="11" height="11"><polyline points="3,6 5,6 21,6"/><path d="M19,6l-1,14a2,2,0,0,1-2,2H8a2,2,0,0,1-2-2L5,6"/></svg>
        </button>
      </div>`;
  }

  function groupHTML(title, items, color) {
    if (!items.length) return '';
    return `
      <div class="task-group">
        <div class="task-group-header" style="color:${color||'var(--text-muted)'}">
          ${title} <span style="font-weight:400;color:var(--text-muted);text-transform:none;letter-spacing:0">(${items.length})</span>
        </div>
        ${items.map(taskItemHTML).join('')}
      </div>`;
  }

  const container = document.getElementById('tasks-list');
  const html = [
    groupHTML('Overdue', overdue, 'var(--red)'),
    groupHTML('Due Today', dueToday, 'var(--yellow)'),
    groupHTML('Upcoming', upcoming, 'var(--text-dim)'),
    groupHTML('Done', done, 'var(--text-muted)'),
  ].join('');
  container.innerHTML = html || `<div class="empty-state"><div class="empty-state-title">No tasks yet</div><div class="empty-state-sub">Click "Add Task" to get started</div></div>`;
}

function openTaskModal(preContactId = null) {
  document.getElementById('task-form-id').value       = '';
  document.getElementById('task-form-title').value    = '';
  document.getElementById('task-form-duedate').value  = new Date().toISOString().slice(0,10);
  document.getElementById('task-form-priority').value = 'Medium';
  const cSel = document.getElementById('task-form-contact');
  cSel.innerHTML = `<option value="">No Contact</option>` + db.contacts.map(c => `<option value="${c.id}" ${preContactId===c.id?'selected':''}>${esc(c.name)}</option>`).join('');
  openModal('modal-task');
}

function openTaskModalForDeal(dealId) {
  const deal = db.deals.find(d => d.id === dealId);
  openTaskModal(deal ? deal.contact : null);
  // Pre-wire save to attach dealId — we'll set it after modal opens
  document.getElementById('btn-save-task').dataset.dealId = dealId;
}

function saveTask() {
  const title = document.getElementById('task-form-title').value.trim();
  if (!title) { toast('Task title is required', 'error'); return; }
  const btn   = document.getElementById('btn-save-task');
  const task = {
    id:        uid(),
    title,
    dueDate:   document.getElementById('task-form-duedate').value || null,
    contactId: document.getElementById('task-form-contact').value || null,
    dealId:    btn.dataset.dealId || null,
    priority:  document.getElementById('task-form-priority').value,
    status:    'Open',
    createdAt: Date.now(),
  };
  delete btn.dataset.dealId;
  db.tasks = db.tasks || [];
  db.tasks.push(task);
  saveDB();
  closeModal('modal-task');
  renderTasks();
  if (currentView === 'dashboard') renderDashboard();
  updateTasksBadge();
  toast('Task added', 'success');
}

function markTaskDone(id) {
  const task = (db.tasks||[]).find(t => t.id === id);
  if (!task) return;
  task.status = 'Done';
  saveDB();
  updateTasksBadge();
  if (currentView === 'dashboard') renderDashboard();
  toast('Task marked done', 'success');
}

function deleteTask(id) {
  db.tasks = (db.tasks||[]).filter(t => t.id !== id);
  saveDB();
  renderTasks();
  updateTasksBadge();
  if (currentView === 'dashboard') renderDashboard();
  toast('Task deleted', 'info');
}

// ── Notification Bell ──────────────────────────────────────────────────────
function updateNotificationBell() {
  const todayStr = new Date().toISOString().slice(0, 10);
  const overdue  = (db.tasks||[]).filter(t => t.status === 'Open' && t.dueDate < todayStr);
  const badge    = document.getElementById('notif-badge');
  const list     = document.getElementById('notif-list');
  if (!badge || !list) return;
  if (overdue.length > 0) {
    badge.style.display = '';
    badge.textContent   = overdue.length;
  } else {
    badge.style.display = 'none';
  }
  list.innerHTML = overdue.length ? overdue.slice(0,8).map(t => {
    const c = t.contactId ? db.contacts.find(x => x.id === t.contactId) : null;
    return `
      <div class="notif-item" onclick="navigate('tasks');closeNotifBell()">
        <div class="notif-item-title">${esc(t.title)}</div>
        <div class="notif-item-meta">Due ${formatDate(t.dueDate)}${c ? ` · ${esc(c.name)}` : ''}</div>
      </div>`;
  }).join('') : '<div style="padding:12px 16px;font-size:12px;color:var(--text-muted)">No overdue tasks</div>';
}

function toggleNotifBell() {
  const dd = document.getElementById('notif-dropdown');
  if (!dd) return;
  const isOpen = dd.classList.contains('open');
  document.querySelectorAll('.notif-dropdown.open').forEach(el => el.classList.remove('open'));
  if (!isOpen) { updateNotificationBell(); dd.classList.add('open'); }
}

function closeNotifBell() {
  const dd = document.getElementById('notif-dropdown');
  if (dd) dd.classList.remove('open');
}

// ── Export / Import ────────────────────────────────────────────────────────
function csvRow(fields) {
  return fields.map(v => `"${String(v == null ? '' : v).replace(/"/g,'""')}"`).join(',');
}

function downloadFile(filename, content, mimeType) {
  const blob = new Blob([content], { type: mimeType });
  const url  = URL.createObjectURL(blob);
  const a    = document.createElement('a');
  a.href = url; a.download = filename; a.click();
  URL.revokeObjectURL(url);
}

