function importData() {
  const input = document.createElement('input');
  input.type = 'file'; input.accept = '.json,.csv';
  input.onchange = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    if (file.name.endsWith('.csv')) {
      importContactsCSV(file);
    } else {
      importJSON(file);
    }
  };
  input.click();
}

function importJSON(file) {
  const reader = new FileReader();
  reader.onload = (ev) => {
    try {
      const data = JSON.parse(ev.target.result);
      if (!data.contacts || !data.deals) { toast('Invalid CRM export file', 'error'); return; }
      if (!confirm('This will replace all current data. Continue?')) return;
      db = data;
      db.settings = db.settings || { pipelineStages: null, emailTemplates: [] };
      db.settings.emailTemplates = db.settings.emailTemplates || [];
      saveDB();
      renderView(currentView);
      toast('Data imported successfully', 'success');
    } catch { toast('Failed to parse JSON file', 'error'); }
  };
  reader.readAsText(file);
}

function importContactsCSV(file) {
  const reader = new FileReader();
  reader.onload = (ev) => {
    try {
      const lines  = ev.target.result.split('\n').filter(l => l.trim());
      if (lines.length < 2) { toast('CSV appears empty', 'error'); return; }
      const headers = parseCSVRow(lines[0]).map(h => h.toLowerCase().trim());
      const col = (names) => {
        for (const n of names) {
          const idx = headers.findIndex(h => h.includes(n));
          if (idx >= 0) return idx;
        }
        return -1;
      };
      const nameIdx    = col(['name','full name','contact']);
      const emailIdx   = col(['email']);
      const phoneIdx   = col(['phone']);
      const companyIdx = col(['company','organization']);
      const titleIdx   = col(['title','job title','position']);
      const stageIdx   = col(['stage','status']);
      const ownerIdx   = col(['owner']);
      const tagsIdx    = col(['tags']);
      const notesIdx   = col(['notes','note']);

      if (nameIdx < 0) { toast('CSV must have a Name column', 'error'); return; }

      let added = 0, skipped = 0;
      for (let i = 1; i < lines.length; i++) {
        const cols  = parseCSVRow(lines[i]);
        const name  = (cols[nameIdx]||'').trim();
        if (!name) continue;
        const email = emailIdx >= 0 ? (cols[emailIdx]||'').trim() : '';
        // Duplicate check
        if (email && db.contacts.find(c => c.email && c.email.toLowerCase() === email.toLowerCase())) {
          skipped++; continue;
        }
        // Resolve company
        let companyId = '';
        if (companyIdx >= 0 && cols[companyIdx]) {
          const cName = cols[companyIdx].trim();
          let co = db.companies.find(c => c.name.toLowerCase() === cName.toLowerCase());
          if (!co && cName) {
            co = { id: uid(), name: cName, createdAt: Date.now() };
            db.companies.push(co);
          }
          if (co) companyId = co.id;
        }
        const stageVal = stageIdx >= 0 ? cols[stageIdx]||'' : 'Lead';
        const validStage = CONTACT_STAGES.find(s => s.toLowerCase() === stageVal.toLowerCase()) || 'Lead';
        const tagsRaw = tagsIdx >= 0 ? (cols[tagsIdx]||'') : '';
        const tags = tagsRaw ? tagsRaw.split(/[;,]/).map(t => t.trim()).filter(Boolean) : [];
        db.contacts.push({
          id: uid(), createdAt: Date.now(), lastActivity: Date.now(),
          name, email, phone: phoneIdx>=0?(cols[phoneIdx]||'').trim():'',
          company: companyId, title: titleIdx>=0?(cols[titleIdx]||'').trim():'',
          stage: validStage, owner: ownerIdx>=0?(cols[ownerIdx]||'').trim():'',
          tags, notes: notesIdx>=0?(cols[notesIdx]||'').trim():'',
        });
        added++;
      }
      saveDB();
      navigate('contacts');
      toast(`Imported ${added} contact${added!==1?'s':''}${skipped?` (${skipped} duplicate${skipped!==1?'s':''} skipped)`:''}`, 'success');
    } catch(err) { toast('Failed to parse CSV: ' + err.message, 'error'); }
  };
  reader.readAsText(file);
}

function parseCSVRow(line) {
  const result = [];
  let cur = '', inQuote = false;
  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    if (ch === '"') {
      if (inQuote && line[i+1] === '"') { cur += '"'; i++; }
      else inQuote = !inQuote;
    } else if (ch === ',' && !inQuote) { result.push(cur); cur = ''; }
    else cur += ch;
  }
  result.push(cur);
  return result;
}

