function openEmailTemplatesModal() {
  renderEmailTemplatesList();
  document.getElementById('template-form-subject').value = '';
  document.getElementById('template-form-body').value    = '';
  openModal('modal-email-templates');
}

function renderEmailTemplatesList() {
  const templates = db.settings.emailTemplates || [];
  const container = document.getElementById('email-templates-list');
  const CATEGORY_COLORS = { 'General':'#6b7280','Intro':'#6366f1','Follow-up':'#3b82f6','Proposal':'#f97316','Closing':'#22c55e' };
  container.innerHTML = templates.length ? templates.map(t => {
    const cat = t.category || 'General';
    const catColor = CATEGORY_COLORS[cat] || '#6b7280';
    const catBadge = `<span style="background:${catColor}22;color:${catColor};border:1px solid ${catColor}55;border-radius:3px;padding:0 5px;font-size:10px;font-weight:600">${esc(cat)}</span>`;
    return `<div class="email-template-item">
      <div style="flex:1;min-width:0">
        <div style="display:flex;align-items:center;gap:6px;margin-bottom:2px">
          ${catBadge}
          <div class="email-template-subject">${esc(t.name || t.subject)}</div>
        </div>
        <div class="email-template-preview" style="color:var(--text-muted);font-size:11px">${esc(t.subject)}</div>
        ${t.body ? `<div class="email-template-preview" style="font-size:11px;color:var(--text-dim)">${esc(t.body.slice(0,100))}${t.body.length>100?'...':''}</div>` : ''}
      </div>
      <button class="btn btn-ghost btn-xs" onclick="deleteEmailTemplate('${t.id}')" title="Delete template">
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" width="11" height="11"><polyline points="3,6 5,6 21,6"/><path d="M19,6l-1,14a2,2,0,0,1-2,2H8a2,2,0,0,1-2-2L5,6"/></svg>
      </button>
    </div>`;
  }).join('') : '<div style="color:var(--text-muted);font-size:12px;padding:8px 0">No templates yet. Add one below.</div>';
  updateTemplatePickerSelect();
}

function addEmailTemplate() {
  const name     = (document.getElementById('template-form-name')?.value || '').trim();
  const category = document.getElementById('template-form-category')?.value || 'General';
  const subject  = document.getElementById('template-form-subject').value.trim();
  const body     = document.getElementById('template-form-body').value.trim();
  if (!subject) { toast('Subject is required', 'error'); return; }
  db.settings.emailTemplates.push({ id: uid(), name: name || subject, subject, body, category });
  saveDB();
  renderEmailTemplatesList();
  if (document.getElementById('template-form-name')) document.getElementById('template-form-name').value = '';
  document.getElementById('template-form-subject').value = '';
  document.getElementById('template-form-body').value    = '';
  toast('Template saved', 'success');
}

// Phase 20: preview template form with sample data
function p20PreviewTemplateForm() {
  const body = document.getElementById('template-form-body')?.value || '';
  const previewEl = document.getElementById('template-form-preview');
  if (!previewEl) return;
  const VARS = {
    '{{contact.name}}':    'John Smith',
    '{{contact.company}}': 'Acme Corp',
    '{{deal.name}}':       'Acme — Enterprise Deal',
    '{{deal.value}}':      '$50,000',
    '{{user.name}}':       (_currentUser?.name || 'Your Name'),
  };
  let rendered = body;
  Object.entries(VARS).forEach(([k, v]) => {
    rendered = rendered.replaceAll(k, `<mark style="background:rgba(99,102,241,0.15);color:var(--accent);border-radius:2px;padding:0 2px">${v}</mark>`);
  });
  previewEl.style.display = '';
  previewEl.innerHTML = '<div style="font-size:10px;font-weight:600;color:var(--text-muted);margin-bottom:4px;text-transform:uppercase;letter-spacing:0.05em">Preview (sample data)</div>' + rendered.replace(/\n/g, '<br>');
}
