// ── Export Dropdown ────────────────────────────────────────────────────────
function toggleExportDropdown(wrapId) {
  const menu = document.getElementById(wrapId + '-menu');
  if (!menu) return;
  const wasOpen = menu.classList.contains('open');
  document.querySelectorAll('.dropdown-menu.open').forEach(m => m.classList.remove('open'));
  if (!wasOpen) menu.classList.add('open');
}
function closeExportDropdown(wrapId) {
  const menu = document.getElementById(wrapId + '-menu');
  if (menu) menu.classList.remove('open');
}

// ── Modal helpers ──────────────────────────────────────────────────────────
function openModal(id) { document.getElementById(id).classList.add('open'); document.body.style.overflow = 'hidden'; }
function closeModal(id) { document.getElementById(id).classList.remove('open'); document.body.style.overflow = ''; }

// Close modal on overlay click
document.addEventListener('click', (e) => {
  if (e.target.classList.contains('modal-overlay')) closeModal(e.target.id);
  // Close dropdowns and notification bell on outside click
  if (!e.target.closest('.dropdown-wrap'))    document.querySelectorAll('.dropdown-menu.open').forEach(m => m.classList.remove('open'));
  if (!e.target.closest('.notif-bell-wrap'))  closeNotifBell();
});

// Escape key closes modals
document.addEventListener('keydown', (e) => {
  if (e.key === 'Escape') {
    document.querySelectorAll('.modal-overlay.open').forEach(m => closeModal(m.id));
    closeNotifBell();
  }
});

// ── Init ───────────────────────────────────────────────────────────────────
async function init() {
  // Always set up event listeners first
  setupEventListeners();

  // Check for existing token
  if (!_authToken) {
    showLoginScreen();
    return; // doLogin() will call startApp() after successful auth
  }

  loadDB(); // load local cache for instant UI render
  await startApp();
}

// Called after successful login
async function startApp() {
  try {
    await loadDBFromAPI();
  } catch(err) {
    if (err.message === 'Unauthorized') return;
    console.warn('API load failed, using cached data');
  }
  // Add logout to nav if not already there
  addLogoutButton();
  navigate('dashboard');
}

function addLogoutButton() {
  if (document.getElementById('btn-logout')) return;
  const nav = document.querySelector('.sidebar-nav') || document.querySelector('.nav');
  if (!nav) return;
  const btn = document.createElement('button');
  btn.id = 'btn-logout';
  btn.className = 'btn btn-ghost btn-sm';
  btn.style.cssText = 'margin:8px 12px;width:calc(100% - 24px);text-align:left;color:var(--text-muted);font-size:12px';
  btn.innerHTML = `<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="14" height="14" style="margin-right:6px"><path d="M9 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h4"/><polyline points="16,17 21,12 16,7"/><line x1="21" y1="12" x2="9" y2="12"/></svg>Sign Out`;
  btn.onclick = doLogout;
  nav.appendChild(btn);
}

function setupEventListeners() {
  // Guard: only run once
  if (window._listenersSetup) return;
  window._listenersSetup = true;

  // Nav
  document.querySelectorAll('.nav-item').forEach(item => {
    item.addEventListener('click', () => navigate(item.dataset.view));
  });

  // Contacts
  document.getElementById('btn-add-contact').addEventListener('click', () => openContactModal());
  document.getElementById('contact-search').addEventListener('input', (e) => { contactSearch = e.target.value; renderContacts(); });
  document.getElementById('contact-stage-filter').addEventListener('change', (e) => { contactStageFilter = e.target.value; renderContacts(); });
  document.getElementById('contacts-tag-filter').addEventListener('change', (e) => { contactTagFilter = e.target.value; renderContacts(); });
  // Phase 15: health filter
  const healthFilterEl2 = document.getElementById('contacts-health-filter');
  if (healthFilterEl2) healthFilterEl2.addEventListener('change', () => renderContacts());
  document.getElementById('contact-select-all').addEventListener('change', toggleSelectAll);

  // Contact table sort
  document.querySelectorAll('#contacts-table thead th[data-sort]').forEach(th => {
    th.addEventListener('click', () => {
      const col = th.dataset.sort;
      if (contactSort.col === col) contactSort.dir = contactSort.dir === 'asc' ? 'desc' : 'asc';
      else { contactSort.col = col; contactSort.dir = 'asc'; }
      document.querySelectorAll('#contacts-table thead th').forEach(t => t.classList.remove('sort-asc','sort-desc'));
      th.classList.add(contactSort.dir === 'asc' ? 'sort-asc' : 'sort-desc');
      renderContacts();
    });
  });

  // Contact modal tags input
  document.getElementById('contact-tags-input').addEventListener('keydown', (e) => {
    if (e.key === 'Enter' || e.key === ',') {
      e.preventDefault();
      const val = e.target.value.trim().replace(/,/g,'').toLowerCase();
      if (val && !contactModalTags.includes(val)) { contactModalTags.push(val); renderContactModalTags(); }
      e.target.value = '';
    }
    if (e.key === 'Backspace' && !e.target.value && contactModalTags.length) {
      contactModalTags.pop(); renderContactModalTags();
    }
  });

  document.getElementById('btn-save-contact').addEventListener('click', saveContact);

  // Companies
  document.getElementById('btn-add-company').addEventListener('click', () => openCompanyModal());
  document.getElementById('company-search').addEventListener('input', (e) => { companySearch = e.target.value; renderCompanies(); });
  document.getElementById('btn-save-company').addEventListener('click', saveCompany);

  // Pipeline
  document.getElementById('btn-add-deal').addEventListener('click', () => openDealModal(null));
  document.getElementById('btn-save-deal').addEventListener('click', saveDeal);
  document.getElementById('btn-pipeline-settings').addEventListener('click', openPipelineSettings);
  document.getElementById('btn-save-pipeline-settings').addEventListener('click', savePipelineSettings);

  // Activities
  document.getElementById('btn-log-activity').addEventListener('click', () => openActivityModal());
  document.getElementById('btn-save-activity').addEventListener('click', saveActivity);
  document.getElementById('act-type-filter').addEventListener('change', (e) => { actTypeFilter = e.target.value; renderActivities(); });
  document.getElementById('act-date-filter').addEventListener('change', (e) => { actDateFilter = e.target.value; renderActivities(); });

  // Activity modal: show template picker only for Email type
  document.getElementById('activity-form-type').addEventListener('change', (e) => {
    const picker = document.getElementById('email-template-picker');
    picker.style.display = e.target.value === 'Email' ? '' : 'none';
    if (e.target.value === 'Email') updateTemplatePickerSelect();
  });

  // Template picker populates textarea
  document.getElementById('template-picker-select').addEventListener('change', (e) => {
    const id = e.target.value;
    if (!id) return;
    const tmpl = (db.settings.emailTemplates||[]).find(t => t.id === id);
    if (tmpl) {
      document.getElementById('activity-form-note').value = tmpl.body;
      e.target.value = ''; // reset picker
    }
  });

  // Tasks
  document.getElementById('btn-add-task').addEventListener('click', () => openTaskModal());
  document.getElementById('btn-save-task').addEventListener('click', saveTask);

  // Import / Export
  document.getElementById('btn-import').addEventListener('click', importData);
  document.getElementById('btn-import-2').addEventListener('click', importData);

  // Dashboard quick-add
  document.getElementById('dash-add-contact').addEventListener('click', () => { navigate('contacts'); openContactModal(); });
  document.getElementById('dash-log-activity').addEventListener('click', () => { navigate('activities'); openActivityModal(); });
  document.getElementById('dash-add-deal').addEventListener('click', () => { navigate('pipeline'); setTimeout(() => openDealModal(null), 50); });

  // Global search input
  const spi = document.getElementById('search-palette-input');
  if (spi) spi.addEventListener('input', (e) => runSearch(e.target.value));

  // Phase 5 additions
  addSearchHint();
  applyProfile();

  // Hash routing (e.g. #contact/p1, #deal/d1)
  function handleHash() {
    const hash = location.hash;
    if      (hash.startsWith('#contact/')) navigate('contact-detail', hash.slice('#contact/'.length));
    else if (hash.startsWith('#deal/'))    navigate('deal-detail', hash.slice('#deal/'.length));
    else if (hash === '#tasks')            navigate('tasks');
    else if (hash === '#contacts')         navigate('contacts');
    else if (hash === '#pipeline')         navigate('pipeline');
  }
  window.addEventListener('hashchange', handleHash);
} // end setupEventListeners

document.addEventListener('DOMContentLoaded', init);

