// Canvas helpers
function getCtx(id, w, h) {
  const canvas = document.getElementById(id);
  if (!canvas) return null;
  // DPR scaling
  const dpr = window.devicePixelRatio || 1;
  canvas.width  = w * dpr;
  canvas.height = h * dpr;
  canvas.style.width  = w + 'px';
  canvas.style.height = h + 'px';
  const ctx = canvas.getContext('2d');
  ctx.scale(dpr, dpr);
  return ctx;
}

function drawDonut(ctx, cx, cy, r, data, total, lineWidth) {
  // data: [{value, color}]
  let angle = -Math.PI / 2;
  data.forEach(d => {
    if (!d.value) return;
    const slice = (d.value / total) * 2 * Math.PI;
    ctx.beginPath();
    ctx.moveTo(cx, cy);
    ctx.arc(cx, cy, r, angle, angle + slice);
    ctx.closePath();
    ctx.fillStyle = d.color;
    ctx.fill();
    angle += slice;
  });
  // Hollow center
  ctx.beginPath();
  ctx.arc(cx, cy, r - lineWidth, 0, 2 * Math.PI);
  ctx.fillStyle = '#1a1a2e'; // matches --bg
  ctx.fill();
}

function drawHBar(ctx, x, y, w, h, pct, color, bg) {
  ctx.fillStyle = bg || '#2a2a3e';
  ctx.beginPath();
  roundRect(ctx, x, y, w, h, h/2);
  ctx.fill();
  if (pct > 0) {
    ctx.fillStyle = color;
    ctx.beginPath();
    roundRect(ctx, x, y, Math.max(w * pct, h), h, h/2);
    ctx.fill();
  }
}

function drawVBar(ctx, x, y, w, h, color) {
  if (h <= 0) return;
  ctx.fillStyle = color;
  ctx.beginPath();
  roundRect(ctx, x, y, w, h, 3);
  ctx.fill();
}

function roundRect(ctx, x, y, w, h, r) {
  ctx.moveTo(x + r, y);
  ctx.lineTo(x + w - r, y);
  ctx.quadraticCurveTo(x + w, y, x + w, y + r);
  ctx.lineTo(x + w, y + h - r);
  ctx.quadraticCurveTo(x + w, y + h, x + w - r, y + h);
  ctx.lineTo(x + r, y + h);
  ctx.quadraticCurveTo(x, y + h, x, y + h - r);
  ctx.lineTo(x, y + r);
  ctx.quadraticCurveTo(x, y, x + r, y);
  ctx.closePath();
}

function ctxText(ctx, text, x, y, size, color, align) {
  ctx.font = `${size}px Inter, -apple-system, sans-serif`;
  ctx.fillStyle = color || '#e2e2e8';
  ctx.textAlign = align || 'left';
  ctx.fillText(text, x, y);
}

// Win Rate Chart
function renderWinRateChart() {
  const won  = db.deals.filter(d => d.stage === 'Won').length;
  const lost = db.deals.filter(d => d.stage === 'Lost').length;
  const open = db.deals.filter(d => d.stage !== 'Won' && d.stage !== 'Lost').length;
  const total = won + lost + open || 1;
  const ctx = getCtx('chart-winrate', 200, 200);
  if (!ctx) return;

  const data = [
    { value: won,  color: '#22c55e', label: 'Won',  val: won },
    { value: lost, color: '#ef4444', label: 'Lost', val: lost },
    { value: open, color: '#6366f1', label: 'Open', val: open },
  ];
  drawDonut(ctx, 100, 100, 78, data, total, 28);

  // Center text
  const rate = won + lost > 0 ? Math.round(won / (won + lost) * 100) : 0;
  ctxText(ctx, rate + '%', 100, 96, 22, '#e2e2e8', 'center');
  ctxText(ctx, 'win rate', 100, 114, 11, '#71717a', 'center');

  // Legend
  const legend = document.getElementById('chart-winrate-legend');
  if (legend) legend.innerHTML = data.map(d => `
    <div class="chart-legend-item">
      <div class="chart-legend-dot" style="background:${d.color}"></div>
      <span class="chart-legend-label">${d.label}</span>
      <span class="chart-legend-val">${d.val}</span>
    </div>`).join('');
}

// Pipeline Value by Stage Chart
function renderPipelineChart() {
  const ctx = getCtx('chart-pipeline', 500, 200);
  if (!ctx) return;
  const stages  = getDealStages();
  const values  = stages.map(s => db.deals.filter(d => d.stage === s).reduce((sum,d) => sum+(d.value||0), 0));
  const maxVal  = Math.max(...values, 1);
  const W = 500, H = 200;
  const padLeft = 110, padRight = 80, padTop = 16, padBottom = 32;
  const barH    = Math.min(22, (H - padTop - padBottom) / stages.length - 6);
  const barSpacing = (H - padTop - padBottom) / stages.length;

  stages.forEach((s, i) => {
    const y = padTop + i * barSpacing + (barSpacing - barH) / 2;
    const pct = values[i] / maxVal;
    const color = getStageColor(s);
    // Label
    ctxText(ctx, s, padLeft - 8, y + barH/2 + 4, 11, '#71717a', 'right');
    // Bar
    drawHBar(ctx, padLeft, y, W - padLeft - padRight, barH, pct, color + 'cc', '#2a2a3e');
    // Value
    const displayW = Math.max((W - padLeft - padRight) * pct, barH);
    ctxText(ctx, formatCurrency(values[i]), padLeft + displayW + 8, y + barH/2 + 4, 11, '#a1a1aa', 'left');
  });
}

// Activity Breakdown Chart
function renderActivityChart() {
  const counts = {};
  ACTIVITY_TYPES.forEach(t => { counts[t] = 0; });
  db.activities.forEach(a => { if (counts[a.type] != null) counts[a.type]++; });
  const total = Object.values(counts).reduce((s,v) => s+v, 0) || 1;
  const colors = { 'Note':'#a1a1aa', 'Call':'#22c55e', 'Email':'#3b82f6', 'Meeting':'#eab308', 'Task':'#f97316' };
  const data = ACTIVITY_TYPES.map(t => ({ value: counts[t], color: colors[t], label: t, val: counts[t] }));
  const ctx = getCtx('chart-activities', 200, 200);
  if (!ctx) return;
  drawDonut(ctx, 100, 100, 78, data, total, 28);
  ctxText(ctx, db.activities.length.toString(), 100, 96, 22, '#e2e2e8', 'center');
  ctxText(ctx, 'activities', 100, 114, 11, '#71717a', 'center');

  const legend = document.getElementById('chart-activities-legend');
  if (legend) legend.innerHTML = data.map(d => `
    <div class="chart-legend-item">
      <div class="chart-legend-dot" style="background:${d.color}"></div>
      <span class="chart-legend-label">${d.label}</span>
      <span class="chart-legend-val">${d.val}</span>
    </div>`).join('');
}

// Monthly Revenue Chart
function renderMonthlyChart() {
  const ctx = getCtx('chart-monthly', 500, 200);
  if (!ctx) return;
  const W = 500, H = 200;
  const padLeft = 60, padRight = 20, padTop = 16, padBottom = 36;

  // Last 6 months
  const months = [];
  for (let i = 5; i >= 0; i--) {
    const d = new Date();
    d.setMonth(d.getMonth() - i);
    months.push({ year: d.getFullYear(), month: d.getMonth(), label: d.toLocaleDateString('en-US', { month: 'short' }) });
  }

  const values = months.map(m =>
    db.deals.filter(d => {
      if (d.stage !== 'Won' || !d.closeDate) return false;
      const cd = new Date(d.closeDate);
      return cd.getFullYear() === m.year && cd.getMonth() === m.month;
    }).reduce((sum,d) => sum+(d.value||0), 0)
  );

  const maxVal = Math.max(...values, 1);
  const n = months.length;
  const barW = Math.floor((W - padLeft - padRight) / n * 0.6);
  const gap  = Math.floor((W - padLeft - padRight) / n);

  // Grid lines
  ctx.strokeStyle = '#2a2a3e';
  ctx.lineWidth = 1;
  [0.25, 0.5, 0.75, 1].forEach(pct => {
    const y = padTop + (H - padTop - padBottom) * (1 - pct);
    ctx.beginPath(); ctx.moveTo(padLeft, y); ctx.lineTo(W - padRight, y); ctx.stroke();
    ctxText(ctx, formatCurrency(maxVal * pct), padLeft - 6, y + 4, 9, '#52525b', 'right');
  });

  // Bars
  months.forEach((m, i) => {
    const barH = ((values[i] / maxVal) * (H - padTop - padBottom));
    const x = padLeft + i * gap + (gap - barW) / 2;
    const y = padTop + (H - padTop - padBottom) - barH;
    drawVBar(ctx, x, y, barW, barH, '#6366f1cc');
    ctxText(ctx, m.label, x + barW/2, H - padBottom + 16, 10, '#71717a', 'center');
    if (values[i] > 0) ctxText(ctx, formatCurrency(values[i]), x + barW/2, y - 4, 9, '#a1a1aa', 'center');
  });
}

// Deal Velocity Table
function renderVelocityTable() {
  const container = document.getElementById('report-velocity');
  if (!container) return;
  const stages = getDealStages();
  const rows = stages.map(s => {
    const stageDeals = db.deals.filter(d => d.stage === s && d.movedAt && d.createdAt);
    const avgDays = stageDeals.length
      ? Math.round(stageDeals.reduce((sum,d) => sum + daysInStage(d.movedAt||d.createdAt), 0) / stageDeals.length)
      : null;
    const totalVal = stageDeals.reduce((sum,d) => sum+(d.value||0), 0);
    return { stage: s, count: stageDeals.length, avgDays, totalVal };
  });
  const maxDays = Math.max(...rows.map(r => r.avgDays||0), 1);
  const color   = s => getStageColor(s);
  container.innerHTML = `
    <table class="velocity-table">
      <thead><tr>
        <th>Stage</th><th>Deals</th><th>Avg Days in Stage</th><th style="width:200px"></th><th>Total Value</th>
      </tr></thead>
      <tbody>${rows.map(r => `
        <tr>
          <td><span style="display:inline-flex;align-items:center;gap:6px"><span style="width:8px;height:8px;border-radius:50%;background:${color(r.stage)};display:inline-block"></span>${esc(r.stage)}</span></td>
          <td>${r.count}</td>
          <td>${r.avgDays != null ? r.avgDays + ' days' : '—'}</td>
          <td>
            <div class="velocity-bar-wrap">
              <div class="velocity-bar" style="width:${r.avgDays?Math.round(r.avgDays/maxDays*100):0}%;background:${color(r.stage)}"></div>
            </div>
          </td>
          <td style="color:var(--green);font-weight:600">${r.totalVal ? formatCurrency(r.totalVal) : '—'}</td>
        </tr>`).join('')}
      </tbody>
    </table>`;
}

// Top Contacts by Deal Value
function renderTopContacts() {
  const container = document.getElementById('report-top-contacts');
  if (!container) return;
  const ranked = db.contacts.map(c => {
    const total = getContactDeals(c.id).reduce((sum,d) => sum+(d.value||0), 0);
    const won   = getContactDeals(c.id).filter(d => d.stage==='Won').reduce((sum,d) => sum+(d.value||0), 0);
    return { ...c, totalDealValue: total, wonValue: won };
  }).sort((a,b) => b.totalDealValue - a.totalDealValue).slice(0, 8);

  const maxVal = ranked[0]?.totalDealValue || 1;
  container.innerHTML = ranked.length ? `
    <table class="velocity-table">
      <thead><tr><th>Contact</th><th>Company</th><th>Stage</th><th>Pipeline Value</th><th style="width:200px"></th><th>Won</th></tr></thead>
      <tbody>${ranked.map(c => `
        <tr style="cursor:pointer" onclick="showContactDetail('${c.id}')">
          <td class="td-name"><div style="display:flex;align-items:center;gap:8px"><div class="avatar">${esc(initials(c.name))}</div>${esc(c.name)}</div></td>
          <td class="td-muted">${esc(companyName(c.company))}</td>
          <td><span class="stage-pill ${stageClass(c.stage)}">${esc(c.stage)}</span></td>
          <td style="font-weight:600">${formatCurrency(c.totalDealValue)}</td>
          <td><div class="velocity-bar-wrap"><div class="velocity-bar" style="width:${Math.round(c.totalDealValue/maxVal*100)}%;background:#6366f1"></div></div></td>
          <td style="color:var(--green);font-weight:600">${c.wonValue ? formatCurrency(c.wonValue) : '—'}</td>
        </tr>`).join('')}
      </tbody>
    </table>` : '<div class="empty-state"><div class="empty-state-title">No deal data yet</div></div>';
}

function exportReportsCSV() {
  const won  = db.deals.filter(d => d.stage === 'Won');
  const lost = db.deals.filter(d => d.stage === 'Lost');
  const rows = [csvRow(['Metric','Value'])];
  rows.push(csvRow(['Total Contacts', db.contacts.length]));
  rows.push(csvRow(['Total Companies', db.companies.length]));
  rows.push(csvRow(['Total Deals', db.deals.length]));
  rows.push(csvRow(['Deals Won', won.length]));
  rows.push(csvRow(['Deals Lost', lost.length]));
  rows.push(csvRow(['Revenue Won', won.reduce((s,d) => s+(d.value||0),0)]));
  rows.push(csvRow(['Total Activities', db.activities.length]));
  downloadFile(`crm-report-${new Date().toISOString().slice(0,10)}.csv`, rows.join('\n'), 'text/csv');
  toast('Report exported', 'success');
}

// ── Dashboard Insights Panel ───────────────────────────────
function renderInsightsPanel() {
  const bar       = document.getElementById('insights-bar');
  if (!bar) return;
  const insights  = [];
  const now       = Date.now();
  const todayStr  = new Date().toISOString().slice(0,10);

  // Cold deals: no activity + deal hasn't moved in 14+ days (not Won/Lost)
  const coldDeals = db.deals.filter(d => {
    if (d.stage === 'Won' || d.stage === 'Lost') return false;
    const movedMs = d.movedAt ? (typeof d.movedAt === 'string' ? new Date(d.movedAt).getTime() : d.movedAt) : d.createdAt;
    return (now - movedMs) > 14 * 86400000;
  });
  if (coldDeals.length) {
    insights.push({
      type: 'warn',
      icon: `<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><path d="M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z"/><line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/></svg>`,
      text: `${coldDeals.length} deal${coldDeals.length!==1?'s':''} stuck — no movement in 14+ days`,
      action: () => navigate('pipeline'),
    });
  }

  // Deals closing this week
  const nextWeekStr = new Date(now + 7*86400000).toISOString().slice(0,10);
  const closingSoon = db.deals.filter(d => d.closeDate && d.closeDate >= todayStr && d.closeDate <= nextWeekStr && d.stage !== 'Won' && d.stage !== 'Lost');
  if (closingSoon.length) {
    insights.push({
      type: 'caution',
      icon: `<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>`,
      text: `${closingSoon.length} deal${closingSoon.length!==1?'s':''} closing this week — ${formatCurrency(closingSoon.reduce((s,d) => s+(d.value||0),0))}`,
      action: () => navigate('pipeline'),
    });
  }

  // Dormant contacts: no activity in 30+ days
  const dormant = db.contacts.filter(c => {
    if (!c.lastActivity) return true;
    const ms = typeof c.lastActivity === 'string' ? new Date(c.lastActivity).getTime() : c.lastActivity;
    return (now - ms) > 30 * 86400000;
  });
  if (dormant.length > 0) {
    insights.push({
      type: dormant.length > 5 ? 'caution' : null,
      icon: `<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/></svg>`,
      text: `${dormant.length} contact${dormant.length!==1?'s':''} not touched in 30+ days`,
      action: () => navigate('contacts'),
    });
  }

  // Win rate
  const won = db.deals.filter(d => d.stage === 'Won').length;
  const total = db.deals.filter(d => d.stage === 'Won' || d.stage === 'Lost').length;
  if (total >= 3) {
    const rate = Math.round(won / total * 100);
    insights.push({
      type: rate >= 50 ? 'good' : 'caution',
      icon: `<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><polyline points="22 12 18 12 15 21 9 3 6 12 2 12"/></svg>`,
      text: `${rate}% win rate — ${won} won, ${total-won} lost`,
      action: () => navigate('reports'),
    });
  }

  if (!insights.length) { bar.style.display = 'none'; return; }
  bar.style.display = '';
  bar.innerHTML = `<div class="insights-bar">${insights.map((ins, i) => `
    <div class="insight-chip ${ins.type||''}" onclick="insightAction(${i})">
      ${ins.icon}
      <span>${esc(ins.text)}</span>
    </div>`).join('')}</div>`;
  window._insightActions = insights.map(i => i.action);
}

function insightAction(i) {
  if (window._insightActions && window._insightActions[i]) window._insightActions[i]();
}

// ── Global Search (Cmd+K) ──────────────────────────────────
let searchPaletteOpen = false;

function openSearchPalette() {
  const overlay = document.getElementById('search-palette-overlay');
  const input   = document.getElementById('search-palette-input');
  if (!overlay || !input) return;
  overlay.classList.add('open');
  searchPaletteOpen = true;
  input.value = '';
  document.getElementById('search-palette-results').innerHTML = `<div class="search-palette-empty">Start typing to search contacts, companies, and deals...</div>`;
  setTimeout(() => input.focus(), 50);
}

function closeSearchPalette() {
  const overlay = document.getElementById('search-palette-overlay');
  if (overlay) overlay.classList.remove('open');
  searchPaletteOpen = false;
}

function runSearch(query) {
  const q = query.toLowerCase().trim();
  const results = document.getElementById('search-palette-results');
  if (!q) {
    results.innerHTML = `<div class="search-palette-empty">Start typing to search...</div>`;
    return;
  }

  const contacts = db.contacts.filter(c =>
    c.name.toLowerCase().includes(q) ||
    (c.email||'').toLowerCase().includes(q) ||
    companyName(c.company).toLowerCase().includes(q)
  ).slice(0, 5);

  const companies = db.companies.filter(c =>
    c.name.toLowerCase().includes(q) ||
    (c.industry||'').toLowerCase().includes(q) ||
    (c.city||'').toLowerCase().includes(q)
  ).slice(0, 5);

  const deals = db.deals.filter(d =>
    d.name.toLowerCase().includes(q) ||
    companyName(d.company).toLowerCase().includes(q)
  ).slice(0, 5);

  if (!contacts.length && !companies.length && !deals.length) {
    results.innerHTML = `<div class="search-palette-empty">No results for "${esc(query)}"</div>`;
    return;
  }

  let html = '';
  if (contacts.length) {
    html += `<div class="search-result-group"><div class="search-result-group-label">Contacts</div>`;
    html += contacts.map(c => `
      <div class="search-result-item" onclick="closeSearchPalette();showContactDetail('${c.id}')">
        <div class="search-result-icon contact">${esc(initials(c.name))}</div>
        <div><div class="search-result-name">${esc(c.name)}</div><div class="search-result-sub">${esc(c.title||'')}${c.title&&companyName(c.company)?' · ':''}${esc(companyName(c.company))}</div></div>
      </div>`).join('');
    html += '</div>';
  }
  if (companies.length) {
    html += `<div class="search-result-group"><div class="search-result-group-label">Companies</div>`;
    html += companies.map(c => `
      <div class="search-result-item" onclick="closeSearchPalette();editCompanyModal('${c.id}')">
        <div class="search-result-icon company">${esc(initials(c.name))}</div>
        <div><div class="search-result-name">${esc(c.name)}</div><div class="search-result-sub">${esc(c.industry||'')}${c.industry&&c.city?' · ':''}${esc(c.city||'')}</div></div>
      </div>`).join('');
    html += '</div>';
  }
  if (deals.length) {
    html += `<div class="search-result-group"><div class="search-result-group-label">Deals</div>`;
    html += deals.map(d => `
      <div class="search-result-item" onclick="closeSearchPalette();showDealDetail('${d.id}')">
        <div class="search-result-icon deal" style="font-size:13px">$</div>
        <div><div class="search-result-name">${esc(d.name)}</div><div class="search-result-sub">${esc(d.stage)} · ${formatCurrency(d.value||0)}</div></div>
      </div>`).join('');
    html += '</div>';
  }

  results.innerHTML = html;
}

// Keyboard shortcut: Cmd+K / Ctrl+K
document.addEventListener('keydown', (e) => {
  if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
    e.preventDefault();
    if (searchPaletteOpen) closeSearchPalette();
    else openSearchPalette();
  }
  if (e.key === 'Escape' && searchPaletteOpen) closeSearchPalette();
});

