// ── Settings ───────────────────────────────────────────────
function renderSettings() {
  // Load saved profile
  const profile = db.settings.profile || {};
  const nameEl  = document.getElementById('settings-user-name');
  const coEl    = document.getElementById('settings-company-name');
  if (nameEl) nameEl.value = profile.userName || '';
  if (coEl)   coEl.value   = profile.companyName || '';

  // Template count
  const tpl = document.getElementById('settings-template-count');
  const n   = (db.settings.emailTemplates || []).length;
  if (tpl) tpl.textContent = n ? `${n} template${n!==1?'s':''} saved` : 'No templates saved yet.';

  // Data size
  const sizeEl = document.getElementById('settings-data-size');
  if (sizeEl) {
    const bytes = new Blob([localStorage.getItem(STORE_KEY)||'']).size;
    sizeEl.textContent = `Local storage: ${(bytes/1024).toFixed(1)} KB`;
  }

  // Update sidebar name
  applyProfile();
  loadInvoiceSettings();
  renderCustomFieldsList();
  loadGoalSettings();
  renderPlaybookSettings();
}

function saveProfileSettings() {
  const name = document.getElementById('settings-user-name').value.trim();
  const co   = document.getElementById('settings-company-name').value.trim();
  db.settings.profile = { userName: name, companyName: co };
  saveDB();
  applyProfile();
  toast('Profile saved', 'success');
}

function applyProfile() {
  const profile = db.settings.profile || {};
  const nameEl  = document.getElementById('sidebar-user-name');
  if (nameEl && profile.userName) nameEl.textContent = profile.userName;
}

function resetToSampleData() {
  if (!confirm('Reset all data to the default demo dataset? This cannot be undone.')) return;
  db = defaultData();
  saveDB();
  navigate('dashboard');
  toast('Reset to sample data', 'info');
}

function clearAllData() {
  if (!confirm('Delete ALL data permanently? This cannot be undone.')) return;
  if (!confirm('Are you sure? This will erase every contact, deal, and company.')) return;
  db = { companies: [], contacts: [], deals: [], activities: [], tasks: [], settings: { pipelineStages: null, emailTemplates: [] } };
  saveDB();
  navigate('dashboard');
  toast('All data cleared', 'info');
}

