// ── Update renderView and init for Phase 5 ────────────────
// (These run after the original init — we patch via prototype-style override)
const _origRenderView = renderView;

// [consolidated above]

// We need to add 'settings' to renderView. Since renderView is a switch,
// let's re-declare it here after the original definition has already run.
// This override takes effect at runtime because JS is single-threaded
// and all function declarations are hoisted, but the redefinition here
