// Add Cmd+K search hint to sidebar
function addSearchHint() {
  const nav = document.querySelector('.sidebar-nav');
  if (!nav || document.querySelector('.search-hint')) return;
  const hint = document.createElement('div');
  hint.className = 'search-hint';
  hint.onclick = openSearchPalette;
  hint.innerHTML = `
    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" width="12" height="12"><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg>
    <span style="flex:1">Search</span>
    <kbd>K</kbd>`;
  nav.insertBefore(hint, nav.firstChild);
}

