// ── Invoice listeners (wired on DOMContentLoaded) ─────────
document.addEventListener('DOMContentLoaded', () => {
  // Wire invoice-specific UI after init has already run
  const createBtn = document.getElementById('btn-create-invoice');
  if (createBtn) createBtn.addEventListener('click', () => navigate('invoice-detail', null));
  const invSearch = document.getElementById('invoice-search');
  if (invSearch) invSearch.addEventListener('input', (e) => { invoiceSearch = e.target.value; renderInvoices(); });
  const invFilter = document.getElementById('invoice-status-filter');
  if (invFilter) invFilter.addEventListener('change', (e) => { invoiceStatusFilter = e.target.value; renderInvoices(); });
});

