// ── Invoice Settings ───────────────────────────────────────
function loadInvoiceSettings() {
  const s = db.settings.invoiceSettings || {};
  const get = id => document.getElementById(id);
  if (get('inv-settings-prefix'))  get('inv-settings-prefix').value  = s.prefix  || 'INV-';
  if (get('inv-settings-start'))   get('inv-settings-start').value   = s.nextNumber || 1001;
  if (get('inv-settings-company')) get('inv-settings-company').value = s.companyName || '';
  if (get('inv-settings-address')) get('inv-settings-address').value = s.address || '';
  if (get('inv-settings-email'))   get('inv-settings-email').value   = s.email || '';
}

function saveInvoiceSettings() {
  if (!db.settings.invoiceSettings) db.settings.invoiceSettings = {};
  const s = db.settings.invoiceSettings;
  const get = id => document.getElementById(id);
  s.prefix      = get('inv-settings-prefix')?.value.trim()  || 'INV-';
  s.nextNumber  = parseInt(get('inv-settings-start')?.value) || s.nextNumber || 1001;
  s.companyName = get('inv-settings-company')?.value.trim() || '';
  s.address     = get('inv-settings-address')?.value.trim() || '';
  s.email       = get('inv-settings-email')?.value.trim()   || '';
  saveDB();
  toast('Invoice settings saved', 'success');
}

// ── Custom Fields ──────────────────────────────────────────
function initCustomFields() {
  if (!db.settings.customFields) db.settings.customFields = [];
}

function renderCustomFieldsList() {
  initCustomFields();
  const el = document.getElementById('custom-fields-list');
  if (!el) return;
  el.innerHTML = db.settings.customFields.length
    ? db.settings.customFields.map(f => `
        <div style="display:flex;align-items:center;gap:8px;padding:5px 0;border-bottom:1px solid var(--border)">
          <span style="flex:1;font-size:12px">${esc(f.name)}</span>
          <span style="font-size:10px;color:var(--text-muted);text-transform:uppercase">${esc(f.type)}</span>
          <button class="btn btn-ghost btn-xs" onclick="deleteCustomField('${f.id}')" style="opacity:0.5">
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" width="11" height="11"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
          </button>
        </div>`).join('')
    : `<div style="font-size:11px;color:var(--text-muted);margin-bottom:8px">No custom fields yet.</div>`;
}

function addCustomField() {
  initCustomFields();
  const nameEl = document.getElementById('new-custom-field-name');
  const typeEl = document.getElementById('new-custom-field-type');
  const name = nameEl?.value.trim();
  if (!name) { toast('Enter a field name', 'error'); return; }
  db.settings.customFields.push({ id: uid(), name, type: typeEl?.value || 'text' });
  saveDB();
  if (nameEl) nameEl.value = '';
  renderCustomFieldsList();
  toast('Custom field added', 'success');
}

function deleteCustomField(fieldId) {
  initCustomFields();
  db.settings.customFields = db.settings.customFields.filter(f => f.id !== fieldId);
  saveDB();
  renderCustomFieldsList();
}

// Render custom field inputs inside the contact modal
function renderCustomFieldInputs(contact) {
  initCustomFields();
  const fields = db.settings.customFields;
  if (!fields.length) return '';
  return fields.map(f => {
    const val = contact?.customFields?.[f.id] || '';
    return `
      <div class="form-group">
        <label class="form-label">${esc(f.name)}</label>
        <input type="${f.type==='number'?'number':f.type==='date'?'date':'text'}" class="form-input custom-field-input"
          data-field-id="${f.id}" value="${esc(String(val))}" placeholder="${esc(f.name)}..." />
      </div>`;
  }).join('');
}

// Collect custom field values from modal
function collectCustomFieldValues() {
  const result = {};
  document.querySelectorAll('.custom-field-input').forEach(el => {
    result[el.dataset.fieldId] = el.value;
  });
  return result;
}

// ── Client Portal ──────────────────────────────────────────
function portalToken(dealId) {
  // Simple deterministic token — not cryptographic, but enough to prevent casual guessing
  let h = 0;
  const str = dealId + 'boredroomCRM';
  for (let i = 0; i < str.length; i++) { h = (Math.imul(31, h) + str.charCodeAt(i)) | 0; }
  return (h >>> 0).toString(36);
}

function copyPortalLink(dealId) {
  const url = `${location.origin}${location.pathname}#portal/${dealId}/${portalToken(dealId)}`;
  navigator.clipboard.writeText(url).then(() => toast('Portal link copied', 'success')).catch(() => toast('Copy failed — link: ' + url, 'error'));
}

function renderPortal(param) {
  const el = document.getElementById('view-portal');
  // param format: "dealId/token"
  const [dealId, token] = (param || '').split('/');
  const deal = dealId ? db.deals.find(d => d.id === dealId) : null;

  if (!deal || !token || token !== portalToken(dealId)) {
    el.innerHTML = `
      <div style="display:flex;align-items:center;justify-content:center;height:100%;flex-direction:column;gap:16px;padding:40px;text-align:center">
        <div style="font-size:32px;font-weight:700;color:var(--text-muted)">404</div>
        <div style="color:var(--text-muted)">Invalid or expired portal link.</div>
      </div>`;
    return;
  }

  const contact = db.contacts.find(c => c.id === deal.contact);
  const company = db.companies.find(c => c.id === deal.company);
  const stages  = getDealStages();
  const stageIdx = stages.findIndex(s => s.name === deal.stage);
  const profile  = db.settings.profile || {};

  // Only show external-facing activities
  const dealActivities = (db.activities || [])
    .filter(a => a.deal === deal.id && a.type !== 'Note')
    .sort((a,b) => b.date - a.date)
    .slice(0, 10);

  el.innerHTML = `
    <div class="portal-wrap">
      <div class="portal-header">
        <div class="portal-brand">${esc(profile.companyName || 'BoredRoom')}</div>
        <div style="font-size:12px;color:var(--text-muted)">Client Project Portal</div>
      </div>
      <div class="portal-card">
        <div class="portal-deal-name">${esc(deal.name)}</div>
        ${company ? `<div style="font-size:13px;color:var(--text-muted);margin-top:4px">${esc(company.name)}</div>` : ''}
        <div style="margin:24px 0">
          <div style="font-size:10px;text-transform:uppercase;letter-spacing:0.08em;color:var(--text-muted);margin-bottom:10px;font-weight:600">Project Stage</div>
          <div class="portal-stage-track">
            ${stages.map((s,i) => `
              <div class="portal-stage-step ${i <= stageIdx && deal.stage !== 'Lost' ? 'done' : ''} ${s.name === deal.stage ? 'current' : ''}">
                <div class="portal-stage-dot"></div>
                <div class="portal-stage-label">${esc(s.name)}</div>
              </div>`).join('<div class="portal-stage-line"></div>')}
          </div>
        </div>
        ${deal.closeDate ? `
          <div style="margin:16px 0;padding:12px 16px;background:var(--surface2);border-radius:8px;font-size:12px">
            <span style="color:var(--text-muted)">Expected close:</span>
            <span style="font-weight:600;margin-left:8px">${formatDate(deal.closeDate)}</span>
          </div>` : ''}
        ${deal.value ? `
          <div style="margin:8px 0;padding:12px 16px;background:var(--surface2);border-radius:8px;font-size:12px">
            <span style="color:var(--text-muted)">Deal value:</span>
            <span style="font-weight:600;margin-left:8px;color:var(--green)">${formatCurrency(deal.value)}</span>
          </div>` : ''}
      </div>

      ${dealActivities.length ? `
        <div class="portal-card" style="margin-top:16px">
          <div style="font-size:12px;font-weight:600;text-transform:uppercase;letter-spacing:0.08em;color:var(--text-muted);margin-bottom:12px">Recent Activity</div>
          ${dealActivities.map(a => `
            <div style="display:flex;gap:10px;padding:8px 0;border-bottom:1px solid var(--border)">
              <div style="width:28px;height:28px;border-radius:50%;background:var(--surface3);display:flex;align-items:center;justify-content:center;flex-shrink:0;font-size:11px;color:var(--text-muted)">${esc(a.type[0])}</div>
              <div>
                <div style="font-size:12px;font-weight:500">${esc(a.type)}</div>
                <div style="font-size:11px;color:var(--text-muted)">${a.notes ? esc(a.notes.slice(0,80)) : ''}</div>
              </div>
              <div style="font-size:10px;color:var(--text-muted);margin-left:auto;flex-shrink:0">${formatDate(a.date)}</div>
            </div>`).join('')}
        </div>` : ''}

      <div style="text-align:center;margin-top:24px;font-size:11px;color:var(--text-muted)">
        Powered by BoredRoom CRM
      </div>
    </div>`;
}

