// ── Revenue Goals ──────────────────────────────────────────
function initGoals() {
  if (!db.settings.goals) db.settings.goals = { monthlyRevenue: 0, quarterlyRevenue: 0 };
}

function saveGoals() {
  initGoals();
  db.settings.goals.monthlyRevenue  = parseFloat(document.getElementById('goal-monthly')?.value)   || 0;
  db.settings.goals.quarterlyRevenue = parseFloat(document.getElementById('goal-quarterly')?.value) || 0;
  saveDB();
  toast('Goals saved', 'success');
  renderGoalProgress();
}

function loadGoalSettings() {
  initGoals();
  const g = db.settings.goals;
  const mEl = document.getElementById('goal-monthly');
  const qEl = document.getElementById('goal-quarterly');
  if (mEl) mEl.value = g.monthlyRevenue  || '';
  if (qEl) qEl.value = g.quarterlyRevenue || '';
}

function calcMonthlyRevenue() {
  const now   = new Date();
  const month = now.getMonth();
  const year  = now.getFullYear();
  return db.deals
    .filter(d => {
      if (d.stage !== 'Won') return false;
      const t = new Date(d.movedAt || d.createdAt);
      return t.getMonth() === month && t.getFullYear() === year;
    })
    .reduce((s,d) => s + (d.value||0), 0);
}

function calcQuarterlyRevenue() {
  const now    = new Date();
  const qStart = Math.floor(now.getMonth() / 3) * 3;
  const year   = now.getFullYear();
  return db.deals
    .filter(d => {
      if (d.stage !== 'Won') return false;
      const t  = new Date(d.movedAt || d.createdAt);
      const tQ = Math.floor(t.getMonth() / 3) * 3;
      return tQ === qStart && t.getFullYear() === year;
    })
    .reduce((s,d) => s + (d.value||0), 0);
}

function renderGoalProgress() {
  initGoals();
  const g   = db.settings.goals;
  const el  = document.getElementById('goal-progress-bar');
  if (!el) return;
  if (!g.monthlyRevenue && !g.quarterlyRevenue) { el.style.display = 'none'; return; }
  el.style.display = '';

  const monthActual    = calcMonthlyRevenue();
  const quarterActual  = calcQuarterlyRevenue();
  const monthPct       = g.monthlyRevenue  ? Math.min(100, (monthActual / g.monthlyRevenue) * 100)   : null;
  const quarterPct     = g.quarterlyRevenue ? Math.min(100, (quarterActual / g.quarterlyRevenue) * 100) : null;

  el.innerHTML = `
    <div class="goal-bar-wrap">
      ${monthPct !== null ? `
        <div class="goal-bar-item">
          <div class="goal-bar-labels">
            <span>Monthly Goal</span>
            <span>${formatCurrency(monthActual)} / ${formatCurrency(g.monthlyRevenue)} (${Math.round(monthPct)}%)</span>
          </div>
          <div class="goal-track"><div class="goal-fill" style="width:${monthPct}%;background:${monthPct>=100?'var(--green)':'var(--accent)'}"></div></div>
        </div>` : ''}
      ${quarterPct !== null ? `
        <div class="goal-bar-item">
          <div class="goal-bar-labels">
            <span>Quarterly Goal</span>
            <span>${formatCurrency(quarterActual)} / ${formatCurrency(g.quarterlyRevenue)} (${Math.round(quarterPct)}%)</span>
          </div>
          <div class="goal-track"><div class="goal-fill" style="width:${quarterPct}%;background:${quarterPct>=100?'var(--green)':'var(--accent)'}"></div></div>
        </div>` : ''}
    </div>`;
}

// ── Smart Lists ────────────────────────────────────────────
function initSmartLists() {
  if (!db.settings.smartLists) db.settings.smartLists = [];
}

const CONTACT_FIELDS = [
  { value: 'name',       label: 'Name',         ops: ['contains','equals'] },
  { value: 'email',      label: 'Email',         ops: ['contains','equals'] },
  { value: 'stage',      label: 'Lead Stage',    ops: ['equals'] },
  { value: 'owner',      label: 'Owner',         ops: ['contains','equals'] },
  { value: 'company',    label: 'Company',       ops: ['contains','equals'] },
];
const DEAL_FIELDS = [
  { value: 'name',       label: 'Deal Name',     ops: ['contains','equals'] },
  { value: 'stage',      label: 'Stage',         ops: ['equals'] },
  { value: 'owner',      label: 'Owner',         ops: ['contains','equals'] },
  { value: 'value',      label: 'Value',         ops: ['gt','lt','equals'] },
];

function openSmartListModal() {
  document.getElementById('sl-form-name').value = '';
  document.getElementById('sl-form-type').value = 'contacts';
  document.getElementById('sl-criteria-list').innerHTML = '';
  addSlCriteria();
  openModal('modal-smartlist');
}

function updateSlCriteriaFields() {
  document.getElementById('sl-criteria-list').innerHTML = '';
  addSlCriteria();
}

let _slCriteriaCount = 0;
function addSlCriteria() {
  const type   = document.getElementById('sl-form-type')?.value || 'contacts';
  const fields = type === 'contacts' ? CONTACT_FIELDS : DEAL_FIELDS;
  const idx    = _slCriteriaCount++;
  const div    = document.createElement('div');
  div.style.cssText = 'display:flex;gap:6px;align-items:center';
  div.innerHTML = `
    <select class="form-select" style="flex:1;font-size:12px" id="sl-c-field-${idx}" onchange="updateSlOpOptions(${idx})">
      ${fields.map(f => `<option value="${f.value}">${f.label}</option>`).join('')}
    </select>
    <select class="form-select" style="width:90px;font-size:12px" id="sl-c-op-${idx}">
      <option value="contains">contains</option>
      <option value="equals">equals</option>
    </select>
    <input type="text" class="form-input" style="flex:1;font-size:12px" id="sl-c-val-${idx}" placeholder="value" />
    <button class="btn btn-ghost btn-xs" onclick="this.closest('div').remove()" style="opacity:0.5">
      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" width="10" height="10"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
    </button>`;
  document.getElementById('sl-criteria-list').appendChild(div);
}

function updateSlOpOptions(idx) {
  const type    = document.getElementById('sl-form-type')?.value || 'contacts';
  const fields  = type === 'contacts' ? CONTACT_FIELDS : DEAL_FIELDS;
  const fieldEl = document.getElementById(`sl-c-field-${idx}`);
  const opEl    = document.getElementById(`sl-c-op-${idx}`);
  if (!fieldEl || !opEl) return;
  const field = fields.find(f => f.value === fieldEl.value);
  if (!field) return;
  opEl.innerHTML = field.ops.map(op => `<option value="${op}">${op==='gt'?'greater than':op==='lt'?'less than':op}</option>`).join('');
}

function saveSmartList() {
  initSmartLists();
  const name = document.getElementById('sl-form-name')?.value.trim();
  if (!name) { toast('Enter a list name', 'error'); return; }
  const type = document.getElementById('sl-form-type')?.value || 'contacts';

  const criteria = [];
  document.querySelectorAll('#sl-criteria-list > div').forEach((row, i) => {
    const f = row.querySelector('[id^="sl-c-field-"]');
    const o = row.querySelector('[id^="sl-c-op-"]');
    const v = row.querySelector('[id^="sl-c-val-"]');
    if (f && o && v && v.value.trim()) {
      criteria.push({ field: f.value, op: o.value, value: v.value.trim() });
    }
  });

  db.settings.smartLists.push({ id: uid(), name, type, criteria, createdAt: Date.now() });
  saveDB();
  closeModal('modal-smartlist');
  renderSmartLists();
  toast('Smart list saved', 'success');
}

function applySmartListFilter(record, criteria) {
  return criteria.every(c => {
    const fieldVal = String(record[c.field] || '').toLowerCase();
    const target   = c.value.toLowerCase();
    if (c.op === 'contains') return fieldVal.includes(target);
    if (c.op === 'equals')   return fieldVal === target;
    if (c.op === 'gt')       return parseFloat(record[c.field]||0) > parseFloat(target);
    if (c.op === 'lt')       return parseFloat(record[c.field]||0) < parseFloat(target);
    return true;
  });
}

function renderSmartLists() {
  initSmartLists();
  const container = document.getElementById('smartlists-container');
  if (!container) return;

  if (!db.settings.smartLists.length) {
    container.innerHTML = `
      <div class="empty-state" style="margin-top:60px">
        <div class="empty-state-title">No smart lists yet</div>
        <div class="empty-state-sub">Create dynamic segments of your contacts and deals</div>
      </div>`;
    return;
  }

  container.innerHTML = `
    <div class="settings-grid">
      ${db.settings.smartLists.map(list => {
        const records   = list.type === 'contacts' ? db.contacts : db.deals;
        const matched   = records.filter(r => applySmartListFilter(r, list.criteria));
        return `
          <div class="panel settings-card">
            <div class="panel-header">
              <div class="panel-title">${esc(list.name)}</div>
              <button class="btn btn-ghost btn-xs panel-action" onclick="deleteSmartList('${list.id}')" style="opacity:0.4">
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" width="11" height="11"><polyline points="3,6 5,6 21,6"/><path d="M19,6l-1,14H6L5,6"/></svg>
              </button>
            </div>
            <div style="padding:12px 16px">
              <div style="font-size:32px;font-weight:700;color:var(--accent);margin-bottom:4px">${matched.length}</div>
              <div style="font-size:12px;color:var(--text-muted);margin-bottom:10px">${esc(list.type)} matched</div>
              <div style="font-size:10px;color:var(--text-muted);margin-bottom:8px">
                ${list.criteria.map(c => `<span style="background:var(--surface3);border-radius:4px;padding:1px 6px;margin-right:4px">${esc(c.field)} ${esc(c.op)} "${esc(c.value)}"</span>`).join('')}
              </div>
              <button class="btn btn-secondary btn-sm" onclick="viewSmartListResults('${list.id}')">View Results</button>
            </div>
          </div>`;
      }).join('')}
    </div>`;
}

function deleteSmartList(id) {
  if (!confirm('Delete this smart list?')) return;
  db.settings.smartLists = db.settings.smartLists.filter(l => l.id !== id);
  saveDB();
  renderSmartLists();
  toast('List deleted', 'info');
}

function viewSmartListResults(id) {
  const list = db.settings.smartLists.find(l => l.id === id);
  if (!list) return;
  if (list.type === 'contacts') navigate('contacts');
  else navigate('pipeline');
  toast(`Showing ${list.name} — filter manually in the ${list.type} view for now`, 'info');
}

// ── Funnel Conversion Analytics (adds to Reports) ─────────
function renderConversionFunnel() {
  const el = document.getElementById('report-funnel');
  if (!el) return;
  const stages = getDealStages();
  const allDeals = db.deals.filter(d => d.stage !== 'Lost');

  el.innerHTML = `
    <div style="overflow-x:auto">
      <table style="width:100%;border-collapse:collapse">
        <thead>
          <tr>
            <th style="text-align:left;font-size:10px;text-transform:uppercase;letter-spacing:0.06em;color:var(--text-muted);padding:6px 0;border-bottom:1px solid var(--border)">Stage</th>
            <th style="text-align:right;font-size:10px;text-transform:uppercase;letter-spacing:0.06em;color:var(--text-muted);padding:6px 0;border-bottom:1px solid var(--border)">Deals</th>
            <th style="text-align:right;font-size:10px;text-transform:uppercase;letter-spacing:0.06em;color:var(--text-muted);padding:6px 0;border-bottom:1px solid var(--border)">Value</th>
            <th style="text-align:right;font-size:10px;text-transform:uppercase;letter-spacing:0.06em;color:var(--text-muted);padding:6px 0;border-bottom:1px solid var(--border)">% of Total</th>
          </tr>
        </thead>
        <tbody>
          ${stages.map(s => {
            const count = allDeals.filter(d => d.stage === s.name).length;
            const val   = allDeals.filter(d => d.stage === s.name).reduce((sum,d) => sum+(d.value||0), 0);
            const pct   = allDeals.length ? Math.round((count/allDeals.length)*100) : 0;
            return `<tr>
              <td style="padding:8px 0;border-bottom:1px solid var(--border);font-size:12px">
                <span style="display:inline-block;width:8px;height:8px;border-radius:50%;background:${s.color};margin-right:6px"></span>
                ${esc(s.name)}
              </td>
              <td style="text-align:right;padding:8px 0;border-bottom:1px solid var(--border);font-size:12px;font-weight:600">${count}</td>
              <td style="text-align:right;padding:8px 0;border-bottom:1px solid var(--border);font-size:12px;color:var(--green)">${formatCurrency(val)}</td>
              <td style="padding:8px 0;border-bottom:1px solid var(--border)">
                <div style="display:flex;align-items:center;gap:6px;justify-content:flex-end">
                  <div style="height:4px;width:60px;background:var(--surface3);border-radius:2px;overflow:hidden">
                    <div style="height:100%;width:${pct}%;background:${s.color}"></div>
                  </div>
                  <span style="font-size:11px;color:var(--text-muted);min-width:28px;text-align:right">${pct}%</span>
                </div>
              </td>
            </tr>`;
          }).join('')}
        </tbody>
      </table>
    </div>`;
}

