// ── Lead Scoring ───────────────────────────────────────────
function calcLeadScore(contact) {
  let score = 0;
  if (contact.email)   score += 10;
  if (contact.phone)   score += 5;
  if (contact.company) score += 5;
  if (contact.stage === 'Hot')  score += 20;
  else if (contact.stage === 'Warm') score += 10;

  const activities = (db.activities||[]).filter(a => a.contact === contact.id);
  score += Math.min(30, activities.length * 5);

  // Recency of last activity
  if (activities.length) {
    const lastAct = Math.max(...activities.map(a => a.date));
    const daysAgo = (Date.now() - lastAct) / 86400000;
    if (daysAgo < 7)  score += 20;
    else if (daysAgo < 30) score += 10;
  }

  // Has linked deals
  const deals = (db.deals||[]).filter(d => d.contact === contact.id);
  if (deals.length) score += 10;
  const stages = getDealStages();
  const totalStages = stages.length;
  deals.forEach(d => {
    const idx = stages.findIndex(s => s.name === d.stage);
    if (idx > totalStages / 2) score += 10;
    if (d.stage === 'Won') score += 10;
  });

  return Math.min(100, score);
}

function leadScoreBadge(score) {
  let cls = 'ls-cold';
  if (score >= 70) cls = 'ls-hot';
  else if (score >= 40) cls = 'ls-warm';
  return `<span class="lead-score-badge ${cls}">${score}</span>`;
}

// ── Probability Override ───────────────────────────────────
// Deal gets a user-set probability (0-100) that overrides stage default
// Already stored in deal.probability if set.
// We'll expose it in the deal detail side panel as an editable field.

function saveDealProbabilityOverride(dealId, prob) {
  const idx = db.deals.findIndex(d => d.id === dealId);
  if (idx === -1) return;
  const str = String(prob).trim();
  const val = parseInt(str);
  db.deals[idx].probabilityOverride = (!str || isNaN(val)) ? null : Math.min(100, Math.max(0, val));
  saveDB();
  toast(db.deals[idx].probabilityOverride != null ? 'Probability override set' : 'Probability reset to stage default', 'success');
  renderDealDetail(dealId);
}

// Returns probability as a 0-1 decimal (consistent with getStageProbability)
function getDealEffectiveProbability(deal) {
  if (deal.probabilityOverride != null) return deal.probabilityOverride / 100;
  return getStageProbability(deal.stage);
}

// ── Bulk Email Composer ────────────────────────────────────
let _bulkEmailRecipients = [];

function openBulkEmailModal() {
  const checked = [...document.querySelectorAll('.contact-checkbox:checked')];
  if (!checked.length) { toast('Select at least one contact', 'error'); return; }
  _bulkEmailRecipients = checked.map(cb => {
    const c = db.contacts.find(c => c.id === cb.value);
    return c ? { id: c.id, name: c.name, email: c.email } : null;
  }).filter(Boolean);

  const recipientEl = document.getElementById('bulk-email-recipients');
  if (recipientEl) recipientEl.innerHTML = _bulkEmailRecipients.map(r =>
    `<span style="background:var(--surface3);border-radius:4px;padding:2px 8px;font-size:11px">${esc(r.name)}${r.email?' — '+esc(r.email):' (no email)'}</span>`
  ).join('');

  document.getElementById('bulk-email-subject').value = '';
  document.getElementById('bulk-email-body').value = '';
  openModal('modal-bulk-email');
}

function sendBulkEmail() {
  const subject = document.getElementById('bulk-email-subject')?.value.trim();
  const body    = document.getElementById('bulk-email-body')?.value.trim();
  if (!subject) { toast('Enter a subject', 'error'); return; }

  const withEmail = _bulkEmailRecipients.filter(r => r.email);
  const noEmail   = _bulkEmailRecipients.filter(r => !r.email);

  // Log activity for each contact
  const now = Date.now();
  withEmail.forEach(r => {
    db.activities.unshift({ id: uid(), type: 'Email', contact: r.id, deal: null, notes: `Subject: ${subject}`, date: now });
  });
  saveDB();

  // Open mailto with all valid emails
  if (withEmail.length) {
    const emails = withEmail.map(r => r.email).join(',');
    window.open(`mailto:${emails}?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`, '_blank');
  }

  closeModal('modal-bulk-email');
  toast(`Email logged for ${withEmail.length} contact${withEmail.length!==1?'s':''}${noEmail.length?' ('+noEmail.length+' skipped — no email)':''}`, 'success');

  if (currentView === 'contacts') renderContacts();
}

