// ── Win/Loss Reason ────────────────────────────────────────
function toggleWinLossReason(stage) {
  const wrap  = document.getElementById('win-loss-reason-wrap');
  const label = document.getElementById('win-loss-reason-label');
  if (!wrap) return;
  const show = stage === 'Won' || stage === 'Lost';
  wrap.style.display = show ? '' : 'none';
  if (label) label.textContent = stage === 'Won' ? 'Win Reason' : 'Loss Reason';
}

