// ── Activity Quick-Log Presets ─────────────────────────────
const QUICK_LOG_PRESETS = [
  { label: 'Called',        type: 'Call',     note: 'Called — connected' },
  { label: 'No answer',     type: 'Call',     note: 'Called — no answer' },
  { label: 'Voicemail',     type: 'Call',     note: 'Left voicemail' },
  { label: 'Email sent',    type: 'Email',    note: 'Email sent' },
  { label: 'Meeting done',  type: 'Meeting',  note: 'Meeting completed' },
  { label: 'Demo given',    type: 'Demo',     note: 'Demo completed' },
];

function quickLogPresets(context, contactId, dealId) {
  return QUICK_LOG_PRESETS.map(p =>
    `<button class="quick-log-btn" onclick="quickLog('${p.type}','${encodeURIComponent(p.note)}','${contactId||''}','${dealId||''}')">${p.label}</button>`
  ).join('');
}

function quickLog(type, noteEncoded, contactId, dealId) {
  const note = decodeURIComponent(noteEncoded);
  const act  = {
    id:        uid(),
    type,
    notes:     note,
    contact:   contactId || null,
    deal:      dealId    || null,
    date:      Date.now(),
    createdAt: Date.now(),
  };
  db.activities.unshift(act);
  if (contactId) {
    const ci = db.contacts.findIndex(c => c.id === contactId);
    if (ci !== -1) db.contacts[ci].lastActivity = Date.now();
  }
  saveDB();
  updateNotifBadge();
  toast(`${type} logged — ${note}`, 'success');
  // Refresh the current detail view
  if (currentView === 'contact-detail' && contactId) renderContactDetail(contactId);
  if (currentView === 'deal-detail'    && dealId)    renderDealDetail(dealId);
}

// ── Contact Merge ──────────────────────────────────────────
let _mergePrimaryId  = null;
let _mergeTargetId   = null;

function openMergeModal(primaryId) {
  _mergePrimaryId = primaryId;
  _mergeTargetId  = null;
  const primary = db.contacts.find(c => c.id === primaryId);
  const nameEl  = document.getElementById('merge-primary-name');
  if (nameEl) nameEl.textContent = `${primary.name}${primary.email ? ' — ' + primary.email : ''}`;
  const searchEl = document.getElementById('merge-search-input');
  if (searchEl) searchEl.value = '';
  const resultsEl = document.getElementById('merge-search-results');
  if (resultsEl) resultsEl.innerHTML = '';
  const previewEl = document.getElementById('merge-target-preview');
  if (previewEl) previewEl.style.display = 'none';
  const confirmBtn = document.getElementById('btn-confirm-merge');
  if (confirmBtn) confirmBtn.disabled = true;
  openModal('modal-merge-contact');
}

function searchMergeTarget(query) {
  const q = query.toLowerCase().trim();
  const resultsEl = document.getElementById('merge-search-results');
  if (!resultsEl) return;
  if (!q) { resultsEl.innerHTML = ''; return; }

  const matches = db.contacts
    .filter(c => c.id !== _mergePrimaryId && (
      c.name.toLowerCase().includes(q) || (c.email||'').toLowerCase().includes(q)
    ))
    .slice(0, 6);

  resultsEl.innerHTML = matches.map(c => `
    <div onclick="selectMergeTarget('${c.id}')"
      style="padding:8px 10px;background:var(--surface2);border:1px solid var(--border);border-radius:6px;cursor:pointer;font-size:12px;transition:border-color 0.12s"
      onmouseover="this.style.borderColor='var(--accent)'" onmouseout="this.style.borderColor='var(--border)'">
      <span style="font-weight:500">${esc(c.name)}</span>
      ${c.email ? `<span style="color:var(--text-muted);margin-left:8px">${esc(c.email)}</span>` : ''}
      <span style="color:var(--text-muted);margin-left:8px;font-size:10px">${(db.activities||[]).filter(a=>a.contact===c.id).length} activities · ${(db.deals||[]).filter(d=>d.contact===c.id).length} deals</span>
    </div>`).join('') || `<div style="font-size:11px;color:var(--text-muted);padding:6px">No contacts found</div>`;
}

function selectMergeTarget(id) {
  _mergeTargetId = id;
  const c = db.contacts.find(c => c.id === id);
  const previewEl = document.getElementById('merge-target-preview');
  if (previewEl) {
    const actCount  = (db.activities||[]).filter(a => a.contact === id).length;
    const dealCount = (db.deals||[]).filter(d => d.contact === id).length;
    const taskCount = (db.tasks||[]).filter(t => t.contactId === id).length;
    previewEl.style.display = '';
    previewEl.innerHTML = `
      <strong>Selected duplicate:</strong> ${esc(c.name)}${c.email ? ' — ' + esc(c.email) : ''}<br/>
      <span style="color:var(--text-muted)">Will merge ${actCount} activities, ${dealCount} deals, ${taskCount} tasks into primary</span>`;
  }
  document.getElementById('merge-search-results').innerHTML = '';
  document.getElementById('merge-search-input').value = c.name;
  const confirmBtn = document.getElementById('btn-confirm-merge');
  if (confirmBtn) confirmBtn.disabled = false;
}

function confirmMerge() {
  if (!_mergePrimaryId || !_mergeTargetId) return;
  const primary = db.contacts.find(c => c.id === _mergePrimaryId);
  const target  = db.contacts.find(c => c.id === _mergeTargetId);
  if (!primary || !target) return;

  if (!confirm(`Merge "${target.name}" into "${primary.name}"? The duplicate will be permanently deleted.`)) return;

  // Reassign all related records to primary
  db.activities.forEach(a => { if (a.contact === _mergeTargetId) a.contact = _mergePrimaryId; });
  db.deals.forEach(d     => { if (d.contact === _mergeTargetId)  d.contact = _mergePrimaryId; });
  db.tasks.forEach(t     => { if (t.contactId === _mergeTargetId) t.contactId = _mergePrimaryId; });

  // Merge tags from target into primary (deduplicate)
  const mergedTags = [...new Set([...(primary.tags||[]), ...(target.tags||[])])];
  const pi = db.contacts.findIndex(c => c.id === _mergePrimaryId);
  db.contacts[pi].tags = mergedTags;

  // Delete target contact
  db.contacts = db.contacts.filter(c => c.id !== _mergeTargetId);

  saveDB();
  closeModal('modal-merge-contact');
  toast(`Merged ${target.name} into ${primary.name}`, 'success');
  renderContactDetail(_mergePrimaryId);
}

// ── Win/Loss Report (added to Reports view) ───────────────
function renderWinLossReport() {
  const el = document.getElementById('report-win-loss');
  if (!el) return;

  const won  = db.deals.filter(d => d.stage === 'Won');
  const lost = db.deals.filter(d => d.stage === 'Lost');

  const winReasons  = won.filter(d => d.winLossReason).map(d => d.winLossReason);
  const lossReasons = lost.filter(d => d.winLossReason).map(d => d.winLossReason);

  const countMap = arr => arr.reduce((m, r) => { m[r] = (m[r]||0)+1; return m; }, {});
  const winMap   = countMap(winReasons);
  const lossMap  = countMap(lossReasons);

  const rateNum = won.length + lost.length;
  const winRate = rateNum ? Math.round((won.length / rateNum) * 100) : 0;

  el.innerHTML = `
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:16px">
      <div>
        <div style="font-size:10px;text-transform:uppercase;letter-spacing:0.06em;color:var(--text-muted);margin-bottom:8px">Win Rate</div>
        <div style="font-size:28px;font-weight:700;color:var(--green)">${winRate}%</div>
        <div style="font-size:11px;color:var(--text-muted)">${won.length} won · ${lost.length} lost</div>
      </div>
      <div>
        <div style="font-size:10px;text-transform:uppercase;letter-spacing:0.06em;color:var(--text-muted);margin-bottom:8px">Avg deal value (won)</div>
        <div style="font-size:20px;font-weight:700;color:var(--green)">${formatCurrency(won.length ? won.reduce((s,d)=>s+(d.value||0),0)/won.length : 0)}</div>
      </div>
    </div>
    ${winReasons.length ? `
      <div style="margin-top:14px">
        <div style="font-size:10px;text-transform:uppercase;letter-spacing:0.06em;color:var(--green);margin-bottom:6px">Win Reasons</div>
        ${Object.entries(winMap).sort((a,b)=>b[1]-a[1]).map(([r,n]) => `
          <div style="display:flex;justify-content:space-between;font-size:11px;padding:3px 0;border-bottom:1px solid var(--border)">
            <span>${esc(r)}</span><span style="color:var(--green);font-weight:600">${n}</span>
          </div>`).join('')}
      </div>` : ''}
    ${lossReasons.length ? `
      <div style="margin-top:14px">
        <div style="font-size:10px;text-transform:uppercase;letter-spacing:0.06em;color:var(--red);margin-bottom:6px">Loss Reasons</div>
        ${Object.entries(lossMap).sort((a,b)=>b[1]-a[1]).map(([r,n]) => `
          <div style="display:flex;justify-content:space-between;font-size:11px;padding:3px 0;border-bottom:1px solid var(--border)">
            <span>${esc(r)}</span><span style="color:var(--red);font-weight:600">${n}</span>
          </div>`).join('')}
      </div>` : ''}`;
}

