// ── Activity Sequences ─────────────────────────────────────
// A sequence is a template of follow-up steps: [{type, note, daysFromNow}]
// Applying a sequence to a contact/deal creates tasks scheduled accordingly

function initSequences() {
  if (!db.settings.sequences) {
    db.settings.sequences = [
      {
        id: uid(), name: 'Standard Follow-Up',
        steps: [
          { type: 'Call',  note: 'Intro call',             daysFromNow: 0 },
          { type: 'Email', note: 'Follow-up email',         daysFromNow: 3 },
          { type: 'Call',  note: 'Check-in call',           daysFromNow: 7 },
          { type: 'Email', note: 'Final follow-up email',   daysFromNow: 14 },
        ]
      },
      {
        id: uid(), name: 'Post-Demo Nurture',
        steps: [
          { type: 'Email', note: 'Thank you + recap email', daysFromNow: 0 },
          { type: 'Call',  note: 'Questions / objections',  daysFromNow: 2 },
          { type: 'Email', note: 'Proposal or pricing',     daysFromNow: 5 },
          { type: 'Call',  note: 'Close call',              daysFromNow: 10 },
        ]
      }
    ];
  }
}

function applySequence(seqId, contactId, dealId) {
  initSequences();
  const seq = db.settings.sequences.find(s => s.id === seqId);
  if (!seq) return;
  const now = Date.now();
  let created = 0;
  seq.steps.forEach(step => {
    const dueDate = new Date(now + step.daysFromNow * 86400000).toISOString().slice(0,10);
    db.tasks.push({
      id:        uid(),
      title:     `${step.type}: ${step.note}`,
      type:      step.type,
      contactId: contactId || null,
      dealId:    dealId    || null,
      dueDate,
      status:    'Open',
      createdAt: now,
    });
    created++;
  });
  saveDB();
  updateNotifBadge();
  toast(`${created} tasks created from "${seq.name}"`, 'success');
  if (currentView === 'contact-detail' && contactId) renderContactDetail(contactId);
  if (currentView === 'deal-detail'    && dealId)    renderDealDetail(dealId);
}

function renderSequencePicker(contactId, dealId) {
  initSequences();
  return `
    <div class="seq-picker">
      <span class="quick-log-label">Sequence:</span>
      ${db.settings.sequences.map(s =>
        `<button class="quick-log-btn" onclick="applySequence('${s.id}','${contactId||''}','${dealId||''}')">${esc(s.name)}</button>`
      ).join('')}
    </div>`;
}

// Sequence picker is injected inline via quickLogBar() calls in the detail renderers

// ── Pipeline Forecast by Close Date ───────────────────────
function renderPipelineForecast() {
  const el = document.getElementById('forecast-panel');
  if (!el) return;

  const now     = new Date();
  const months  = [];
  for (let i = 0; i < 3; i++) {
    const d = new Date(now.getFullYear(), now.getMonth() + i, 1);
    months.push({ label: d.toLocaleString('default', { month:'long', year:'numeric' }), start: d, end: new Date(d.getFullYear(), d.getMonth()+1, 0) });
  }

  const openDeals = db.deals.filter(d => d.stage !== 'Won' && d.stage !== 'Lost' && d.closeDate);

  el.innerHTML = months.map(m => {
    const inMonth = openDeals.filter(d => {
      const cd = new Date(d.closeDate);
      return cd >= m.start && cd <= m.end;
    });
    const raw      = inMonth.reduce((s,d) => s+(d.value||0), 0);
    const weighted = inMonth.reduce((s,d) => s+(d.value||0)*getDealEffectiveProbability(d), 0);
    return `
      <div style="padding:10px 0;border-bottom:1px solid var(--border)">
        <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:4px">
          <span style="font-size:12px;font-weight:600">${esc(m.label)}</span>
          <span style="font-size:11px;color:var(--text-muted)">${inMonth.length} deal${inMonth.length!==1?'s':''}</span>
        </div>
        <div style="display:flex;justify-content:space-between;font-size:11px;color:var(--text-muted)">
          <span>Pipeline</span><span style="font-weight:600;color:var(--text)">${formatCurrency(raw)}</span>
        </div>
        <div style="display:flex;justify-content:space-between;font-size:11px;color:var(--text-muted)">
          <span>Weighted forecast</span><span style="font-weight:600;color:var(--green)">${formatCurrency(weighted)}</span>
        </div>
      </div>`;
  }).join('') + (openDeals.length === 0 ? `<div style="font-size:11px;color:var(--text-muted);padding:8px 0">No deals with close dates</div>` : '');
}

