// ── Inline Notes (contact/deal detail right panel) ─────────
function renderInlineNotes(entityType, entityId) {
  if (!db.notes) db.notes = [];
  const notes = db.notes.filter(n => n.entityType === entityType && n.entityId === entityId)
                         .sort((a,b) => b.createdAt - a.createdAt);
  return `
    <div class="panel" style="margin-top:0">
      <div class="panel-header"><div class="panel-title">Notes</div></div>
      <div style="padding:12px 16px">
        <textarea class="form-textarea" id="new-note-${entityId}" placeholder="Add a note..." style="min-height:70px;font-size:12px;margin-bottom:8px"></textarea>
        <button class="btn btn-secondary btn-sm" onclick="saveNote('${entityType}','${entityId}')">Save Note</button>
        <div style="margin-top:12px;display:flex;flex-direction:column;gap:8px" id="notes-list-${entityId}">
          ${notes.map(n => `
            <div style="padding:8px;background:var(--surface2);border-radius:6px;font-size:12px">
              <div style="color:var(--text);white-space:pre-wrap">${esc(n.text)}</div>
              <div style="display:flex;justify-content:space-between;align-items:center;margin-top:4px">
                <span style="font-size:10px;color:var(--text-muted)">${formatDate(n.createdAt)}</span>
                <button class="btn btn-ghost btn-xs" onclick="deleteNote('${n.id}','${entityType}','${entityId}')" style="opacity:0.4;font-size:9px">Delete</button>
              </div>
            </div>`).join('')}
        </div>
      </div>
    </div>`;
}

function saveNote(entityType, entityId) {
  if (!db.notes) db.notes = [];
  const el   = document.getElementById(`new-note-${entityId}`);
  const text = el?.value.trim();
  if (!text) { toast('Note is empty', 'error'); return; }
  db.notes.push({ id: uid(), entityType, entityId, text, createdAt: Date.now() });
  saveDB();
  if (el) el.value = '';
  // Refresh notes list
  const listEl = document.getElementById(`notes-list-${entityId}`);
  if (listEl) {
    const notes = db.notes.filter(n => n.entityType === entityType && n.entityId === entityId)
                           .sort((a,b) => b.createdAt - a.createdAt);
    listEl.innerHTML = notes.map(n => `
      <div style="padding:8px;background:var(--surface2);border-radius:6px;font-size:12px">
        <div style="color:var(--text);white-space:pre-wrap">${esc(n.text)}</div>
        <div style="display:flex;justify-content:space-between;align-items:center;margin-top:4px">
          <span style="font-size:10px;color:var(--text-muted)">${formatDate(n.createdAt)}</span>
          <button class="btn btn-ghost btn-xs" onclick="deleteNote('${n.id}','${entityType}','${entityId}')" style="opacity:0.4;font-size:9px">Delete</button>
        </div>
      </div>`).join('');
    toast('Note saved', 'success');
  }
}

function deleteNote(noteId, entityType, entityId) {
  if (!confirm('Delete this note?')) return;
  db.notes = (db.notes||[]).filter(n => n.id !== noteId);
  saveDB();
  const listEl = document.getElementById(`notes-list-${entityId}`);
  if (listEl) {
    const notes = db.notes.filter(n => n.entityType === entityType && n.entityId === entityId)
                           .sort((a,b) => b.createdAt - a.createdAt);
    listEl.innerHTML = notes.map(n => `
      <div style="padding:8px;background:var(--surface2);border-radius:6px;font-size:12px">
        <div style="color:var(--text);white-space:pre-wrap">${esc(n.text)}</div>
        <div style="font-size:10px;color:var(--text-muted);margin-top:4px">${formatDate(n.createdAt)}</div>
      </div>`).join('');
  }
}

