// ── Owner Performance Dashboard ───────────────────────────
function renderOwnerPerformance() {
  const el = document.getElementById('report-owner-perf');
  if (!el) return;

  // Gather all unique owners from deals and contacts
  const ownerSet = new Set();
  db.deals.forEach(d => { if (d.owner) ownerSet.add(d.owner); });
  db.contacts.forEach(c => { if (c.owner) ownerSet.add(c.owner); });
  const owners = [...ownerSet].sort();

  if (!owners.length) {
    el.innerHTML = '<div style="font-size:12px;color:var(--text-muted);padding:8px 0">No owners assigned to deals or contacts yet.</div>';
    return;
  }

  // Build per-owner stats
  const rows = owners.map(owner => {
    const ownerDeals = db.deals.filter(d => d.owner === owner);
    const won        = ownerDeals.filter(d => d.stage === 'Won');
    const lost       = ownerDeals.filter(d => d.stage === 'Lost');
    const open       = ownerDeals.filter(d => d.stage !== 'Won' && d.stage !== 'Lost');
    const closedTotal = won.length + lost.length;
    const closeRate   = closedTotal ? Math.round((won.length / closedTotal) * 100) : 0;
    const wonValue    = won.reduce((s, d) => s + (d.value || 0), 0);
    const pipelineVal = open.reduce((s, d) => s + (d.value || 0), 0);
    const avgDealSize = won.length ? Math.round(wonValue / won.length) : 0;

    // Count activities where the linked contact or deal belongs to this owner
    const actCount = (db.activities || []).filter(a => {
      const c = a.contactId ? db.contacts.find(ct => ct.id === a.contactId) : null;
      const d = a.dealId    ? db.deals.find(dl => dl.id === a.dealId)       : null;
      return (c && c.owner === owner) || (d && d.owner === owner);
    }).length;

    return { owner, open: open.length, won: won.length, lost: lost.length, closeRate, wonValue, pipelineVal, avgDealSize, actCount };
  });

  // Sort by won value desc
  rows.sort((a, b) => b.wonValue - a.wonValue);

  el.innerHTML = `
    <div style="overflow-x:auto">
      <table style="width:100%;border-collapse:collapse;font-size:12px">
        <thead>
          <tr>
            ${['Owner','Open Deals','Won','Lost','Close Rate','Won Value','Pipeline','Avg Deal','Activities'].map(h =>
              `<th style="text-align:${h==='Owner'?'left':'right'};font-size:10px;text-transform:uppercase;letter-spacing:0.06em;color:var(--text-muted);padding:8px ${h==='Owner'?'12px 8px 0':'0 0 8px'};border-bottom:1px solid var(--border)">${h}</th>`
            ).join('')}
          </tr>
        </thead>
        <tbody>
          ${rows.map((r, ri) => `
            <tr style="border-bottom:${ri < rows.length-1 ? '1px solid var(--border)' : 'none'}">
              <td style="padding:10px 12px 10px 0">
                <div style="display:inline-flex;align-items:center;justify-content:center;width:28px;height:28px;border-radius:6px;background:var(--accent);color:#fff;font-size:10px;font-weight:700;letter-spacing:0.02em;margin-right:8px">${esc(r.owner)}</div>
              </td>
              <td style="text-align:right;padding:10px 0;color:var(--text-dim)">${r.open}</td>
              <td style="text-align:right;padding:10px 0;color:var(--green);font-weight:600">${r.won}</td>
              <td style="text-align:right;padding:10px 0;color:var(--red)">${r.lost}</td>
              <td style="text-align:right;padding:10px 0">
                <span style="font-weight:600;color:${r.closeRate>=50?'var(--green)':'var(--text-dim)'}">${r.closeRate}%</span>
              </td>
              <td style="text-align:right;padding:10px 0;color:var(--green);font-weight:600">${r.wonValue ? formatCurrency(r.wonValue) : '—'}</td>
              <td style="text-align:right;padding:10px 0;color:var(--text-dim)">${r.pipelineVal ? formatCurrency(r.pipelineVal) : '—'}</td>
              <td style="text-align:right;padding:10px 0;color:var(--text-dim)">${r.avgDealSize ? formatCurrency(r.avgDealSize) : '—'}</td>
              <td style="text-align:right;padding:10px 0;color:var(--text-dim)">${r.actCount}</td>
            </tr>`).join('')}
        </tbody>
      </table>
    </div>`;
}

// ── Activity Trends ────────────────────────────────────────
function renderActivityTrends() {
  const el = document.getElementById('report-act-trends');
  if (!el) return;

  const TYPES   = ['Call', 'Email', 'Meeting', 'Note', 'Task'];
  const COLORS  = { Call:'#22c55e', Email:'#3b82f6', Meeting:'#eab308', Note:'#a1a1aa', Task:'#f97316' };
  const now     = Date.now();
  const WEEKS   = 8;
  const MS_WEEK = 7 * 86400000;

  // Build weekly bins for the last 8 weeks
  const bins = [];
  for (let i = WEEKS - 1; i >= 0; i--) {
    const wStart = now - (i + 1) * MS_WEEK;
    const wEnd   = now - i * MS_WEEK;
    const startDate = new Date(wStart);
    const label  = `${startDate.getMonth()+1}/${startDate.getDate()}`;
    const counts = {};
    TYPES.forEach(t => counts[t] = 0);
    (db.activities || []).forEach(a => {
      // a.date may be ISO string or timestamp
      const ts = typeof a.date === 'string' ? new Date(a.date).getTime() : (a.date || a.createdAt || 0);
      if (ts >= wStart && ts < wEnd && counts[a.type] !== undefined) {
        counts[a.type]++;
      }
    });
    const total = TYPES.reduce((s, t) => s + counts[t], 0);
    bins.push({ label, counts, total });
  }

  const maxTotal = Math.max(...bins.map(b => b.total), 1);
  const barH     = 120; // px

  // Build stacked bars via inline SVG-like divs
  const barsHtml = bins.map(b => {
    const stackedBars = TYPES.filter(t => b.counts[t] > 0).map(t => {
      const pct = (b.counts[t] / maxTotal) * barH;
      return `<div style="width:100%;height:${pct.toFixed(1)}px;background:${COLORS[t]};min-height:1px" title="${t}: ${b.counts[t]}"></div>`;
    }).join('');
    const emptyH = b.total === 0 ? barH : 0;
    return `
      <div style="flex:1;display:flex;flex-direction:column;align-items:center;gap:0">
        <div style="display:flex;flex-direction:column-reverse;align-items:stretch;width:80%;height:${barH}px;gap:0" title="Week of ${b.label}: ${b.total} total">
          ${stackedBars || `<div style="width:100%;height:${barH}px;background:var(--surface3);border-radius:2px 2px 0 0"></div>`}
        </div>
        <div style="font-size:9px;color:var(--text-muted);margin-top:4px;white-space:nowrap">${b.label}</div>
      </div>`;
  }).join('');

  const legendHtml = TYPES.map(t => `
    <div style="display:flex;align-items:center;gap:5px">
      <div style="width:8px;height:8px;border-radius:2px;background:${COLORS[t]};flex-shrink:0"></div>
      <span style="font-size:11px;color:var(--text-dim)">${t}</span>
    </div>`).join('');

  const totalAll = (db.activities || []).filter(a => {
    const ts = typeof a.date === 'string' ? new Date(a.date).getTime() : (a.date || 0);
    return ts >= now - WEEKS * MS_WEEK;
  }).length;

  el.innerHTML = `
    <div style="display:flex;gap:8px;align-items:flex-end;height:${barH}px;margin-bottom:4px;padding-bottom:0">
      ${barsHtml}
    </div>
    <div style="display:flex;gap:6px;margin-top:16px;flex-wrap:wrap">${legendHtml}</div>
    <div style="margin-top:12px;font-size:12px;color:var(--text-muted)">${totalAll} activities across the last ${WEEKS} weeks</div>
  `;
}

// Owner Performance + Activity Trends injected in the main renderReports setTimeout block above


// ═══════════════════════════════════════════════════════════
// PHASE 13 — PRODUCT CATALOG + SALES PLAYBOOKS + COHORT ANALYSIS
// ═══════════════════════════════════════════════════════════

// ──────────────────────────────────────────────────────────
// PRODUCT / SERVICE CATALOG
// ──────────────────────────────────────────────────────────

function renderCatalog() {
  const grid = document.getElementById('catalog-grid');
  if (!grid) return;

  const query    = (document.getElementById('catalog-search')?.value || '').toLowerCase();
  const category = document.getElementById('catalog-category-filter')?.value || '';
  const products  = (db.products || []).filter(p => {
    if (category && p.category !== category) return false;
    if (query && !(p.name.toLowerCase().includes(query) || (p.desc||'').toLowerCase().includes(query))) return false;
    return true;
  });

  if (!products.length) {
    grid.innerHTML = `<div style="grid-column:1/-1;text-align:center;padding:60px 0;color:var(--text-muted)">
      <div style="font-weight:600;margin-bottom:6px;color:var(--text-dim)">No catalog items yet</div>
      <div style="font-size:12px">Add your products and services to use them in proposals and invoices</div>
    </div>`;
    return;
  }

  const billingBadge = { 'one-time': 'One-Time', 'monthly': '/mo', 'annual': '/yr', 'hourly': '/hr' };

  grid.innerHTML = products.map(p => `
    <div class="panel" style="cursor:pointer;transition:border-color 0.15s" onclick="openCatalogModal('${p.id}')" onmouseenter="this.style.borderColor='var(--accent)'" onmouseleave="this.style.borderColor=''">
      <div style="padding:16px">
        <div style="display:flex;align-items:flex-start;justify-content:space-between;gap:8px;margin-bottom:10px">
          <div>
            <div style="font-weight:600;font-size:13px;color:var(--text);line-height:1.3">${esc(p.name)}</div>
            ${p.sku ? `<div style="font-size:10px;color:var(--text-muted);margin-top:2px">SKU: ${esc(p.sku)}</div>` : ''}
          </div>
          ${p.category ? `<span style="font-size:10px;font-weight:500;padding:2px 7px;border-radius:10px;background:var(--surface3);color:var(--text-muted);white-space:nowrap">${esc(p.category)}</span>` : ''}
        </div>
        ${p.desc ? `<div style="font-size:12px;color:var(--text-dim);line-height:1.5;margin-bottom:10px">${esc(p.desc)}</div>` : ''}
        <div style="display:flex;align-items:center;justify-content:space-between;margin-top:8px">
          <div style="font-size:16px;font-weight:700;color:var(--green)">
            $${Number(p.price||0).toLocaleString('en-US',{minimumFractionDigits:2,maximumFractionDigits:2})}
            <span style="font-size:11px;font-weight:400;color:var(--text-muted)">${billingBadge[p.billing]||''}</span>
          </div>
          <button class="btn btn-secondary btn-sm" onclick="event.stopPropagation();openProductPicker('invoice','${p.id}')">Add to Invoice</button>
        </div>
      </div>
    </div>`).join('');
}

let _pickerTarget = 'invoice';
let _pickerSingleId = null;

function openCatalogModal(id) {
  const isEdit = !!id;
  const p = isEdit ? (db.products||[]).find(x => x.id === id) : null;
  document.getElementById('modal-catalog-item-title').textContent = isEdit ? 'Edit Catalog Item' : 'Add Catalog Item';
  document.getElementById('catalog-form-id').value   = id || '';
  document.getElementById('catalog-form-name').value = p?.name || '';
  document.getElementById('catalog-form-category').value = p?.category || '';
  document.getElementById('catalog-form-price').value = p?.price != null ? p.price : '';
  document.getElementById('catalog-form-billing').value = p?.billing || 'one-time';
  document.getElementById('catalog-form-sku').value  = p?.sku || '';
  document.getElementById('catalog-form-desc').value = p?.desc || '';
  document.getElementById('btn-delete-catalog-item').style.display = isEdit ? 'inline-flex' : 'none';
  openModal('modal-catalog-item');
  setTimeout(() => document.getElementById('catalog-form-name').focus(), 50);
}

function saveCatalogItem() {
  const id   = document.getElementById('catalog-form-id').value;
  const name = document.getElementById('catalog-form-name').value.trim();
  if (!name) { toast('Name is required', 'error'); return; }

  if (!db.products) db.products = [];

  const data = {
    name,
    category: document.getElementById('catalog-form-category').value,
    price:    parseFloat(document.getElementById('catalog-form-price').value) || 0,
    billing:  document.getElementById('catalog-form-billing').value,
    sku:      document.getElementById('catalog-form-sku').value.trim(),
    desc:     document.getElementById('catalog-form-desc').value.trim(),
    updatedAt: Date.now(),
  };

  if (id) {
    const idx = db.products.findIndex(p => p.id === id);
    if (idx >= 0) db.products[idx] = { ...db.products[idx], ...data };
  } else {
    db.products.push({ id: uid(), createdAt: Date.now(), ...data });
  }

  saveDB();
  closeModal('modal-catalog-item');
  toast(id ? 'Item updated' : 'Item added', 'success');
  if (currentView === 'catalog') renderCatalog();
}

function deleteCatalogItem() {
  const id = document.getElementById('catalog-form-id').value;
  if (!id) return;
  if (!confirm('Delete this catalog item?')) return;
  db.products = (db.products||[]).filter(p => p.id !== id);
  saveDB();
  closeModal('modal-catalog-item');
  toast('Item deleted', 'success');
  if (currentView === 'catalog') renderCatalog();
}

// ── Product Picker ─────────────────────────────────────────

function openProductPicker(target, singleId) {
  _pickerTarget   = target || 'invoice';
  _pickerSingleId = singleId || null;

  if (singleId) {
    // Fast path: insert immediately without opening modal
    insertPickedProduct(singleId);
    return;
  }

  document.getElementById('picker-search').value = '';
  renderProductPicker();
  openModal('modal-product-picker');
  setTimeout(() => document.getElementById('picker-search').focus(), 50);
}

function renderProductPicker() {
  const q    = (document.getElementById('picker-search')?.value || '').toLowerCase();
  const prods = (db.products||[]).filter(p => !q || p.name.toLowerCase().includes(q) || (p.desc||'').toLowerCase().includes(q));
  const el   = document.getElementById('picker-results');
  if (!el) return;

  if (!prods.length) {
    el.innerHTML = `<div style="text-align:center;padding:24px;color:var(--text-muted);font-size:12px">
      ${db.products?.length ? 'No items match your search' : 'Catalog is empty — add items in the Catalog section'}
    </div>`;
    return;
  }

  el.innerHTML = prods.map(p => `
    <div style="display:flex;align-items:center;gap:10px;padding:10px 12px;border-radius:8px;cursor:pointer;transition:background 0.1s"
         onmouseenter="this.style.background='var(--surface2)'" onmouseleave="this.style.background=''"
         onclick="insertPickedProduct('${p.id}')">
      <div style="flex:1;min-width:0">
        <div style="font-weight:500;font-size:13px;color:var(--text)">${esc(p.name)}</div>
        ${p.desc ? `<div style="font-size:11px;color:var(--text-muted);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${esc(p.desc)}</div>` : ''}
      </div>
      <div style="text-align:right;flex-shrink:0">
        <div style="font-weight:600;color:var(--green);font-size:13px">$${Number(p.price||0).toLocaleString('en-US',{minimumFractionDigits:2,maximumFractionDigits:2})}</div>
        ${p.billing && p.billing !== 'one-time' ? `<div style="font-size:10px;color:var(--text-muted)">${p.billing}</div>` : ''}
      </div>
    </div>`).join('');
}

function insertPickedProduct(productId) {
  const p = (db.products||[]).find(x => x.id === productId);
  if (!p) return;

  if (_pickerTarget === 'invoice') {
    // Insert as invoice line item
    const newItem = { id: uid(), description: p.name + (p.sku ? ` (${p.sku})` : ''), qty: 1, rate: p.price || 0, catalogId: productId };
    if (!window._currentInvItems) window._currentInvItems = [];
    window._currentInvItems.push(newItem);
    const container = document.getElementById('inv-line-items');
    if (container) {
      const div = document.createElement('div');
      div.innerHTML = renderLineItemRow(newItem, window._currentInvItems.length - 1);
      container.appendChild(div.firstElementChild);
      recalcInvoiceTotals();
    }
    toast(`"${p.name}" added`, 'success');
    closeModal('modal-product-picker');
  }
}

// ──────────────────────────────────────────────────────────
// SALES PLAYBOOKS — per-stage deal checklists
// ──────────────────────────────────────────────────────────

function renderPlaybookSettings() {
  const container = document.getElementById('playbooks-list');
  if (!container) return;
  const playbooks = db.settings.playbooks || [];
  const stages    = getDealStages();

  if (!playbooks.length) {
    container.innerHTML = `<div style="font-size:12px;color:var(--text-muted)">No playbooks defined yet. Add a stage checklist below.</div>`;
    return;
  }

  container.innerHTML = playbooks.map((pb, pbIdx) => `
    <div style="border:1px solid var(--border);border-radius:8px;padding:12px">
      <div style="display:flex;align-items:center;gap:8px;margin-bottom:8px">
        <select class="form-select" style="font-size:12px;flex:1" id="pb-stage-${pbIdx}" onchange="">
          ${stages.map(s => `<option value="${esc(s)}" ${pb.stage === s ? 'selected' : ''}>${esc(s)}</option>`).join('')}
        </select>
        <button class="btn btn-ghost btn-xs" onclick="removePlaybookStage(${pbIdx})" style="opacity:0.5;flex-shrink:0">Remove</button>
      </div>
      <div style="display:flex;flex-direction:column;gap:4px" id="pb-items-${pbIdx}">
        ${(pb.items||[]).map((item, itemIdx) => `
          <div style="display:flex;align-items:center;gap:6px">
            <input type="text" class="form-input" style="font-size:12px;flex:1" value="${esc(item)}" id="pb-item-${pbIdx}-${itemIdx}" />
            <button class="btn btn-ghost btn-xs" onclick="removePlaybookItem(${pbIdx},${itemIdx})" style="opacity:0.4">✕</button>
          </div>`).join('')}
      </div>
      <button class="btn btn-ghost btn-xs" onclick="addPlaybookItem(${pbIdx})" style="margin-top:6px;font-size:11px">+ Add step</button>
    </div>`).join('');
}

function addPlaybookStage() {
  if (!db.settings.playbooks) db.settings.playbooks = [];
  const stages = getDealStages();
  db.settings.playbooks.push({ stage: stages[0] || '', items: [''] });
  renderPlaybookSettings();
}

function removePlaybookStage(pbIdx) {
  if (!db.settings.playbooks) return;
  db.settings.playbooks.splice(pbIdx, 1);
  renderPlaybookSettings();
}

function addPlaybookItem(pbIdx) {
  if (!db.settings.playbooks?.[pbIdx]) return;
  db.settings.playbooks[pbIdx].items = db.settings.playbooks[pbIdx].items || [];
  db.settings.playbooks[pbIdx].items.push('');
  renderPlaybookSettings();
}

function removePlaybookItem(pbIdx, itemIdx) {
  if (!db.settings.playbooks?.[pbIdx]) return;
  db.settings.playbooks[pbIdx].items.splice(itemIdx, 1);
  renderPlaybookSettings();
}

function savePlaybooks() {
  if (!db.settings.playbooks) db.settings.playbooks = [];
  // Collect current values from the DOM
  db.settings.playbooks.forEach((pb, pbIdx) => {
    const stageEl = document.getElementById(`pb-stage-${pbIdx}`);
    if (stageEl) pb.stage = stageEl.value;
    pb.items = (pb.items||[]).map((_, itemIdx) => {
      const el = document.getElementById(`pb-item-${pbIdx}-${itemIdx}`);
      return el ? el.value.trim() : '';
    }).filter(Boolean);
  });
  // Remove playbooks with empty stage or no items
  db.settings.playbooks = db.settings.playbooks.filter(pb => pb.stage && pb.items.length > 0);
  saveDB();
  renderPlaybookSettings();
  toast('Playbooks saved', 'success');
}

// ── Deal Playbook HTML (injected into renderDealDetail) ────

function getDealPlaybookHTML(deal) {
  const playbooks = db.settings.playbooks || [];
  const stagePlaybook = playbooks.find(pb => pb.stage === deal.stage);
  if (!stagePlaybook || !stagePlaybook.items?.length) return '';

  // Load saved checklist progress for this deal
  const progressKey = `pb_${deal.id}_${deal.stage}`;
  const progress    = (db.settings._playbookProgress || {})[progressKey] || {};
  const total       = stagePlaybook.items.length;
  const done        = stagePlaybook.items.filter((_, i) => progress[i]).length;
  const pct         = total ? Math.round((done / total) * 100) : 0;

  return `
    <div class="panel" style="margin-top:12px">
      <div class="panel-header">
        <div class="panel-title">Playbook — ${esc(deal.stage)}</div>
        <span style="font-size:11px;color:${pct===100?'var(--green)':'var(--text-muted)'};">${done}/${total} complete</span>
      </div>
      <div style="padding:0 16px 8px">
        <div style="height:4px;background:var(--surface3);border-radius:2px;margin-bottom:12px;overflow:hidden">
          <div style="height:100%;width:${pct}%;background:${pct===100?'var(--green)':'var(--accent)'};border-radius:2px;transition:width 0.3s"></div>
        </div>
        ${stagePlaybook.items.map((item, i) => `
          <label style="display:flex;align-items:flex-start;gap:10px;padding:8px 0;border-bottom:1px solid var(--border);cursor:pointer;font-size:12px;${i===stagePlaybook.items.length-1?'border-bottom:none':''}"
                 onclick="togglePlaybookItem('${deal.id}','${deal.stage}',${i})">
            <div style="width:16px;height:16px;border-radius:4px;border:2px solid ${progress[i]?'var(--accent)':'var(--border)'};background:${progress[i]?'var(--accent)':'transparent'};flex-shrink:0;margin-top:0px;display:flex;align-items:center;justify-content:center;transition:all 0.15s">
              ${progress[i] ? '<svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="white" stroke-width="3" stroke-linecap="round"><polyline points="20 6 9 17 4 12"/></svg>' : ''}
            </div>
            <span style="color:${progress[i]?'var(--text-muted)':'var(--text)'};text-decoration:${progress[i]?'line-through':'none'}">${esc(item)}</span>
          </label>`).join('')}
      </div>
    </div>`;
}

function togglePlaybookItem(dealId, stage, itemIdx) {
  if (!db.settings._playbookProgress) db.settings._playbookProgress = {};
  const progressKey = `pb_${dealId}_${stage}`;
  if (!db.settings._playbookProgress[progressKey]) db.settings._playbookProgress[progressKey] = {};
  const current = db.settings._playbookProgress[progressKey][itemIdx];
  db.settings._playbookProgress[progressKey][itemIdx] = !current;
  saveDB();
  renderDealDetail(dealId);
}

// ──────────────────────────────────────────────────────────
// REVENUE COHORT ANALYSIS (new report card)
// ──────────────────────────────────────────────────────────

function renderRevenueCohort() {
  const el = document.getElementById('report-revenue-cohort');
  if (!el) return;

  const won    = db.deals.filter(d => d.stage === 'Won');
  const months = 6;
  const now    = new Date();

  // Build 6-month buckets
  const buckets = [];
  for (let i = months - 1; i >= 0; i--) {
    const d = new Date(now.getFullYear(), now.getMonth() - i, 1);
    buckets.push({
      label: d.toLocaleString('en-US', { month: 'short', year: '2-digit' }),
      month: d.getMonth(),
      year:  d.getFullYear(),
      newRevenue:       0,
      expansionRevenue: 0,
    });
  }

  // Bucket the won deals
  won.forEach(deal => {
    const closedAt = new Date(deal.movedAt || deal.createdAt);
    const bucket   = buckets.find(b => b.month === closedAt.getMonth() && b.year === closedAt.getFullYear());
    if (!bucket) return;

    // "Expansion" = company has a prior won deal
    const priorWon = won.filter(d2 => d2.id !== deal.id && d2.company === deal.company && (d2.movedAt || d2.createdAt) < (deal.movedAt || deal.createdAt));
    if (priorWon.length > 0) {
      bucket.expansionRevenue += (deal.value || 0);
    } else {
      bucket.newRevenue += (deal.value || 0);
    }
  });

  const maxVal = Math.max(...buckets.map(b => b.newRevenue + b.expansionRevenue), 1);

  el.innerHTML = `
    <div style="display:flex;align-items:flex-end;gap:8px;height:120px;width:100%;padding:0 4px">
      ${buckets.map(b => {
        const total  = b.newRevenue + b.expansionRevenue;
        const newH   = Math.round((b.newRevenue / maxVal) * 100);
        const expH   = Math.round((b.expansionRevenue / maxVal) * 100);
        return `
          <div style="flex:1;display:flex;flex-direction:column;align-items:center;gap:2px;height:100%">
            <div style="flex:1;display:flex;align-items:flex-end;width:100%;gap:0" title="New: $${b.newRevenue.toLocaleString()} | Expansion: $${b.expansionRevenue.toLocaleString()}">
              <div style="flex:1;display:flex;flex-direction:column;align-items:center;justify-content:flex-end;height:100%;gap:0">
                ${expH > 0 ? `<div style="width:100%;height:${expH}%;background:var(--accent);border-radius:2px 2px 0 0;opacity:0.6"></div>` : ''}
                ${newH > 0 ? `<div style="width:100%;height:${newH}%;background:var(--green);border-radius:${expH>0?'0':'2px 2px'} 0 0"></div>` : ''}
                ${total === 0 ? `<div style="width:100%;height:4px;background:var(--surface3);border-radius:2px"></div>` : ''}
              </div>
            </div>
            <div style="font-size:9px;color:var(--text-muted);text-align:center;margin-top:3px">${b.label}</div>
          </div>`;
      }).join('')}
    </div>
    <div style="display:flex;gap:14px;margin-top:8px;font-size:11px">
      <span style="display:flex;align-items:center;gap:5px"><span style="display:inline-block;width:10px;height:10px;border-radius:2px;background:var(--green)"></span>New</span>
      <span style="display:flex;align-items:center;gap:5px"><span style="display:inline-block;width:10px;height:10px;border-radius:2px;background:var(--accent);opacity:0.7"></span>Expansion</span>
      <span style="margin-left:auto;color:var(--text-muted)">Last ${months} months</span>
    </div>`;
}

// ── Inject Revenue Cohort into renderReports ───────────────
// Patch: wrap original renderReports to also inject cohort card
(function() {
  const _origRenderReports = renderReports;
  window.renderReports = function() {
    _origRenderReports.call(this);
    // Inject cohort card after the existing cards render
    setTimeout(() => {
      const grid = document.querySelector('#view-reports .reports-grid');
      if (!grid) return;
      if (!document.getElementById('report-revenue-cohort')) {
        const card = document.createElement('div');
        card.className = 'panel report-card report-card-wide';
        card.innerHTML = '<div class="panel-header"><div class="panel-title">Revenue Cohort — New vs Expansion</div></div><div id="report-revenue-cohort" style="padding:16px"></div>';
        grid.appendChild(card);
      }
      renderRevenueCohort();
    }, 10);
  };
})();

// ── Wire Catalog view keyboard shortcut & button wiring ────
document.addEventListener('DOMContentLoaded', () => {
  // nothing extra needed — nav-item data-view="catalog" handled by existing router
});

