// Patch loadDB to init new collections
(function p15PatchLoadDB() {
  const _origLoadDB = loadDB;
  loadDB = function() {
    _origLoadDB.call(this);
    db.documents = db.documents || [];
    db.competitorEntries = db.competitorEntries || [];
  };
})();

// Patch renderView to handle 'documents' view
(function p15PatchRenderView() {
  const _origRenderView = renderView;
  renderView = function(view, param) {
    if (view === 'documents') {
      renderDocuments();
      return;
    }
    _origRenderView.call(this, view, param);
  };
})();

// Patch renderContactDetail to inject health score + documents panels
(function p15PatchContactDetail() {
  const _orig = renderContactDetail;
  renderContactDetail = function(id) {
    _orig.call(this, id);
    const contact = db.contacts.find(c => c.id === id);
    if (!contact) return;

    // Inject health panel into left column (after contact info / open tasks)
    const leftCol = document.querySelector('#view-contact-detail .contact-detail-left');
    if (leftCol && !leftCol.querySelector('.p15-health-injected')) {
      const healthHTML = renderContactHealthPanel(contact);
      if (healthHTML) {
        const wrapper = document.createElement('div');
        wrapper.className = 'p15-health-injected';
        wrapper.innerHTML = healthHTML;
        leftCol.appendChild(wrapper);
      }
    }

    // Inject documents panel into right column (before inline notes)
    const rightCol = document.querySelector('#view-contact-detail .contact-detail-right');
    if (rightCol && !rightCol.querySelector('.p15-docs-injected')) {
      const docsWrapper = document.createElement('div');
      docsWrapper.className = 'p15-docs-injected';
      docsWrapper.innerHTML = renderDocsPanel('contact', id);
      // Insert before inline-notes if it exists, otherwise append
      const notesPanel = rightCol.querySelector('.inline-notes-panel');
      if (notesPanel) rightCol.insertBefore(docsWrapper, notesPanel);
      else rightCol.appendChild(docsWrapper);
    }
  };
})();

// Patch renderDealDetail to inject documents + competitors panels
(function p15PatchDealDetail() {
  const _orig = renderDealDetail;
  renderDealDetail = function(id) {
    _orig.call(this, id);
    const deal = db.deals.find(d => d.id === id);
    if (!deal) return;

    // Inject competitors panel into left column
    const leftCol = document.querySelector('#view-deal-detail .contact-detail-left');
    if (leftCol && !leftCol.querySelector('.p15-comp-injected')) {
      const compWrapper = document.createElement('div');
      compWrapper.className = 'p15-comp-injected';
      compWrapper.innerHTML = renderCompetitorsPanel(deal);
      leftCol.appendChild(compWrapper);
    }

    // Inject documents panel into right column
    const rightCol = document.querySelector('#view-deal-detail .contact-detail-right');
    if (rightCol && !rightCol.querySelector('.p15-docs-injected')) {
      const docsWrapper = document.createElement('div');
      docsWrapper.className = 'p15-docs-injected';
      docsWrapper.innerHTML = renderDocsPanel('deal', id);
      const notesPanel = rightCol.querySelector('.inline-notes-panel');
      if (notesPanel) rightCol.insertBefore(docsWrapper, notesPanel);
      else rightCol.appendChild(docsWrapper);
    }
  };
})();

// Patch renderContacts to inject health badges and support health sort/filter
