// Patch renderDealCard to show doc/competitor count badges
(function p15PatchDealCard() {
  const _orig = renderDealCard;
  renderDealCard = function(d) {
    let html = _orig.call(this, d);
    const docCount  = docCountForEntity('deal', d.id);
    const compCount = getCompetitorsForDeal(d.id).length;
    if (docCount > 0 || compCount > 0) {
      const badges = [];
      if (docCount  > 0) badges.push(`<span style="font-size:9px;padding:1px 5px;border-radius:3px;background:var(--accent-dim);color:var(--accent-hover);font-weight:600">${docCount} doc${docCount!==1?'s':''}</span>`);
      if (compCount > 0) badges.push(`<span style="font-size:9px;padding:1px 5px;border-radius:3px;background:rgba(239,68,68,0.1);color:var(--red);font-weight:600">${compCount} comp${compCount!==1?'s':''}</span>`);
      const badgeBar = `<div style="display:flex;gap:4px;margin-top:4px">${badges.join('')}</div>`;
      // Insert before the last </div> of the card
      const lastDiv = html.lastIndexOf('</div>');
      if (lastDiv !== -1) html = html.slice(0, lastDiv) + badgeBar + html.slice(lastDiv);
    }
    return html;
  };
})();

// Wire up Documents view event listeners (run after DOM ready)
(function p15InitDocView() {
  function tryInit() {
    const searchEl = document.getElementById('doc-search');
    const typeEl = document.getElementById('doc-type-filter');
    const entityEl = document.getElementById('doc-entity-filter');
    if (!searchEl) return;
    searchEl.addEventListener('input', e => { p15DocSearch = e.target.value; renderDocuments(); });
    typeEl && typeEl.addEventListener('change', e => { p15DocTypeFilter = e.target.value; renderDocuments(); });
    entityEl && entityEl.addEventListener('change', e => { p15DocEntityFilter = e.target.value; renderDocuments(); });
  }
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', tryInit);
  } else {
    tryInit();
  }
})();

// Ensure db.documents and db.competitorEntries are initialized if db is already loaded
