// ════════════════════════════════════════════════════════════
// PHASE 15 — Deal Gantt / Timeline View
// ════════════════════════════════════════════════════════════

let pipelineViewMode = 'kanban'; // 'kanban' | 'timeline'

function setPipelineView(mode) {
  pipelineViewMode = mode;
  const board = document.getElementById('pipeline-board');
  const gantt = document.getElementById('pipeline-gantt');
  const btnKanban   = document.getElementById('btn-pipeline-kanban');
  const btnTimeline = document.getElementById('btn-pipeline-timeline');

  if (mode === 'timeline') {
    if (board) board.style.display = 'none';
    if (gantt) gantt.style.display = 'flex';
    if (btnKanban)   btnKanban.classList.remove('active');
    if (btnTimeline) btnTimeline.classList.add('active');
    renderPipelineGantt();
  } else {
    if (board) board.style.display = 'flex';
    if (gantt) gantt.style.display = 'none';
    if (btnKanban)   btnKanban.classList.add('active');
    if (btnTimeline) btnTimeline.classList.remove('active');
    renderPipeline();
  }
}

function renderPipelineGantt() {
  const gantt = document.getElementById('pipeline-gantt');
  if (!gantt) return;

  const stages = getDealStages();
  const now    = Date.now();
  const today  = new Date().toISOString().slice(0, 10);

  // Collect active deals (exclude Lost unless user wants them)
  const activeDeals = db.deals.filter(d => d.stage !== 'Lost');

  if (!activeDeals.length) {
    gantt.innerHTML = '<div class="empty-state" style="margin:auto;padding:64px 24px"><div class="empty-state-title">No deals to display</div><div class="empty-state-sub">Add deals with close dates to see the timeline</div></div>';
    return;
  }

  // Determine the global time range
  const allDates = [];
  activeDeals.forEach(d => {
    if (d.createdAt) allDates.push(typeof d.createdAt === 'number' ? d.createdAt : new Date(d.createdAt).getTime());
    if (d.closeDate) allDates.push(new Date(d.closeDate).getTime());
  });
  allDates.push(now);

  // Snap to month boundaries
  const minTs    = Math.min(...allDates);
  const maxTs    = Math.max(...allDates) + 30 * 86400000; // add 30 day buffer
  const startD   = new Date(minTs);
  const rangeStart = new Date(startD.getFullYear(), startD.getMonth(), 1).getTime();
  const endD     = new Date(maxTs);
  const rangeEnd = new Date(endD.getFullYear(), endD.getMonth() + 1, 1).getTime();
  const totalMs  = rangeEnd - rangeStart;

  // Generate month headers
  const months = [];
  let cur = new Date(rangeStart);
  while (cur.getTime() < rangeEnd) {
    months.push(new Date(cur));
    cur = new Date(cur.getFullYear(), cur.getMonth() + 1, 1);
  }

  const LABEL_W  = 200; // left label column width
  const MIN_CHART_W = 600;
  const CHART_W  = Math.max(MIN_CHART_W, months.length * 100);

  function xPct(ts) {
    const clamped = Math.max(rangeStart, Math.min(rangeEnd, ts));
    return ((clamped - rangeStart) / totalMs) * CHART_W;
  }

  // Month header
  const monthHeader = months.map(m => {
    const x   = xPct(m.getTime());
    const x2  = xPct(new Date(m.getFullYear(), m.getMonth() + 1, 1).getTime());
    const w   = x2 - x;
    return `<div class="gantt-month-cell" style="left:${x}px;width:${w}px">${m.toLocaleString('en-US', { month: 'short', year: '2-digit' })}</div>`;
  }).join('');

  // Today marker
  const todayX = xPct(now);
  const todayMarker = `<div class="gantt-today-line" style="left:${todayX}px"></div>`;

  // Group deals by stage
  const byStage = {};
  stages.forEach(s => { byStage[s] = []; });
  activeDeals.forEach(d => {
    if (byStage[d.stage]) byStage[d.stage].push(d);
    else byStage[d.stage] = [d];
  });

  // Build rows
  let rowsHTML = '';
  stages.forEach(stage => {
    const deals = byStage[stage] || [];
    if (!deals.length) return;
    const color = getStageColor(stage);

    // Stage group header row
    rowsHTML += `
      <div class="gantt-group-row">
        <div class="gantt-row-label" style="width:${LABEL_W}px">
          <span class="gantt-stage-dot" style="background:${color}"></span>
          <strong>${esc(stage)}</strong>
          <span class="gantt-stage-count">${deals.length}</span>
        </div>
        <div class="gantt-row-bar" style="width:${CHART_W}px;position:relative">
          ${months.map(m => {
            const x = xPct(m.getTime());
            return `<div class="gantt-grid-line" style="left:${x}px"></div>`;
          }).join('')}
        </div>
      </div>`;

    // Deal rows
    deals.forEach(deal => {
      const startTs = deal.createdAt
        ? (typeof deal.createdAt === 'number' ? deal.createdAt : new Date(deal.createdAt).getTime())
        : rangeStart;
      const endTs = deal.closeDate
        ? new Date(deal.closeDate).getTime()
        : now;
      const effectiveEnd = Math.max(startTs + 86400000, endTs); // at least 1 day wide

      const barX = xPct(startTs);
      const barW = Math.max(4, xPct(effectiveEnd) - xPct(startTs));
      const isPast = deal.closeDate && deal.closeDate < today && deal.stage !== 'Won';
      const barColor = isPast ? 'var(--red)' : color;
      const opacityStyle = deal.stage === 'Won' ? 'opacity:0.6' : '';

      rowsHTML += `
        <div class="gantt-deal-row" onclick="showDealDetail('${deal.id}')">
          <div class="gantt-row-label" style="width:${LABEL_W}px">
            <div class="gantt-deal-name">${esc(deal.name)}</div>
            <div class="gantt-deal-sub">${formatCurrency(deal.value || 0)}${deal.closeDate ? ' · ' + formatDate(deal.closeDate) : ''}</div>
          </div>
          <div class="gantt-row-bar" style="width:${CHART_W}px;position:relative">
            ${months.map(m => {
              const x = xPct(m.getTime());
              return `<div class="gantt-grid-line" style="left:${x}px"></div>`;
            }).join('')}
            <div class="gantt-bar" style="left:${barX}px;width:${barW}px;background:${barColor};${opacityStyle}"
              title="${esc(deal.name)} — ${formatDate(deal.createdAt)} to ${deal.closeDate ? formatDate(deal.closeDate) : 'ongoing'}">
              <div class="gantt-bar-label">${esc(deal.name)}</div>
            </div>
          </div>
        </div>`;
    });
  });

  gantt.innerHTML = `
    <div class="gantt-container">
      <div class="gantt-header">
        <div class="gantt-label-header" style="width:${LABEL_W}px">Deal</div>
        <div class="gantt-chart-header" style="width:${CHART_W}px;position:relative">
          ${monthHeader}
          ${todayMarker}
        </div>
      </div>
      <div class="gantt-body">
        ${rowsHTML}
      </div>
      <div class="gantt-legend">
        <span class="gantt-legend-item"><span class="gantt-legend-dot" style="background:var(--red)"></span>Past Due</span>
        <span class="gantt-legend-item"><span class="gantt-legend-dot" style="background:#6366f1"></span>Today</span>
        ${stages.filter(s => s !== 'Lost').map(s => `<span class="gantt-legend-item"><span class="gantt-legend-dot" style="background:${getStageColor(s)}"></span>${esc(s)}</span>`).join('')}
      </div>
    </div>`;
}

