function renderCampaignsSummary() {
  const el = document.getElementById('report-campaigns-summary');
  if (!el) return;
  const campaigns = db.campaigns || [];
  if (!campaigns.length) {
    el.innerHTML = '<div class="empty-state" style="padding:32px"><div class="empty-state-title">No campaigns yet</div><div class="empty-state-sub">Create email campaigns to track outreach performance</div></div>';
    return;
  }

  const sent = campaigns.filter(c => c.status === 'sent');
  const totalSent = sent.reduce((s, c) => s + (c.sentCount || 0), 0);
  const totalOpened = sent.reduce((s, c) => s + (c.opened || 0), 0);
  const totalReplied = sent.reduce((s, c) => s + (c.replied || 0), 0);
  const avgOpenRate = totalSent ? Math.round(totalOpened / totalSent * 100) : 0;
  const avgReplyRate = totalSent ? Math.round(totalReplied / totalSent * 100) : 0;

  el.innerHTML = `
    <div style="display:flex;gap:12px;margin-bottom:16px;flex-wrap:wrap">
      <div class="campaign-stat-card" style="min-width:80px">
        <div class="campaign-stat-value">${campaigns.length}</div>
        <div class="campaign-stat-label">Total</div>
      </div>
      <div class="campaign-stat-card" style="min-width:80px">
        <div class="campaign-stat-value">${totalSent.toLocaleString()}</div>
        <div class="campaign-stat-label">Emails Sent</div>
      </div>
      <div class="campaign-stat-card" style="min-width:80px">
        <div class="campaign-stat-value">${avgOpenRate}%</div>
        <div class="campaign-stat-label">Avg Open Rate</div>
      </div>
      <div class="campaign-stat-card" style="min-width:80px">
        <div class="campaign-stat-value">${avgReplyRate}%</div>
        <div class="campaign-stat-label">Avg Reply Rate</div>
      </div>
    </div>
    <div style="overflow-x:auto">
      <table>
        <thead>
          <tr>
            <th>Campaign</th>
            <th>Status</th>
            <th style="text-align:right">Sent</th>
            <th style="text-align:right">Opened</th>
            <th style="text-align:right">Open Rate</th>
            <th style="text-align:right">Replied</th>
            <th>Send Date</th>
          </tr>
        </thead>
        <tbody>
          ${[...campaigns].sort((a,b) => b.createdAt - a.createdAt).slice(0, 10).map(c => {
            const or = c.sentCount ? Math.round(c.opened / c.sentCount * 100) : 0;
            const orColor = or >= 30 ? 'var(--green)' : or >= 15 ? 'var(--yellow)' : 'var(--text-muted)';
            return `<tr onclick="navigate('campaign-detail','${c.id}')" style="cursor:pointer">
              <td style="font-weight:500;color:var(--text)">${esc(c.name)}</td>
              <td><span class="campaign-status camp-${c.status||'draft'}">${esc(c.status||'draft')}</span></td>
              <td style="text-align:right;color:var(--text-dim)">${c.sentCount || '—'}</td>
              <td style="text-align:right;color:var(--text-dim)">${c.opened || '—'}</td>
              <td style="text-align:right;color:${orColor};font-weight:600">${c.sentCount ? or + '%' : '—'}</td>
              <td style="text-align:right;color:var(--text-dim)">${c.replied || '—'}</td>
              <td style="color:var(--text-muted)">${c.sendDate ? formatDate(c.sendDate) : '—'}</td>
            </tr>`;
          }).join('')}
        </tbody>
      </table>
    </div>`;
}

function renderReportDealTimeline() {
  const el = document.getElementById('report-deal-timeline');
  if (!el) return;

  const stages = getDealStages();
  const now    = Date.now();
  const activeDeals = db.deals.filter(d => d.stage !== 'Lost');

  if (!activeDeals.length) {
    el.innerHTML = '<div class="empty-state" style="padding:32px"><div class="empty-state-title">No deals to display</div></div>';
    return;
  }

  const allDates = [];
  activeDeals.forEach(d => {
    if (d.createdAt) allDates.push(typeof d.createdAt === 'number' ? d.createdAt : new Date(d.createdAt).getTime());
    if (d.closeDate) allDates.push(new Date(d.closeDate).getTime());
  });
  allDates.push(now);

  const minTs     = Math.min(...allDates);
  const maxTs     = Math.max(...allDates) + 15 * 86400000;
  const startD    = new Date(minTs);
  const rangeStart = new Date(startD.getFullYear(), startD.getMonth(), 1).getTime();
  const endD      = new Date(maxTs);
  const rangeEnd  = new Date(endD.getFullYear(), endD.getMonth() + 1, 1).getTime();
  const totalMs   = rangeEnd - rangeStart;

  const months = [];
  let cur = new Date(rangeStart);
  while (cur.getTime() < rangeEnd) {
    months.push(new Date(cur));
    cur = new Date(cur.getFullYear(), cur.getMonth() + 1, 1);
  }

  const LABEL_W  = 180;
  const CHART_W  = Math.max(400, months.length * 90);
  const today    = new Date().toISOString().slice(0, 10);

  function xPct(ts) {
    const clamped = Math.max(rangeStart, Math.min(rangeEnd, ts));
    return ((clamped - rangeStart) / totalMs) * CHART_W;
  }

  const monthHeader = months.map(m => {
    const x  = xPct(m.getTime());
    const x2 = xPct(new Date(m.getFullYear(), m.getMonth() + 1, 1).getTime());
    return `<div class="gantt-month-cell" style="left:${x}px;width:${x2 - x}px">${m.toLocaleString('en-US',{month:'short',year:'2-digit'})}</div>`;
  }).join('');

  const todayX = xPct(now);
  const todayLine = `<div class="gantt-today-line" style="left:${todayX}px"></div>`;

  let rowsHTML = '';
  stages.forEach(stage => {
    const deals = activeDeals.filter(d => d.stage === stage);
    if (!deals.length) return;
    const color = getStageColor(stage);
    rowsHTML += `<div class="gantt-group-row">
      <div class="gantt-row-label" style="width:${LABEL_W}px">
        <span class="gantt-stage-dot" style="background:${color}"></span>
        <strong style="font-size:11px">${esc(stage)}</strong>
        <span class="gantt-stage-count">${deals.length}</span>
      </div>
      <div class="gantt-row-bar" style="width:${CHART_W}px;position:relative">
        ${months.map(m => `<div class="gantt-grid-line" style="left:${xPct(m.getTime())}px"></div>`).join('')}
      </div>
    </div>`;
    deals.forEach(deal => {
      const startTs = deal.createdAt
        ? (typeof deal.createdAt === 'number' ? deal.createdAt : new Date(deal.createdAt).getTime())
        : rangeStart;
      const endTs    = deal.closeDate ? new Date(deal.closeDate).getTime() : now;
      const effectiveEnd = Math.max(startTs + 86400000, endTs);
      const barX     = xPct(startTs);
      const barW     = Math.max(4, xPct(effectiveEnd) - xPct(startTs));
      const isPast   = deal.closeDate && deal.closeDate < today && deal.stage !== 'Won';
      const barColor = isPast ? 'var(--red)' : color;

      rowsHTML += `<div class="gantt-deal-row" onclick="showDealDetail('${deal.id}')">
        <div class="gantt-row-label" style="width:${LABEL_W}px">
          <div class="gantt-deal-name" style="max-width:${LABEL_W - 16}px">${esc(deal.name)}</div>
          <div class="gantt-deal-sub">${formatCurrency(deal.value||0)}</div>
        </div>
        <div class="gantt-row-bar" style="width:${CHART_W}px;position:relative">
          ${months.map(m => `<div class="gantt-grid-line" style="left:${xPct(m.getTime())}px"></div>`).join('')}
          <div class="gantt-bar" style="left:${barX}px;width:${barW}px;background:${barColor}" title="${esc(deal.name)}">
            <div class="gantt-bar-label">${esc(deal.name)}</div>
          </div>
        </div>
      </div>`;
    });
  });

  el.innerHTML = `<div class="gantt-container">
    <div class="gantt-header">
      <div class="gantt-label-header" style="width:${LABEL_W}px">Deal</div>
      <div class="gantt-chart-header" style="width:${CHART_W}px;position:relative">${monthHeader}${todayLine}</div>
    </div>
    <div class="gantt-body">${rowsHTML}</div>
  </div>`;
}

// Add today line to all gantt row bars after rendering
function injectGanttTodayLines(containerEl, rangeStart, rangeEnd, totalMs, CHART_W) {
  if (!containerEl) return;
  const now = Date.now();
  if (now < rangeStart || now > rangeEnd) return;
  const x = ((now - rangeStart) / totalMs) * CHART_W;
  containerEl.querySelectorAll('.gantt-row-bar').forEach(bar => {
    if (!bar.querySelector('.gantt-today-row-line')) {
      const line = document.createElement('div');
      line.className = 'gantt-today-row-line';
      line.style.cssText = `position:absolute;top:0;bottom:0;left:${x}px;width:2px;background:var(--accent);opacity:0.4;pointer-events:none;z-index:4`;
      bar.appendChild(line);
    }
  });
}

