// ── Nav wiring for renewals ─────────────────────────────────
(function p16WireNav() {
  function wire() {
    document.querySelectorAll('.nav-item[data-view="renewals"]').forEach(el => {
      el.addEventListener('click', () => navigate('renewals'));
    });
  }
  if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', wire);
  else wire();
})();

function updateRenewalsBadge() {
  const badge = document.getElementById('nav-renewals-badge');
  if (!badge) return;
  const today = new Date().toISOString().slice(0, 10);
  const in30  = new Date(Date.now() + 30 * 86400000).toISOString().slice(0, 10);
  const due   = (db.renewals || []).filter(r => r.status === 'Active' && r.renewalDate && r.renewalDate >= today && r.renewalDate <= in30).length;
  badge.textContent = due;
  badge.style.display = due > 0 ? '' : 'none';
}

