// Patch openContactModal to populate lead source + territory fields
(function p16PatchContactModal() {
  const _orig = openContactModal;
  window.openContactModal = function(contact) {
    _orig.call(this, contact);
    const srcEl  = document.getElementById('contact-form-lead-source');
    const terrEl = document.getElementById('contact-form-territory');
    if (srcEl)  srcEl.value  = contact ? (contact.leadSource||'') : '';
    if (terrEl) terrEl.value = contact ? (contact.territory||'') : '';
  };
})();

// Patch saveContact to include lead source + territory
(function p16PatchSaveContact() {
  const _orig = saveContact;
  window.saveContact = function() {
    // Inject the new fields before calling original save
    const srcEl  = document.getElementById('contact-form-lead-source');
    const terrEl = document.getElementById('contact-form-territory');
    const id = document.getElementById('contact-form-id').value;

    // Store temporarily on the in-memory record so the original save picks them up
    if (id) {
      const idx = db.contacts.findIndex(c => c.id === id);
      if (idx !== -1) {
        db.contacts[idx]._p16LeadSource = srcEl ? srcEl.value : '';
        db.contacts[idx]._p16Territory  = terrEl ? terrEl.value : '';
      }
    } else {
      window._p16NewContactLeadSource = srcEl ? srcEl.value : '';
      window._p16NewContactTerritory  = terrEl ? terrEl.value : '';
    }
    _orig.call(this);
  };
})();

// We also need to inject these via a post-save API call using the PUT endpoint.
// The cleanest approach: wrap saveContact more deeply and use the API directly.
// Let's override saveContact entirely for Phase 16 to use API endpoints:
(function p16FullSaveContact() {
  window.saveContact = async function() {
    const id   = document.getElementById('contact-form-id').value;
    const name = document.getElementById('contact-form-name').value.trim();
    if (!name) { toast('Name is required', 'error'); return; }

    const email = document.getElementById('contact-form-email').value.trim();
    if (!id && email) {
      const dup = db.contacts.find(c => c.email && c.email.toLowerCase() === email.toLowerCase());
      if (dup) {
        if (!confirm(`A contact with email "${email}" already exists (${dup.name}). Add anyway?`)) return;
      }
    }

    const data = {
      name,
      email,
      phone:       document.getElementById('contact-form-phone').value.trim(),
      company:     document.getElementById('contact-form-company').value,
      title:       document.getElementById('contact-form-title').value.trim(),
      stage:       document.getElementById('contact-form-stage').value,
      owner:       document.getElementById('contact-form-owner').value.trim(),
      notes:       document.getElementById('contact-form-notes').value.trim(),
      tags:        [...contactModalTags],
      leadSource:  (document.getElementById('contact-form-lead-source')?.value || ''),
      territory:   (document.getElementById('contact-form-territory')?.value || ''),
      lastActivity: Date.now(),
    };

    try {
      let saved;
      if (id) {
        const existing = db.contacts.find(c => c.id === id);
        saved = await apiPut('/contacts/' + id, { ...existing, ...data });
        const idx = db.contacts.findIndex(c => c.id === id);
        if (idx !== -1) db.contacts[idx] = saved;
        toast('Contact updated', 'success');
      } else {
        saved = await apiPost('/contacts', data);
        db.contacts.push(saved);
        toast('Contact added', 'success');
      }
      // Re-add custom fields if any
      if (id) {
        const existing = db.contacts.find(c => c.id === id);
        if (existing && existing.customFields) {
          const cfData = {};
          const cfEls = document.querySelectorAll('[id^="cf-"]');
          cfEls.forEach(el => { cfData[el.id.replace('cf-','')] = el.value; });
          if (Object.keys(cfData).length > 0) {
            saved = await apiPut('/contacts/' + id, { ...saved, customFields: cfData });
            const idx = db.contacts.findIndex(c => c.id === id);
            if (idx !== -1) db.contacts[idx] = saved;
          }
        }
      }
    } catch(e) {
      toast('Failed to save contact: ' + e.message, 'error');
      return;
    }

    saveDBLocal();
    closeModal('modal-contact');
    renderContacts();
    if (currentView === 'dashboard') renderDashboard();
    if (currentView === 'contact-detail') renderContactDetail(id);
  };
})();

// Patch openDealModal to populate lead source
(function p16PatchDealModal() {
  const _orig = openDealModal;
  window.openDealModal = function(id, defaultStage) {
    _orig.call(this, id, defaultStage);
    const deal  = id ? db.deals.find(d => d.id === id) : null;
    const srcEl = document.getElementById('deal-form-lead-source');
    if (srcEl) srcEl.value = deal ? (deal.leadSource||'') : '';
  };
})();

// Patch saveDeal to include lead source
(function p16PatchSaveDeal() {
  const _origSaveDeal = window.saveDeal;
  if (_origSaveDeal) {
    window.saveDeal = async function() {
      const id  = document.getElementById('deal-form-id').value;
      const src = document.getElementById('deal-form-lead-source')?.value || '';
      if (id) {
        const idx = db.deals.findIndex(d => d.id === id);
        if (idx !== -1) db.deals[idx]._p16LeadSource = src;
      }
      window._p16NewDealLeadSource = src;
      await _origSaveDeal.call(this);
      // After save, patch via API
      const savedId = document.getElementById('deal-form-id').value || (db.deals[db.deals.length-1]?.id);
      if (savedId && src) {
        const deal = db.deals.find(d => d.id === savedId);
        if (deal && deal.leadSource !== src) {
          try {
            const updated = await apiPut('/deals/' + savedId, { ...deal, leadSource: src });
            const idx = db.deals.findIndex(d => d.id === savedId);
            if (idx !== -1) db.deals[idx] = updated;
          } catch(e) { /* non-fatal */ }
        }
      }
    };
  }
})();

// Patch openCompanyModal to populate territory
(function p16PatchCompanyModal() {
  const _orig = openCompanyModal;
  window.openCompanyModal = function(company) {
    _orig.call(this, company);
    const terrEl = document.getElementById('company-form-territory');
    if (terrEl) terrEl.value = company ? (company.territory||'') : '';
  };
})();

// Patch saveCompany to include territory via API
(function p16PatchSaveCompany() {
  const _orig = saveCompany;
  window.saveCompany = async function() {
    const id     = document.getElementById('company-form-id').value;
    const terrEl = document.getElementById('company-form-territory');
    const territory = terrEl ? terrEl.value : '';

    // Call original to save base fields
    _orig.call(this);

    // Then patch via API to save territory
    if (id) {
      const co = db.companies.find(c => c.id === id);
      if (co && co.territory !== territory) {
        try {
          const updated = await apiPut('/companies/' + id, { ...co, territory });
          const idx = db.companies.findIndex(c => c.id === id);
          if (idx !== -1) db.companies[idx] = updated;
        } catch(e) { /* non-fatal */ }
      }
    }
  };
})();

// ════════════════════════════════════════════════════════════
// FEATURE 2: SMS / CALL LOG
// ════════════════════════════════════════════════════════════

function openCallLogModal(contactId, logId) {
  const log = logId ? (db.callLogs||[]).find(l => l.id === logId) : null;
  document.getElementById('modal-call-log-title').textContent = log ? 'Edit Log' : 'Log Call / SMS';
  document.getElementById('call-log-form-id').value = log ? log.id : '';
  document.getElementById('call-log-form-contact-id').value = contactId || (log?.contactId||'');
  document.getElementById('call-log-form-type').value = log ? log.type : 'call';
  document.getElementById('call-log-form-direction').value = log ? log.direction : 'outbound';
  document.getElementById('call-log-form-notes').value = log ? (log.notes||'') : '';

  // Date/time: default to now
  const now = new Date();
  now.setSeconds(0, 0);
  document.getElementById('call-log-form-date').value = log
    ? (log.date ? log.date.slice(0,16) : now.toISOString().slice(0,16))
    : now.toISOString().slice(0,16);

  // Duration in minutes
  const durEl = document.getElementById('call-log-form-duration');
  if (durEl) durEl.value = log ? Math.round((log.duration||0) / 60) : '';

  toggleCallDuration();
  openModal('modal-call-log');
}

function toggleCallDuration() {
  const type = document.getElementById('call-log-form-type')?.value;
  const wrap = document.getElementById('call-log-duration-wrap');
  if (wrap) wrap.style.display = (type === 'sms') ? 'none' : '';
}

async function saveCallLog() {
  const id        = document.getElementById('call-log-form-id').value;
  const contactId = document.getElementById('call-log-form-contact-id').value;
  const type      = document.getElementById('call-log-form-type').value;
  const direction = document.getElementById('call-log-form-direction').value;
  const date      = document.getElementById('call-log-form-date').value;
  const durMins   = parseFloat(document.getElementById('call-log-form-duration')?.value || '0') || 0;
  const notes     = document.getElementById('call-log-form-notes').value.trim();

  if (!date) { toast('Date is required', 'error'); return; }

  const data = {
    contactId, type, direction,
    date: new Date(date).toISOString(),
    duration: Math.round(durMins * 60),
    notes,
  };

  try {
    if (id) {
      const updated = await apiPut('/call-logs/' + id, data);
      const idx = (db.callLogs||[]).findIndex(l => l.id === id);
      if (idx !== -1) db.callLogs[idx] = updated;
      toast('Log updated', 'success');
    } else {
      const created = await apiPost('/call-logs', data);
      db.callLogs = db.callLogs || [];
      db.callLogs.unshift(created);
      toast('Log saved', 'success');
    }
    closeModal('modal-call-log');
    if (currentView === 'contact-detail') renderContactDetail(contactId);
    if (currentView === 'activities') renderActivities();
  } catch(e) {
    toast('Failed to save: ' + e.message, 'error');
  }
}

async function deleteCallLog(id, contactId) {
  if (!confirm('Delete this log entry?')) return;
  try {
    await apiDelete('/call-logs/' + id);
    db.callLogs = (db.callLogs||[]).filter(l => l.id !== id);
    toast('Log deleted', 'info');
    if (currentView === 'contact-detail') renderContactDetail(contactId);
  } catch(e) {
    toast('Delete failed', 'error');
  }
}

function formatCallDuration(seconds) {
  if (!seconds) return '';
  const m = Math.floor(seconds / 60);
  const s = seconds % 60;
  if (m >= 60) return Math.floor(m / 60) + 'h ' + (m % 60) + 'm';
  if (s === 0) return m + ' min';
  return m + 'm ' + s + 's';
}

function renderCallLogTimeline(contactId) {
  const logs = (db.callLogs||[]).filter(l => l.contactId === contactId)
    .sort((a, b) => new Date(b.date) - new Date(a.date));
  if (!logs.length) return '';
  return `
    <div class="panel" style="margin-top:0">
      <div class="panel-header">
        <div class="panel-title">Call / SMS Log</div>
        <span class="panel-count">${logs.length}</span>
        <button class="btn btn-secondary btn-sm panel-action" onclick="openCallLogModal('${contactId}')">+ Log</button>
      </div>
      <div style="padding:8px 12px;display:flex;flex-direction:column;gap:6px;max-height:320px;overflow-y:auto">
        ${logs.map(l => `
          <div class="call-log-entry">
            <div class="call-log-type-badge call-log-${l.type}" title="${l.type === 'call' ? 'Call' : 'SMS'}">
              ${l.type === 'call'
                ? `<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><path d="M22 16.92v3a2 2 0 0 1-2.18 2 19.79 19.79 0 0 1-8.63-3.07A19.5 19.5 0 0 1 4.69 13a19.79 19.79 0 0 1-3.07-8.67A2 2 0 0 1 3.6 2h3a2 2 0 0 1 2 1.72c.127.96.361 1.903.7 2.81a2 2 0 0 1-.45 2.11L8.09 9.91a16 16 0 0 0 6 6l1.27-1.27a2 2 0 0 1 2.11-.45c.907.339 1.85.573 2.81.7A2 2 0 0 1 22 16.92z"/></svg>`
                : `<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/></svg>`
              }
            </div>
            <div style="flex:1;min-width:0">
              <div style="display:flex;align-items:center;gap:6px;margin-bottom:1px">
                <span style="font-size:11px;font-weight:600;color:var(--text);text-transform:capitalize">${l.type}</span>
                <span class="call-dir-badge call-dir-${l.direction}">${l.direction}</span>
                ${l.duration ? `<span style="font-size:10px;color:var(--text-muted)">${formatCallDuration(l.duration)}</span>` : ''}
              </div>
              ${l.notes ? `<div style="font-size:11px;color:var(--text-dim);line-height:1.4">${esc(l.notes)}</div>` : ''}
            </div>
            <div style="display:flex;flex-direction:column;align-items:flex-end;gap:2px;flex-shrink:0">
              <span style="font-size:10px;color:var(--text-muted)">${formatDate(l.date)}</span>
              <div style="display:flex;gap:2px">
                <button class="btn btn-ghost btn-xs" onclick="openCallLogModal('${contactId}','${l.id}')" style="padding:2px 4px;font-size:10px">Edit</button>
                <button class="btn btn-ghost btn-xs" onclick="deleteCallLog('${l.id}','${contactId}')" style="padding:2px 4px;font-size:10px;color:var(--red)">Del</button>
              </div>
            </div>
          </div>`).join('')}
      </div>
    </div>`;
}

// Patch renderContactDetail to inject call log panel and quick-log button
(function p16PatchContactDetail() {
  const _orig = renderContactDetail;
  window.renderContactDetail = function(id) {
    _orig.call(this, id);
    setTimeout(() => {
      // Add "Log Call/SMS" button to quick-log bar
      const quickBar = document.querySelector('#view-contact-detail .quick-log-bar');
      if (quickBar && !quickBar.querySelector('.p16-call-btn')) {
        const btn = document.createElement('button');
        btn.className = 'btn btn-secondary btn-sm p16-call-btn';
        btn.textContent = 'Log Call / SMS';
        btn.onclick = () => openCallLogModal(id);
        quickBar.appendChild(btn);
      }

      // Inject call log panel into right column
      const rightCol = document.querySelector('#view-contact-detail .contact-detail-right');
      if (rightCol && !rightCol.querySelector('.p16-call-log-panel')) {
        const wrap = document.createElement('div');
        wrap.className = 'p16-call-log-panel';
        wrap.innerHTML = renderCallLogTimeline(id);
        if (wrap.innerHTML.trim()) rightCol.appendChild(wrap);
      }

      // Show lead source and territory in contact info panel
      const contact = db.contacts.find(c => c.id === id);
      if (!contact) return;
      const infoPanel = document.querySelector('#view-contact-detail .contact-detail-left .panel .detail-field:last-of-type');
      if (infoPanel) {
        const infoContainer = infoPanel.closest('div[style]') || infoPanel.parentElement;
        if (infoContainer && !infoContainer.querySelector('.p16-contact-meta')) {
          const meta = document.createElement('div');
          meta.className = 'p16-contact-meta';
          if (contact.leadSource) {
            meta.innerHTML += `<div class="detail-field"><span class="detail-field-label">Lead Source</span><span class="detail-field-value source-badge source-${(contact.leadSource||'').toLowerCase().replace(/\s+/g,'-')}">${esc(contact.leadSource)}</span></div>`;
          }
          if (contact.territory) {
            meta.innerHTML += `<div class="detail-field"><span class="detail-field-label">Territory</span><span class="detail-field-value territory-badge">${esc(contact.territory)}</span></div>`;
          }
          if (meta.innerHTML) infoContainer.appendChild(meta);
        }
      }
    }, 10);
  };
})();

// ════════════════════════════════════════════════════════════
// FEATURE 3: TERRITORY / REGION SEGMENTATION
// ════════════════════════════════════════════════════════════

// Patch renderContacts to add territory filter
(function p16PatchContacts() {
  const _orig = renderContacts;
  window.renderContacts = function() {
    _orig.call(this);
    // Inject territory filter if not present
    const header = document.querySelector('#view-contacts .page-header .header-actions');
    if (header && !document.getElementById('territory-filter')) {
      const sel = document.createElement('select');
      sel.className = 'form-select';
      sel.id = 'territory-filter';
      sel.style.width = '120px';
      sel.innerHTML = `<option value="">Territory</option>${TERRITORIES.map(t => `<option value="${t}">${t}</option>`).join('')}`;
      sel.onchange = () => filterContactsByTerritory(sel.value);
      header.insertBefore(sel, header.firstChild);
    }
  };
})();

let _p16TerritoryFilter = '';
function filterContactsByTerritory(val) {
  _p16TerritoryFilter = val;
  // Apply by patching the table — re-render contacts with filter applied
  const rows = document.querySelectorAll('#contacts-tbody tr');
  rows.forEach(row => {
    // Find the contact by name in row
    const nameEl = row.querySelector('.td-name');
    if (!nameEl) return;
    const name = nameEl.textContent.trim();
    const contact = db.contacts.find(c => c.name === name);
    if (!val || !contact || contact.territory === val) {
      row.style.display = '';
    } else {
      row.style.display = 'none';
    }
  });
}

// ════════════════════════════════════════════════════════════
// FEATURE 4: RENEWAL / SUBSCRIPTION TRACKING
// ════════════════════════════════════════════════════════════

function renderRenewals() {
  if (currentView !== 'renewals') return;
  const statusFilter = document.getElementById('renewals-status-filter')?.value || '';
  let renewals = [...(db.renewals||[])];
  if (statusFilter) renewals = renewals.filter(r => r.status === statusFilter);
  renewals.sort((a, b) => {
    if (!a.renewalDate && !b.renewalDate) return 0;
    if (!a.renewalDate) return 1;
    if (!b.renewalDate) return -1;
    return a.renewalDate.localeCompare(b.renewalDate);
  });

  const countEl = document.getElementById('renewals-count');
  if (countEl) countEl.textContent = renewals.length + ' subscription' + (renewals.length !== 1 ? 's' : '');

  const today = new Date().toISOString().slice(0, 10);
  const in30  = new Date(Date.now() + 30 * 86400000).toISOString().slice(0, 10);

  const tbody = document.getElementById('renewals-tbody');
  if (!tbody) return;

  if (!renewals.length) {
    tbody.innerHTML = `<tr><td colspan="9" style="text-align:center;padding:40px;color:var(--text-muted)">No subscriptions yet. Add your first subscription to start tracking renewals.</td></tr>`;
    return;
  }

  tbody.innerHTML = renewals.map(r => {
    const isDue = r.renewalDate && r.renewalDate >= today && r.renewalDate <= in30;
    const isPast = r.renewalDate && r.renewalDate < today;
    const renewalColor = isPast ? 'var(--red)' : (isDue ? 'var(--yellow)' : 'var(--text-dim)');
    const statusClass  = { Active: 'renewal-active', 'At Risk': 'renewal-risk', Churned: 'renewal-churned' }[r.status] || 'renewal-active';
    return `
      <tr>
        <td class="td-name">${esc(r.serviceName)}</td>
        <td>${r.contactId ? `<a href="#" onclick="event.preventDefault();showContactDetail('${r.contactId}')" style="color:var(--accent-hover);text-decoration:none">${esc(contactName(r.contactId))}</a>` : '—'}</td>
        <td>${r.companyId ? esc(companyName(r.companyId)) : '—'}</td>
        <td style="font-weight:600;color:var(--green)">$${(r.mrr||0).toLocaleString()}</td>
        <td style="color:var(--text-dim)">${r.startDate ? formatDate(r.startDate) : '—'}</td>
        <td style="color:${renewalColor};font-weight:${isDue?'600':'400'}">
          ${r.renewalDate ? formatDate(r.renewalDate) : '—'}
          ${isDue ? ' <span class="renewal-due-badge">Due Soon</span>' : ''}
          ${isPast && r.status !== 'Churned' ? ' <span class="renewal-past-badge">Past Due</span>' : ''}
        </td>
        <td><span class="renewal-status-pill ${statusClass}">${esc(r.status)}</span></td>
        <td style="color:var(--text-muted);font-size:11px;max-width:160px;overflow:hidden;text-overflow:ellipsis">${esc(r.notes||'')}</td>
        <td>
          <button class="btn btn-ghost btn-xs" onclick="openRenewalModal('${r.id}')">Edit</button>
          <button class="btn btn-ghost btn-xs" onclick="deleteRenewal('${r.id}')" style="color:var(--red)">Del</button>
        </td>
      </tr>`;
  }).join('');

  updateRenewalsBadge();
}

function openRenewalModal(id) {
  const renewal = id ? (db.renewals||[]).find(r => r.id === id) : null;
  document.getElementById('modal-renewal-title').textContent = renewal ? 'Edit Subscription' : 'Add Subscription';
  document.getElementById('renewal-form-id').value = renewal ? renewal.id : '';
  document.getElementById('renewal-form-service').value = renewal ? renewal.serviceName : '';
  document.getElementById('renewal-form-mrr').value = renewal ? (renewal.mrr||'') : '';
  document.getElementById('renewal-form-status').value = renewal ? (renewal.status||'Active') : 'Active';
  document.getElementById('renewal-form-start').value = renewal ? (renewal.startDate||'') : '';
  document.getElementById('renewal-form-renewal').value = renewal ? (renewal.renewalDate||'') : '';
  document.getElementById('renewal-form-notes').value = renewal ? (renewal.notes||'') : '';

  const cSel = document.getElementById('renewal-form-contact');
  cSel.innerHTML = `<option value="">No Contact</option>` + (db.contacts||[]).map(c => `<option value="${c.id}" ${renewal && renewal.contactId === c.id ? 'selected' : ''}>${esc(c.name)}</option>`).join('');

  const coSel = document.getElementById('renewal-form-company');
  coSel.innerHTML = `<option value="">No Company</option>` + (db.companies||[]).map(c => `<option value="${c.id}" ${renewal && renewal.companyId === c.id ? 'selected' : ''}>${esc(c.name)}</option>`).join('');

  const delBtn = document.getElementById('btn-delete-renewal');
  delBtn.style.display = renewal ? 'inline-flex' : 'none';
  delBtn.onclick = () => deleteRenewal(renewal.id);

  openModal('modal-renewal');
}

async function saveRenewal() {
  const id          = document.getElementById('renewal-form-id').value;
  const serviceName = document.getElementById('renewal-form-service').value.trim();
  if (!serviceName) { toast('Service name is required', 'error'); return; }

  const data = {
    serviceName,
    contactId:   document.getElementById('renewal-form-contact').value,
    companyId:   document.getElementById('renewal-form-company').value,
    mrr:         parseFloat(document.getElementById('renewal-form-mrr').value) || 0,
    status:      document.getElementById('renewal-form-status').value,
    startDate:   document.getElementById('renewal-form-start').value,
    renewalDate: document.getElementById('renewal-form-renewal').value,
    notes:       document.getElementById('renewal-form-notes').value.trim(),
  };

  try {
    if (id) {
      const updated = await apiPut('/renewals/' + id, data);
      const idx = (db.renewals||[]).findIndex(r => r.id === id);
      if (idx !== -1) db.renewals[idx] = updated;
      toast('Subscription updated', 'success');
    } else {
      const created = await apiPost('/renewals', data);
      db.renewals = db.renewals || [];
      db.renewals.push(created);
      toast('Subscription added', 'success');
    }
    closeModal('modal-renewal');
    if (currentView === 'renewals') renderRenewals();
    if (currentView === 'dashboard') renderDashboard();
    updateRenewalsBadge();
  } catch(e) {
    toast('Failed to save: ' + e.message, 'error');
  }
}

async function deleteRenewal(id) {
  if (!confirm('Delete this subscription?')) return;
  try {
    await apiDelete('/renewals/' + id);
    db.renewals = (db.renewals||[]).filter(r => r.id !== id);
    toast('Subscription deleted', 'info');
    closeModal('modal-renewal');
    if (currentView === 'renewals') renderRenewals();
    updateRenewalsBadge();
  } catch(e) {
    toast('Delete failed', 'error');
  }
}

// Dashboard widget: upcoming renewals in next 30 days
function renderUpcomingRenewals() {
  const el = document.getElementById('dash-upcoming-renewals');
  if (!el) return;
  const today = new Date().toISOString().slice(0, 10);
  const in30  = new Date(Date.now() + 30 * 86400000).toISOString().slice(0, 10);
  const upcoming = (db.renewals||[])
    .filter(r => r.status === 'Active' && r.renewalDate && r.renewalDate >= today && r.renewalDate <= in30)
    .sort((a,b) => a.renewalDate.localeCompare(b.renewalDate));

  if (!upcoming.length) {
    el.innerHTML = '<div style="color:var(--text-muted);font-size:12px;padding:12px 16px">No renewals due in the next 30 days.</div>';
    return;
  }

  el.innerHTML = upcoming.map(r => {
    const daysLeft = Math.ceil((new Date(r.renewalDate) - new Date()) / 86400000);
    return `
      <div style="display:flex;align-items:center;gap:10px;padding:8px 16px;border-bottom:1px solid var(--border)">
        <div style="flex:1;min-width:0">
          <div style="font-size:12px;font-weight:500;color:var(--text)">${esc(r.serviceName)}</div>
          <div style="font-size:11px;color:var(--text-muted)">${r.contactId ? esc(contactName(r.contactId)) : (r.companyId ? esc(companyName(r.companyId)) : '')}</div>
        </div>
        <div style="text-align:right">
          <div style="font-size:12px;font-weight:600;color:var(--green)">$${(r.mrr||0).toLocaleString()}<span style="font-size:10px;font-weight:400;color:var(--text-muted)">/mo</span></div>
          <div style="font-size:10px;color:${daysLeft<=7?'var(--red)':'var(--yellow)'};font-weight:500">${daysLeft}d left</div>
        </div>
      </div>`;
  }).join('');
}

// Patch renderDashboard to inject renewals widget
(function p16PatchDashboard() {
  const _orig = renderDashboard;
  window.renderDashboard = function() {
    _orig.call(this);
    setTimeout(() => {
      const pageContent = document.querySelector('#view-dashboard .page-content');
      if (!pageContent) return;
      if (!document.getElementById('dash-renewals-panel')) {
        const panel = document.createElement('div');
        panel.className = 'panel';
        panel.id = 'dash-renewals-panel';
        panel.style.marginBottom = '16px';
        panel.innerHTML = `
          <div class="panel-header">
            <div class="panel-title">Upcoming Renewals</div>
            <a href="#" onclick="event.preventDefault();navigate('renewals')" style="font-size:11px;color:var(--accent-hover);text-decoration:none">View All</a>
          </div>
          <div id="dash-upcoming-renewals"></div>`;
        // Insert at top of content
        pageContent.insertBefore(panel, pageContent.firstChild);
      }
      renderUpcomingRenewals();
    }, 20);
  };
})();

// ════════════════════════════════════════════════════════════
// FEATURE 5: USER ACTIVITY LOG (AUDIT TRAIL)
// ════════════════════════════════════════════════════════════

let _p16AuditEntries = [];

async function loadAuditLog() {
  const container = document.getElementById('audit-log-container');
  if (!container) return;
  container.innerHTML = '<div style="color:var(--text-muted);font-size:12px;padding:16px;text-align:center">Loading...</div>';
  try {
    const data = await apiGet('/audit-log?limit=200');
    _p16AuditEntries = data.entries || [];
    renderAuditLog();
  } catch(e) {
    container.innerHTML = '<div style="color:var(--text-muted);font-size:12px;padding:16px;text-align:center">Could not load activity log.</div>';
  }
}

function renderAuditLog() {
  const container = document.getElementById('audit-log-container');
  if (!container) return;
  const typeFilter   = document.getElementById('audit-type-filter')?.value || '';
  const actionFilter = document.getElementById('audit-action-filter')?.value || '';

  let entries = _p16AuditEntries;
  if (typeFilter)   entries = entries.filter(e => e.entity_type === typeFilter);
  if (actionFilter) entries = entries.filter(e => e.action === actionFilter);

  if (!entries.length) {
    container.innerHTML = '<div style="color:var(--text-muted);font-size:12px;padding:16px;text-align:center">No activity logged yet.</div>';
    return;
  }

  const actionColors = { created: 'var(--green)', updated: 'var(--accent-hover)', deleted: 'var(--red)' };
  const entityIcons  = {
    contact: '&#128100;', deal: '&#128181;', company: '&#127968;',
    renewal: '&#128260;', call_log: '&#128222;',
  };

  container.innerHTML = `
    <table style="font-size:11px;width:100%">
      <thead>
        <tr>
          <th style="padding:6px 8px;text-align:left;color:var(--text-muted);font-weight:500;border-bottom:1px solid var(--border)">When</th>
          <th style="padding:6px 8px;text-align:left;color:var(--text-muted);font-weight:500;border-bottom:1px solid var(--border)">User</th>
          <th style="padding:6px 8px;text-align:left;color:var(--text-muted);font-weight:500;border-bottom:1px solid var(--border)">Action</th>
          <th style="padding:6px 8px;text-align:left;color:var(--text-muted);font-weight:500;border-bottom:1px solid var(--border)">Entity</th>
          <th style="padding:6px 8px;text-align:left;color:var(--text-muted);font-weight:500;border-bottom:1px solid var(--border)">Record</th>
          <th style="padding:6px 8px;text-align:left;color:var(--text-muted);font-weight:500;border-bottom:1px solid var(--border)">Detail</th>
        </tr>
      </thead>
      <tbody>
        ${entries.slice(0, 100).map(e => `
          <tr style="border-bottom:1px solid var(--border2)">
            <td style="padding:5px 8px;color:var(--text-muted);white-space:nowrap">${timeAgo(e.created_at)}</td>
            <td style="padding:5px 8px;color:var(--text-dim)">${esc(e.user_name||'System')}</td>
            <td style="padding:5px 8px">
              <span style="color:${actionColors[e.action]||'var(--text)'};font-weight:600;text-transform:capitalize">${esc(e.action)}</span>
            </td>
            <td style="padding:5px 8px;color:var(--text-muted);text-transform:capitalize">${esc((e.entity_type||'').replace('_',' '))}</td>
            <td style="padding:5px 8px;color:var(--text);font-weight:500">${esc(e.entity_name||e.entity_id||'')}</td>
            <td style="padding:5px 8px;color:var(--text-muted)">
              ${e.field_name ? `<span style="color:var(--text-dim)">${esc(e.field_name)}</span>: ` : ''}
              ${e.old_value ? `<span style="text-decoration:line-through;opacity:0.6">${esc(e.old_value)}</span> &rarr; ` : ''}
              ${e.new_value ? `<span style="color:var(--green)">${esc(e.new_value)}</span>` : ''}
            </td>
          </tr>`).join('')}
      </tbody>
    </table>`;
}

