// FEATURE 1+3: REPORTS — Lead Source Chart + Territory Breakdown
// ════════════════════════════════════════════════════════════

(function p16PatchReports() {
  const _orig = renderReports;
  window.renderReports = function() {
    _orig.call(this);
    setTimeout(() => {
      const grid = document.querySelector('#view-reports .reports-grid');
      if (!grid) return;

      // Lead Source Breakdown
      if (!document.getElementById('report-lead-source')) {
        const card = document.createElement('div');
        card.className = 'panel report-card';
        card.innerHTML = '<div class="panel-header"><div class="panel-title">Lead Source Breakdown</div></div><div id="report-lead-source" style="padding:16px"></div>';
        grid.appendChild(card);
      }
      renderLeadSourceReport();

      // Territory Breakdown
      if (!document.getElementById('report-territory')) {
        const card = document.createElement('div');
        card.className = 'panel report-card';
        card.innerHTML = '<div class="panel-header"><div class="panel-title">Territory Breakdown</div></div><div id="report-territory" style="padding:16px"></div>';
        grid.appendChild(card);
      }
      renderTerritoryReport();

      // MRR Trend (Renewals)
      if (!document.getElementById('report-mrr')) {
        const card = document.createElement('div');
        card.className = 'panel report-card';
        card.innerHTML = '<div class="panel-header"><div class="panel-title">MRR by Status</div></div><div id="report-mrr" style="padding:16px"></div>';
        grid.appendChild(card);
      }
      renderMRRReport();
    }, 150);
  };
})();

function renderLeadSourceReport() {
  const el = document.getElementById('report-lead-source');
  if (!el) return;

  const all = [...db.contacts, ...db.deals];
  const counts = {};
  LEAD_SOURCES.forEach(s => { counts[s] = 0; });
  counts['Unknown'] = 0;

  db.contacts.forEach(c => {
    const src = c.leadSource || 'Unknown';
    counts[src] = (counts[src]||0) + 1;
  });
  db.deals.forEach(d => {
    const src = d.leadSource || 'Unknown';
    counts[src] = (counts[src]||0) + 1;
  });

  const total = Object.values(counts).reduce((a,b) => a+b, 0);
  if (!total) { el.innerHTML = '<div style="color:var(--text-muted);font-size:12px">No lead source data yet. Set lead source on contacts and deals.</div>'; return; }

  const colors = { Referral:'#22c55e', 'Cold Outreach':'#3b82f6', Website:'#6366f1', Social:'#f97316', Event:'#eab308', Other:'#a1a1aa', Unknown:'#52525b' };
  const entries = Object.entries(counts).filter(([,v]) => v > 0).sort((a,b) => b[1]-a[1]);

  el.innerHTML = `
    <div style="display:flex;flex-direction:column;gap:8px">
      ${entries.map(([src, count]) => {
        const pct = Math.round(count / total * 100);
        const color = colors[src] || '#6366f1';
        return `
          <div>
            <div style="display:flex;justify-content:space-between;margin-bottom:3px">
              <span style="font-size:12px;font-weight:500;color:var(--text)">${esc(src)}</span>
              <span style="font-size:12px;color:var(--text-muted)">${count} <span style="opacity:0.6">(${pct}%)</span></span>
            </div>
            <div style="height:6px;background:var(--border);border-radius:3px;overflow:hidden">
              <div style="height:100%;width:${pct}%;background:${color};border-radius:3px;transition:width 0.3s"></div>
            </div>
          </div>`;
      }).join('')}
    </div>`;
}

function renderTerritoryReport() {
  const el = document.getElementById('report-territory');
  if (!el) return;

  const contactsByTerritory = {};
  const dealsByTerritory    = {};

  (db.contacts||[]).forEach(c => {
    const t = c.territory || 'Unassigned';
    contactsByTerritory[t] = (contactsByTerritory[t]||0) + 1;
  });

  (db.deals||[]).forEach(d => {
    const contact = db.contacts.find(c => c.id === d.contact);
    const t = (contact?.territory) || 'Unassigned';
    dealsByTerritory[t] = (dealsByTerritory[t]||0) + 1;
  });

  const territories = [...new Set([...Object.keys(contactsByTerritory), ...Object.keys(dealsByTerritory)])].sort();
  if (!territories.length) { el.innerHTML = '<div style="color:var(--text-muted);font-size:12px">No territory data yet.</div>'; return; }

  const colors = { North:'#3b82f6', South:'#f97316', East:'#22c55e', West:'#eab308', Central:'#6366f1', Remote:'#a1a1aa', Unassigned:'#52525b' };

  el.innerHTML = `
    <div style="overflow-x:auto">
      <table>
        <thead>
          <tr>
            <th>Territory</th>
            <th style="text-align:right">Contacts</th>
            <th style="text-align:right">Deals</th>
            <th style="min-width:100px">Distribution</th>
          </tr>
        </thead>
        <tbody>
          ${territories.map(t => {
            const contacts = contactsByTerritory[t]||0;
            const deals    = dealsByTerritory[t]||0;
            const total    = (db.contacts||[]).length || 1;
            const pct      = Math.round(contacts/total*100);
            const color    = colors[t] || '#6366f1';
            return `<tr>
              <td>
                <div style="display:flex;align-items:center;gap:6px">
                  <div style="width:8px;height:8px;border-radius:50%;background:${color};flex-shrink:0"></div>
                  <span style="font-weight:500">${esc(t)}</span>
                </div>
              </td>
              <td style="text-align:right;color:var(--text-dim)">${contacts}</td>
              <td style="text-align:right;color:var(--text-dim)">${deals}</td>
              <td>
                <div style="height:6px;background:var(--border);border-radius:3px;overflow:hidden;min-width:80px">
                  <div style="height:100%;width:${pct}%;background:${color};border-radius:3px"></div>
                </div>
              </td>
            </tr>`;
          }).join('')}
        </tbody>
      </table>
    </div>`;
}

function renderMRRReport() {
  const el = document.getElementById('report-mrr');
  if (!el) return;
  const renewals = db.renewals || [];
  if (!renewals.length) { el.innerHTML = '<div style="color:var(--text-muted);font-size:12px">No subscription data yet. Add subscriptions under Renewals.</div>'; return; }

  const byStatus = { Active: 0, 'At Risk': 0, Churned: 0 };
  renewals.forEach(r => { byStatus[r.status] = (byStatus[r.status]||0) + (r.mrr||0); });
  const totalMRR = Object.values(byStatus).reduce((a,b) => a+b, 0);
  const activeMRR = byStatus['Active'] || 0;
  const atRiskMRR = byStatus['At Risk'] || 0;
  const churnedMRR = byStatus['Churned'] || 0;

  const upcoming30 = new Date().toISOString().slice(0,10);
  const in30 = new Date(Date.now()+30*86400000).toISOString().slice(0,10);
  const upcomingCount = renewals.filter(r => r.status==='Active' && r.renewalDate && r.renewalDate >= upcoming30 && r.renewalDate <= in30).length;

  el.innerHTML = `
    <div style="display:flex;gap:12px;flex-wrap:wrap;margin-bottom:16px">
      <div style="flex:1;min-width:100px;background:var(--surface2);border-radius:8px;padding:12px">
        <div style="font-size:18px;font-weight:700;color:var(--green)">$${activeMRR.toLocaleString()}</div>
        <div style="font-size:11px;color:var(--text-muted);margin-top:2px">Active MRR</div>
      </div>
      <div style="flex:1;min-width:100px;background:var(--surface2);border-radius:8px;padding:12px">
        <div style="font-size:18px;font-weight:700;color:var(--yellow)">$${atRiskMRR.toLocaleString()}</div>
        <div style="font-size:11px;color:var(--text-muted);margin-top:2px">At Risk MRR</div>
      </div>
      <div style="flex:1;min-width:100px;background:var(--surface2);border-radius:8px;padding:12px">
        <div style="font-size:18px;font-weight:700;color:var(--red)">$${churnedMRR.toLocaleString()}</div>
        <div style="font-size:11px;color:var(--text-muted);margin-top:2px">Churned MRR</div>
      </div>
      <div style="flex:1;min-width:100px;background:var(--surface2);border-radius:8px;padding:12px">
        <div style="font-size:18px;font-weight:700;color:var(--accent-hover)">${upcomingCount}</div>
        <div style="font-size:11px;color:var(--text-muted);margin-top:2px">Renewals in 30d</div>
      </div>
    </div>
    <div style="overflow-x:auto">
      <table>
        <thead>
          <tr>
            <th>Service</th>
            <th>Contact / Company</th>
            <th style="text-align:right">MRR</th>
            <th>Renewal Date</th>
            <th>Status</th>
          </tr>
        </thead>
        <tbody>
          ${[...renewals].sort((a,b) => (b.mrr||0)-(a.mrr||0)).slice(0,15).map(r => {
            const statusClass = { Active: 'renewal-active', 'At Risk': 'renewal-risk', Churned: 'renewal-churned' }[r.status]||'renewal-active';
            const entity = r.contactId ? contactName(r.contactId) : (r.companyId ? companyName(r.companyId) : '—');
            return `<tr>
              <td style="font-weight:500">${esc(r.serviceName)}</td>
              <td style="color:var(--text-muted)">${esc(entity)}</td>
              <td style="text-align:right;font-weight:600;color:var(--green)">$${(r.mrr||0).toLocaleString()}</td>
              <td style="color:var(--text-muted)">${r.renewalDate ? formatDate(r.renewalDate) : '—'}</td>
              <td><span class="renewal-status-pill ${statusClass}">${esc(r.status)}</span></td>
            </tr>`;
          }).join('')}
        </tbody>
      </table>
    </div>`;
}

