// ── Role Helpers ────────────────────────────────────────────────────────────
function currentUserRole() { return _currentUser?.role || 'admin'; }
function isAdmin()   { return currentUserRole() === 'admin'; }
function isManager() { return currentUserRole() === 'manager'; }
function isRep()     { return currentUserRole() === 'rep'; }

function applyRoleBasedUI() {
  const role = currentUserRole();

  // Show settings nav for admin + manager; hide for rep
  const settingsNav = document.querySelector('.nav-item[data-view="settings"]');
  if (settingsNav) settingsNav.style.display = (role === 'rep') ? 'none' : '';

  // Users panel in settings — admin only
  const usersPanel = document.getElementById('settings-users-panel');
  if (usersPanel) usersPanel.style.display = (role === 'admin') ? '' : 'none';

  // Update sidebar user name badge
  const sidebarName = document.getElementById('sidebar-user-name');
  if (sidebarName && _currentUser?.name) sidebarName.textContent = _currentUser.name;

  // Notification status
  updateNotificationStatus();
}

// ── Team Users ──────────────────────────────────────────────────────────────
let teamUsers = [];

async function loadTeamUsers() {
  if (!isAdmin() && !isManager()) return;
  try {
    teamUsers = await apiGet('/users');
    renderTeamUsers();
  } catch(e) {
    teamUsers = [];
  }
}

function renderTeamUsers() {
  const container = document.getElementById('users-table-container');
  if (!container) return;

  if (!teamUsers.length) {
    container.innerHTML = '<div style="color:var(--text-muted);font-size:12px;padding:8px 0">No team members yet. Click "Invite Member" to add one.</div>';
    return;
  }

  const roleLabel = { admin: 'Admin', manager: 'Manager', rep: 'Rep' };
  const rolePill  = { admin: 'stage-customer', manager: 'stage-qualified', rep: 'stage-lead' };

  container.innerHTML = `
    <div style="overflow-x:auto">
      <table>
        <thead>
          <tr>
            <th>Name</th>
            <th>Email</th>
            <th>Role</th>
            <th>Owner Tag</th>
            <th>Joined</th>
            <th></th>
          </tr>
        </thead>
        <tbody>
          ${teamUsers.map(u => `
            <tr>
              <td style="font-weight:500">${esc(u.name)}</td>
              <td style="color:var(--text-muted)">${esc(u.email)}</td>
              <td><span class="stage-pill ${rolePill[u.role]||'stage-lead'}">${roleLabel[u.role]||esc(u.role)}</span></td>
              <td style="color:var(--text-muted);font-family:monospace">${u.ownerTag ? esc(u.ownerTag) : '—'}</td>
              <td style="color:var(--text-muted)">${formatDate(u.createdAt)}</td>
              <td>${isAdmin() ? `<button class="btn btn-ghost btn-xs" onclick="editTeamUser('${u.id}')">Edit</button>` : ''}</td>
            </tr>`).join('')}
        </tbody>
      </table>
    </div>
    <div style="font-size:11px;color:var(--text-muted);margin-top:10px;padding-top:8px;border-top:1px solid var(--border)">
      Roles: Admin = full access. Manager = all records, no user management. Rep = only their own deals (matched by owner tag).
    </div>`;
}

function openInviteUserModal() {
  document.getElementById('invite-user-form-id').value = '';
  document.getElementById('invite-user-name').value = '';
  document.getElementById('invite-user-email').value = '';
  document.getElementById('invite-user-email').disabled = false;
  document.getElementById('invite-user-role').value = 'rep';
  document.getElementById('invite-user-owner-tag').value = '';
  document.getElementById('invite-user-password').value = 'BoredRoom2025!';
  document.getElementById('modal-invite-user-title').textContent = 'Invite Team Member';
  document.getElementById('btn-save-user').textContent = 'Add Member';
  document.getElementById('btn-delete-user').style.display = 'none';
  document.getElementById('invite-user-password-wrap').style.display = '';
  openModal('modal-invite-user');
}

function editTeamUser(id) {
  const user = teamUsers.find(u => u.id === id);
  if (!user) return;
  document.getElementById('invite-user-form-id').value = id;
  document.getElementById('invite-user-name').value = user.name;
  document.getElementById('invite-user-email').value = user.email;
  document.getElementById('invite-user-email').disabled = true;
  document.getElementById('invite-user-role').value = user.role;
  document.getElementById('invite-user-owner-tag').value = user.ownerTag || '';
  document.getElementById('invite-user-password').value = '';
  document.getElementById('modal-invite-user-title').textContent = 'Edit Team Member';
  document.getElementById('btn-save-user').textContent = 'Save Changes';
  document.getElementById('btn-delete-user').style.display = '';
  document.getElementById('invite-user-password-wrap').style.display = '';
  openModal('modal-invite-user');
}

async function saveTeamUser() {
  const id       = document.getElementById('invite-user-form-id').value;
  const name     = document.getElementById('invite-user-name').value.trim();
  const email    = document.getElementById('invite-user-email').value.trim();
  const role     = document.getElementById('invite-user-role').value;
  const ownerTag = document.getElementById('invite-user-owner-tag').value.trim();
  const password = document.getElementById('invite-user-password').value.trim();

  if (!name || (!id && !email)) { toast('Name and email are required', 'error'); return; }

  try {
    if (id) {
      const updated = await apiPut('/users/' + id, { name, role, ownerTag });
      const idx = teamUsers.findIndex(u => u.id === id);
      if (idx >= 0) teamUsers[idx] = updated;
      if (password) await apiPut('/users/' + id + '/password', { password });
      toast('User updated', 'success');
    } else {
      const result = await apiPost('/users/invite', { name, email, role, ownerTag, password });
      teamUsers.push({ id: result.id, name, email, role, ownerTag, createdAt: Date.now() });
      toast('Team member added. Login: ' + email + ' / ' + (password || 'BoredRoom2025!'), 'success');
    }
    renderTeamUsers();
    closeModal('modal-invite-user');
  } catch(e) {
    toast('Failed: ' + e.message, 'error');
  }
}

async function deleteTeamUser() {
  const id   = document.getElementById('invite-user-form-id').value;
  if (!id) return;
  const user = teamUsers.find(u => u.id === id);
  if (!confirm('Remove ' + (user?.name || 'this user') + ' from the team?')) return;
  try {
    await apiDelete('/users/' + id);
    teamUsers = teamUsers.filter(u => u.id !== id);
    renderTeamUsers();
    closeModal('modal-invite-user');
    toast('Team member removed', 'success');
  } catch(e) {
    toast('Failed: ' + e.message, 'error');
  }
}

// ── Dashboard Widget Customize ───────────────────────────────────────────────
const DASHBOARD_WIDGETS = [
  { id: 'w-stat-contacts',          label: 'Total Contacts',        statId: 'stat-contacts' },
  { id: 'w-stat-open-deals',        label: 'Open Deals',            statId: 'stat-open-deals' },
  { id: 'w-stat-pipeline-value',    label: 'Pipeline Value',        statId: 'stat-pipeline-value' },
  { id: 'w-stat-activities',        label: 'Activities This Week',  statId: 'stat-activities' },
  { id: 'w-stat-weighted-pipeline', label: 'Weighted Pipeline',     statId: 'stat-weighted-pipeline' },
  { id: 'w-stat-overdue-tasks',     label: 'Overdue Tasks',         cardId: 'stat-card-overdue' },
  { id: 'w-stat-mrr',               label: 'MRR',                   statId: 'stat-mrr' },
  { id: 'w-stat-arr',               label: 'ARR',                   statId: 'stat-arr' },
  { id: 'w-stat-invoices',          label: 'Outstanding Invoices',  statId: 'stat-invoices-outstanding' },
  { id: 'w-panel-activity-feed',    label: 'Activity Feed Panel',   panelContentId: 'dashboard-activity-feed' },
  { id: 'w-panel-pipeline',         label: 'Pipeline by Stage',     panelContentId: 'pipeline-summary' },
  { id: 'w-panel-contacts',         label: 'Recent Contacts',       panelContentId: 'recent-contacts-list' },
];

function loadDashboardPrefs() {
  try {
    const raw = localStorage.getItem('crm_dashboard_widgets_v2');
    return raw ? JSON.parse(raw) : {};
  } catch { return {}; }
}

function applyDashboardPrefs(prefs) {
  DASHBOARD_WIDGETS.forEach(w => {
    const visible = prefs[w.id] !== false; // default visible
    let el = null;
    if (w.cardId) {
      el = document.getElementById(w.cardId);
    } else if (w.statId) {
      const inner = document.getElementById(w.statId);
      if (inner) el = inner.closest('.stat-card');
    } else if (w.panelContentId) {
      const inner = document.getElementById(w.panelContentId);
      if (inner) el = inner.closest('.panel');
    }
    if (el) el.style.display = visible ? '' : 'none';
  });
}

function openDashboardCustomize() {
  const prefs = loadDashboardPrefs();
  const container = document.getElementById('dashboard-widget-toggles');
  container.innerHTML = DASHBOARD_WIDGETS.map(w => {
    const checked = prefs[w.id] !== false;
    return `
      <label class="widget-toggle-row">
        <span style="font-size:13px;font-weight:500;color:var(--text);flex:1">${esc(w.label)}</span>
        <div class="toggle-switch">
          <input type="checkbox" id="widget-toggle-${w.id}" ${checked ? 'checked' : ''} />
          <span class="toggle-slider"></span>
        </div>
      </label>`;
  }).join('');
  openModal('modal-dashboard-customize');
}

function saveDashboardWidgets() {
  const prefs = {};
  DASHBOARD_WIDGETS.forEach(w => {
    const cb = document.getElementById('widget-toggle-' + w.id);
    if (cb) prefs[w.id] = cb.checked;
  });
  localStorage.setItem('crm_dashboard_widgets_v2', JSON.stringify(prefs));
  applyDashboardPrefs(prefs);
}

function resetDashboardWidgets() {
  localStorage.removeItem('crm_dashboard_widgets_v2');
  DASHBOARD_WIDGETS.forEach(w => {
    const cb = document.getElementById('widget-toggle-' + w.id);
    if (cb) cb.checked = true;
  });
  applyDashboardPrefs({});
  toast('Dashboard reset to default', 'info');
}

// ── Push Notifications ───────────────────────────────────────────────────────
function updateNotificationStatus() {
  const statusEl  = document.getElementById('notification-status');
  const enableBtn = document.getElementById('btn-enable-notifications');
  const testBtn   = document.getElementById('btn-test-notification');
  if (!statusEl) return;

  if (!('Notification' in window)) {
    statusEl.textContent = 'Status: Not supported in this browser';
    if (enableBtn) enableBtn.style.display = 'none';
    return;
  }

  const perm = Notification.permission;
  if (perm === 'granted') {
    statusEl.textContent = 'Status: Enabled';
    statusEl.style.color = 'var(--green)';
    if (enableBtn) enableBtn.textContent = 'Notifications Enabled';
    if (enableBtn) enableBtn.disabled = true;
    if (testBtn) testBtn.style.display = '';
  } else if (perm === 'denied') {
    statusEl.textContent = 'Status: Blocked by browser. Enable in browser settings.';
    statusEl.style.color = 'var(--red)';
    if (enableBtn) enableBtn.textContent = 'Blocked — Enable in Browser Settings';
    if (enableBtn) enableBtn.disabled = true;
  } else {
    statusEl.textContent = 'Status: Not enabled';
    if (enableBtn) enableBtn.textContent = 'Enable Notifications';
    if (enableBtn) enableBtn.disabled = false;
    if (testBtn) testBtn.style.display = 'none';
  }
}

async function enablePushNotifications() {
  if (!('Notification' in window)) {
    toast('This browser does not support notifications', 'warning');
    return;
  }
  const perm = await Notification.requestPermission();
  if (perm === 'granted') {
    localStorage.setItem('crm_notifications_enabled', '1');
    updateNotificationStatus();
    toast('Notifications enabled', 'success');
    checkAndFireNotifications();
  } else {
    toast('Notification permission denied. Check browser settings.', 'error');
    updateNotificationStatus();
  }
}

function sendTestNotification() {
  if (Notification.permission !== 'granted') {
    toast('Notifications not enabled', 'error');
    return;
  }
  new Notification('BoredRoom CRM', {
    body: 'Test notification. Everything is working.',
    icon: '/logo.png',
  });
  toast('Test notification sent', 'success');
}

function checkAndFireNotifications() {
  if (!('Notification' in window)) return;
  if (Notification.permission !== 'granted') return;

  const today = new Date().toISOString().slice(0, 10);
  const in7   = new Date(Date.now() + 7 * 86400000).toISOString().slice(0, 10);

  // Overdue tasks
  const overdueTasks = (db.tasks || []).filter(t =>
    t.status === 'Open' && t.dueDate && t.dueDate < today
  );
  if (overdueTasks.length > 0) {
    const n = overdueTasks.length;
    new Notification('Overdue Tasks', {
      body: `You have ${n} overdue task${n > 1 ? 's' : ''} that need attention.`,
      icon: '/logo.png',
      tag: 'crm-overdue-tasks',
    });
  }

  // Renewals due within 7 days
  const upcomingRenewals = (db.renewals || []).filter(r =>
    r.status === 'Active' && r.renewalDate && r.renewalDate >= today && r.renewalDate <= in7
  );
  if (upcomingRenewals.length > 0) {
    const n = upcomingRenewals.length;
    new Notification('Renewals Due Soon', {
      body: `${n} renewal${n > 1 ? 's' : ''} due within 7 days.`,
      icon: '/logo.png',
      tag: 'crm-renewals',
    });
  }

  // Deals with past close dates (not Won/Lost)
  const overdueDeals = (db.deals || []).filter(d =>
    !['Won', 'Lost'].includes(d.stage) && d.closeDate && d.closeDate < today
  );
  if (overdueDeals.length > 0) {
    const n = overdueDeals.length;
    new Notification('Deals Past Close Date', {
      body: `${n} deal${n > 1 ? 's' : ''} past their expected close date.`,
      icon: '/logo.png',
      tag: 'crm-overdue-deals',
    });
  }
}

// ── Saved Searches ───────────────────────────────────────────────────────────
let savedSearches = [];

async function loadSavedSearches() {
  try {
    savedSearches = await apiGet('/saved-searches');
    renderSavedSearchChips('contacts');
    renderSavedSearchChips('deals');
  } catch(e) {
    savedSearches = [];
  }
}

function renderSavedSearchChips(entity) {
  const barId = entity === 'contacts' ? 'contacts-saved-searches' : 'pipeline-saved-searches';
  const bar   = document.getElementById(barId);
  if (!bar) return;

  const relevant = savedSearches.filter(s => s.entity === entity);
  if (!relevant.length) { bar.style.display = 'none'; return; }

  bar.style.display = '';
  bar.innerHTML = `
    <span class="saved-search-label">Saved:</span>
    ${relevant.map(s => `
      <span class="saved-search-chip" onclick="applySavedSearch('${s.id}')">
        ${esc(s.name)}
        <span class="saved-search-chip-del" onclick="event.stopPropagation();deleteSavedSearch('${s.id}')" title="Remove">
          <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
        </span>
      </span>`).join('')}`;
}

let _pendingSaveSearchFilters = {};

function openSaveSearchModal(entity) {
  const nameEl    = document.getElementById('save-search-name');
  const entityEl  = document.getElementById('save-search-entity');
  const previewEl = document.getElementById('save-search-preview');

  entityEl.value = entity;
  nameEl.value   = '';

  const filters = {};
  const parts   = [];

  if (entity === 'contacts') {
    const search = document.getElementById('contact-search')?.value;
    const stage  = document.getElementById('contact-stage-filter')?.value;
    const tag    = document.getElementById('contacts-tag-filter')?.value;
    const health = document.getElementById('contacts-health-filter')?.value;
    if (search) { filters.search = search; parts.push(`Search: "${search}"`); }
    if (stage)  { filters.stage  = stage;  parts.push(`Stage: ${stage}`); }
    if (tag)    { filters.tag    = tag;    parts.push(`Tag: ${tag}`); }
    if (health) { filters.health = health; parts.push(`Health: ${health}`); }
  } else if (entity === 'deals') {
    const owner = document.getElementById('pipeline-owner-filter')?.value;
    const stage = document.getElementById('pipeline-stage-filter')?.value;
    if (owner) { filters.owner = owner; parts.push(`Owner: ${owner}`); }
    if (stage) { filters.stage = stage; parts.push(`Stage: ${stage}`); }
  }

  _pendingSaveSearchFilters = filters;
  previewEl.textContent = parts.length
    ? 'Active filters: ' + parts.join(' · ')
    : 'No active filters — saves as "Show All"';

  openModal('modal-save-search');
  setTimeout(() => nameEl.focus(), 100);
}

async function confirmSaveSearch() {
  const name   = document.getElementById('save-search-name').value.trim();
  const entity = document.getElementById('save-search-entity').value;
  if (!name) { toast('Enter a name for this filter', 'error'); return; }

  try {
    const saved = await apiPost('/saved-searches', { name, entity, filters: _pendingSaveSearchFilters });
    savedSearches.push(saved);
    renderSavedSearchChips(entity);
    closeModal('modal-save-search');
    toast(`Filter "${name}" saved`, 'success');
  } catch(e) {
    toast('Failed to save: ' + e.message, 'error');
  }
}

async function deleteSavedSearch(id) {
  try {
    await apiDelete('/saved-searches/' + id);
    const entity = savedSearches.find(s => s.id === id)?.entity;
    savedSearches = savedSearches.filter(s => s.id !== id);
    if (entity) renderSavedSearchChips(entity);
    renderSavedSearchChips('contacts');
    renderSavedSearchChips('deals');
    toast('Saved filter removed', 'success');
  } catch(e) {
    toast('Failed to remove filter', 'error');
  }
}

function applySavedSearch(id) {
  const ss = savedSearches.find(s => s.id === id);
  if (!ss) return;
  const f = ss.filters || {};

  if (ss.entity === 'contacts') {
    navigate('contacts');
    setTimeout(() => {
      const setVal = (elId, val) => { const el = document.getElementById(elId); if (el && val !== undefined) el.value = val; };
      setVal('contact-search', f.search || '');
      setVal('contact-stage-filter', f.stage || '');
      setVal('contacts-tag-filter', f.tag || '');
      setVal('contacts-health-filter', f.health || '');
      renderContacts();
    }, 100);
  } else if (ss.entity === 'deals') {
    navigate('pipeline');
    setTimeout(() => {
      const setVal = (elId, val) => { const el = document.getElementById(elId); if (el && val !== undefined) el.value = val; };
      setVal('pipeline-owner-filter', f.owner || '');
      setVal('pipeline-stage-filter', f.stage || '');
      renderPipeline();
    }, 100);
  }
}

// ── Data Export Center ───────────────────────────────────────────────────────
async function downloadExport(type, format) {
  const token = getToken();
  if (!token) { toast('Not logged in', 'error'); return; }

  const isFullBackup = (type === 'full');
  const url = isFullBackup
    ? `${API_BASE}/export/full`
    : `${API_BASE}/export/${type}${format === 'csv' ? '?format=csv' : ''}`;

  const btn = event?.target;
  if (btn) { btn.disabled = true; btn.textContent = 'Exporting...'; }

  try {
    const response = await fetch(url, {
      headers: { 'Authorization': 'Bearer ' + token }
    });
    if (!response.ok) throw new Error(`Export failed (${response.status})`);

    const blob     = await response.blob();
    const ext      = isFullBackup ? 'json' : format;
    const filename = isFullBackup
      ? `boredroom-backup-${new Date().toISOString().slice(0,10)}.json`
      : `${type}-${new Date().toISOString().slice(0,10)}.${ext}`;

    const a = document.createElement('a');
    a.href  = URL.createObjectURL(blob);
    a.download = filename;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(a.href);

    const label = isFullBackup ? 'Full backup' : (type.charAt(0).toUpperCase() + type.slice(1));
    toast(`${label} downloaded as ${ext.toUpperCase()}`, 'success');
  } catch(e) {
    toast('Export failed: ' + e.message, 'error');
  } finally {
    if (btn) {
      btn.disabled = false;
      btn.textContent = isFullBackup ? 'Download Backup' : ext.toUpperCase();
    }
  }
}

