// ══════════════════════════════════════════════════════════════════════════════
// ██████████████████████████  PHASE 18  ████████████████████████████████████████
// ══════════════════════════════════════════════════════════════════════════════

// ─────────────────────────────────────────────────────────────
// 18.1  PIPELINE FORECAST AI
// ─────────────────────────────────────────────────────────────

function computeForecastScoreLocal(deal) {
  const now   = Date.now();
  const MS_DAY = 86400000;

  // Factor 1: Freshness (0–25)
  const daysInSt = Math.max(0, (now - (deal.movedAt || deal.createdAt)) / MS_DAY);
  const freshness = Math.max(0, 1 - (daysInSt / 30)) * 25;

  // Factor 2: Engagement — activities in last 14 days (0–25)
  const since14 = now - 14 * MS_DAY;
  const recentActs = (db.activities || []).filter(a =>
    a.dealId === deal.id && new Date(a.date).getTime() > since14
  ).length;
  const engagement = Math.min(25, recentActs * 5);

  // Factor 3: Urgency — days until close date (0–25)
  let urgency = 10;
  if (deal.closeDate) {
    const daysToClose = (new Date(deal.closeDate).getTime() - now) / MS_DAY;
    if (daysToClose < 0)      urgency = 5;
    else if (daysToClose <= 7)  urgency = 25;
    else if (daysToClose <= 30) urgency = 20;
    else if (daysToClose <= 90) urgency = 15;
    else                        urgency = 8;
  }

  // Factor 4: Size fit vs. avg won deal (0–25)
  const wonDeals = (db.deals || []).filter(d => d.stage === 'Won' && d.value > 0);
  let sizeFit = 12.5;
  if (wonDeals.length > 0) {
    const avgWon = wonDeals.reduce((s, d) => s + d.value, 0) / wonDeals.length;
    const ratio  = (deal.value || 0) / avgWon;
    sizeFit = (ratio >= 0.5 && ratio <= 2.0) ? 25 : (ratio >= 0.3 && ratio <= 3.0) ? 18 : 8;
  }

  // Factor 5: Owner win rate (0–25)
  let ownerScore = 12.5;
  if (deal.owner) {
    const ownerClosed = (db.deals || []).filter(d => d.owner === deal.owner && (d.stage === 'Won' || d.stage === 'Lost'));
    if (ownerClosed.length >= 3) {
      const wins = ownerClosed.filter(d => d.stage === 'Won').length;
      ownerScore = (wins / ownerClosed.length) * 25;
    }
  }

  return Math.round(Math.min(100, Math.max(0, freshness + engagement + urgency + sizeFit + ownerScore)));
}

function forecastScoreColor(score) {
  if (score >= 70) return 'var(--green)';
  if (score >= 40) return 'var(--yellow)';
  return 'var(--red)';
}

function forecastScoreBadge(score) {
  const color = forecastScoreColor(score);
  return `<span title="AI close probability" style="font-size:9px;font-weight:700;padding:2px 6px;border-radius:10px;background:${color}22;color:${color};border:1px solid ${color}44;white-space:nowrap">AI ${score}%</span>`;
}

// Patch renderDealCard to include AI forecast badge
(function patchRenderDealCardForecast() {
  const _origCard = window.renderDealCard;
  if (typeof _origCard !== 'function') return;
  window.renderDealCard = function(d) {
    let html = _origCard.call(this, d);
    if (d.stage === 'Won' || d.stage === 'Lost') return html;
    const score = computeForecastScoreLocal(d);
    const badge = forecastScoreBadge(score);
    // Insert badge after the stage dot / name area — look for the prob% span and add after
    html = html.replace(/(<span[^>]*>\s*\d+%\s*<\/span>)/, `$1 ${badge}`);
    return html;
  };
})();

// Forecast panel injected into Reports
function renderForecastReportPanel() {
  const activeDeals = (db.deals || []).filter(d => d.stage !== 'Won' && d.stage !== 'Lost');
  const scored = activeDeals.map(d => ({ ...d, aiScore: computeForecastScoreLocal(d) }))
    .sort((a, b) => b.aiScore - a.aiScore);

  const now = new Date();
  const thisMonthKey  = `${now.getFullYear()}-${String(now.getMonth()+1).padStart(2,'0')}`;
  const nextMonthDate = new Date(now.getFullYear(), now.getMonth()+1, 1);
  const nextMonthKey  = `${nextMonthDate.getFullYear()}-${String(nextMonthDate.getMonth()+1).padStart(2,'0')}`;
  const qEnd = new Date(now.getFullYear(), Math.floor(now.getMonth()/3)*3+3, 0).toISOString().slice(0,10);

  let thisMonthExp = 0, nextMonthExp = 0, thisQtrExp = 0;
  scored.forEach(d => {
    const prob = d.aiScore / 100;
    const exp  = (d.value || 0) * prob;
    if (d.closeDate) {
      if (d.closeDate.slice(0,7) === thisMonthKey) thisMonthExp += exp;
      if (d.closeDate.slice(0,7) === nextMonthKey) nextMonthExp += exp;
      if (d.closeDate <= qEnd)                     thisQtrExp   += exp;
    }
  });

  // Trend: last 6 months won revenue
  const months = [];
  for (let i = 5; i >= 0; i--) {
    const d   = new Date(now.getFullYear(), now.getMonth()-i, 1);
    const key = `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}`;
    const won = (db.deals || []).filter(dd => dd.stage === 'Won' && dd.closeDate && dd.closeDate.startsWith(key));
    const actual = won.reduce((s, dd) => s + (dd.value||0), 0);
    months.push({ month: key, actual });
  }
  const maxVal = Math.max(...months.map(m => m.actual), thisMonthExp, nextMonthExp, 1);

  const trendBars = months.map(m => {
    const h = Math.round((m.actual / maxVal) * 80);
    const label = m.month.slice(5);
    return `<div style="display:flex;flex-direction:column;align-items:center;gap:4px;flex:1">
      <div style="font-size:9px;color:var(--text-muted)">${formatCurrency(m.actual, true)}</div>
      <div style="height:${h || 2}px;width:100%;background:var(--accent);border-radius:3px 3px 0 0;min-height:2px"></div>
      <div style="font-size:9px;color:var(--text-muted)">${label}</div>
    </div>`;
  }).join('');

  return `
    <div class="panel" style="margin-bottom:16px">
      <div class="panel-header"><div class="panel-title">Pipeline Forecast AI</div></div>
      <div style="padding:16px">
        <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin-bottom:20px">
          <div style="padding:14px;background:var(--surface2);border-radius:8px;border:1px solid var(--border)">
            <div style="font-size:10px;text-transform:uppercase;letter-spacing:0.06em;color:var(--text-muted);margin-bottom:4px">This Month Expected</div>
            <div style="font-size:22px;font-weight:700;color:var(--green)">${formatCurrency(thisMonthExp)}</div>
          </div>
          <div style="padding:14px;background:var(--surface2);border-radius:8px;border:1px solid var(--border)">
            <div style="font-size:10px;text-transform:uppercase;letter-spacing:0.06em;color:var(--text-muted);margin-bottom:4px">Next Month Expected</div>
            <div style="font-size:22px;font-weight:700;color:var(--accent)">${formatCurrency(nextMonthExp)}</div>
          </div>
          <div style="padding:14px;background:var(--surface2);border-radius:8px;border:1px solid var(--border)">
            <div style="font-size:10px;text-transform:uppercase;letter-spacing:0.06em;color:var(--text-muted);margin-bottom:4px">This Quarter Expected</div>
            <div style="font-size:22px;font-weight:700;color:var(--yellow)">${formatCurrency(thisQtrExp)}</div>
          </div>
        </div>

        <div style="margin-bottom:20px">
          <div style="font-size:11px;font-weight:600;color:var(--text-muted);margin-bottom:8px;text-transform:uppercase;letter-spacing:0.05em">Won Revenue — Last 6 Months</div>
          <div style="display:flex;align-items:flex-end;gap:4px;height:100px;border-bottom:1px solid var(--border);padding-bottom:0">
            ${trendBars}
          </div>
        </div>

        <div style="font-size:11px;font-weight:600;color:var(--text-muted);margin-bottom:8px;text-transform:uppercase;letter-spacing:0.05em">Active Deal Scores</div>
        <div style="display:flex;flex-direction:column;gap:4px;max-height:300px;overflow-y:auto">
          ${scored.length ? scored.map(d => {
            const prob = getStageProbability(d.stage);
            return `<div style="display:flex;align-items:center;gap:10px;padding:8px 10px;background:var(--surface2);border-radius:6px;border:1px solid var(--border)">
              <div style="flex:1;min-width:0">
                <div style="font-size:12px;font-weight:500;color:var(--text);overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${esc(d.name)}</div>
                <div style="font-size:10px;color:var(--text-muted)">${esc(d.stage)} · ${formatCurrency(d.value||0)}</div>
              </div>
              <div style="display:flex;align-items:center;gap:6px;flex-shrink:0">
                <div style="width:60px;height:4px;background:var(--surface3);border-radius:2px">
                  <div style="height:100%;width:${d.aiScore}%;background:${forecastScoreColor(d.aiScore)};border-radius:2px"></div>
                </div>
                ${forecastScoreBadge(d.aiScore)}
              </div>
            </div>`;
          }).join('') : '<div style="color:var(--text-muted);font-size:12px;padding:12px">No active deals in pipeline.</div>'}
        </div>
      </div>
    </div>`;
}

