// Patch generateProposalFromModal to save proposal to API for e-signature
(function patchGenerateProposalSave() {
  const _origGen = window.generateProposalFromModal;
  window.generateProposalFromModal = function() {
    const dealId    = document.getElementById('prop-deal-select')?.value || null;
    const contactId = document.getElementById('prop-contact-select')?.value || null;
    const title     = document.getElementById('prop-title')?.value?.trim() || '';
    const scope     = document.getElementById('prop-scope')?.value?.trim()  || '';
    const terms     = document.getElementById('prop-terms')?.value?.trim()  || '';
    const items     = _proposalItems ? _proposalItems.filter(i => i.description || i.rate) : [];
    const total     = items.reduce((s,i) => s + (i.qty||1)*(i.rate||0), 0);

    // Save to API first (fire and forget — don't block the window open)
    const deal    = dealId    ? (db.deals    || []).find(d => d.id === dealId)    : null;
    const contact = contactId ? (db.contacts || []).find(c => c.id === contactId) : null;
    const content = [
      scope  ? 'Scope of Work:\n' + scope   : '',
      terms  ? 'Terms:\n' + terms            : '',
      items.length ? 'Items:\n' + items.map(i => `${i.description} x${i.qty||1} @ $${i.rate||0}`).join('\n') : '',
      `Total: $${total.toLocaleString()}`,
    ].filter(Boolean).join('\n\n');

    // Save to API in background (non-blocking)
    apiPost('/proposals', {
      dealId:    dealId    || null,
      contactId: contactId || null,
      title:     title || deal?.name || 'Proposal',
      content,
      status:    'Draft',
    }).then(prop => {
      db.proposals = db.proposals || [];
      db.proposals.push(prop);
    }).catch(() => {});

    // Run original immediately (opens print window)
    if (_origGen) _origGen.call(this);
    else {
      const deal2    = dealId    ? (db.deals    || []).find(d => d.id === dealId)    : null;
      const contact2 = contactId ? (db.contacts || []).find(c => c.id === contactId) : null;
      const company2 = contact2?.company ? (db.companies||[]).find(c => c.id === contact2.company) :
                       deal2?.company    ? (db.companies||[]).find(c => c.id === deal2.company) : null;
      const profile2 = db.settings?.profile || {};
      const validUntil = document.getElementById('prop-valid-until')?.value;
      const today  = new Date().toLocaleDateString('en-US', { month:'long', day:'numeric', year:'numeric' });
      const validStr = validUntil ? new Date(validUntil).toLocaleDateString('en-US', { month:'long', day:'numeric', year:'numeric' }) : '';
      closeModal('modal-proposal');
      _doOpenProposalWindow({ deal: deal2, contact: contact2, company: company2, profile: profile2, items, total, scope, terms, title: title || deal2?.name || 'Proposal', today, validStr });
    }
  };
})();

