// Show proposals panel in deal detail (patched in after renderDealDetail runs)
async function loadProposalsForDeal(dealId) {
  // db.proposals is already loaded
  return (db.proposals || []).filter(p => p.dealId === dealId);
}

async function requestProposalSignature(proposalId, dealId) {
  try {
    const data = await apiPost(`/proposals/${proposalId}/request-signature`, {});
    // Build shareable link
    const base = window.location.origin + window.location.pathname;
    const link = `${base}#sign/${data.sigToken}`;
    // Show a toast with the link copied to clipboard
    try { await navigator.clipboard.writeText(link); toast('Signature link copied to clipboard', 'success'); }
    catch { toast('Signature link: ' + link, 'info'); }
    // Refresh proposals
    const proposals = await apiGet('/proposals');
    db.proposals = proposals;
    // Re-render deal detail if on that view
    if (dealId && currentView === 'deal-detail') renderDealDetail(dealId);
  } catch(err) {
    toast('Failed to generate signature link: ' + err.message, 'error');
  }
}

// Proposal panel HTML for deal detail
function renderProposalsPanelHTML(dealId) {
  const props = (db.proposals || []).filter(p => p.dealId === dealId);
  if (!props.length) return '';
  const rows = props.map(p => {
    const isSigned = !!p.signedAt;
    const hasToken = !!p.token && p.status === 'Awaiting Signature' && !isSigned;
    const statusColor = isSigned ? 'var(--green)' : p.status === 'Awaiting Signature' ? 'var(--yellow)' : 'var(--text-muted)';
    return `<div style="display:flex;align-items:center;gap:8px;padding:8px 10px;background:var(--surface2);border:1px solid var(--border);border-radius:6px;margin-bottom:6px">
      <div style="flex:1;min-width:0">
        <div style="font-size:12px;font-weight:500;color:var(--text)">${esc(p.title||'Proposal')}</div>
        <div style="font-size:10px;color:${statusColor};margin-top:2px">${esc(p.status||'Draft')}</div>
        ${isSigned ? `<div style="font-size:10px;color:var(--green)">Signed ${formatDate(p.signedAt)}</div>` : ''}
      </div>
      ${isSigned
        ? `<span style="font-size:10px;font-weight:600;color:var(--green);padding:2px 8px;border-radius:10px;background:#22c55e22;border:1px solid #22c55e44">Signed</span>`
        : `<button class="btn btn-secondary btn-xs" onclick="requestProposalSignature('${p.id}','${dealId}')">Request Signature</button>`}
    </div>`;
  }).join('');

  return `<div class="panel" style="margin-top:12px">
    <div class="panel-header">
      <div class="panel-title">Proposals</div>
      <span class="panel-count">${props.length}</span>
    </div>
    <div style="padding:10px 12px">${rows}</div>
  </div>`;
}

// Patch renderDealDetail to add proposals panel
(function patchRenderDealDetailProposals() {
  const _orig2 = window.renderDealDetail;
  window.renderDealDetail = function(id) {
    _orig2.call(this, id);
    setTimeout(() => {
      const el = document.getElementById('view-deal-detail');
      if (!el) return;
      const leftCol = el.querySelector('.contact-detail-left');
      if (!leftCol) return;
      const html = renderProposalsPanelHTML(id);
      if (html && !leftCol.querySelector('#proposals-panel')) {
        const div = document.createElement('div');
        div.id = 'proposals-panel';
        div.innerHTML = html;
        leftCol.appendChild(div);
      }
    }, 50);
  };
})();

// Signature page renderer
function renderSignaturePage(token) {
  const el = document.getElementById('view-sign');
  if (!el) return;

  el.innerHTML = `<div style="display:flex;align-items:center;justify-content:center;height:100%;padding:24px">
    <div style="text-align:center;color:var(--text-muted)">Loading proposal...</div>
  </div>`;

  // Fetch proposal (public endpoint, no auth required)
  fetch(`${API_BASE}/proposals/sign/${token}`)
    .then(r => r.json())
    .then(prop => {
      if (prop.error) {
        el.innerHTML = `<div style="display:flex;align-items:center;justify-content:center;height:100%;flex-direction:column;gap:12px;padding:40px;text-align:center">
          <div style="font-size:28px;font-weight:700;color:var(--red)">Invalid Link</div>
          <div style="color:var(--text-muted)">This signature link is invalid or has expired.</div>
        </div>`;
        return;
      }

      const alreadySigned = !!prop.signedAt;

      el.innerHTML = `
        <div style="max-width:680px;margin:0 auto;padding:32px 20px">
          <div style="text-align:center;margin-bottom:28px">
            <div style="font-size:22px;font-weight:700;color:var(--accent)">BoredRoom CRM</div>
            <div style="font-size:12px;color:var(--text-muted)">Document Signature</div>
          </div>

          <div class="panel" style="margin-bottom:16px">
            <div class="panel-header"><div class="panel-title">${esc(prop.title || 'Proposal')}</div></div>
            <div style="padding:16px">
              ${prop.contact ? `<div style="font-size:13px;color:var(--text-muted);margin-bottom:8px">Prepared for: <strong style="color:var(--text)">${esc(prop.contact.name)}</strong></div>` : ''}
              ${prop.deal    ? `<div style="font-size:13px;color:var(--text-muted);margin-bottom:8px">Deal: <strong style="color:var(--text)">${esc(prop.deal.name)}</strong>${prop.deal.value ? ` — ${formatCurrency(prop.deal.value)}` : ''}</div>` : ''}
              ${prop.content ? `<div style="margin-top:12px;padding-top:12px;border-top:1px solid var(--border);font-size:13px;color:var(--text-dim);line-height:1.6;white-space:pre-wrap">${esc(prop.content)}</div>` : ''}
            </div>
          </div>

          ${alreadySigned ? `
            <div class="panel" style="border:2px solid var(--green)">
              <div style="padding:20px;text-align:center">
                <div style="font-size:18px;font-weight:700;color:var(--green);margin-bottom:4px">Signed</div>
                <div style="font-size:12px;color:var(--text-muted)">Signed on ${new Date(prop.signedAt).toLocaleDateString('en-US',{month:'long',day:'numeric',year:'numeric'})}</div>
                ${prop.signatureData ? `<div style="margin-top:12px;border:1px solid var(--border);border-radius:8px;overflow:hidden;display:inline-block"><img src="${prop.signatureData}" style="max-width:240px;height:80px;display:block" /></div>` : ''}
              </div>
            </div>` : `
            <div class="panel">
              <div class="panel-header"><div class="panel-title">Sign Below</div></div>
              <div style="padding:16px">
                <div style="font-size:12px;color:var(--text-muted);margin-bottom:10px">Draw your signature in the box below. Use your mouse or finger to sign.</div>
                <div style="position:relative;border:2px solid var(--border);border-radius:8px;overflow:hidden;background:#fff;margin-bottom:12px">
                  <canvas id="sig-canvas" width="640" height="160" style="display:block;width:100%;touch-action:none;cursor:crosshair"></canvas>
                  <button onclick="clearSignatureCanvas()" style="position:absolute;top:6px;right:6px;font-size:10px;padding:3px 8px;border:1px solid var(--border);border-radius:4px;background:var(--surface2);color:var(--text-muted);cursor:pointer">Clear</button>
                </div>
                <div style="font-size:11px;color:var(--text-muted);margin-bottom:16px">By clicking "Submit Signature" you agree to the terms set forth in this proposal.</div>
                <button class="btn btn-primary" style="width:100%" onclick="submitSignature('${token}')">Submit Signature</button>
              </div>
            </div>`}

          <div style="text-align:center;margin-top:20px;font-size:11px;color:var(--text-muted)">
            Powered by BoredRoom CRM
          </div>
        </div>`;

      if (!alreadySigned) initSignatureCanvas();
    })
    .catch(() => {
      el.innerHTML = `<div style="display:flex;align-items:center;justify-content:center;height:100%;flex-direction:column;gap:12px;padding:40px">
        <div style="font-size:18px;font-weight:700;color:var(--red)">Connection Error</div>
        <div style="color:var(--text-muted)">Could not load proposal. Please try again.</div>
      </div>`;
    });
}

let _sigCanvas = null, _sigCtx = null, _sigDrawing = false;

function initSignatureCanvas() {
  _sigCanvas = document.getElementById('sig-canvas');
  if (!_sigCanvas) return;
  _sigCtx = _sigCanvas.getContext('2d');
  _sigCtx.strokeStyle = '#111';
  _sigCtx.lineWidth = 2;
  _sigCtx.lineCap = 'round';
  _sigCtx.lineJoin = 'round';

  function getPos(e) {
    const r = _sigCanvas.getBoundingClientRect();
    const sx = _sigCanvas.width / r.width;
    const sy = _sigCanvas.height / r.height;
    const cl = e.touches ? e.touches[0] : e;
    return { x: (cl.clientX - r.left) * sx, y: (cl.clientY - r.top) * sy };
  }

  _sigCanvas.addEventListener('mousedown',  e => { _sigDrawing = true; _sigCtx.beginPath(); const p = getPos(e); _sigCtx.moveTo(p.x, p.y); });
  _sigCanvas.addEventListener('mousemove',  e => { if (!_sigDrawing) return; const p = getPos(e); _sigCtx.lineTo(p.x, p.y); _sigCtx.stroke(); });
  _sigCanvas.addEventListener('mouseup',    () => { _sigDrawing = false; });
  _sigCanvas.addEventListener('mouseleave', () => { _sigDrawing = false; });
  _sigCanvas.addEventListener('touchstart', e => { e.preventDefault(); _sigDrawing = true; _sigCtx.beginPath(); const p = getPos(e); _sigCtx.moveTo(p.x, p.y); }, { passive: false });
  _sigCanvas.addEventListener('touchmove',  e => { e.preventDefault(); if (!_sigDrawing) return; const p = getPos(e); _sigCtx.lineTo(p.x, p.y); _sigCtx.stroke(); }, { passive: false });
  _sigCanvas.addEventListener('touchend',   () => { _sigDrawing = false; });
}

function clearSignatureCanvas() {
  if (!_sigCtx || !_sigCanvas) return;
  _sigCtx.clearRect(0, 0, _sigCanvas.width, _sigCanvas.height);
}

async function submitSignature(token) {
  if (!_sigCanvas) { toast('Signature canvas not found', 'error'); return; }
  // Check if anything was drawn
  const blank = document.createElement('canvas');
  blank.width  = _sigCanvas.width;
  blank.height = _sigCanvas.height;
  if (_sigCanvas.toDataURL() === blank.toDataURL()) {
    toast('Please draw your signature before submitting', 'error');
    return;
  }
  const signatureData = _sigCanvas.toDataURL('image/png');
  try {
    await fetch(`${API_BASE}/proposals/sign/${token}`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ signatureData }),
    }).then(r => r.json());
    // Re-render signed state
    renderSignaturePage(token);
    toast('Signature submitted successfully', 'success');
  } catch(err) {
    toast('Failed to submit signature: ' + err.message, 'error');
  }
}

// Handle #sign/TOKEN links in the URL hash
(function handleSignRoute() {
  function checkHash() {
    const hash = window.location.hash;
    if (hash && hash.startsWith('#sign/')) {
      const token = hash.slice(6);
      navigate('sign', token);
    }
  }
  window.addEventListener('hashchange', checkHash);
  // check on load (after app is ready)
  document.addEventListener('DOMContentLoaded', () => setTimeout(checkHash, 1200));
})();

// ─────────────────────────────────────────────────────────────
// 18.3  BULK TASK ASSIGNMENT
// ─────────────────────────────────────────────────────────────

let _selectedTaskIds = new Set();

// Patch renderTasks to add checkboxes and selection tracking
(function patchRenderTasksBulk() {
  const _origTasks = window.renderTasks;
  window.renderTasks = function() {
    // Reset selection on full re-render
    _selectedTaskIds = new Set();
    updateBulkTaskBar();
    _origTasks.call(this);

    // Inject checkboxes into task items
    setTimeout(() => {
      document.querySelectorAll('#tasks-list .task-item').forEach(item => {
        // Get the task id from any button onclick in this item
        const doneBtn = item.querySelector('button');
        if (!doneBtn) return;
        const onclickStr = doneBtn.getAttribute('onclick') || '';
        const m = onclickStr.match(/markTaskDone\('([^']+)'\)/);
        if (!m) return;
        const taskId = m[1];
        item.dataset.taskId = taskId;

        // Add checkbox at start
        if (!item.querySelector('.task-check')) {
          const cb = document.createElement('input');
          cb.type = 'checkbox';
          cb.className = 'task-check';
          cb.style.cssText = 'width:14px;height:14px;cursor:pointer;flex-shrink:0;margin-right:2px';
          cb.checked = _selectedTaskIds.has(taskId);
          cb.onchange = () => {
            if (cb.checked) _selectedTaskIds.add(taskId);
            else _selectedTaskIds.delete(taskId);
            updateBulkTaskBar();
          };
          item.insertBefore(cb, item.firstChild);
        }
      });
    }, 20);
  };
})();

function updateBulkTaskBar() {
  let bar = document.getElementById('bulk-task-bar');
  if (_selectedTaskIds.size === 0) {
    if (bar) bar.style.display = 'none';
    return;
  }
  if (!bar) {
    bar = document.createElement('div');
    bar.id = 'bulk-task-bar';
    document.body.appendChild(bar);
  }
  bar.style.cssText = 'position:fixed;bottom:24px;left:50%;transform:translateX(-50%);background:var(--surface2);border:1px solid var(--border);border-radius:12px;padding:10px 20px;display:flex;align-items:center;gap:12px;box-shadow:0 8px 32px rgba(0,0,0,0.4);z-index:1000;white-space:nowrap';
  bar.innerHTML = `
    <span style="font-size:13px;font-weight:600;color:var(--text)">${_selectedTaskIds.size} task${_selectedTaskIds.size===1?'':'s'} selected</span>
    <button class="btn btn-secondary btn-sm" onclick="openBulkTaskAssignModal()">Assign Selected</button>
    <button class="btn btn-secondary btn-sm" onclick="bulkCompleteTasks()">Mark Complete</button>
    <button class="btn btn-danger btn-sm" onclick="bulkDeleteTasks()">Delete</button>
    <button class="btn btn-ghost btn-sm" onclick="_selectedTaskIds=new Set();updateBulkTaskBar();renderTasks()">Clear</button>`;
}

async function openBulkTaskAssignModal() {
  const countEl = document.getElementById('bulk-task-assign-count');
  if (countEl) countEl.textContent = `Assigning ${_selectedTaskIds.size} task${_selectedTaskIds.size===1?'':'s'}`;

  const ownerSel = document.getElementById('bulk-task-assign-owner');
  if (ownerSel) {
    ownerSel.innerHTML = '<option value="">Select team member...</option>';
    try {
      const users = await apiGet('/users');
      users.forEach(u => {
        const opt = document.createElement('option');
        opt.value = u.name;
        opt.textContent = `${u.name} (${u.role})`;
        ownerSel.appendChild(opt);
      });
    } catch {
      // Non-admin can't list users — add current user as option
      if (_currentUser) {
        const opt = document.createElement('option');
        opt.value = _currentUser.name;
        opt.textContent = _currentUser.name;
        ownerSel.appendChild(opt);
      }
    }
  }

  const dueEl = document.getElementById('bulk-task-assign-due');
  if (dueEl) dueEl.value = '';

  openModal('modal-bulk-task-assign');
}

async function executeBulkAssign() {
  const ids = Array.from(_selectedTaskIds);
  const owner = document.getElementById('bulk-task-assign-owner')?.value;
  const dueDate = document.getElementById('bulk-task-assign-due')?.value || null;

  if (!owner) { toast('Please select a team member', 'error'); return; }

  try {
    await apiPost('/tasks/bulk-assign', { ids, assignedOwner: owner, dueDate });
    // Update local db
    ids.forEach(id => {
      const t = (db.tasks||[]).find(t => t.id === id);
      if (t) { t.assignedOwner = owner; if (dueDate) t.dueDate = dueDate; }
    });
    closeModal('modal-bulk-task-assign');
    _selectedTaskIds = new Set();
    updateBulkTaskBar();
    renderTasks();
    toast(`Assigned ${ids.length} task${ids.length===1?'':'s'} to ${owner}`, 'success');
  } catch(err) {
    toast('Bulk assign failed: ' + err.message, 'error');
  }
}

async function bulkCompleteTasks() {
  const ids = Array.from(_selectedTaskIds);
  if (!ids.length) return;
  if (!confirm(`Mark ${ids.length} task${ids.length===1?'':'s'} as complete?`)) return;
  try {
    await apiPost('/tasks/bulk-complete', { ids });
    ids.forEach(id => {
      const t = (db.tasks||[]).find(t => t.id === id);
      if (t) t.status = 'Done';
    });
    _selectedTaskIds = new Set();
    updateBulkTaskBar();
    renderTasks();
    updateTasksBadge();
    toast(`${ids.length} task${ids.length===1?'':'s'} marked complete`, 'success');
  } catch(err) {
    toast('Bulk complete failed: ' + err.message, 'error');
  }
}

async function bulkDeleteTasks() {
  const ids = Array.from(_selectedTaskIds);
  if (!ids.length) return;
  if (!confirm(`Delete ${ids.length} task${ids.length===1?'':'s'}? This cannot be undone.`)) return;
  try {
    await apiPost('/tasks/bulk-delete', { ids });
    db.tasks = (db.tasks||[]).filter(t => !ids.includes(t.id));
    _selectedTaskIds = new Set();
    updateBulkTaskBar();
    renderTasks();
    updateTasksBadge();
    toast(`${ids.length} task${ids.length===1?'':'s'} deleted`, 'info');
  } catch(err) {
    toast('Bulk delete failed: ' + err.message, 'error');
  }
}

