// Load email logs from API
async function loadEmailLogs() {
  try {
    const logs = await apiGet('/email-logs');
    db.emailLogs = logs || [];
  } catch { db.emailLogs = []; }
}

function openEmailLogModal(contactId) {
  document.getElementById('email-log-id').value        = '';
  document.getElementById('email-log-contact-id').value = contactId || '';
  document.getElementById('email-log-subject').value   = '';
  document.getElementById('email-log-direction').value = 'outbound';
  document.getElementById('email-log-date').value      = new Date().toISOString().slice(0,10);
  document.getElementById('email-log-body').value      = '';
  openModal('modal-email-log');
}

async function saveEmailLog() {
  const subject   = document.getElementById('email-log-subject').value.trim();
  const contactId = document.getElementById('email-log-contact-id').value;
  if (!subject) { toast('Subject is required', 'error'); return; }

  const payload = {
    contactId: contactId || null,
    subject,
    body:      document.getElementById('email-log-body').value.trim(),
    direction: document.getElementById('email-log-direction').value,
    date:      document.getElementById('email-log-date').value || new Date().toISOString().slice(0,10),
  };

  try {
    const logId = document.getElementById('email-log-id').value;
    const log = logId
      ? await apiPut(`/email-logs/${logId}`, payload)
      : await apiPost('/email-logs', payload);

    db.emailLogs = db.emailLogs || [];
    if (logId) {
      const idx = db.emailLogs.findIndex(l => l.id === logId);
      if (idx >= 0) db.emailLogs[idx] = log;
    } else {
      db.emailLogs.push(log);
    }

    closeModal('modal-email-log');
    toast('Email logged', 'success');
    if (currentView === 'contact-detail' && contactId) renderContactDetail(contactId);
  } catch(err) {
    toast('Failed to save: ' + err.message, 'error');
  }
}

async function deleteEmailLog(id, contactId) {
  if (!confirm('Delete this email log?')) return;
  try {
    await apiDelete(`/email-logs/${id}`);
    db.emailLogs = (db.emailLogs || []).filter(l => l.id !== id);
    toast('Email log deleted', 'info');
    if (currentView === 'contact-detail' && contactId) renderContactDetail(contactId);
  } catch(err) {
    toast('Delete failed: ' + err.message, 'error');
  }
}

// Patch renderContactDetail to add email log tab + button + timeline entries
