// ─────────────────────────────────────────────────────────────
// 18.A  forecastPipeline() — Pipeline-view forecast panel
//        Calls /api/forecast/deals, injects scores into kanban
// ─────────────────────────────────────────────────────────────
async function forecastPipeline() {
  let scored = [];
  try {
    scored = await apiGet('/forecast/deals');
  } catch {
    // Fall back to local computation
    scored = (db.deals || [])
      .filter(d => d.stage !== 'Won' && d.stage !== 'Lost')
      .map(d => ({ ...d, forecastScore: computeForecastScoreLocal(d) }));
  }

  // Build a lookup: dealId → forecastScore
  const scoreMap = {};
  scored.forEach(d => { scoreMap[d.id] = d.forecastScore ?? d.aiScore ?? 0; });

  // Overlay forecast badges on every deal card currently rendered
  document.querySelectorAll('.deal-card').forEach(card => {
    const btn = card.querySelector('button, [onclick]') || card;
    const m = (card.getAttribute('onclick') || card.querySelector('[onclick]')?.getAttribute('onclick') || '').match(/showDealDetail\('([^']+)'\)/);
    if (!m) return;
    const id    = m[1];
    const score = scoreMap[id];
    if (score === undefined) return;
    if (!card.querySelector('.pipeline-forecast-badge')) {
      const badge = document.createElement('span');
      badge.className = 'pipeline-forecast-badge';
      badge.title = 'AI Forecast Score';
      badge.style.cssText = `font-size:9px;font-weight:700;padding:2px 6px;border-radius:10px;background:${forecastScoreColor(score)}22;color:${forecastScoreColor(score)};border:1px solid ${forecastScoreColor(score)}44;white-space:nowrap;display:inline-block;margin-top:3px`;
      badge.textContent = `AI ${score}%`;
      card.appendChild(badge);
    }
  });

  // Inject / update a "Forecast Summary" panel above the kanban board
  const board = document.getElementById('pipeline-board');
  if (!board) return;
  const pipelineEl = document.getElementById('view-pipeline');
  if (!pipelineEl) return;

  let summaryBar = document.getElementById('pipeline-forecast-bar');
  if (!summaryBar) {
    summaryBar = document.createElement('div');
    summaryBar.id = 'pipeline-forecast-bar';
    summaryBar.style.cssText = 'display:flex;gap:10px;padding:10px 16px;flex-wrap:wrap;border-bottom:1px solid var(--border);background:var(--surface2);align-items:center';
    board.parentElement.insertBefore(summaryBar, board);
  }

  const totalPipeline = scored.reduce((s, d) => s + (d.value || 0), 0);
  const totalWeighted = scored.reduce((s, d) => s + (d.value || 0) * ((d.forecastScore ?? d.aiScore ?? 50) / 100), 0);
  const highConf      = scored.filter(d => (d.forecastScore ?? d.aiScore ?? 0) >= 70).length;

  summaryBar.innerHTML = `
    <span style="font-size:11px;font-weight:700;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.06em;margin-right:4px">AI Forecast</span>
    <div style="display:flex;gap:8px;flex-wrap:wrap">
      <span style="font-size:12px;background:var(--surface3);border:1px solid var(--border);border-radius:6px;padding:3px 10px">
        Pipeline: <strong style="color:var(--text)">${formatCurrency(totalPipeline)}</strong>
      </span>
      <span style="font-size:12px;background:var(--surface3);border:1px solid var(--border);border-radius:6px;padding:3px 10px">
        Weighted: <strong style="color:var(--green)">${formatCurrency(totalWeighted)}</strong>
      </span>
      <span style="font-size:12px;background:var(--surface3);border:1px solid var(--border);border-radius:6px;padding:3px 10px">
        High-conf deals: <strong style="color:var(--accent)">${highConf}</strong>
      </span>
      <button class="btn btn-ghost btn-sm" onclick="forecastPipeline()" style="font-size:10px">↻ Refresh</button>
    </div>`;
}

