// ─────────────────────────────────────────────────────────────
// 18.D  renderEmailLog(contactId, containerEl) — standalone renderer
//        Renders email log entries into a given container.
//        Falls back to fetching from API if db.emailLogs not populated.
// ─────────────────────────────────────────────────────────────
async function renderEmailLog(contactId, containerEl) {
  if (!containerEl) {
    containerEl = document.getElementById('contact-email-panel') ||
                  document.getElementById('email-log-container');
  }
  if (!containerEl) {
    console.warn('renderEmailLog: no container element found');
    return;
  }

  // Try to load fresh from API (contact-specific query)
  let logs = [];
  try {
    logs = await apiGet(`/email-logs?contactId=${encodeURIComponent(contactId)}`);
  } catch {
    // Fall back to cached db
    logs = (db.emailLogs || []).filter(l => l.contactId === contactId);
  }
  logs = logs.sort((a, b) => new Date(b.date) - new Date(a.date));

  const dirLabel = dir =>
    dir === 'inbound'
      ? '<span style="color:var(--green);font-weight:500">Inbound</span>'
      : '<span style="color:var(--accent);font-weight:500">Outbound</span>';

  containerEl.innerHTML = `
    <div class="panel-header">
      <div class="panel-title">Email Log</div>
      <span class="panel-count">${logs.length}</span>
      <button class="btn btn-secondary btn-sm panel-action" onclick="openEmailLogModal('${contactId}')">+ Log Email</button>
    </div>
    <div style="max-height:340px;overflow-y:auto" id="email-log-list-${contactId}">
      ${logs.length ? logs.map(l => `
        <div class="email-log-entry" data-log-id="${l.id}" style="padding:10px 14px;border-bottom:1px solid var(--border)">
          <div style="display:flex;align-items:flex-start;gap:8px">
            <div style="flex:1;min-width:0">
              <div style="font-size:12px;font-weight:500;color:var(--text)">${esc(l.subject)}</div>
              <div style="font-size:10px;color:var(--text-muted);margin-top:2px">
                ${dirLabel(l.direction)} · ${formatDate(l.date)}
              </div>
              ${l.body ? `<div style="font-size:11px;color:var(--text-dim);margin-top:4px;line-height:1.5">${esc(l.body.slice(0, 140))}${l.body.length > 140 ? '…' : ''}</div>` : ''}
            </div>
            <div style="display:flex;gap:4px;flex-shrink:0">
              <button class="btn btn-ghost btn-xs" title="Edit"
                onclick="(function(){
                  document.getElementById('email-log-id').value='${l.id}';
                  document.getElementById('email-log-contact-id').value='${l.contactId||''}';
                  document.getElementById('email-log-subject').value='${esc(l.subject).replace(/'/g,'\\\'')}';
                  document.getElementById('email-log-direction').value='${l.direction||'outbound'}';
                  document.getElementById('email-log-date').value='${l.date||''}';
                  document.getElementById('email-log-body').value=\`${(l.body||'').replace(/`/g,'\\`')}\`;
                  openModal('modal-email-log');
                })()" style="opacity:0.6;padding:2px 5px">
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" width="11" height="11"><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"/></svg>
              </button>
              <button class="btn btn-ghost btn-xs" title="Delete"
                onclick="deleteEmailLog('${l.id}','${contactId}')" style="opacity:0.5;padding:2px 5px">
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" width="11" height="11"><polyline points="3,6 5,6 21,6"/><path d="M19,6l-1,14a2,2,0,0,1-2,2H8a2,2,0,0,1-2-2L5,6"/></svg>
              </button>
            </div>
          </div>
        </div>`).join('')
      : `<div class="empty-state" style="padding:24px">
           <div class="empty-state-title">No emails logged</div>
           <div class="empty-state-sub">Click "+ Log Email" to record a sent or received email</div>
         </div>`}
    </div>`;

  // Re-sync db cache
  if (contactId) {
    db.emailLogs = db.emailLogs || [];
    logs.forEach(l => {
      const idx = db.emailLogs.findIndex(x => x.id === l.id);
      if (idx >= 0) db.emailLogs[idx] = l; else db.emailLogs.push(l);
    });
  }
}

// Re-patch renderContactDetail to use the new renderEmailLog function
(function repatchContactDetailWithRenderEmailLog() {
  const _origCD2 = window.renderContactDetail;
  window.renderContactDetail = function(id) {
    _origCD2.call(this, id);
    setTimeout(() => {
      const contact = (db.contacts || []).find(c => c.id === id);
      if (!contact) return;
      const el = document.getElementById('view-contact-detail');
      if (!el) return;

      // Ensure "Log Email" button in header
      const headerActions = el.querySelector('.header-actions');
      if (headerActions && !headerActions.querySelector('[data-email-log2]')) {
        const btn = document.createElement('button');
        btn.className = 'btn btn-secondary';
        btn.setAttribute('data-email-log2', '1');
        btn.textContent = '📧 Log Email';
        btn.onclick = () => openEmailLogModal(id);
        headerActions.insertBefore(btn, headerActions.firstChild);
      }

      // Create or refresh the email log panel
      const rightCol = el.querySelector('.contact-detail-right') || el;
      let emailPanel = rightCol.querySelector('#contact-email-panel-v2');
      if (!emailPanel) {
        emailPanel = document.createElement('div');
        emailPanel.id = 'contact-email-panel-v2';
        emailPanel.className = 'panel';
        emailPanel.style.marginBottom = '16px';
        const firstPanel = rightCol.querySelector('.panel');
        if (firstPanel) rightCol.insertBefore(emailPanel, firstPanel.nextSibling);
        else rightCol.appendChild(emailPanel);
      }
      renderEmailLog(id, emailPanel);
    }, 60);
  };
})();

// Patch deleteEmailLog to re-render email log panel after deletion
(function patchDeleteEmailLogRefresh() {
  const _origDel = window.deleteEmailLog;
  window.deleteEmailLog = async function(id, contactId) {
    await _origDel.call(this, id, contactId);
    // Refresh the v2 panel if visible
    const panel = document.getElementById('contact-email-panel-v2');
    if (panel && contactId) renderEmailLog(contactId, panel);
  };
})();

// Patch saveEmailLog to re-render email log panel after save
(function patchSaveEmailLogRefresh() {
  const _origSave = window.saveEmailLog;
  window.saveEmailLog = async function() {
    const contactId = document.getElementById('email-log-contact-id')?.value;
    await _origSave.call(this);
    const panel = document.getElementById('contact-email-panel-v2');
    if (panel && contactId) setTimeout(() => renderEmailLog(contactId, panel), 100);
  };
})();

