// ─────────────────────────────────────────────────────────────────────────────
// 19.A  IN-APP NOTIFICATION CENTER
// ─────────────────────────────────────────────────────────────────────────────

let _notifOpen = false;
let _notifPollTimer = null;

async function toggleNotifCenter() {
  if (_notifOpen) {
    closeNotifCenter();
  } else {
    _notifOpen = true;
    const drawer = document.getElementById('notif-drawer');
    const overlay = document.getElementById('notif-overlay');
    if (drawer)  { drawer.classList.add('open'); }
    if (overlay) { overlay.style.display = ''; }
    await loadNotifications();
  }
}

function closeNotifCenter() {
  _notifOpen = false;
  const drawer = document.getElementById('notif-drawer');
  const overlay = document.getElementById('notif-overlay');
  if (drawer)  drawer.classList.remove('open');
  if (overlay) overlay.style.display = 'none';
}

async function loadNotifications() {
  let notifs = [];
  try {
    notifs = await apiGet('/notifications?limit=50');
  } catch(e) {
    console.warn('Notifications load failed', e);
  }
  renderNotifList(notifs);
  return notifs;
}

function renderNotifList(notifs) {
  const el = document.getElementById('notif-drawer-list');
  if (!el) return;
  if (!notifs || !notifs.length) {
    el.innerHTML = '<div style="padding:28px;text-align:center;color:var(--text-muted);font-size:13px">No notifications</div>';
    return;
  }
  el.innerHTML = notifs.map(n => {
    const ago = timeAgo(n.createdAt);
    const unreadCls = n.read ? '' : 'notif-item-unread';
    const icon = notifIcon(n.type);
    return `<div class="notif-item ${unreadCls}" data-notif-id="${n.id}" onclick="handleNotifClick('${n.id}','${n.entityType||''}','${n.entityId||''}')">
      <div style="display:flex;gap:10px;align-items:flex-start">
        <div class="notif-item-icon">${icon}</div>
        <div style="flex:1;min-width:0">
          <div style="font-size:12px;color:var(--text);line-height:1.4">${esc(n.message)}</div>
          <div style="font-size:10px;color:var(--text-muted);margin-top:3px">${ago}</div>
        </div>
        ${!n.read ? '<div style="width:7px;height:7px;border-radius:50%;background:var(--accent);flex-shrink:0;margin-top:4px"></div>' : ''}
      </div>
    </div>`;
  }).join('');
}

function notifIcon(type) {
  const icons = {
    deal_created:   '<svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="var(--green)" stroke-width="2" stroke-linecap="round"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="16"/><line x1="8" y1="12" x2="16" y2="12"/></svg>',
    deal_won:       '<svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="var(--accent)" stroke-width="2" stroke-linecap="round"><polyline points="20 6 9 17 4 12"/></svg>',
    deal_stage:     '<svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="var(--text-muted)" stroke-width="2" stroke-linecap="round"><polyline points="5 12 12 5 19 12"/></svg>',
    task_assigned:  '<svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="#f59e0b" stroke-width="2" stroke-linecap="round"><polyline points="9 11 12 14 22 4"/><path d="M21 12v7a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11"/></svg>',
    task_overdue:   '<svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="#ef4444" stroke-width="2" stroke-linecap="round"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>',
    invoice_overdue:'<svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="#ef4444" stroke-width="2" stroke-linecap="round"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14,2 14,8 20,8"/></svg>',
    renewal_due:    '<svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="#f59e0b" stroke-width="2" stroke-linecap="round"><path d="M23 4v6h-6"/><path d="M1 20v-6h6"/></svg>',
    contact_merged: '<svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="var(--text-muted)" stroke-width="2" stroke-linecap="round"><path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/></svg>',
  };
  return icons[type] || '<svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="var(--text-muted)" stroke-width="2" stroke-linecap="round"><circle cx="12" cy="12" r="10"/></svg>';
}

async function handleNotifClick(notifId, entityType, entityId) {
  // Mark as read
  try { await apiPatch('/notifications/' + notifId + '/read', {}); } catch {}
  // Update local badge
  updateNotifBadge();
  // Navigate to entity
  if (entityType === 'deal' && entityId) { closeNotifCenter(); navigate('deal-detail', entityId); }
  else if (entityType === 'contact' && entityId) { closeNotifCenter(); navigate('contact-detail', entityId); }
  else if (entityType === 'task') { closeNotifCenter(); navigate('tasks'); }
  else if (entityType === 'invoice') { closeNotifCenter(); navigate('invoices'); }
  else if (entityType === 'renewal') { closeNotifCenter(); navigate('renewals'); }
  // Update row styling
  const row = document.querySelector(`[data-notif-id="${notifId}"]`);
  if (row) row.classList.remove('notif-item-unread');
}

async function markAllNotifsRead() {
  try { await apiPost('/notifications/mark-all-read', {}); } catch {}
  updateNotifBadge();
  document.querySelectorAll('.notif-item-unread').forEach(el => el.classList.remove('notif-item-unread'));
  document.querySelectorAll('[data-notif-id] > div > div:last-child').forEach(el => {
    if (el.style.background) el.remove();
  });
  loadNotifications();
}

async function updateNotifBadge() {
  try {
    const { count } = await apiGet('/notifications/unread-count');
    const badge = document.getElementById('notif-badge');
    if (!badge) return;
    if (count > 0) {
      badge.textContent = count > 99 ? '99+' : count;
      badge.style.display = '';
    } else {
      badge.style.display = 'none';
    }
  } catch {}
}

// Poll for unread count every 60s while page is open
function startNotifPolling() {
  updateNotifBadge();
  if (_notifPollTimer) clearInterval(_notifPollTimer);
  _notifPollTimer = setInterval(updateNotifBadge, 60000);
}

// Helper: apiPatch (uses existing auth mechanism)
if (typeof apiPatch !== 'function') {
  window.apiPatch = function(path, body) { return apiRequest('PATCH', path, body); };
}

function timeAgo(ts) {
  if (!ts) return '';
  const diff = Date.now() - (typeof ts === 'number' ? ts : new Date(ts).getTime());
  const m = Math.floor(diff / 60000);
  if (m < 1) return 'just now';
  if (m < 60) return `${m}m ago`;
  const h = Math.floor(m / 60);
  if (h < 24) return `${h}h ago`;
  const d = Math.floor(h / 24);
  return `${d}d ago`;
}

