let _webhooks = [];

async function loadWebhooks() {
  try {
    _webhooks = await apiGet('/webhooks');
  } catch(e) {
    _webhooks = [];
    console.warn('Webhooks load failed', e);
  }
  renderWebhooksList();
}

function renderWebhooksList() {
  const el = document.getElementById('webhooks-list');
  if (!el) return;
  if (!_webhooks.length) {
    el.innerHTML = '<div style="color:var(--text-muted);font-size:12px;padding:8px">No webhooks configured yet.</div>';
    return;
  }
  el.innerHTML = `<table style="width:100%;border-collapse:collapse;font-size:12px">
    <thead><tr>
      <th style="text-align:left;padding:6px 8px;color:var(--text-muted);font-weight:500;border-bottom:1px solid var(--border)">URL</th>
      <th style="text-align:left;padding:6px 8px;color:var(--text-muted);font-weight:500;border-bottom:1px solid var(--border)">Events</th>
      <th style="text-align:center;padding:6px 8px;color:var(--text-muted);font-weight:500;border-bottom:1px solid var(--border)">Active</th>
      <th style="padding:6px 8px;border-bottom:1px solid var(--border)"></th>
    </tr></thead>
    <tbody>${_webhooks.map(wh => `
      <tr style="border-bottom:1px solid var(--border)">
        <td style="padding:8px;max-width:220px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;color:var(--accent)">${esc(wh.url)}</td>
        <td style="padding:8px;color:var(--text-dim)">${(wh.events||[]).join(', ') || '<span style="color:var(--text-muted)">none</span>'}</td>
        <td style="padding:8px;text-align:center">
          <span style="display:inline-block;width:8px;height:8px;border-radius:50%;background:${wh.active ? 'var(--green)' : 'var(--text-muted)'}"></span>
        </td>
        <td style="padding:8px;text-align:right;white-space:nowrap">
          <button class="btn btn-ghost btn-xs" onclick="openWebhookModal('${wh.id}')" style="margin-right:4px">Edit</button>
          <button class="btn btn-ghost btn-xs" onclick="deleteWebhook('${wh.id}')" style="opacity:0.6">Delete</button>
        </td>
      </tr>`).join('')}
    </tbody>
  </table>`;
}

function openWebhookModal(id) {
  const wh = id ? _webhooks.find(w => w.id === id) : null;
  document.getElementById('webhook-edit-id').value = id || '';
  document.getElementById('webhook-modal-title').textContent = id ? 'Edit Webhook' : 'Add Webhook';
  document.getElementById('webhook-url').value = wh ? wh.url : '';
  document.getElementById('webhook-active').checked = wh ? wh.active : true;
  const testBtn = document.getElementById('webhook-test-btn');
  if (testBtn) testBtn.style.display = id ? '' : 'none';
  const testResult = document.getElementById('webhook-test-result');
  if (testResult) testResult.textContent = '';
  // Check event boxes
  document.querySelectorAll('.webhook-event-cb').forEach(cb => {
    cb.checked = wh ? (wh.events || []).includes(cb.value) : false;
  });
  openModal('modal-webhook');
}

async function saveWebhook() {
  const id     = document.getElementById('webhook-edit-id').value;
  const url    = document.getElementById('webhook-url').value.trim();
  const active = document.getElementById('webhook-active').checked;
  const events = [...document.querySelectorAll('.webhook-event-cb:checked')].map(cb => cb.value);
  if (!url) { toast('URL is required', 'warning'); return; }
  try {
    if (id) {
      await apiPut('/webhooks/' + id, { url, events, active });
      toast('Webhook updated', 'success');
    } else {
      await apiPost('/webhooks', { url, events, active });
      toast('Webhook created', 'success');
    }
    closeModal('modal-webhook');
    await loadWebhooks();
  } catch(e) { toast('Error saving webhook: ' + e.message, 'error'); }
}

async function deleteWebhook(id) {
  if (!confirm('Delete this webhook?')) return;
  try {
    await apiDelete('/webhooks/' + id);
    toast('Webhook deleted', 'info');
    await loadWebhooks();
  } catch(e) { toast('Error: ' + e.message, 'error'); }
}

async function testWebhook() {
  const id = document.getElementById('webhook-edit-id').value;
  if (!id) return;
  const resultEl = document.getElementById('webhook-test-result');
  if (resultEl) resultEl.textContent = 'Sending...';
  try {
    const resp = await apiPost('/webhooks/' + id + '/test', {});
    if (resultEl) resultEl.textContent = 'HTTP ' + (resp.status || '?') + (resp.error ? ' — ' + resp.error : '');
  } catch(e) {
    if (resultEl) resultEl.textContent = 'Error: ' + e.message;
  }
}

// Helper: apiDelete
if (typeof apiDelete !== 'function') {
  window.apiDelete = async function(path) {
    const token = localStorage.getItem('crm_token');
    const resp = await fetch('/api' + path, {
      method: 'DELETE',
      headers: token ? { Authorization: 'Bearer ' + token } : {},
    });
    if (!resp.ok) throw new Error(await resp.text());
    return resp.json();
  };
}

