// 19.C  CUSTOM FIELDS BUILDER
// ─────────────────────────────────────────────────────────────────────────────

let _customFieldDefs = [];
let _cfdFilter = 'all';

async function loadCustomFieldDefs() {
  try {
    _customFieldDefs = await apiGet('/custom-field-defs');
  } catch(e) {
    _customFieldDefs = [];
    console.warn('Custom field defs load failed', e);
  }
  renderCustomFieldDefsList();
}

function setCFDFilter(filter) {
  _cfdFilter = filter;
  ['all','contact','company','deal'].forEach(f => {
    const btn = document.getElementById('cfd-filter-' + f);
    if (!btn) return;
    if (f === filter) {
      btn.style.background = 'var(--accent)';
      btn.style.color = '#fff';
      btn.style.border = 'none';
    } else {
      btn.style.background = 'var(--surface2)';
      btn.style.color = 'var(--text)';
      btn.style.border = '1px solid var(--border)';
    }
  });
  renderCustomFieldDefsList();
}

function renderCustomFieldDefsList() {
  const el = document.getElementById('custom-field-defs-list');
  if (!el) return;
  const fields = _cfdFilter === 'all' ? _customFieldDefs : _customFieldDefs.filter(f => f.entityType === _cfdFilter);
  if (!fields.length) {
    el.innerHTML = '<div style="color:var(--text-muted);font-size:12px;padding:8px">No custom fields defined yet.</div>';
    return;
  }
  const entityColor = { contact: 'var(--green)', company: 'var(--accent)', deal: '#f59e0b' };
  el.innerHTML = `<table style="width:100%;border-collapse:collapse;font-size:12px">
    <thead><tr>
      <th style="text-align:left;padding:6px 8px;color:var(--text-muted);font-weight:500;border-bottom:1px solid var(--border)">Name</th>
      <th style="text-align:left;padding:6px 8px;color:var(--text-muted);font-weight:500;border-bottom:1px solid var(--border)">Type</th>
      <th style="text-align:left;padding:6px 8px;color:var(--text-muted);font-weight:500;border-bottom:1px solid var(--border)">Entity</th>
      <th style="text-align:center;padding:6px 8px;color:var(--text-muted);font-weight:500;border-bottom:1px solid var(--border)">Req.</th>
      <th style="padding:6px 8px;border-bottom:1px solid var(--border)"></th>
    </tr></thead>
    <tbody>${fields.map(f => `
      <tr style="border-bottom:1px solid var(--border)">
        <td style="padding:8px;color:var(--text)">${esc(f.name)}</td>
        <td style="padding:8px;color:var(--text-dim);text-transform:capitalize">${f.type}</td>
        <td style="padding:8px"><span style="font-size:10px;padding:2px 7px;border-radius:10px;background:${entityColor[f.entityType]||'var(--surface2)'}22;color:${entityColor[f.entityType]||'var(--text-muted)'};border:1px solid ${entityColor[f.entityType]||'var(--border)'}66;text-transform:capitalize">${f.entityType}</span></td>
        <td style="padding:8px;text-align:center;color:var(--text-muted)">${f.required ? '<svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="var(--green)" stroke-width="2.5" stroke-linecap="round"><polyline points="20 6 9 17 4 12"/></svg>' : '—'}</td>
        <td style="padding:8px;text-align:right;white-space:nowrap">
          <button class="btn btn-ghost btn-xs" onclick="openCustomFieldDefModal('${f.id}')" style="margin-right:4px">Edit</button>
          <button class="btn btn-ghost btn-xs" onclick="deleteCustomFieldDef('${f.id}')" style="opacity:0.6">Delete</button>
        </td>
      </tr>`).join('')}
    </tbody>
  </table>`;
}

function openCustomFieldDefModal(id) {
  const f = id ? _customFieldDefs.find(x => x.id === id) : null;
  document.getElementById('cfd-edit-id').value = id || '';
  document.getElementById('cfd-modal-title').textContent = id ? 'Edit Custom Field' : 'Add Custom Field';
  document.getElementById('cfd-name').value = f ? f.name : '';
  document.getElementById('cfd-entity-type').value = f ? f.entityType : 'contact';
  document.getElementById('cfd-type').value = f ? f.type : 'text';
  document.getElementById('cfd-required').checked = f ? f.required : false;
  document.getElementById('cfd-options').value = f && f.options ? f.options.join('\n') : '';
  toggleDropdownOptions();
  openModal('modal-custom-field-def');
}

function toggleDropdownOptions() {
  const type = document.getElementById('cfd-type')?.value;
  const wrap = document.getElementById('cfd-options-wrap');
  if (wrap) wrap.style.display = (type === 'dropdown' || type === 'select') ? '' : 'none';
}

async function saveCustomFieldDef() {
  const id         = document.getElementById('cfd-edit-id').value;
  const name       = document.getElementById('cfd-name').value.trim();
  const entityType = document.getElementById('cfd-entity-type').value;
  const type       = document.getElementById('cfd-type').value;
  const required   = document.getElementById('cfd-required').checked;
  const optionsRaw = document.getElementById('cfd-options').value;
  const options    = optionsRaw.split('\n').map(s => s.trim()).filter(Boolean);
  if (!name) { toast('Field name is required', 'warning'); return; }
  try {
    if (id) {
      await apiPut('/custom-field-defs/' + id, { name, entityType, type, required, options });
      toast('Custom field updated', 'success');
    } else {
      await apiPost('/custom-field-defs', { name, entityType, type, required, options });
      toast('Custom field created', 'success');
    }
    closeModal('modal-custom-field-def');
    await loadCustomFieldDefs();
  } catch(e) { toast('Error: ' + e.message, 'error'); }
}

async function deleteCustomFieldDef(id) {
  if (!confirm('Delete this custom field? Existing values will be removed.')) return;
  try {
    await apiDelete('/custom-field-defs/' + id);
    toast('Custom field deleted', 'info');
    await loadCustomFieldDefs();
  } catch(e) { toast('Error: ' + e.message, 'error'); }
}

// Render custom fields for a given entity type in a form container
async function renderEntityCustomFields(entityType, entityId, container) {
  if (!container) return;
  const fields = _customFieldDefs.filter(f => f.entityType === entityType);
  if (!fields.length) { container.innerHTML = ''; return; }

  // Load existing values
  let values = {};
  if (entityId) {
    try {
      const vals = await apiGet(`/custom-field-values?entityType=${entityType}&entityId=${entityId}`);
      vals.forEach(v => { values[v.fieldId] = v.value; });
    } catch {}
  }

  container.innerHTML = `
    <div style="margin-top:16px;padding-top:16px;border-top:1px solid var(--border)">
      <div style="font-size:11px;font-weight:600;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.07em;margin-bottom:12px">Custom Fields</div>
      <div style="display:flex;flex-direction:column;gap:10px">
        ${fields.map(f => {
          const val = values[f.id] || '';
          const req = f.required ? 'required' : '';
          const reqMark = f.required ? '<span style="color:#ef4444;margin-left:2px">*</span>' : '';
          let input = '';
          if (f.type === 'text')   input = `<input type="text"  class="form-input" data-cfd-id="${f.id}" value="${esc(val)}" ${req} />`;
          else if (f.type === 'number') input = `<input type="number" class="form-input" data-cfd-id="${f.id}" value="${esc(val)}" ${req} />`;
          else if (f.type === 'date')   input = `<input type="date"   class="form-input" data-cfd-id="${f.id}" value="${esc(val)}" ${req} />`;
          else if (f.type === 'dropdown' || f.type === 'select') {
            const opts = (f.options || []).map(o => `<option value="${esc(o)}" ${o === val ? 'selected' : ''}>${esc(o)}</option>`).join('');
            input = `<select class="form-select" data-cfd-id="${f.id}" ${req}><option value="">— Select —</option>${opts}</select>`;
          }
          else if (f.type === 'checkbox') {
            input = `<label style="display:flex;align-items:center;gap:8px;font-size:13px;cursor:pointer"><input type="checkbox" data-cfd-id="${f.id}" ${val === 'true' || val === '1' ? 'checked' : ''} style="width:14px;height:14px" /></label>`;
          }
          return `<div class="form-group"><label class="form-label">${esc(f.name)}${reqMark}</label>${input}</div>`;
        }).join('')}
      </div>
    </div>`;
}

// Collect custom field values from a rendered container
function collectCFDValues(container) {
  if (!container) return {};
  const values = {};
  container.querySelectorAll('[data-cfd-id]').forEach(el => {
    const id = el.dataset.cfdId;
    if (el.type === 'checkbox') values[id] = el.checked ? 'true' : 'false';
    else values[id] = el.value;
  });
  return values;
}

// Save custom field values for entity
async function saveEntityCustomFields(entityType, entityId, container) {
  if (!container) return;
  const values = collectCFDValues(container);
  if (!Object.keys(values).length) return;
  try {
    await apiPut(`/custom-field-values/${entityType}/${entityId}`, values);
  } catch(e) { console.warn('Custom field values save failed', e); }
}

// ─────────────────────────────────────────────────────────────────────────────
// 19.D  GOALS PER REP & LEADERBOARD
// ─────────────────────────────────────────────────────────────────────────────

let _userGoals = [];

async function loadGoalsPerRep() {
  const container = document.getElementById('goals-per-rep-container');
  if (!container) return;

  let users = [];
  let goals = [];
  try {
    users = await apiGet('/users');
    goals = await apiGet('/user-goals');
    _userGoals = goals;
  } catch(e) {
    container.innerHTML = '<div style="color:var(--text-muted);font-size:12px">Failed to load users</div>';
    return;
  }

  const now = new Date();
  const year = now.getFullYear();
  const month = now.getMonth() + 1;
  const quarter = Math.ceil(month / 3);

  const getGoal = (userId, periodType, period) => {
    const g = goals.find(x => x.userId === userId && x.periodType === periodType && x.year === year && x.period === period);
    return g ? g.goalAmount : 0;
  };

  container.innerHTML = `
    <div style="overflow-x:auto">
      <table style="width:100%;border-collapse:collapse;font-size:12px">
        <thead><tr>
          <th style="text-align:left;padding:6px 8px;color:var(--text-muted);font-weight:500;border-bottom:1px solid var(--border)">Rep</th>
          <th style="text-align:right;padding:6px 8px;color:var(--text-muted);font-weight:500;border-bottom:1px solid var(--border)">Monthly Goal (${year}/${String(month).padStart(2,'0')})</th>
          <th style="text-align:right;padding:6px 8px;color:var(--text-muted);font-weight:500;border-bottom:1px solid var(--border)">Quarterly Goal (Q${quarter})</th>
        </tr></thead>
        <tbody>${users.map(u => `
          <tr style="border-bottom:1px solid var(--border)">
            <td style="padding:8px;color:var(--text)">${esc(u.name || u.email)}</td>
            <td style="padding:8px;text-align:right">
              <input type="number" min="0" step="1000" class="form-input" style="width:120px;text-align:right;font-size:12px"
                data-goal-user="${u.id}" data-goal-period-type="monthly" data-goal-period="${month}" data-goal-year="${year}"
                value="${getGoal(u.id, 'monthly', month)}" placeholder="0" />
            </td>
            <td style="padding:8px;text-align:right">
              <input type="number" min="0" step="5000" class="form-input" style="width:120px;text-align:right;font-size:12px"
                data-goal-user="${u.id}" data-goal-period-type="quarterly" data-goal-period="${quarter}" data-goal-year="${year}"
                value="${getGoal(u.id, 'quarterly', quarter)}" placeholder="0" />
            </td>
          </tr>`).join('')}
        </tbody>
      </table>
    </div>`;
}

async function saveGoalsPerRep() {
  const inputs = document.querySelectorAll('#goals-per-rep-container [data-goal-user]');
  const goals = [];
  inputs.forEach(inp => {
    const val = parseFloat(inp.value) || 0;
    if (val > 0) {
      goals.push({
        userId:     inp.dataset.goalUser,
        periodType: inp.dataset.goalPeriodType,
        year:       parseInt(inp.dataset.goalYear),
        period:     parseInt(inp.dataset.goalPeriod),
        goalAmount: val,
      });
    }
  });
  if (!goals.length) { toast('No goals to save', 'warning'); return; }
  try {
    await apiPut('/user-goals', goals);
    toast('Goals saved', 'success');
  } catch(e) { toast('Error saving goals: ' + e.message, 'error'); }
}

async function renderLeaderboard() {
  const grid = document.querySelector('#view-reports .reports-grid');
  if (!grid) return;

  let container = document.getElementById('report-leaderboard');
  if (!container) {
    const card = document.createElement('div');
    card.className = 'panel report-card report-card-full';
    card.innerHTML = '<div class="panel-header"><div class="panel-title">Rep Leaderboard</div></div><div id="report-leaderboard" style="padding:16px"></div>';
    grid.appendChild(card);
    container = document.getElementById('report-leaderboard');
  }

  container.innerHTML = '<div style="color:var(--text-muted);font-size:12px;padding:8px">Loading...</div>';

  try {
    const attainment = await apiGet('/user-goals/attainment');

    if (!attainment.length) {
      container.innerHTML = '<div style="color:var(--text-muted);font-size:12px;padding:8px">No data available</div>';
      return;
    }

    // Sort by won this month descending
    const sorted = [...attainment].sort((a, b) => b.wonThisMonth - a.wonThisMonth);

    container.innerHTML = `
      <div style="display:flex;flex-direction:column;gap:14px">
        ${sorted.map((rep, i) => {
          const isFirst = i === 0;
          const pct = rep.monthlyGoal > 0 ? Math.min(100, Math.round((rep.wonThisMonth / rep.monthlyGoal) * 100)) : 0;
          const barColor = pct >= 100 ? 'var(--green)' : pct >= 60 ? 'var(--accent)' : '#f59e0b';
          const trophy = isFirst ? `<span style="display:inline-block;width:18px;height:18px;position:relative;margin-right:6px;flex-shrink:0">
            <svg viewBox="0 0 24 24" fill="none" stroke="#f59e0b" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" width="18" height="18"><path d="M6 9H4.5a2.5 2.5 0 0 1 0-5H6"/><path d="M18 9h1.5a2.5 2.5 0 0 0 0-5H18"/><path d="M4 22h16"/><path d="M10 14.66V17c0 .55-.47.98-.97 1.21C7.85 18.75 7 20.24 7 22"/><path d="M14 14.66V17c0 .55.47.98.97 1.21C16.15 18.75 17 20.24 17 22"/><path d="M18 2H6v7a6 6 0 0 0 12 0V2z"/></svg>
          </span>` : `<span style="display:inline-block;width:18px;height:18px;text-align:center;margin-right:6px;font-size:12px;color:var(--text-muted);line-height:18px;flex-shrink:0">${i+1}</span>`;
          return `
            <div style="display:flex;align-items:flex-start;gap:12px">
              ${trophy}
              <div style="flex:1;min-width:0">
                <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:5px">
                  <span style="font-size:13px;font-weight:${isFirst?600:400};color:var(--text)">${esc(rep.userName)}</span>
                  <div style="text-align:right">
                    <span style="font-size:12px;color:var(--text)">$${(rep.wonThisMonth||0).toLocaleString()}</span>
                    ${rep.monthlyGoal > 0 ? `<span style="font-size:10px;color:var(--text-muted);margin-left:6px">/ $${rep.monthlyGoal.toLocaleString()} goal</span>` : ''}
                  </div>
                </div>
                ${rep.monthlyGoal > 0 ? `
                <div style="height:6px;background:var(--surface2);border-radius:3px;overflow:hidden">
                  <div style="height:100%;width:${pct}%;background:${barColor};border-radius:3px;transition:width 0.4s ease"></div>
                </div>
                <div style="font-size:10px;color:var(--text-muted);margin-top:3px">${pct}% of monthly goal</div>` : `
                <div style="font-size:10px;color:var(--text-muted)">No goal set</div>`}
              </div>
            </div>`;
        }).join('')}
      </div>`;
  } catch(e) {
    container.innerHTML = '<div style="color:var(--text-muted);font-size:12px;padding:8px">Could not load leaderboard</div>';
  }
}

