let _kbNotes = [];
let _kbQuery = '';

async function renderNotes() {
  const el = document.getElementById('view-notes');
  if (!el) return;

  el.innerHTML = `
    <div class="page-header">
      <div>
        <div class="page-title">Knowledge Base</div>
      </div>
      <div class="header-actions">
        <input type="text" class="form-input" id="kb-search" placeholder="Search notes..." style="width:220px"
          oninput="debounceKBSearch()" value="${esc(_kbQuery)}" />
        <button class="btn btn-primary" onclick="openNoteModal()">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" width="14" height="14"><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg>
          New Note
        </button>
      </div>
    </div>
    <div id="kb-tags-bar" style="display:flex;gap:6px;flex-wrap:wrap;padding:0 24px 12px;margin-top:-4px"></div>
    <div class="page-content" style="overflow-y:auto">
      <div id="kb-notes-grid" style="display:grid;grid-template-columns:repeat(auto-fill,minmax(280px,1fr));gap:14px"></div>
    </div>`;

  await loadKBNotes();
}

async function loadKBNotes() {
  try {
    const q = _kbQuery ? `?q=${encodeURIComponent(_kbQuery)}` : '';
    _kbNotes = await apiGet('/kb-notes' + q);
  } catch(e) { _kbNotes = []; }
  renderKBNotesList();
  renderKBTagsBar();
}

function renderKBNotesList(filter) {
  const grid = document.getElementById('kb-notes-grid');
  if (!grid) return;
  let notes = filter ? _kbNotes.filter(n => (n.tags||[]).includes(filter)) : _kbNotes;
  if (!notes.length) {
    grid.innerHTML = `<div class="empty-state" style="grid-column:1/-1">
      <div class="empty-state-title">No notes yet</div>
      <div class="empty-state-sub">Create your first Knowledge Base note</div>
    </div>`;
    return;
  }
  grid.innerHTML = notes.map(n => {
    const preview = (n.body || '').replace(/\*\*/g,'').replace(/\*/g,'').replace(/##/g,'').slice(0, 120);
    const tags = (n.tags || []).slice(0, 4);
    const co = n.companyId ? (db.companies||[]).find(c => c.id === n.companyId) : null;
    return `<div class="panel kb-note-card" style="cursor:pointer;transition:transform 0.1s,box-shadow 0.1s" onclick="openNoteDetail('${n.id}')" onmouseenter="this.style.transform='translateY(-2px)'" onmouseleave="this.style.transform=''">
      <div style="padding:14px 16px">
        <div style="display:flex;align-items:flex-start;justify-content:space-between;gap:8px;margin-bottom:8px">
          <div style="font-size:13px;font-weight:600;color:var(--text);line-height:1.3">${n.pinned ? `<svg width="11" height="11" viewBox="0 0 24 24" fill="var(--accent)" stroke="var(--accent)" stroke-width="2" stroke-linecap="round" style="margin-right:5px;vertical-align:-1px"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"/></svg>` : ''}${esc(n.title)}</div>
          <div style="display:flex;gap:4px;flex-shrink:0">
            <button class="btn btn-ghost btn-xs" onclick="event.stopPropagation();openNoteModal('${n.id}')" title="Edit">
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" width="11" height="11"><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"/></svg>
            </button>
            <button class="btn btn-ghost btn-xs" onclick="event.stopPropagation();deleteKBNote('${n.id}')" title="Delete" style="opacity:0.6">
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" width="11" height="11"><polyline points="3,6 5,6 21,6"/><path d="M19,6l-1,14a2,2,0,0,1-2,2H8a2,2,0,0,1-2-2L5,6"/></svg>
            </button>
          </div>
        </div>
        ${preview ? `<div style="font-size:11px;color:var(--text-muted);line-height:1.5;margin-bottom:10px">${esc(preview)}${n.body.length > 120 ? '…' : ''}</div>` : ''}
        ${co ? `<div style="font-size:10px;color:var(--accent);margin-bottom:8px">${esc(co.name)}</div>` : ''}
        <div style="display:flex;flex-wrap:wrap;gap:4px;margin-bottom:6px">
          ${tags.map(t => `<span style="font-size:10px;padding:2px 7px;border-radius:10px;background:var(--surface2);border:1px solid var(--border);color:var(--text-muted);cursor:pointer" onclick="event.stopPropagation();filterKBByTag('${esc(t)}')">${esc(t)}</span>`).join('')}
        </div>
        <div style="font-size:10px;color:var(--text-muted)">${formatDate(n.updatedAt || n.createdAt)}</div>
      </div>
    </div>`;
  }).join('');
}

function renderKBTagsBar() {
  const bar = document.getElementById('kb-tags-bar');
  if (!bar) return;
  const allTags = [...new Set(_kbNotes.flatMap(n => n.tags || []))].sort();
  bar.innerHTML = allTags.length ? allTags.map(t =>
    `<button style="font-size:11px;padding:3px 10px;border-radius:12px;background:var(--surface2);border:1px solid var(--border);color:var(--text-muted);cursor:pointer" onclick="filterKBByTag('${esc(t)}')">${esc(t)}</button>`
  ).join('') : '';
}

function filterKBByTag(tag) {
  renderKBNotesList(tag);
}

let _kbSearchTimer = null;
function debounceKBSearch() {
  _kbQuery = document.getElementById('kb-search')?.value || '';
  if (_kbSearchTimer) clearTimeout(_kbSearchTimer);
  _kbSearchTimer = setTimeout(loadKBNotes, 250);
}

function openNoteModal(id) {
  const n = id ? _kbNotes.find(x => x.id === id) : null;
  document.getElementById('note-edit-id').value = id || '';
  document.getElementById('note-modal-title').textContent = id ? 'Edit Note' : 'New Note';
  document.getElementById('note-title').value = n ? n.title : '';
  document.getElementById('note-body').value = n ? n.body : '';
  document.getElementById('note-tags').value = n ? (n.tags || []).join(', ') : '';
  document.getElementById('note-pinned').checked = n ? n.pinned : false;
  // Populate company select
  const coSel = document.getElementById('note-company');
  if (coSel) {
    const companies = db.companies || [];
    coSel.innerHTML = '<option value="">— No company —</option>' +
      companies.map(c => `<option value="${c.id}" ${n && n.companyId === c.id ? 'selected' : ''}>${esc(c.name)}</option>`).join('');
  }
  openModal('modal-kb-note');
}

async function saveKBNote() {
  const id      = document.getElementById('note-edit-id').value;
  const title   = document.getElementById('note-title').value.trim();
  const body    = document.getElementById('note-body').value;
  const tagsRaw = document.getElementById('note-tags').value;
  const pinned  = document.getElementById('note-pinned').checked;
  const coId    = document.getElementById('note-company').value || null;
  const tags    = tagsRaw.split(',').map(s => s.trim()).filter(Boolean);
  if (!title) { toast('Title is required', 'warning'); return; }
  try {
    if (id) {
      await apiPut('/kb-notes/' + id, { title, body, tags, pinned, companyId: coId });
      toast('Note updated', 'success');
    } else {
      await apiPost('/kb-notes', { title, body, tags, pinned, companyId: coId });
      toast('Note created', 'success');
    }
    closeModal('modal-kb-note');
    await loadKBNotes();
  } catch(e) { toast('Error: ' + e.message, 'error'); }
}

async function deleteKBNote(id) {
  if (!confirm('Delete this note?')) return;
  try {
    await apiDelete('/kb-notes/' + id);
    _kbNotes = _kbNotes.filter(n => n.id !== id);
    renderKBNotesList();
    renderKBTagsBar();
    toast('Note deleted', 'info');
  } catch(e) { toast('Error: ' + e.message, 'error'); }
}

function openNoteDetail(id) {
  const n = _kbNotes.find(x => x.id === id);
  if (!n) return;
  // Render simple detail view in-place
  const grid = document.getElementById('kb-notes-grid');
  if (!grid) return;
  const co = n.companyId ? (db.companies||[]).find(c => c.id === n.companyId) : null;
  const bodyHtml = renderMarkdownSimple(n.body || '');
  grid.innerHTML = `
    <div style="grid-column:1/-1">
      <div style="display:flex;align-items:center;gap:10px;margin-bottom:16px">
        <button class="btn btn-ghost btn-sm" onclick="loadKBNotes()">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" width="13" height="13"><line x1="19" y1="12" x2="5" y2="12"/><polyline points="12 19 5 12 12 5"/></svg>
          Back
        </button>
        <h2 style="font-size:18px;font-weight:600;color:var(--text);margin:0">${esc(n.title)}</h2>
        <div style="margin-left:auto;display:flex;gap:8px">
          <button class="btn btn-secondary" onclick="openNoteModal('${n.id}')">Edit</button>
          <button class="btn btn-ghost" onclick="deleteKBNote('${n.id}')">Delete</button>
        </div>
      </div>
      ${co ? `<div style="font-size:12px;color:var(--accent);margin-bottom:10px">${esc(co.name)}</div>` : ''}
      ${(n.tags||[]).length ? `<div style="display:flex;gap:4px;margin-bottom:14px">${(n.tags||[]).map(t => `<span style="font-size:11px;padding:2px 8px;border-radius:10px;background:var(--surface2);border:1px solid var(--border);color:var(--text-muted)">${esc(t)}</span>`).join('')}</div>` : ''}
      <div class="panel" style="padding:20px;line-height:1.7;font-size:13px;color:var(--text)">${bodyHtml}</div>
      <div style="font-size:11px;color:var(--text-muted);margin-top:10px">Last updated ${formatDate(n.updatedAt || n.createdAt)}</div>
    </div>`;
}

// Simple markdown renderer (no external deps)
function renderMarkdownSimple(text) {
  if (!text) return '';
  let html = esc(text);
  // Headings
  html = html.replace(/^### (.+)$/gm, '<h3 style="font-size:14px;font-weight:600;color:var(--text);margin:14px 0 6px">$1</h3>');
  html = html.replace(/^## (.+)$/gm, '<h2 style="font-size:16px;font-weight:600;color:var(--text);margin:16px 0 8px">$1</h2>');
  html = html.replace(/^# (.+)$/gm, '<h1 style="font-size:18px;font-weight:700;color:var(--text);margin:18px 0 10px">$1</h1>');
  // Bold + Italic
  html = html.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
  html = html.replace(/\*(.+?)\*/g, '<em>$1</em>');
  // Unordered list
  html = html.replace(/^- (.+)$/gm, '<li style="margin:3px 0 3px 18px;list-style:disc">$1</li>');
  // Line breaks
  html = html.replace(/\n/g, '<br>');
  return html;
}

