// Extend renderView to handle 'notes'
(function patchRenderViewP19() {
  const _origRV = window.renderView;
  window.renderView = function(view, param) {
    _origRV.call(this, view, param);
    if (view === 'notes') renderNotes();
    if (view === 'reports') {
      setTimeout(() => renderLeaderboard(), 100);
    }
  };
})();

// Extend renderSettings to load webhooks + custom fields + goals per rep
(function patchRenderSettingsP19() {
  const _orig = window.renderSettings;
  window.renderSettings = function() {
    _orig.call(this);
    loadWebhooks();
    loadCustomFieldDefs();
    loadGoalsPerRep();
  };
})();

// Patch startApp to boot notification polling
(function patchStartAppP19() {
  const _orig = window.startApp;
  window.startApp = async function() {
    await _orig.call(this);
    startNotifPolling();
  };
})();

// Patch loadDBFromAPI to seed _customFieldDefs early
(function patchLoadDBFromAPIP19() {
  const _orig = window.loadDBFromAPI;
  if (!_orig) return;
  window.loadDBFromAPI = async function() {
    await _orig.call(this);
    try { _customFieldDefs = await apiGet('/custom-field-defs'); } catch {}
    try { _webhooks = await apiGet('/webhooks'); } catch {}
  };
})();

// Close notif drawer on outside click
document.addEventListener('click', function(e) {
  if (_notifOpen && !e.target.closest('.notif-drawer') && !e.target.closest('.notif-bell-wrap')) {
    closeNotifCenter();
  }
});

