(function injectP19CSS() {
  if (document.getElementById('p19-styles')) return;
  const style = document.createElement('style');
  style.id = 'p19-styles';
  style.textContent = `
    /* Notification Bell */
    .notif-bell-wrap { position:relative; display:flex; align-items:center; }
    .notif-bell-btn  { background:none;border:none;cursor:pointer;color:var(--text-muted);padding:6px;border-radius:6px;transition:background 0.15s; display:flex; align-items:center; }
    .notif-bell-btn:hover { background:var(--surface2);color:var(--text); }
    .notif-badge     { position:absolute;top:2px;right:2px;min-width:16px;height:16px;border-radius:8px;background:#ef4444;color:#fff;font-size:9px;font-weight:700;display:flex;align-items:center;justify-content:center;padding:0 3px;pointer-events:none;border:2px solid var(--surface); }

    /* Notification Drawer */
    .notif-drawer    { position:fixed;top:0;right:-380px;width:360px;height:100vh;background:var(--surface);border-left:1px solid var(--border);z-index:1200;transition:right 0.25s ease;display:flex;flex-direction:column;box-shadow:-4px 0 20px rgba(0,0,0,0.2); }
    .notif-drawer.open { right:0; }
    .notif-drawer-header { display:flex;align-items:center;justify-content:space-between;padding:14px 16px;border-bottom:1px solid var(--border);flex-shrink:0; }
    .notif-drawer-list   { flex:1;overflow-y:auto; }
    .notif-item      { padding:12px 16px;cursor:pointer;border-bottom:1px solid var(--border);transition:background 0.1s; }
    .notif-item:hover { background:var(--surface2); }
    .notif-item-unread { background:color-mix(in srgb, var(--accent) 6%, var(--surface)); }
    .notif-item-icon { width:24px;height:24px;display:flex;align-items:center;justify-content:center;flex-shrink:0;margin-top:1px; }

    /* KB Note cards */
    .kb-note-card { transition:transform 0.15s, box-shadow 0.15s; }
    .kb-note-card:hover { box-shadow:0 4px 16px rgba(0,0,0,0.15); }
  `;
  document.head.appendChild(style);
})();

