// 19.I  WEBHOOK EVENT FIRING — Wire into existing CRM actions
// ─────────────────────────────────────────────────────────────────────────────

// Patch apiPost to fire webhook events after key actions
(function patchApiPostForWebhooks() {
  const _orig = window.apiPost;
  if (!_orig) return;
  window.apiPost = async function(path, body) {
    const result = await _orig.call(this, path, body);
    // Skip event endpoints to prevent infinite loop
    if (path.startsWith('/events/')) return result;
    // Fire after deal created
    if (path === '/deals' && result?.id) {
      _orig.call(this, '/events/deal-created', { dealId: result.id }).catch(() => {});
    }
    // Fire after contact created
    if (path === '/contacts' && result?.id) {
      _orig.call(this, '/events/contact-created', { contactId: result.id }).catch(() => {});
    }
    // Fire after contact merged
    if (path === '/contacts/merge' && result?.winnerId) {
      _orig.call(this, '/events/contact-merged', { winnerId: result.winnerId, loserName: result.loserName || '' }).catch(() => {});
    }
    return result;
  };
})();

// Patch apiPut to fire deal.won / deal stage changed
(function patchApiPutForWebhooks() {
  const _orig = window.apiPut;
  if (!_orig) return;
  window.apiPut = async function(path, body) {
    const result = await _orig.call(this, path, body);
    if (path.match(/^\/deals\//) && body?.stage && result?.id) {
      if (body.stage === 'Won') {
        apiPost('/events/deal-won', { dealId: result.id }).catch(() => {});
      }
      apiPost('/events/deal-stage-changed', { dealId: result.id, toStage: body.stage }).catch(() => {});
    }
    return result;
  };
})();

// Run overdue check once on startup (after DB loads)
(function scheduleOverdueCheck() {
  const _orig = window.startApp;
  window.startApp = async function() {
    if (_orig) await _orig.call(this);
    // Fire overdue check 5s after app loads
    setTimeout(() => apiPost('/events/check-overdue', {})
      .then(() => updateNotifBadge())
      .catch(() => {}), 5000);
  };
})();

