// Inject custom fields into contact, company, deal detail pages
// by patching renderContactDetail, renderDealDetail, renderCompanyDetail

(function patchDetailPagesForCustomFields() {
  // After a detail page renders, append custom field values
  const _origContactDetail = window.renderContactDetail;
  if (_origContactDetail) {
    window.renderContactDetail = function(id) {
      _origContactDetail.call(this, id);
      setTimeout(async () => {
        const defs = (_customFieldDefs || []).filter(d => d.entityType === 'contact');
        if (!defs.length) return;
        let cfContainer = document.getElementById('contact-custom-fields-section');
        if (!cfContainer) {
          cfContainer = document.createElement('div');
          cfContainer.id = 'contact-custom-fields-section';
          const detailEl = document.getElementById('view-contact-detail');
          if (detailEl) {
            const content = detailEl.querySelector('.page-content') || detailEl;
            content.appendChild(cfContainer);
          }
        }
        await renderEntityCustomFields('contact', id, cfContainer);
      }, 200);
    };
  }

  const _origDealDetail = window.renderDealDetail;
  if (_origDealDetail) {
    window.renderDealDetail = function(id) {
      _origDealDetail.call(this, id);
      setTimeout(async () => {
        const defs = (_customFieldDefs || []).filter(d => d.entityType === 'deal');
        if (!defs.length) return;
        let cfContainer = document.getElementById('deal-custom-fields-section');
        if (!cfContainer) {
          cfContainer = document.createElement('div');
          cfContainer.id = 'deal-custom-fields-section';
          const detailEl = document.getElementById('view-deal-detail');
          if (detailEl) {
            const content = detailEl.querySelector('.page-content') || detailEl;
            content.appendChild(cfContainer);
          }
        }
        await renderEntityCustomFields('deal', id, cfContainer);
      }, 200);
    };
  }

  const _origCompanyDetail = window.renderCompanyDetail;
  if (_origCompanyDetail) {
    window.renderCompanyDetail = function(id) {
      _origCompanyDetail.call(this, id);
      setTimeout(async () => {
        // Custom fields
        const defs = (_customFieldDefs || []).filter(d => d.entityType === 'company');
        if (defs.length) {
          let cfContainer = document.getElementById('company-custom-fields-section');
          if (!cfContainer) {
            cfContainer = document.createElement('div');
            cfContainer.id = 'company-custom-fields-section';
            const detailEl = document.getElementById('view-company-detail');
            if (detailEl) {
              const content = detailEl.querySelector('.page-content') || detailEl;
              content.appendChild(cfContainer);
            }
          }
          await renderEntityCustomFields('company', id, cfContainer);
        }
        // Linked KB Notes
        let notesContainer = document.getElementById('company-kb-notes-section');
        if (!notesContainer) {
          notesContainer = document.createElement('div');
          notesContainer.id = 'company-kb-notes-section';
          const detailEl = document.getElementById('view-company-detail');
          if (detailEl) {
            const content = detailEl.querySelector('.page-content') || detailEl;
            content.appendChild(notesContainer);
          }
        }
        try {
          const notes = await apiGet('/kb-notes?companyId=' + id);
          if (notes.length) {
            notesContainer.innerHTML = `
              <div class="panel" style="margin:12px 0">
                <div class="panel-header"><div class="panel-title">Linked Notes</div></div>
                <div style="padding:12px;display:flex;flex-direction:column;gap:8px">
                  ${notes.map(n => `<div style="padding:10px;background:var(--surface2);border:1px solid var(--border);border-radius:8px;cursor:pointer" onclick="navigate('notes')">
                    <div style="font-weight:500;font-size:13px">${esc(n.title)}</div>
                    ${(n.tags||[]).length ? `<div style="margin-top:4px;font-size:11px;color:var(--text-muted)">${n.tags.join(', ')}</div>` : ''}
                  </div>`).join('')}
                </div>
              </div>`;
          } else {
            notesContainer.innerHTML = '';
          }
        } catch(e) { notesContainer.innerHTML = ''; }
      }, 300);
    };
  }
})();

