// 20.A  TIME TRACKING
// ══════════════════════════════════════════════════════════════════════════════

let _timeEntries = [];

async function loadTimeEntries(filters = {}) {
  let qs = '';
  if (filters.dealId)    qs += `&dealId=${filters.dealId}`;
  if (filters.contactId) qs += `&contactId=${filters.contactId}`;
  if (filters.userId)    qs += `&userId=${filters.userId}`;
  if (filters.billable !== undefined && filters.billable !== '') qs += `&billable=${filters.billable}`;
  _timeEntries = await apiGet('/time-entries?' + qs.slice(1));
  return _timeEntries;
}

function renderTimeEntries() {
  const userFilter     = document.getElementById('time-filter-user')?.value || '';
  const dealFilter     = document.getElementById('time-filter-deal')?.value || '';
  const billableFilter = document.getElementById('time-filter-billable')?.value || '';

  let entries = (_timeEntries || []).filter(e => {
    if (userFilter  && e.userId  !== userFilter) return false;
    if (dealFilter  && e.dealId  !== dealFilter) return false;
    if (billableFilter === 'true'  && !e.billable) return false;
    if (billableFilter === 'false' &&  e.billable) return false;
    return true;
  });

  const tbody = document.getElementById('time-entries-tbody');
  if (!tbody) return;

  const totalHours   = entries.reduce((s, e) => s + (e.hours || 0), 0);
  const billableAmt  = entries.filter(e => e.billable).reduce((s, e) => s + (e.hours * e.rate), 0);
  const totalsBar    = document.getElementById('time-totals-bar');
  if (totalsBar) {
    totalsBar.innerHTML = `
      <span><strong>${totalHours.toFixed(1)}</strong> hrs total</span>
      <span style="color:var(--green)"><strong>$${billableAmt.toLocaleString(undefined,{minimumFractionDigits:2,maximumFractionDigits:2})}</strong> billable</span>
    `;
  }

  if (!entries.length) {
    tbody.innerHTML = `<tr><td colspan="11" style="text-align:center;color:var(--text-muted);padding:24px">No time entries. Log time on a deal or contact.</td></tr>`;
    return;
  }

  tbody.innerHTML = entries.map(e => {
    const deal    = (db.deals || []).find(d => d.id === e.dealId);
    const contact = (db.contacts || []).find(c => c.id === e.contactId);
    const amount  = e.billable ? (e.hours * e.rate) : 0;
    return `<tr>
      <td style="white-space:nowrap">${e.date || ''}</td>
      <td>${esc(e.description || '')}</td>
      <td>${deal ? `<span class="link-text" onclick="showDealDetail('${deal.id}')">${esc(deal.name)}</span>` : '<span style="color:var(--text-muted)">—</span>'}</td>
      <td>${contact ? `<span class="link-text" onclick="showContactDetail('${contact.id}')">${esc(contact.name)}</span>` : '<span style="color:var(--text-muted)">—</span>'}</td>
      <td style="color:var(--text-muted)">${esc(e.userId || '')}</td>
      <td style="text-align:right;font-weight:500">${(e.hours||0).toFixed(2)}</td>
      <td style="text-align:right;color:var(--text-muted)">${e.rate ? '$' + e.rate + '/hr' : '—'}</td>
      <td style="text-align:right;color:var(--green);font-weight:500">${e.billable && e.rate ? '$' + amount.toFixed(2) : '—'}</td>
      <td style="text-align:center"><span style="color:${e.billable ? 'var(--green)' : 'var(--text-muted)'};font-size:11px;font-weight:600">${e.billable ? 'Yes' : 'No'}</span></td>
      <td style="text-align:center"><span style="color:${e.invoiceId ? 'var(--green)' : 'var(--text-muted)'};font-size:11px">${e.invoiceId ? 'Invoiced' : 'Pending'}</span></td>
      <td style="text-align:right">
        <button class="btn btn-ghost btn-xs" onclick="editTimeEntry('${e.id}')">Edit</button>
        <button class="btn btn-ghost btn-xs" style="color:var(--red)" onclick="deleteTimeEntry('${e.id}')">Del</button>
      </td>
    </tr>`;
  }).join('');
}

async function loadTimeView() {
  await loadTimeEntries();

  // Populate user filter
  const userSel = document.getElementById('time-filter-user');
  if (userSel) {
    const users = await apiGet('/users').catch(() => []);
    userSel.innerHTML = '<option value="">All Users</option>' +
      users.map(u => `<option value="${u.id}">${esc(u.name)}</option>`).join('');
  }

  // Populate deal filter
  const dealSel = document.getElementById('time-filter-deal');
  if (dealSel) {
    dealSel.innerHTML = '<option value="">All Deals</option>' +
      (db.deals || []).map(d => `<option value="${d.id}">${esc(d.name)}</option>`).join('');
  }

  renderTimeEntries();
}

function openTimeEntryModal(prefillDealId, prefillContactId) {
  const modal = document.createElement('div');
  modal.id = 'time-entry-modal';
  modal.className = 'modal-overlay p20-modal';
  modal.innerHTML = `
    <div class="modal" style="width:480px">
      <div class="modal-header">
        <div class="modal-title">Log Time</div>
        <button class="modal-close" onclick="closeModal('time-entry-modal')">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="16" height="16"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
        </button>
      </div>
      <div style="padding:20px;display:flex;flex-direction:column;gap:14px">
        <div class="form-group">
          <label class="form-label">Date</label>
          <input type="date" class="form-input" id="te-date" value="${new Date().toISOString().slice(0,10)}" />
        </div>
        <div class="form-group">
          <label class="form-label">Description</label>
          <input type="text" class="form-input" id="te-description" placeholder="What was worked on?" />
        </div>
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px">
          <div class="form-group">
            <label class="form-label">Hours</label>
            <input type="number" class="form-input" id="te-hours" placeholder="1.5" min="0" step="0.25" />
          </div>
          <div class="form-group">
            <label class="form-label">Rate ($/hr)</label>
            <input type="number" class="form-input" id="te-rate" placeholder="150" min="0" />
          </div>
        </div>
        <div class="form-group">
          <label class="form-label">Deal (optional)</label>
          <select class="form-select" id="te-deal">
            <option value="">No deal</option>
            ${(db.deals || []).map(d => `<option value="${d.id}" ${d.id === prefillDealId ? 'selected' : ''}>${esc(d.name)}</option>`).join('')}
          </select>
        </div>
        <div class="form-group">
          <label class="form-label">Contact (optional)</label>
          <select class="form-select" id="te-contact">
            <option value="">No contact</option>
            ${(db.contacts || []).map(c => `<option value="${c.id}" ${c.id === prefillContactId ? 'selected' : ''}>${esc(c.name)}</option>`).join('')}
          </select>
        </div>
        <label style="display:flex;align-items:center;gap:8px;font-size:13px;cursor:pointer">
          <input type="checkbox" id="te-billable" checked />
          Billable
        </label>
      </div>
      <div class="modal-footer">
        <button class="btn btn-secondary" onclick="closeModal('time-entry-modal')">Cancel</button>
        <button class="btn btn-primary" onclick="saveTimeEntry()">Log Time</button>
      </div>
    </div>`;
  document.body.appendChild(modal);
  modal.addEventListener('click', e => { if (e.target === modal) closeModal('time-entry-modal'); });
}

async function saveTimeEntry() {
  const id    = document.getElementById('te-id')?.value;
  const date  = document.getElementById('te-date').value;
  const desc  = document.getElementById('te-description').value.trim();
  const hours = parseFloat(document.getElementById('te-hours').value) || 0;
  const rate  = parseFloat(document.getElementById('te-rate').value) || 0;
  const dealId    = document.getElementById('te-deal').value || null;
  const contactId = document.getElementById('te-contact').value || null;
  const billable  = document.getElementById('te-billable').checked;

  if (!desc && !hours) { toast('Enter a description and hours', 'error'); return; }
  if (hours <= 0)      { toast('Hours must be greater than 0', 'error'); return; }

  const payload = { date, description: desc, hours, rate, dealId, contactId, billable };
  try {
    if (id) {
      await apiRequest('PUT', `/time-entries/${id}`, payload);
    } else {
      await apiPost('/time-entries', payload);
    }
    closeModal('time-entry-modal');
    toast('Time entry saved', 'success');
    await loadTimeEntries();
    if (currentView === 'time') renderTimeEntries();
    if (currentView === 'deal-detail' && dealId) renderDealDetail(dealId);
    if (currentView === 'contact-detail' && contactId) renderContactDetail(contactId);
  } catch(e) { toast(e.message, 'error'); }
}

function editTimeEntry(id) {
  const entry = _timeEntries.find(e => e.id === id);
  if (!entry) return;
  openTimeEntryModal(entry.dealId, entry.contactId);
  setTimeout(() => {
    const modal = document.getElementById('time-entry-modal');
    if (!modal) return;
    // Add hidden id field
    const idInput = document.createElement('input');
    idInput.type = 'hidden'; idInput.id = 'te-id'; idInput.value = id;
    modal.querySelector('.modal').appendChild(idInput);
    modal.querySelector('#te-date').value = entry.date || '';
    modal.querySelector('#te-description').value = entry.description || '';
    modal.querySelector('#te-hours').value = entry.hours || '';
    modal.querySelector('#te-rate').value = entry.rate || '';
    if (entry.dealId) modal.querySelector('#te-deal').value = entry.dealId;
    if (entry.contactId) modal.querySelector('#te-contact').value = entry.contactId;
    modal.querySelector('#te-billable').checked = entry.billable;
  }, 50);
}

async function deleteTimeEntry(id) {
  if (!confirm('Delete this time entry?')) return;
  await apiDelete('/time-entries/' + id);
  toast('Time entry deleted', 'success');
  _timeEntries = _timeEntries.filter(e => e.id !== id);
  renderTimeEntries();
}

function closeModal(id) {
  const el = document.getElementById(id);
  if (el) el.remove();
}

// Time summary panel for deal/contact detail
async function renderTimeSummaryPanel(dealId, contactId) {
  const filter = dealId ? `dealId=${dealId}` : `contactId=${contactId}`;
  const [entries, totals] = await Promise.all([
    apiGet(`/time-entries?${filter}`),
    apiGet(`/time-entries/totals?${filter}`),
  ]);

  const panel = document.createElement('div');
  panel.className = 'panel';
  panel.style.cssText = 'margin:0';

  const unbiledEntries = entries.filter(e => !e.invoiceId);

  panel.innerHTML = `
    <div class="panel-header">
      <div class="panel-title">Time Tracking</div>
      <div style="display:flex;gap:8px;align-items:center">
        <span style="font-size:11px;color:var(--text-muted)">${(totals.totalHours||0).toFixed(1)} hrs / $${(totals.billableAmount||0).toFixed(2)} billable</span>
        <button class="btn btn-secondary btn-xs" onclick="openTimeEntryModal('${dealId||''}','${contactId||''}')">Log Time</button>
        ${dealId && unbiledEntries.length ? `<button class="btn btn-primary btn-xs" onclick="createInvoiceFromTime('${dealId}')">Create Invoice from Time</button>` : ''}
      </div>
    </div>
    <div style="max-height:260px;overflow-y:auto">
      ${entries.length === 0
        ? `<div style="padding:16px;text-align:center;color:var(--text-muted);font-size:12px">No time logged yet.</div>`
        : `<table style="width:100%;font-size:12px;border-collapse:collapse">
          <thead><tr style="background:var(--surface2)">
            <th style="padding:6px 12px;text-align:left;font-weight:500;color:var(--text-muted);font-size:11px">Date</th>
            <th style="padding:6px 12px;text-align:left;font-weight:500;color:var(--text-muted);font-size:11px">Description</th>
            <th style="padding:6px 12px;text-align:right;font-weight:500;color:var(--text-muted);font-size:11px">Hours</th>
            <th style="padding:6px 12px;text-align:right;font-weight:500;color:var(--text-muted);font-size:11px">Amount</th>
            <th style="padding:6px 12px;text-align:center;font-weight:500;color:var(--text-muted);font-size:11px">Status</th>
          </tr></thead>
          <tbody>
          ${entries.map(e => `<tr style="border-top:1px solid var(--border)">
            <td style="padding:6px 12px;color:var(--text-muted)">${e.date||''}</td>
            <td style="padding:6px 12px">${esc(e.description||'')}</td>
            <td style="padding:6px 12px;text-align:right;font-weight:500">${(e.hours||0).toFixed(2)}</td>
            <td style="padding:6px 12px;text-align:right;color:var(--green)">${e.billable && e.rate ? '$' + (e.hours*e.rate).toFixed(2) : '—'}</td>
            <td style="padding:6px 12px;text-align:center">
              <span style="font-size:10px;font-weight:600;color:${e.invoiceId ? 'var(--green)' : 'var(--text-muted)'}">${e.invoiceId ? 'Invoiced' : (e.billable ? 'Pending' : 'Non-billable')}</span>
            </td>
          </tr>`).join('')}
          </tbody>
        </table>`}
    </div>`;
  return panel;
}

async function createInvoiceFromTime(dealId) {
  const deal = (db.deals || []).find(d => d.id === dealId);
  if (!deal) return;
  const entries = await apiGet(`/time-entries?dealId=${dealId}`);
  const unbilled = entries.filter(e => !e.invoiceId && e.billable);
  if (!unbilled.length) { toast('No unbilled time entries for this deal', 'warning'); return; }

  // Build invoice items from time entries
  const items = unbilled.map(e => ({
    name: e.description || 'Time Entry',
    description: `${e.date} — ${(e.hours||0).toFixed(2)} hrs @ $${e.rate}/hr`,
    qty: e.hours || 0,
    price: e.rate || 0,
    total: (e.hours||0) * (e.rate||0),
  }));

  const subtotal = items.reduce((s, i) => s + i.total, 0);
  const invSettings = db.settings?.invoiceSettings || { prefix: 'INV-', nextNumber: 1001 };
  const number = (invSettings.prefix || 'INV-') + (invSettings.nextNumber || 1001);

  try {
    const inv = await apiPost('/invoices', {
      number,
      dealId: deal.id,
      contactId: deal.contact || null,
      status: 'Draft',
      items,
      subtotal,
      tax: 0,
      total: subtotal,
      issueDate: new Date().toISOString().slice(0,10),
      notes: `Invoice generated from time entries for deal: ${deal.name}`,
    });

    // Increment invoice number
    await apiPut('/settings/invoiceSettings', { ...invSettings, nextNumber: (invSettings.nextNumber || 1001) + 1 });
    db.settings.invoiceSettings = { ...invSettings, nextNumber: (invSettings.nextNumber || 1001) + 1 };

    // Mark entries as invoiced
    await apiPost('/time-entries/mark-invoiced', { entryIds: unbilled.map(e => e.id), invoiceId: inv.id });
    _timeEntries = _timeEntries.map(e => unbilled.find(u => u.id === e.id) ? { ...e, invoiceId: inv.id } : e);

    // Add to local db
    db.invoices = [...(db.invoices || []), inv];

    toast(`Invoice ${number} created from ${unbilled.length} time entries`, 'success');
    navigate('invoice-detail', inv.id);
  } catch(e) { toast(e.message, 'error'); }
}

