// 20.B  PRODUCT BUNDLES
// ══════════════════════════════════════════════════════════════════════════════

let _bundles = [];

async function loadBundles() {
  _bundles = await apiGet('/product-bundles');
  return _bundles;
}

async function renderBundlesList() {
  const container = document.getElementById('bundles-list');
  if (!container) return;
  if (!_bundles.length) {
    container.innerHTML = '<div style="color:var(--text-muted);font-size:12px;padding:8px">No bundles yet. Create one to group products for faster invoicing.</div>';
    return;
  }
  container.innerHTML = _bundles.map(b => `
    <div style="border:1px solid var(--border);border-radius:8px;padding:12px;margin-bottom:8px">
      <div style="display:flex;align-items:flex-start;justify-content:space-between;gap:8px">
        <div>
          <div style="font-weight:500;font-size:13px">${esc(b.name)}</div>
          ${b.description ? `<div style="font-size:11px;color:var(--text-muted);margin-top:2px">${esc(b.description)}</div>` : ''}
          <div style="display:flex;flex-wrap:wrap;gap:4px;margin-top:6px">
            ${b.items.map(i => `<span style="background:var(--surface2);border:1px solid var(--border);border-radius:4px;padding:2px 6px;font-size:11px">${esc(i.productName)} x${i.quantity}</span>`).join('')}
          </div>
        </div>
        <div style="display:flex;gap:4px;flex-shrink:0">
          <button class="btn btn-ghost btn-xs" onclick="editBundle('${b.id}')">Edit</button>
          <button class="btn btn-ghost btn-xs" style="color:var(--red)" onclick="deleteBundle('${b.id}')">Delete</button>
        </div>
      </div>
    </div>`).join('');
}

function openBundleModal(bundleId) {
  const bundle = bundleId ? _bundles.find(b => b.id === bundleId) : null;
  const products = db.products || [];
  const modal = document.createElement('div');
  modal.id = 'bundle-modal';
  modal.className = 'modal-overlay p20-modal';
  modal.innerHTML = `
    <div class="modal" style="width:560px">
      <div class="modal-header">
        <div class="modal-title">${bundle ? 'Edit Bundle' : 'New Bundle'}</div>
        <button class="modal-close" onclick="closeModal('bundle-modal')">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="16" height="16"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
        </button>
      </div>
      <div style="padding:20px;display:flex;flex-direction:column;gap:14px">
        ${bundle ? `<input type="hidden" id="bundle-id" value="${bundle.id}" />` : ''}
        <div class="form-group">
          <label class="form-label">Bundle Name</label>
          <input type="text" class="form-input" id="bundle-name" value="${esc(bundle?.name || '')}" placeholder="e.g. Starter Package" />
        </div>
        <div class="form-group">
          <label class="form-label">Description (optional)</label>
          <input type="text" class="form-input" id="bundle-desc" value="${esc(bundle?.description || '')}" placeholder="Short description" />
        </div>
        <div class="form-group">
          <label class="form-label">Products in Bundle</label>
          <div id="bundle-items-list" style="display:flex;flex-direction:column;gap:6px;margin-bottom:8px">
            ${(bundle?.items || []).map((item, idx) => `
              <div class="bundle-item-row" style="display:flex;gap:8px;align-items:center">
                <select class="form-select" name="bundle-prod" style="flex:1;font-size:12px">
                  ${products.map(p => `<option value="${p.id}" ${p.id === item.productId ? 'selected' : ''}>${esc(p.name)} — $${p.price}</option>`).join('')}
                </select>
                <input type="number" name="bundle-qty" class="form-input" value="${item.quantity}" min="1" step="0.5" style="width:70px;font-size:12px" placeholder="Qty" />
                <button class="btn btn-ghost btn-xs" style="color:var(--red)" onclick="this.closest('.bundle-item-row').remove()">X</button>
              </div>`).join('')}
          </div>
          <button class="btn btn-secondary btn-sm" onclick="addBundleItemRow()">+ Add Product</button>
        </div>
      </div>
      <div class="modal-footer">
        <button class="btn btn-secondary" onclick="closeModal('bundle-modal')">Cancel</button>
        <button class="btn btn-primary" onclick="saveBundle()">Save Bundle</button>
      </div>
    </div>`;
  document.body.appendChild(modal);
  modal.addEventListener('click', e => { if (e.target === modal) closeModal('bundle-modal'); });
  if (!bundle || !bundle.items.length) addBundleItemRow();
}

function addBundleItemRow() {
  const list = document.getElementById('bundle-items-list');
  if (!list) return;
  const products = db.products || [];
  const row = document.createElement('div');
  row.className = 'bundle-item-row';
  row.style.cssText = 'display:flex;gap:8px;align-items:center';
  row.innerHTML = `
    <select class="form-select" name="bundle-prod" style="flex:1;font-size:12px">
      ${products.map(p => `<option value="${p.id}">${esc(p.name)} — $${p.price}</option>`).join('')}
    </select>
    <input type="number" name="bundle-qty" class="form-input" value="1" min="1" step="0.5" style="width:70px;font-size:12px" placeholder="Qty" />
    <button class="btn btn-ghost btn-xs" style="color:var(--red)" onclick="this.closest('.bundle-item-row').remove()">X</button>`;
  list.appendChild(row);
}

async function saveBundle() {
  const id   = document.getElementById('bundle-id')?.value;
  const name = document.getElementById('bundle-name').value.trim();
  const desc = document.getElementById('bundle-desc').value.trim();
  if (!name) { toast('Bundle name required', 'error'); return; }

  const rows = document.querySelectorAll('.bundle-item-row');
  const items = Array.from(rows).map(row => ({
    productId: row.querySelector('[name=bundle-prod]').value,
    quantity:  parseFloat(row.querySelector('[name=bundle-qty]').value) || 1,
  })).filter(i => i.productId);

  try {
    if (id) {
      const updated = await apiRequest('PUT', `/product-bundles/${id}`, { name, description: desc, items });
      _bundles = _bundles.map(b => b.id === id ? updated : b);
    } else {
      const created = await apiPost('/product-bundles', { name, description: desc, items });
      _bundles.push(created);
    }
    closeModal('bundle-modal');
    toast('Bundle saved', 'success');
    renderBundlesList();
  } catch(e) { toast(e.message, 'error'); }
}

function editBundle(id) { openBundleModal(id); }

async function deleteBundle(id) {
  if (!confirm('Delete this bundle?')) return;
  await apiDelete('/product-bundles/' + id);
  _bundles = _bundles.filter(b => b.id !== id);
  toast('Bundle deleted', 'success');
  renderBundlesList();
}

// Add bundle to invoice/proposal (bundle picker)
function openBundlePicker(onSelect) {
  if (!_bundles.length) { toast('No bundles configured. Create one in Settings.', 'warning'); return; }
  const modal = document.createElement('div');
  modal.id = 'bundle-picker-modal';
  modal.className = 'modal-overlay p20-modal';
  modal.innerHTML = `
    <div class="modal" style="width:480px">
      <div class="modal-header">
        <div class="modal-title">Add Bundle</div>
        <button class="modal-close" onclick="closeModal('bundle-picker-modal')">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="16" height="16"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
        </button>
      </div>
      <div style="padding:20px;display:flex;flex-direction:column;gap:8px">
        ${_bundles.map(b => `
          <div onclick="selectBundle('${b.id}')" style="border:1px solid var(--border);border-radius:8px;padding:12px;cursor:pointer;transition:background 0.1s" onmouseenter="this.style.background='var(--surface2)'" onmouseleave="this.style.background=''">
            <div style="font-weight:500;font-size:13px">${esc(b.name)}</div>
            <div style="font-size:11px;color:var(--text-muted);margin-top:4px">
              ${b.items.map(i => `${esc(i.productName)} x${i.quantity}`).join(' · ')}
            </div>
            <div style="font-size:11px;color:var(--green);font-weight:600;margin-top:4px">
              Total: $${b.items.reduce((s,i) => s + i.productPrice * i.quantity, 0).toFixed(2)}
            </div>
          </div>`).join('')}
      </div>
    </div>`;
  document.body.appendChild(modal);
  modal.addEventListener('click', e => { if (e.target === modal) closeModal('bundle-picker-modal'); });
  window._bundlePickerCallback = onSelect;
}

function selectBundle(id) {
  const bundle = _bundles.find(b => b.id === id);
  closeModal('bundle-picker-modal');
  if (bundle && window._bundlePickerCallback) window._bundlePickerCallback(bundle);
}

