function addChecklistStep() {
  const list = document.getElementById('ct-steps-list');
  if (!list) return;
  const row = document.createElement('div');
  row.className = 'ct-step-row';
  row.style.cssText = 'display:flex;gap:8px;align-items:center';
  row.innerHTML = `
    <input type="text" class="form-input" name="ct-step" placeholder="Step description" style="flex:1;font-size:12px" />
    <button class="btn btn-ghost btn-xs" style="color:var(--red)" onclick="this.closest('.ct-step-row').remove()">X</button>`;
  list.appendChild(row);
  row.querySelector('input').focus();
}

async function saveChecklistTemplate() {
  const id   = document.getElementById('ct-id')?.value;
  const name = document.getElementById('ct-name').value.trim();
  if (!name) { toast('Template name required', 'error'); return; }
  const steps = Array.from(document.querySelectorAll('[name=ct-step]'))
    .map(i => ({ title: i.value.trim() })).filter(s => s.title);
  if (!steps.length) { toast('Add at least one step', 'error'); return; }

  try {
    if (id) {
      const updated = await apiRequest('PUT', `/checklist-templates/${id}`, { name, items: steps });
      _checklistTemplates = _checklistTemplates.map(t => t.id === id ? updated : t);
    } else {
      const created = await apiPost('/checklist-templates', { name, items: steps });
      _checklistTemplates.push(created);
    }
    closeModal('checklist-template-modal');
    toast('Checklist template saved', 'success');
    renderChecklistTemplatesList();
  } catch(e) { toast(e.message, 'error'); }
}

function editChecklistTemplate(id) { openChecklistTemplateModal(id); }

async function deleteChecklistTemplate(id) {
  if (!confirm('Delete this template?')) return;
  await apiDelete('/checklist-templates/' + id);
  _checklistTemplates = _checklistTemplates.filter(t => t.id !== id);
  toast('Template deleted', 'success');
  renderChecklistTemplatesList();
}

// Apply a checklist template to a deal
async function applyChecklistToDeal(dealId) {
  if (!_checklistTemplates.length) {
    toast('No checklist templates. Create one in Settings first.', 'warning');
    return;
  }
  const modal = document.createElement('div');
  modal.id = 'apply-checklist-modal';
  modal.className = 'modal-overlay p20-modal';
  modal.innerHTML = `
    <div class="modal" style="width:420px">
      <div class="modal-header">
        <div class="modal-title">Apply Checklist</div>
        <button class="modal-close" onclick="closeModal('apply-checklist-modal')">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="16" height="16"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
        </button>
      </div>
      <div style="padding:20px;display:flex;flex-direction:column;gap:8px">
        ${_checklistTemplates.map(t => `
          <div onclick="doApplyChecklist('${dealId}','${t.id}')" style="border:1px solid var(--border);border-radius:8px;padding:12px;cursor:pointer;transition:background 0.1s" onmouseenter="this.style.background='var(--surface2)'" onmouseleave="this.style.background=''">
            <div style="font-weight:500;font-size:13px">${esc(t.name)}</div>
            <div style="font-size:11px;color:var(--text-muted);margin-top:2px">${t.items.length} steps</div>
          </div>`).join('')}
      </div>
    </div>`;
  document.body.appendChild(modal);
  modal.addEventListener('click', e => { if (e.target === modal) closeModal('apply-checklist-modal'); });
}

async function doApplyChecklist(dealId, templateId) {
  try {
    await apiPost('/deal-checklists', { dealId, templateId });
    closeModal('apply-checklist-modal');
    toast('Checklist applied', 'success');
    renderDealDetail(dealId);
  } catch(e) { toast(e.message, 'error'); }
}

async function renderDealChecklistsPanel(dealId) {
  const checklists = await apiGet(`/deal-checklists?dealId=${dealId}`);
  if (!checklists.length) return null;

  const panel = document.createElement('div');
  panel.className = 'panel';
  panel.style.cssText = 'margin:0';
  panel.innerHTML = `
    <div class="panel-header">
      <div class="panel-title">Onboarding Checklist</div>
    </div>
    <div style="padding:12px;display:flex;flex-direction:column;gap:12px">
      ${checklists.map(cl => `
        <div>
          <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:6px">
            <div style="font-size:12px;font-weight:600">${esc(cl.name)}</div>
            <div style="display:flex;align-items:center;gap:8px">
              <span style="font-size:11px;color:var(--text-muted)">${cl.done}/${cl.total}</span>
              <button class="btn btn-ghost btn-xs" style="color:var(--red)" onclick="deleteDealChecklist('${cl.id}','${dealId}')">Remove</button>
            </div>
          </div>
          <div style="height:4px;background:var(--surface2);border-radius:2px;margin-bottom:8px">
            <div style="height:100%;width:${cl.progress}%;background:${cl.progress === 100 ? 'var(--green)' : 'var(--accent)'};border-radius:2px;transition:width 0.3s"></div>
          </div>
          <div style="display:flex;flex-direction:column;gap:4px">
            ${cl.items.map(item => `
              <label style="display:flex;align-items:center;gap:8px;cursor:pointer;font-size:12px;padding:4px 0">
                <input type="checkbox" ${item.done ? 'checked' : ''} onchange="toggleChecklistItem('${item.id}','${cl.id}','${dealId}')" />
                <span style="${item.done ? 'text-decoration:line-through;color:var(--text-muted)' : ''}">${esc(item.title)}</span>
              </label>`).join('')}
          </div>
        </div>`).join('<hr style="border:none;border-top:1px solid var(--border);margin:4px 0">')}
    </div>`;
  return panel;
}

async function toggleChecklistItem(itemId, checklistId, dealId) {
  await apiRequest('PATCH', `/deal-checklist-items/${itemId}/toggle`, {});
  // Re-render checklists panel
  const existing = document.getElementById('deal-checklists-panel');
  if (existing) {
    const newPanel = await renderDealChecklistsPanel(dealId);
    if (newPanel) {
      newPanel.id = 'deal-checklists-panel';
      existing.replaceWith(newPanel);
    }
  }
}

async function deleteDealChecklist(checklistId, dealId) {
  if (!confirm('Remove this checklist from the deal?')) return;
  await apiDelete('/deal-checklists/' + checklistId);
  toast('Checklist removed', 'success');
  const existing = document.getElementById('deal-checklists-panel');
  if (existing) {
    const newPanel = await renderDealChecklistsPanel(dealId);
    if (newPanel) {
      newPanel.id = 'deal-checklists-panel';
      existing.replaceWith(newPanel);
    } else { existing.remove(); }
  }
}

// ══════════════════════════════════════════════════════════════════════════════
// 20.D  EMAIL TEMPLATES 2.0
// ══════════════════════════════════════════════════════════════════════════════

const EMAIL_TEMPLATE_CATEGORIES = ['General', 'Intro', 'Follow-up', 'Proposal', 'Closing'];
const TEMPLATE_VARS = {
  '{{contact.name}}':    'John Smith',
  '{{contact.company}}': 'Acme Corp',
  '{{deal.name}}':       'Acme — Enterprise Deal',
  '{{deal.value}}':      '$50,000',
  '{{user.name}}':       _currentUser?.name || 'Your Name',
};

function renderTemplateWithVars(body, contact, deal, user) {
  let out = body || '';
  out = out.replace(/\{\{contact\.name\}\}/g, contact?.name || '[Contact Name]');
  out = out.replace(/\{\{contact\.company\}\}/g, (db.companies || []).find(c => c.id === contact?.company)?.name || '[Company]');
  out = out.replace(/\{\{deal\.name\}\}/g, deal?.name || '[Deal Name]');
  out = out.replace(/\{\{deal\.value\}\}/g, deal ? '$' + (deal.value || 0).toLocaleString() : '[Deal Value]');
  out = out.replace(/\{\{user\.name\}\}/g, user?.name || _currentUser?.name || '[Your Name]');
  return out;
}

function previewEmailTemplate(bodyId, previewId) {
  const body = document.getElementById(bodyId)?.value || '';
  const previewEl = document.getElementById(previewId);
  if (!previewEl) return;
  let rendered = body;
  Object.entries(TEMPLATE_VARS).forEach(([k, v]) => { rendered = rendered.replaceAll(k, `<span style="background:rgba(99,102,241,0.15);color:var(--accent);border-radius:3px;padding:0 3px">${v}</span>`); });
  previewEl.innerHTML = rendered.replace(/\n/g, '<br>');
}

const CATEGORY_COLORS = {
  'General':    '#6b7280',
  'Intro':      '#6366f1',
  'Follow-up':  '#3b82f6',
  'Proposal':   '#f97316',
  'Closing':    '#22c55e',
};

function categoryBadge(cat) {
  const color = CATEGORY_COLORS[cat] || '#6b7280';
  return `<span style="display:inline-block;background:${color}22;color:${color};border:1px solid ${color}55;border-radius:4px;padding:1px 6px;font-size:10px;font-weight:600;letter-spacing:0.03em">${esc(cat || 'General')}</span>`;
}

// Patch the existing openEmailTemplatesModal to support categories + preview
(function patchEmailTemplates() {
  const _origOpen = window.openEmailTemplatesModal;
  if (!_origOpen) return;

  window.openEmailTemplatesModal = function() {
    _origOpen.call(this);
    // After the modal opens, patch the template list rendering
    setTimeout(() => {
      const modal = document.getElementById('email-templates-modal');
      if (!modal) return;
      // Find the list container and re-render with categories
      const templates = (db.settings?.emailTemplates || []);
      const listEl = modal.querySelector('#email-templates-list');
      if (listEl) {
        listEl.innerHTML = templates.length === 0
          ? '<div style="color:var(--text-muted);font-size:12px;padding:12px">No templates yet. Create one below.</div>'
          : templates.map((t, i) => `
            <div style="border:1px solid var(--border);border-radius:8px;padding:12px;margin-bottom:8px">
              <div style="display:flex;align-items:flex-start;justify-content:space-between;gap:8px">
                <div style="flex:1">
                  <div style="display:flex;align-items:center;gap:8px;margin-bottom:4px">
                    <div style="font-weight:500;font-size:13px">${esc(t.name)}</div>
                    ${categoryBadge(t.category || 'General')}
                  </div>
                  <div style="font-size:11px;color:var(--text-muted)">Subject: ${esc(t.subject || '')}</div>
                  ${t.body ? `<div style="font-size:11px;color:var(--text-dim);margin-top:2px;white-space:pre-line;max-height:40px;overflow:hidden">${esc(t.body.slice(0,120))}${t.body.length > 120 ? '...' : ''}</div>` : ''}
                </div>
                <div style="display:flex;gap:4px;flex-shrink:0">
                  <button class="btn btn-ghost btn-xs" onclick="p20EditTemplate(${i})">Edit</button>
                  <button class="btn btn-ghost btn-xs" style="color:var(--red)" onclick="deleteEmailTemplate(${i})">Del</button>
                </div>
              </div>
            </div>`).join('');
      }

      // Patch the form area to add category + preview
      patchTemplateForm(modal);
    }, 100);
  };

  function patchTemplateForm(modal) {
    if (modal.dataset.p20patched) return;
    modal.dataset.p20patched = '1';
    // Add category field after name field if not already there
    const nameField = modal.querySelector('#et-name')?.closest('.form-group');
    if (nameField && !modal.querySelector('#et-category')) {
      const catDiv = document.createElement('div');
      catDiv.className = 'form-group';
      catDiv.innerHTML = `
        <label class="form-label">Category</label>
        <select class="form-select" id="et-category">
          ${EMAIL_TEMPLATE_CATEGORIES.map(c => `<option value="${c}">${c}</option>`).join('')}
        </select>`;
      nameField.after(catDiv);
    }
    // Add preview button after body field
    const bodyField = modal.querySelector('#et-body')?.closest('.form-group');
    if (bodyField && !modal.querySelector('#et-preview-btn')) {
      const previewBtn = document.createElement('button');
      previewBtn.id = 'et-preview-btn';
      previewBtn.className = 'btn btn-secondary btn-sm';
      previewBtn.style.cssText = 'margin-top:6px';
      previewBtn.textContent = 'Preview with Sample Data';
      previewBtn.onclick = function() {
        const body = modal.querySelector('#et-body')?.value || '';
        let rendered = body;
        Object.entries(TEMPLATE_VARS).forEach(([k, v]) => { rendered = rendered.replaceAll(k, v); });
        const previewEl = modal.querySelector('#et-preview');
        if (previewEl) { previewEl.style.display = ''; previewEl.innerHTML = '<strong style="font-size:11px;color:var(--text-muted)">Preview:</strong><div style="margin-top:6px;font-size:12px;line-height:1.6;white-space:pre-line">' + rendered + '</div>'; }
      };
      bodyField.after(previewBtn);
      // Add preview container
      const previewDiv = document.createElement('div');
      previewDiv.id = 'et-preview';
      previewDiv.style.cssText = 'display:none;border:1px solid var(--border);border-radius:6px;padding:10px;background:var(--surface2);margin-top:4px';
      previewBtn.after(previewDiv);
    }
    // Add variable hint
    const bodyEl = modal.querySelector('#et-body');
    if (bodyEl && !modal.querySelector('.et-vars-hint')) {
      const hint = document.createElement('div');
      hint.className = 'et-vars-hint';
      hint.style.cssText = 'font-size:10px;color:var(--text-muted);margin-top:4px';
      hint.innerHTML = 'Variables: <code>{{contact.name}}</code> <code>{{contact.company}}</code> <code>{{deal.name}}</code> <code>{{deal.value}}</code> <code>{{user.name}}</code>';
      bodyEl.parentElement.appendChild(hint);
    }
  }

  // Patch saveEmailTemplate to include category
  const _origSave = window.saveEmailTemplate;
  window.saveEmailTemplate = function() {
    const catEl = document.getElementById('et-category');
    const category = catEl ? catEl.value : 'General';
    // Stash the category so the original save can pick it up
    window._p20TemplateCategory = category;
    if (_origSave) _origSave.call(this);
  };
})();

window.p20EditTemplate = function(idx) {
  const templates = db.settings?.emailTemplates || [];
  const t = templates[idx];
  if (!t) return;
  // Use existing edit function
  if (typeof editEmailTemplate === 'function') editEmailTemplate(idx);
  setTimeout(() => {
    const catEl = document.getElementById('et-category');
    if (catEl && t.category) catEl.value = t.category;
  }, 150);
};

// ══════════════════════════════════════════════════════════════════════════════
// 20.E  SLA / STAGE HISTORY
// ══════════════════════════════════════════════════════════════════════════════

let _slaLimits = {};
let _dealsSLAStatus = {};

async function loadSLAData() {
  const row = await apiGet('/settings').catch(() => ({}));
  _slaLimits = row.slaLimits || {};
  try { _dealsSLAStatus = await apiGet('/deals-sla-status'); } catch { _dealsSLAStatus = {}; }
  return { _slaLimits, _dealsSLAStatus };
}

function renderSLALimitsList() {
  const container = document.getElementById('sla-limits-list');
  if (!container) return;
  const stages = getDealStages();
  container.innerHTML = stages.map(stage => `
    <div style="display:flex;align-items:center;gap:12px">
      <div style="width:140px;font-size:12px;font-weight:500;color:var(--text)">${esc(stage)}</div>
      <input type="number" class="form-input" id="sla-${stage.replace(/\s+/g,'-')}" value="${_slaLimits[stage] || ''}" placeholder="Max days" min="1" style="width:100px;font-size:12px" />
      <div style="font-size:11px;color:var(--text-muted)">days</div>
    </div>`).join('');
}

async function saveSLALimits() {
  const stages = getDealStages();
  const limits = {};
  stages.forEach(stage => {
    const val = parseFloat(document.getElementById(`sla-${stage.replace(/\s+/g,'-')}`)?.value);
    if (val > 0) limits[stage] = val;
  });
  await apiPut('/settings/slaLimits', limits);
  _slaLimits = limits;
  toast('SLA limits saved', 'success');
}

async function renderStageHistoryPanel(dealId) {
  const history = await apiGet(`/deal-stage-log/${dealId}`).catch(() => []);
  if (!history.length) return null;

  const maxDays = Math.max(...history.map(h => h.daysSpent), 0.1);
  const panel = document.createElement('div');
  panel.className = 'panel';
  panel.style.cssText = 'margin:0';
  panel.innerHTML = `
    <div class="panel-header">
      <div class="panel-title">Stage History</div>
    </div>
    <div style="padding:12px;display:flex;flex-direction:column;gap:8px">
      ${history.map(h => {
        const slaLimit = _slaLimits[h.stage];
        const breached = slaLimit && h.daysSpent > slaLimit;
        const pct = Math.min((h.daysSpent / maxDays) * 100, 100);
        const color = breached ? '#ef4444' : (h.exitedAt ? 'var(--accent)' : 'var(--green)');
        return `
          <div>
            <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:3px">
              <div style="font-size:12px;font-weight:500;display:flex;align-items:center;gap:6px">
                <span style="width:10px;height:10px;border-radius:50%;background:${getStageColor(h.stage)};display:inline-block;flex-shrink:0"></span>
                ${esc(h.stage)}
                ${breached ? `<span style="background:#ef444422;color:#ef4444;border:1px solid #ef444455;border-radius:3px;padding:0 4px;font-size:10px;font-weight:600">SLA</span>` : ''}
                ${!h.exitedAt ? `<span style="background:var(--green)22;color:var(--green);border:1px solid var(--green)44;border-radius:3px;padding:0 4px;font-size:10px">Current</span>` : ''}
              </div>
              <div style="font-size:11px;color:var(--text-muted)">
                ${h.daysSpent.toFixed(1)} days
                ${slaLimit ? ` / ${slaLimit} day limit` : ''}
              </div>
            </div>
            <div style="height:6px;background:var(--surface2);border-radius:3px">
              <div style="height:100%;width:${pct}%;background:${color};border-radius:3px;transition:width 0.4s"></div>
            </div>
            <div style="font-size:10px;color:var(--text-muted);margin-top:2px">
              ${formatDate(h.enteredAt)} → ${h.exitedAt ? formatDate(h.exitedAt) : 'Present'}
            </div>
          </div>`;
      }).join('')}
    </div>`;
  return panel;
}

function getSLABadgeForDeal(deal) {
  const status = _dealsSLAStatus[deal.id];
  if (!status || !status.slaBreached) return '';
  return `<span style="background:#ef444422;color:#ef4444;border:1px solid #ef444455;border-radius:3px;padding:1px 5px;font-size:10px;font-weight:600;vertical-align:middle" title="SLA breached: ${status.daysInStage.toFixed(1)} days in ${status.stage} (limit: ${status.slaLimit} days)">SLA</span>`;
}

// ══════════════════════════════════════════════════════════════════════════════
// 20.F  CHECKLIST PROGRESS ON DEAL CARDS
// ══════════════════════════════════════════════════════════════════════════════

// Cache for checklist progress
const _checklistProgressCache = {};

async function loadAllChecklistProgress() {
  const deals = db.deals || [];
  await Promise.all(deals.map(async d => {
    try {
      const prog = await apiGet(`/deal-checklists/progress/${d.id}`);
      if (prog.total > 0) _checklistProgressCache[d.id] = prog;
    } catch {}
  }));
}

function checklistProgressHtml(dealId) {
  const prog = _checklistProgressCache[dealId];
  if (!prog || prog.total === 0) return '';
  return `
    <div style="margin-top:6px">
      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:2px">
        <span style="font-size:10px;color:var(--text-muted)">Checklist: ${prog.done}/${prog.total}</span>
        <span style="font-size:10px;color:${prog.progress === 100 ? 'var(--green)' : 'var(--text-muted)'}">${prog.progress}%</span>
      </div>
      <div style="height:3px;background:var(--surface2);border-radius:2px">
        <div style="height:100%;width:${prog.progress}%;background:${prog.progress === 100 ? 'var(--green)' : 'var(--accent)'};border-radius:2px"></div>
      </div>
    </div>`;
}

// ══════════════════════════════════════════════════════════════════════════════
// 20.G  PATCH: Wire into deal detail, pipeline cards, settings, and navigation
// ══════════════════════════════════════════════════════════════════════════════

// Patch renderDealDetail to inject Phase 20 panels
(function patchDealDetailForP20() {
  const _orig = window.renderDealDetail;
  if (!_orig) return;

  window.renderDealDetail = function(id) {
    _orig.call(this, id);
    setTimeout(async () => {
      const deal = (db.deals || []).find(d => d.id === id);
      if (!deal) return;

      // Find the right column to inject into
      const leftCol  = document.querySelector('#view-deal-detail .contact-detail-left');
      const rightCol = document.querySelector('#view-deal-detail .contact-detail-right');
      const pageContent = document.querySelector('#view-deal-detail .page-content');
      const targetCol = rightCol || leftCol || pageContent;
      if (!targetCol) return;

      // Ensure SLA data is loaded
      if (!Object.keys(_dealsSLAStatus).length) {
        try { _dealsSLAStatus = await apiGet('/deals-sla-status'); } catch {}
      }
      if (!Object.keys(_slaLimits).length) {
        try {
          const s = await apiGet('/settings');
          _slaLimits = s.slaLimits || {};
        } catch {}
      }

      // 1. Time tracking panel
      let timePanel = document.getElementById('deal-time-panel');
      if (!timePanel) {
        timePanel = await renderTimeSummaryPanel(id, null);
        if (timePanel) {
          timePanel.id = 'deal-time-panel';
          timePanel.style.marginTop = '0';
          // Insert a wrapper div
          const wrap = document.createElement('div');
          wrap.style.cssText = 'padding:0 0 12px 0';
          wrap.appendChild(timePanel);
          targetCol.appendChild(wrap);
        }
      }

      // 2. Checklists panel
      let clPanel = document.getElementById('deal-checklists-panel');
      if (!clPanel) {
        const rendered = await renderDealChecklistsPanel(id);
        if (rendered) {
          rendered.id = 'deal-checklists-panel';
          const wrap = document.createElement('div');
          wrap.style.cssText = 'padding:0 0 12px 0';
          wrap.appendChild(rendered);
          targetCol.appendChild(wrap);
        }
      }

      // 3. Stage History panel
      let histPanel = document.getElementById('deal-stage-history-panel');
      if (!histPanel) {
        const rendered = await renderStageHistoryPanel(id);
        if (rendered) {
          rendered.id = 'deal-stage-history-panel';
          const wrap = document.createElement('div');
          wrap.style.cssText = 'padding:0 0 12px 0';
          wrap.appendChild(rendered);
          targetCol.appendChild(wrap);
        }
      }

      // 4. Inject "Apply Checklist" button in header actions
      const headerActions = document.querySelector('#view-deal-detail .header-actions');
      if (headerActions && !headerActions.querySelector('.p20-checklist-btn')) {
        const btn = document.createElement('button');
        btn.className = 'btn btn-secondary p20-checklist-btn';
        btn.textContent = 'Apply Checklist';
        btn.onclick = () => applyChecklistToDeal(id);
        headerActions.insertBefore(btn, headerActions.firstChild);
      }

      // 5. SLA warning in deal header
      const slaStatus = _dealsSLAStatus[id];
      if (slaStatus?.slaBreached) {
        const titleEl = document.querySelector('#view-deal-detail .page-title');
        if (titleEl && !titleEl.querySelector('.sla-badge')) {
          const badge = document.createElement('span');
          badge.className = 'sla-badge';
          badge.style.cssText = 'margin-left:8px;background:#ef444422;color:#ef4444;border:1px solid #ef444455;border-radius:4px;padding:2px 7px;font-size:11px;font-weight:600;vertical-align:middle';
          badge.title = `SLA breached: ${slaStatus.daysInStage.toFixed(1)} days in ${slaStatus.stage} (limit: ${slaStatus.slaLimit} days)`;
          badge.textContent = 'SLA Exceeded';
          titleEl.appendChild(badge);
        }
      }
    }, 400);
  };
})();

// Patch renderContactDetail to inject time panel
(function patchContactDetailForP20() {
  const _orig = window.renderContactDetail;
  if (!_orig) return;
  window.renderContactDetail = function(id) {
    _orig.call(this, id);
    setTimeout(async () => {
      const rightCol = document.querySelector('#view-contact-detail .contact-detail-right');
      const pageContent = document.querySelector('#view-contact-detail .page-content');
      const targetCol = rightCol || pageContent;
      if (!targetCol) return;

      let timePanel = document.getElementById('contact-time-panel');
      if (!timePanel) {
        timePanel = await renderTimeSummaryPanel(null, id);
        if (timePanel) {
          timePanel.id = 'contact-time-panel';
          const wrap = document.createElement('div');
          wrap.style.cssText = 'padding:0 0 12px 0';
          wrap.appendChild(timePanel);
          targetCol.appendChild(wrap);
        }
      }
    }, 450);
  };
})();

// Patch renderSettings to load Phase 20 data
(function patchSettingsForP20() {
  const _orig = window.renderSettings;
  window.renderSettings = async function() {
    if (_orig) _orig.call(this);
    setTimeout(async () => {
      await loadBundles();
      renderBundlesList();
      await loadChecklistTemplates();
      renderChecklistTemplatesList();
      // SLA limits
      try {
        const s = await apiGet('/settings');
        _slaLimits = s.slaLimits || {};
        renderSLALimitsList();
      } catch {}
    }, 200);
  };
})();

// Patch renderView to handle 'time' route
(function patchRouterForP20() {
  const _orig = window.renderView;
  window.renderView = function(view, param) {
    if (view === 'time') { loadTimeView(); return; }
    if (_orig) _orig.call(this, view, param);
  };
})();

// Patch navigate to include 'time' in nav
(function patchNavigateForP20() {
  const _origNav = window.navigate;
  window.navigate = function(view, param) {
    document.querySelectorAll('.view').forEach(v => v.classList.remove('active'));
    document.querySelectorAll('.nav-item').forEach(n => n.classList.remove('active'));
    const el = document.getElementById('view-' + view);
    if (el) el.classList.add('active');
    const nav = document.querySelector(`.nav-item[data-view="${view}"]`);
    if (nav) nav.classList.add('active');
    currentView = view;
    renderView(view, param);
  };
})();

// ══════════════════════════════════════════════════════════════════════════════
// 20.H  SLA REPORTS TAB
// ══════════════════════════════════════════════════════════════════════════════

async function renderSLAReport() {
  const grid = document.querySelector('#view-reports .reports-grid');
  if (!grid) return;
  const report = await apiGet('/sla-report').catch(() => []);
  if (!report.length) return;

  const existingCard = document.getElementById('sla-report-card');
  if (existingCard) existingCard.remove();

  const card = document.createElement('div');
  card.id = 'sla-report-card';
  card.className = 'panel';
  card.style.cssText = 'grid-column:span 2;';
  card.innerHTML = `
    <div class="panel-header"><div class="panel-title">SLA Compliance by Stage</div></div>
    <div style="overflow-x:auto">
      <table style="width:100%;font-size:12px;border-collapse:collapse">
        <thead>
          <tr style="background:var(--surface2)">
            <th style="padding:8px 12px;text-align:left;font-weight:500;color:var(--text-muted)">Stage</th>
            <th style="padding:8px 12px;text-align:right;font-weight:500;color:var(--text-muted)">Deals</th>
            <th style="padding:8px 12px;text-align:right;font-weight:500;color:var(--text-muted)">Avg Days</th>
            <th style="padding:8px 12px;text-align:right;font-weight:500;color:var(--text-muted)">SLA Limit</th>
            <th style="padding:8px 12px;text-align:right;font-weight:500;color:var(--text-muted)">Compliant</th>
            <th style="padding:8px 12px;text-align:center;font-weight:500;color:var(--text-muted)">SLA Status</th>
          </tr>
        </thead>
        <tbody>
          ${report.map(row => {
            const good = !row.slaLimit || row.avgDays <= row.slaLimit;
            return `<tr style="border-top:1px solid var(--border)">
              <td style="padding:8px 12px;font-weight:500">
                <span style="display:inline-flex;align-items:center;gap:6px">
                  <span style="width:8px;height:8px;border-radius:50%;background:${getStageColor(row.stage)};display:inline-block"></span>
                  ${esc(row.stage)}
                </span>
              </td>
              <td style="padding:8px 12px;text-align:right;color:var(--text-muted)">${row.count}</td>
              <td style="padding:8px 12px;text-align:right;font-weight:500">${row.avgDays}d</td>
              <td style="padding:8px 12px;text-align:right;color:var(--text-muted)">${row.slaLimit ? row.slaLimit + 'd' : '—'}</td>
              <td style="padding:8px 12px;text-align:right">
                <span style="color:${row.pctCompliant >= 80 ? 'var(--green)' : row.pctCompliant >= 50 ? '#f97316' : '#ef4444'};font-weight:600">${row.pctCompliant}%</span>
                <span style="color:var(--text-muted)"> (${row.compliantCount}/${row.count})</span>
              </td>
              <td style="padding:8px 12px;text-align:center">
                <span style="background:${good ? 'var(--green)22' : '#ef444422'};color:${good ? 'var(--green)' : '#ef4444'};border:1px solid ${good ? 'var(--green)44' : '#ef444455'};border-radius:4px;padding:2px 8px;font-size:10px;font-weight:600">
                  ${good ? 'On Track' : 'Breached'}
                </span>
              </td>
            </tr>`;
          }).join('')}
        </tbody>
      </table>
    </div>`;
  grid.appendChild(card);
}

// Patch renderReports to add SLA tab
(function patchReportsForSLA() {
  const _orig = window.renderReports;
  window.renderReports = function() {
    if (_orig) _orig.call(this);
    setTimeout(() => renderSLAReport(), 300);
  };
})();

// ══════════════════════════════════════════════════════════════════════════════
// 20.I  BUNDLE PICKER INTEGRATION IN INVOICE EDITOR
// ══════════════════════════════════════════════════════════════════════════════

(function patchInvoiceEditorForBundles() {
  const _orig = window.renderInvoiceDetail;
  if (!_orig) return;
  window.renderInvoiceDetail = function(id) {
    _orig.call(this, id);
    setTimeout(() => {
      // Find the "+ Item" button in the invoice editor
      const addItemBtn = document.querySelector('#inv-line-items')?.closest('.panel')?.querySelector('[onclick*="addInvoiceLineItem"]')
        || document.querySelector('[onclick*="addInvoiceLineItem"]');
      if (!addItemBtn) return;
      if (document.getElementById('inv-add-bundle-btn')) return;
      const bundleBtn = document.createElement('button');
      bundleBtn.id = 'inv-add-bundle-btn';
      bundleBtn.className = 'btn btn-secondary btn-sm';
      bundleBtn.textContent = 'Add Bundle';
      bundleBtn.style.marginLeft = '8px';
      bundleBtn.onclick = function() {
        if (!_bundles.length) {
          toast('No bundles configured. Create one in Settings.', 'warning');
          return;
        }
        openBundlePicker(function(bundle) {
          // Add each bundle item using the existing line item mechanism
          bundle.items.forEach(item => {
            if (!window._currentInvItems) window._currentInvItems = [];
            const newItem = {
              id: uid(),
              description: item.productName,
              qty: item.quantity,
              rate: item.productPrice,
            };
            window._currentInvItems.push(newItem);
            const container = document.getElementById('inv-line-items');
            if (container && typeof renderLineItemRow === 'function') {
              const div = document.createElement('div');
              div.innerHTML = renderLineItemRow(newItem, window._currentInvItems.length - 1);
              container.appendChild(div.firstElementChild);
              if (typeof recalcInvoiceTotals === 'function') recalcInvoiceTotals();
            }
          });
          toast(`Bundle "${bundle.name}" added (${bundle.items.length} items)`, 'success');
        });
      };
      addItemBtn.parentElement.appendChild(bundleBtn);
    }, 400);
  };
})();

// ══════════════════════════════════════════════════════════════════════════════
// 20.J  STARTUP: Load Phase 20 data as part of app boot
// ══════════════════════════════════════════════════════════════════════════════

(function bootstrapP20() {
  const _origStart = window.startApp;
  window.startApp = async function() {
    if (_origStart) await _origStart.call(this);
    // Load Phase 20 supporting data
    try {
      await Promise.all([
        loadBundles(),
        loadChecklistTemplates(),
        loadTimeEntries(),
        loadSLAData(),
      ]);
    } catch(e) { console.warn('Phase 20 data load partial:', e.message); }
  };
})();

// ══════════════════════════════════════════════════════════════════════════════
// 20.K  EXPOSE GLOBALS
// ══════════════════════════════════════════════════════════════════════════════

// Fix closeModal to handle both dynamically-created and static modals
// Phase 20 modals are dynamic (appended to body and removed on close)
// Pre-existing modals use classList.open pattern
const _originalCloseModal = window.closeModal;
window.closeModal = function(id) {
  const el = document.getElementById(id);
  if (!el) return;
  // If it's a p20 dynamic modal (not in original HTML), remove it
  if (el.classList.contains('p20-modal')) {
    el.remove();
    return;
  }
  // Fall back to original behavior
  el.classList.remove('open');
  document.body.style.overflow = '';
};

window.openTimeEntryModal        = openTimeEntryModal;
window.saveTimeEntry             = saveTimeEntry;
window.editTimeEntry             = editTimeEntry;
window.deleteTimeEntry           = deleteTimeEntry;
window.loadTimeView              = loadTimeView;
window.renderTimeEntries         = renderTimeEntries;
window.createInvoiceFromTime     = createInvoiceFromTime;
window.renderTimeSummaryPanel    = renderTimeSummaryPanel;

window.openBundleModal           = openBundleModal;
window.addBundleItemRow          = addBundleItemRow;
window.saveBundle                = saveBundle;
window.editBundle                = editBundle;
window.deleteBundle              = deleteBundle;
