// ─────────────────────────────────────────────────────────────────────────────
// PHASE 21 § 1 — AI DEAL COACH
// Rule-based "Next Best Action" callout on deal cards
// ─────────────────────────────────────────────────────────────────────────────

// Default inactivity threshold in days
const DEAL_COACH_DEFAULT_THRESHOLD = 7;

function getDealCoachThreshold() {
  return (db.settings.dealCoachSettings && db.settings.dealCoachSettings.threshold != null)
    ? db.settings.dealCoachSettings.threshold
    : DEAL_COACH_DEFAULT_THRESHOLD;
}

function getDealCoachDismissed() {
  return db.settings.dealCoachDismissed || {};
}

function isDealCoachDismissed(dealId) {
  const dismissed = getDealCoachDismissed();
  return !!dismissed[dealId];
}

function dismissDealCoach(dealId) {
  if (!db.settings.dealCoachDismissed) db.settings.dealCoachDismissed = {};
  db.settings.dealCoachDismissed[dealId] = Date.now();
  saveDB();
  renderPipeline();
}

function markDealCoachDone(dealId) {
  dismissDealCoach(dealId);
  toast('Marked as done', 'success');
}

function getDealCoachSuggestion(deal) {
  if (deal.stage === 'Won' || deal.stage === 'Lost') return null;
  if (isDealCoachDismissed(deal.id)) return null;

  const threshold = getDealCoachThreshold();
  const now = Date.now();
  const todayStr = new Date().toISOString().slice(0, 10);

  // Find last activity for this deal
  const dealActivities = (db.activities || [])
    .filter(a => a.dealId === deal.id)
    .sort((a, b) => new Date(b.date) - new Date(a.date));

  const lastActivityDaysAgo = dealActivities.length
    ? Math.floor((now - new Date(dealActivities[0].date).getTime()) / 86400000)
    : null;
  const lastActivityType = dealActivities.length ? dealActivities[0].type : null;

  const isPastCloseDate = deal.closeDate && deal.closeDate < todayStr;
  const isInactive = lastActivityDaysAgo === null || lastActivityDaysAgo >= threshold;

  if (!isPastCloseDate && !isInactive) return null;

  // Rule-based suggestion by stage + last activity type
  const stage = deal.stage;
  let suggestion = '';

  if (isPastCloseDate) {
    // Past close date suggestions
    if (stage === 'Negotiation') {
      suggestion = 'Close date passed — finalize pricing and request a decision';
    } else if (stage === 'Proposal Sent') {
      suggestion = 'Follow up on proposal — check for blockers and confirm timeline';
    } else {
      suggestion = 'Close date has passed — check in to understand current status';
    }
  } else {
    // Inactive deal suggestions by stage
    if (stage === 'To Contact') {
      suggestion = 'Schedule an initial outreach call';
    } else if (stage === 'Contacted') {
      if (lastActivityType === 'Call') {
        suggestion = 'Send a follow-up email with relevant materials';
      } else if (lastActivityType === 'Email') {
        suggestion = 'Schedule a discovery call to advance the conversation';
      } else {
        suggestion = 'Re-engage — send a personalized check-in message';
      }
    } else if (stage === 'Proposal Sent') {
      if (lastActivityType === 'Email') {
        suggestion = 'Call to walk through the proposal and address questions';
      } else {
        suggestion = 'Send proposal follow-up — confirm receipt and set review date';
      }
    } else if (stage === 'Negotiation') {
      suggestion = 'Check in on timeline and internal approval process';
    } else {
      suggestion = 'Log an activity to keep this deal moving forward';
    }
  }

  return { suggestion, isPastCloseDate, lastActivityDaysAgo, lastActivityType };
}

// Patch renderDealCard to show AI Deal Coach callout
(function patchRenderDealCardForCoach() {
  const _orig = window.renderDealCard;
  if (!_orig) return;
  window.renderDealCard = function(d) {
    let html = _orig.call(this, d);
    const coach = getDealCoachSuggestion(d);
    if (!coach) return html;
    const coachHtml = `
      <div class="deal-coach-callout" style="margin-top:6px;padding:6px 8px;background:rgba(234,179,8,0.1);border:1px solid rgba(234,179,8,0.3);border-radius:5px;font-size:10px;line-height:1.4">
        <div style="font-weight:600;color:#ca8a04;margin-bottom:2px;font-size:9px;text-transform:uppercase;letter-spacing:0.05em">Next Best Action</div>
        <div style="color:var(--text-dim);margin-bottom:5px">${esc(coach.suggestion)}</div>
        <div style="display:flex;gap:5px">
          <button class="btn btn-ghost btn-xs" style="font-size:9px;padding:1px 6px;flex:1" onclick="event.stopPropagation();markDealCoachDone('${d.id}')">Mark Done</button>
          <button class="btn btn-ghost btn-xs" style="font-size:9px;padding:1px 6px;opacity:0.6" onclick="event.stopPropagation();dismissDealCoach('${d.id}')">Dismiss</button>
        </div>
      </div>`;
    // Insert before closing </div> of deal card
    return html.replace(/<\/div>\s*$/, coachHtml + '</div>');
  };
})();

// Settings for Deal Coach — called from settings panel
function saveDealCoachSettings() {
  const threshEl = document.getElementById('deal-coach-threshold');
  if (!threshEl) return;
  const threshold = parseInt(threshEl.value) || DEAL_COACH_DEFAULT_THRESHOLD;
  if (!db.settings.dealCoachSettings) db.settings.dealCoachSettings = {};
  db.settings.dealCoachSettings.threshold = threshold;
  saveDB();
  toast('Deal Coach settings saved', 'success');
}

function renderDealCoachSettings() {
  const container = document.getElementById('deal-coach-settings-panel');
  if (!container) return;
  const threshold = getDealCoachThreshold();
  container.innerHTML = `
    <div class="panel settings-card">
      <div class="settings-card-title">AI Deal Coach</div>
      <div style="margin-bottom:12px;font-size:12px;color:var(--text-muted)">Shows next-best-action suggestions on deal cards when deals are inactive or past close date.</div>
      <div class="form-group" style="max-width:200px">
        <label class="form-label">Inactivity Threshold (days)</label>
        <input type="number" class="form-input" id="deal-coach-threshold" value="${threshold}" min="1" max="90" />
      </div>
      <div style="margin-top:10px">
        <button class="btn btn-primary btn-sm" onclick="saveDealCoachSettings()">Save</button>
      </div>
    </div>`;
}

