let _installsCache = [];

async function loadInstalls(contactId, companyId) {
  try {
    let url = '/installs';
    const params = [];
    if (contactId) params.push('contactId=' + encodeURIComponent(contactId));
    if (companyId) params.push('companyId=' + encodeURIComponent(companyId));
    if (params.length) url += '?' + params.join('&');
    return await apiGet(url);
  } catch(e) { return []; }
}

async function loadUpcomingInstalls() {
  try { return await apiGet('/installs/upcoming'); } catch(e) { return []; }
}

function renderInstallsPanel(entityType, entityId, installs) {
  const createFn = entityType === 'contact'
    ? `openInstallModal('contact','${entityId}',null)`
    : `openInstallModal('company','${entityId}',null)`;

  if (!installs.length) return `
    <div class="panel" style="margin:12px 0">
      <div class="panel-header">
        <div class="panel-title">Installed Products</div>
        <button class="btn btn-secondary btn-sm panel-action" onclick="${createFn}">+ Add Install</button>
      </div>
      <div class="empty-state" style="padding:24px">
        <div class="empty-state-title">No installs tracked</div>
        <div class="empty-state-sub">Track products and services installed for this ${entityType}</div>
      </div>
    </div>`;

  const today = new Date().toISOString().slice(0, 10);
  return `
    <div class="panel" style="margin:12px 0">
      <div class="panel-header">
        <div class="panel-title">Installed Products</div>
        <span class="panel-count">${installs.length}</span>
        <button class="btn btn-secondary btn-sm panel-action" onclick="${createFn}">+ Add Install</button>
      </div>
      <div style="padding:0 12px 12px">
        ${installs.map(inst => {
          const isServiceDue = inst.nextService && inst.nextService <= today;
          const isWarrantyExp = inst.warrantyExpiry && inst.warrantyExpiry <= today;
          return `
          <div style="padding:10px;margin-top:8px;background:var(--surface2);border:1px solid ${isServiceDue ? 'rgba(239,68,68,0.4)' : 'var(--border)'};border-radius:6px">
            <div style="display:flex;align-items:flex-start;justify-content:space-between;gap:8px">
              <div style="flex:1;min-width:0">
                <div style="font-size:13px;font-weight:600;color:var(--text)">${esc(inst.productName || 'Unknown Product')}</div>
                ${inst.serialNumber ? `<div style="font-size:11px;color:var(--text-muted)">S/N: ${esc(inst.serialNumber)}</div>` : ''}
                ${inst.installDate ? `<div style="font-size:11px;color:var(--text-muted)">Installed: ${formatDate(inst.installDate)}</div>` : ''}
                ${inst.warrantyExpiry ? `<div style="font-size:11px;color:${isWarrantyExp ? 'var(--red)' : 'var(--text-muted)'}">Warranty: ${formatDate(inst.warrantyExpiry)}${isWarrantyExp ? ' — EXPIRED' : ''}</div>` : ''}
                ${inst.nextService ? `<div style="font-size:11px;color:${isServiceDue ? 'var(--red)' : 'var(--accent)'}">Next Service: ${formatDate(inst.nextService)}${isServiceDue ? ' — OVERDUE' : ''}</div>` : ''}
              </div>
              <button class="btn btn-ghost btn-xs" onclick="openInstallModal('${entityType}','${entityId}','${inst.id}')">Edit</button>
            </div>
          </div>`;
        }).join('')}
      </div>
    </div>`;
}

async function openInstallModal(entityType, entityId, installId) {
  // Populate product select
  const prodSel = document.getElementById('install-form-product');
  prodSel.innerHTML = `<option value="">Select product...</option>` +
    (db.products || []).map(p => `<option value="${p.id}" data-name="${esc(p.name)}">${esc(p.name)}</option>`).join('');

  const modal = document.getElementById('modal-install');
  const titleEl = document.getElementById('modal-install-title');
  const deleteBtn = document.getElementById('btn-delete-install');

  document.getElementById('install-form-id').value = '';
  document.getElementById('install-form-contact-id').value = entityType === 'contact' ? entityId : '';
  document.getElementById('install-form-company-id').value = entityType === 'company' ? entityId : '';
  document.getElementById('install-form-install-date').value = '';
  document.getElementById('install-form-serial').value = '';
  document.getElementById('install-form-warranty').value = '';
  document.getElementById('install-form-interval').value = '';
  document.getElementById('install-form-last-service').value = '';
  document.getElementById('install-form-next-service').value = '';
  document.getElementById('install-form-notes').value = '';
  prodSel.value = '';

  if (installId) {
    titleEl.textContent = 'Edit Install';
    deleteBtn.style.display = 'inline-flex';
    try {
      const installs = await loadInstalls(
        entityType === 'contact' ? entityId : null,
        entityType === 'company' ? entityId : null
      );
      const inst = installs.find(i => i.id === installId);
      if (inst) {
        document.getElementById('install-form-id').value = inst.id;
        document.getElementById('install-form-install-date').value = inst.installDate || '';
        document.getElementById('install-form-serial').value = inst.serialNumber || '';
        document.getElementById('install-form-warranty').value = inst.warrantyExpiry || '';
        document.getElementById('install-form-interval').value = inst.serviceInterval || '';
        document.getElementById('install-form-last-service').value = inst.lastService || '';
        document.getElementById('install-form-next-service').value = inst.nextService || '';
        document.getElementById('install-form-notes').value = inst.notes || '';
        if (inst.productId) prodSel.value = inst.productId;
      }
    } catch(e) {}
  } else {
    titleEl.textContent = 'Add Install';
    deleteBtn.style.display = 'none';
  }

  // Auto-compute next service when interval changes
  document.getElementById('install-form-interval').onchange = computeNextService;
  document.getElementById('install-form-last-service').onchange = computeNextService;

  openModal('modal-install');
}

function computeNextService() {
  const lastService = document.getElementById('install-form-last-service').value;
  const interval = parseInt(document.getElementById('install-form-interval').value) || 0;
  const nextEl = document.getElementById('install-form-next-service');
  if (lastService && interval > 0) {
    const next = new Date(lastService);
    next.setDate(next.getDate() + interval);
    nextEl.value = next.toISOString().slice(0, 10);
  }
}

async function saveInstall() {
  const id = document.getElementById('install-form-id').value;
  const productEl = document.getElementById('install-form-product');
  const productId = productEl.value;
  const productName = productEl.selectedOptions[0]?.dataset.name || productEl.selectedOptions[0]?.text || '';

  if (!productId) { toast('Please select a product', 'error'); return; }

  const data = {
    contactId:       document.getElementById('install-form-contact-id').value || null,
    companyId:       document.getElementById('install-form-company-id').value || null,
    productId,
    productName,
    installDate:     document.getElementById('install-form-install-date').value || null,
    serialNumber:    document.getElementById('install-form-serial').value.trim() || null,
    warrantyExpiry:  document.getElementById('install-form-warranty').value || null,
    serviceInterval: parseInt(document.getElementById('install-form-interval').value) || 0,
    lastService:     document.getElementById('install-form-last-service').value || null,
    nextService:     document.getElementById('install-form-next-service').value || null,
    notes:           document.getElementById('install-form-notes').value.trim() || null,
  };

  try {
    if (id) {
      await apiPut('/installs/' + id, data);
      toast('Install updated', 'success');
    } else {
      await apiPost('/installs', data);
      toast('Install added', 'success');
    }
    closeModal('modal-install');
    // Refresh detail page
    if (currentView === 'contact-detail' && data.contactId) renderContactDetail(data.contactId);
    if (currentView === 'company-detail' && data.companyId) renderCompanyDetail(data.companyId);
  } catch(e) {
    toast('Failed to save install', 'error');
  }
}

async function deleteInstall() {
  const id = document.getElementById('install-form-id').value;
  if (!id || !confirm('Delete this install record?')) return;
  try {
    const contactId = document.getElementById('install-form-contact-id').value;
    const companyId = document.getElementById('install-form-company-id').value;
    await apiDelete('/installs/' + id);
    toast('Install deleted', 'info');
    closeModal('modal-install');
    if (currentView === 'contact-detail' && contactId) renderContactDetail(contactId);
    if (currentView === 'company-detail' && companyId) renderCompanyDetail(companyId);
  } catch(e) {
    toast('Failed to delete install', 'error');
  }
}

