// ─────────────────────────────────────────────────────────────────────────────
// PHASE 21 § 3 — MULTI-CURRENCY SUPPORT
// ─────────────────────────────────────────────────────────────────────────────

const CURRENCY_SYMBOLS = {
  USD: '$', CAD: 'CA$', EUR: '\u20AC', GBP: '\u00A3',
  AUD: 'A$', MXN: 'MX$', CUSTOM: ''
};

const CURRENCY_DEFAULT_RATES = {
  USD: 1, CAD: 0.73, EUR: 1.08, GBP: 1.27, AUD: 0.65, MXN: 0.058, CUSTOM: 1
};

function getCurrencySettings() {
  return db.settings.currencySettings || { defaultCurrency: 'USD', rates: { ...CURRENCY_DEFAULT_RATES } };
}

function getDefaultCurrency() {
  return getCurrencySettings().defaultCurrency || 'USD';
}

function getExchangeRate(currency) {
  const settings = getCurrencySettings();
  return (settings.rates && settings.rates[currency] != null) ? settings.rates[currency] : (CURRENCY_DEFAULT_RATES[currency] || 1);
}

function convertToDefault(value, currency) {
  const defaultCurrency = getDefaultCurrency();
  if (currency === defaultCurrency || !currency) return value;
  // Convert: value in currency → USD (via rate as USD/currency), then to default
  const rateToUSD = getExchangeRate(currency); // rate = 1 currency = N USD
  const rateDefaultToUSD = getExchangeRate(defaultCurrency);
  return value * rateToUSD / rateDefaultToUSD;
}

function formatDealCurrency(value, currency) {
  if (!currency || currency === 'USD') return formatCurrency(value || 0);
  const sym = CURRENCY_SYMBOLS[currency] || currency + ' ';
  const v = value || 0;
  if (v >= 1000000) return sym + (v / 1000000).toFixed(1) + 'M';
  if (v >= 1000)    return sym + (v / 1000).toFixed(0) + 'K';
  return sym + v.toLocaleString();
}

// Patch renderDealCard to use deal currency
(function patchDealCardCurrency() {
  const _orig = window.renderDealCard;
  if (!_orig) return;
  window.renderDealCard = function(d) {
    // Temporarily override formatCurrency for this call by patching d.value display
    // We do this via a post-render replacement since renderDealCard generates HTML
    let html = _orig.call(this, d);
    if (d.currency && d.currency !== 'USD') {
      // Replace the formatted USD value with currency-aware value
      const usdVal = formatCurrency(d.value || 0);
      const dealVal = formatDealCurrency(d.value, d.currency);
      html = html.replace(
        new RegExp(usdVal.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'g'),
        dealVal + ' <span style="font-size:9px;color:var(--text-muted);font-weight:400">' + (d.currency || 'USD') + '</span>'
      );
    }
    return html;
  };
})();

// Patch openDealModal to set currency field
(function patchOpenDealModalCurrency() {
  const _orig = window.openDealModal;
  if (!_orig) return;
  window.openDealModal = function(id, defaultStage) {
    _orig.call(this, id, defaultStage);
    const deal = id ? db.deals.find(d => d.id === id) : null;
    const currencyEl = document.getElementById('deal-form-currency');
    if (currencyEl) {
      currencyEl.value = deal ? (deal.currency || getDefaultCurrency()) : getDefaultCurrency();
    }
  };
})();

// Patch saveDeal to capture currency
(function patchSaveDealCurrency() {
  const _orig = window.saveDeal;
  if (!_orig) return;
  window.saveDeal = function() {
    const currencyEl = document.getElementById('deal-form-currency');
    if (currencyEl) {
      // We need to inject currency into the save — patch by reading it before original runs
      // and writing it into the deal after
      const id = document.getElementById('deal-form-id').value;
      const currency = currencyEl.value || getDefaultCurrency();
      _orig.call(this);
      // Update the deal we just saved
      const deal = db.deals.find(d => id ? d.id === id : true);
      if (deal) {
        const targetId = id || db.deals[db.deals.length - 1]?.id;
        const targetDeal = db.deals.find(d => d.id === targetId);
        if (targetDeal) {
          targetDeal.currency = currency;
          saveDB();
        }
      }
    } else {
      _orig.call(this);
    }
  };
})();

// Pipeline total with currency conversion note
function getPipelineTotalWithCurrency(deals) {
  const defaultCurrency = getDefaultCurrency();
  const sym = CURRENCY_SYMBOLS[defaultCurrency] || defaultCurrency + ' ';
  const openDeals = deals.filter(d => d.stage !== 'Won' && d.stage !== 'Lost');
  const total = openDeals.reduce((sum, d) => sum + convertToDefault(d.value || 0, d.currency || defaultCurrency), 0);
  const hasMixed = openDeals.some(d => d.currency && d.currency !== defaultCurrency);
  const formatted = formatDealCurrency(total, defaultCurrency);
  return { total, formatted, hasMixed, sym, defaultCurrency };
}

// Currency Settings — rendered in the settings panel
function renderCurrencySettings() {
  const container = document.getElementById('currency-settings-panel');
  if (!container) return;
  const settings = getCurrencySettings();
  const currencies = ['USD', 'CAD', 'EUR', 'GBP', 'AUD', 'MXN', 'CUSTOM'];
  container.innerHTML = `
    <div class="panel settings-card">
      <div class="settings-card-title">Multi-Currency</div>
      <div style="margin-bottom:12px">
        <label class="form-label">Default Currency</label>
        <select class="form-select" id="currency-default-select" style="max-width:200px">
          ${currencies.map(c => `<option value="${c}" ${settings.defaultCurrency === c ? 'selected' : ''}>${c} — ${Object.keys(CURRENCY_SYMBOLS).includes(c) ? (CURRENCY_SYMBOLS[c] ? CURRENCY_SYMBOLS[c] + ' ' : '') + c : c}</option>`).join('')}
        </select>
      </div>
      <div style="margin-bottom:8px;font-size:12px;font-weight:500;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.05em">Exchange Rates (to USD)</div>
      <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(160px,1fr));gap:8px;margin-bottom:12px">
        ${currencies.filter(c => c !== 'USD').map(c => `
          <div>
            <label class="form-label" style="margin-bottom:3px">${c}</label>
            <input type="number" class="form-input" id="currency-rate-${c}" value="${(settings.rates && settings.rates[c] != null) ? settings.rates[c] : CURRENCY_DEFAULT_RATES[c]}" step="0.001" min="0" style="width:100%" />
          </div>`).join('')}
      </div>
      <button class="btn btn-primary btn-sm" onclick="saveCurrencySettings()">Save Currency Settings</button>
    </div>`;
}

function saveCurrencySettings() {
  const defaultCurrency = document.getElementById('currency-default-select')?.value || 'USD';
  const rates = { USD: 1 };
  ['CAD', 'EUR', 'GBP', 'AUD', 'MXN', 'CUSTOM'].forEach(c => {
    const el = document.getElementById('currency-rate-' + c);
    if (el) rates[c] = parseFloat(el.value) || CURRENCY_DEFAULT_RATES[c];
  });
  db.settings.currencySettings = { defaultCurrency, rates };
  saveDB();
  toast('Currency settings saved', 'success');
}

