async function loadDataHealth() {
  const container = document.getElementById('data-health-content');
  if (!container) return;
  container.innerHTML = `<div class="empty-state"><div class="empty-state-title">Loading...</div></div>`;
  try {
    const data = await apiGet('/data-health');
    renderDataHealth(data, container);
  } catch(e) {
    container.innerHTML = `<div class="empty-state"><div class="empty-state-title">Failed to load data health report</div></div>`;
  }
}

function renderDataHealth(data, container) {
  if (!container) container = document.getElementById('data-health-content');
  if (!container) return;

  const { overallScore, scores, issues, counts } = data;

  const scoreColor = (s) => s >= 80 ? 'var(--green)' : s >= 60 ? '#ca8a04' : 'var(--red)';
  const scoreBar = (s) => `
    <div style="height:6px;background:var(--surface3);border-radius:3px;margin-top:4px">
      <div style="height:100%;width:${s}%;background:${scoreColor(s)};border-radius:3px;transition:width 0.4s"></div>
    </div>`;

  const issueSection = (title, items, entityView, labelFn) => {
    if (!items || !items.length) return `
      <div style="padding:10px 0;border-bottom:1px solid var(--border)">
        <div style="display:flex;align-items:center;justify-content:space-between">
          <span style="font-size:12px;font-weight:500;color:var(--text)">${title}</span>
          <span style="font-size:11px;font-weight:600;color:var(--green);padding:1px 8px;background:rgba(34,197,94,0.1);border-radius:3px">None</span>
        </div>
      </div>`;
    return `
      <div style="padding:10px 0;border-bottom:1px solid var(--border)">
        <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:8px">
          <span style="font-size:12px;font-weight:500;color:var(--text)">${title}</span>
          <span style="font-size:11px;font-weight:600;padding:1px 8px;background:rgba(239,68,68,0.1);color:var(--red);border-radius:3px">${items.length}</span>
        </div>
        <div style="display:flex;flex-direction:column;gap:4px">
          ${items.slice(0, 8).map(item => {
            const name = item.name || (item.contacts ? item.contacts.map(c => c.name).join(' / ') : '');
            const id = item.id;
            const clickFn = id ? `navigate('${entityView}', '${id}')` : `navigate('${entityView}')`;
            return `<div style="font-size:11px;color:var(--accent-hover);cursor:pointer;padding:2px 0" onclick="${clickFn}">${esc(name)}${labelFn ? ' — ' + labelFn(item) : ''}</div>`;
          }).join('')}
          ${items.length > 8 ? `<div style="font-size:11px;color:var(--text-muted)">...and ${items.length - 8} more</div>` : ''}
        </div>
      </div>`;
  };

  const dupEmailSection = () => {
    if (!issues.dupByEmail || !issues.dupByEmail.length) return `
      <div style="padding:10px 0;border-bottom:1px solid var(--border)">
        <div style="display:flex;align-items:center;justify-content:space-between">
          <span style="font-size:12px;font-weight:500;color:var(--text)">Duplicate Emails</span>
          <span style="font-size:11px;font-weight:600;color:var(--green);padding:1px 8px;background:rgba(34,197,94,0.1);border-radius:3px">None</span>
        </div>
      </div>`;
    return `
      <div style="padding:10px 0;border-bottom:1px solid var(--border)">
        <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:8px">
          <span style="font-size:12px;font-weight:500;color:var(--text)">Duplicate Emails</span>
          <span style="font-size:11px;font-weight:600;padding:1px 8px;background:rgba(239,68,68,0.1);color:var(--red);border-radius:3px">${issues.dupByEmail.length}</span>
        </div>
        <div style="display:flex;flex-direction:column;gap:4px">
          ${issues.dupByEmail.slice(0, 5).map(dup => `
            <div style="font-size:11px;color:var(--text-dim);padding:2px 0">
              ${esc(dup.email)}: ${dup.contacts.map(c => `<span style="color:var(--accent-hover);cursor:pointer" onclick="navigate('contact-detail','${c.id}')">${esc(c.name)}</span>`).join(', ')}
            </div>`).join('')}
        </div>
      </div>`;
  };

  container.innerHTML = `
    <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(220px,1fr));gap:16px;margin-bottom:24px">
      <div class="panel" style="padding:16px">
        <div style="font-size:11px;font-weight:500;text-transform:uppercase;letter-spacing:0.05em;color:var(--text-muted);margin-bottom:6px">Overall Score</div>
        <div style="font-size:36px;font-weight:700;color:${scoreColor(overallScore)}">${overallScore}<span style="font-size:18px">%</span></div>
        ${scoreBar(overallScore)}
        <div style="font-size:11px;color:var(--text-muted);margin-top:6px">${counts.contacts} contacts, ${counts.companies} companies, ${counts.deals} deals</div>
      </div>
      <div class="panel" style="padding:16px">
        <div style="font-size:11px;font-weight:500;text-transform:uppercase;letter-spacing:0.05em;color:var(--text-muted);margin-bottom:10px">By Entity</div>
        <div style="display:flex;flex-direction:column;gap:8px">
          ${['contacts', 'companies', 'deals'].map(e => `
            <div>
              <div style="display:flex;justify-content:space-between;font-size:12px;margin-bottom:2px">
                <span style="color:var(--text);text-transform:capitalize">${e}</span>
                <span style="font-weight:600;color:${scoreColor(scores[e])}">${scores[e]}%</span>
              </div>
              ${scoreBar(scores[e])}
            </div>`).join('')}
        </div>
      </div>
      <div class="panel" style="padding:16px">
        <div style="font-size:11px;font-weight:500;text-transform:uppercase;letter-spacing:0.05em;color:var(--text-muted);margin-bottom:10px">Issue Summary</div>
        <div style="display:flex;flex-direction:column;gap:5px;font-size:12px">
          <div style="display:flex;justify-content:space-between"><span style="color:var(--text-muted)">Missing email</span><span style="font-weight:600;color:${issues.missingEmail.length ? 'var(--red)' : 'var(--green)'}">${issues.missingEmail.length}</span></div>
          <div style="display:flex;justify-content:space-between"><span style="color:var(--text-muted)">Missing phone</span><span style="font-weight:600;color:${issues.missingPhone.length ? '#ca8a04' : 'var(--green)'}">${issues.missingPhone.length}</span></div>
          <div style="display:flex;justify-content:space-between"><span style="color:var(--text-muted)">Missing website</span><span style="font-weight:600;color:${issues.missingWebsite.length ? '#ca8a04' : 'var(--green)'}">${issues.missingWebsite.length}</span></div>
          <div style="display:flex;justify-content:space-between"><span style="color:var(--text-muted)">Stale contacts</span><span style="font-weight:600;color:${issues.staleContacts.length ? 'var(--red)' : 'var(--green)'}">${issues.staleContacts.length}</span></div>
          <div style="display:flex;justify-content:space-between"><span style="color:var(--text-muted)">Duplicate emails</span><span style="font-weight:600;color:${issues.dupByEmail.length ? 'var(--red)' : 'var(--green)'}">${issues.dupByEmail.length}</span></div>
        </div>
      </div>
    </div>

    <div style="display:grid;grid-template-columns:1fr 1fr;gap:16px">
      <div class="panel" style="padding:16px">
        <div style="font-size:12px;font-weight:600;color:var(--text);margin-bottom:12px;padding-bottom:8px;border-bottom:1px solid var(--border)">Contact Issues</div>
        ${issueSection('Contacts Missing Email', issues.missingEmail, 'contact-detail', null)}
        ${issueSection('Contacts Missing Phone', issues.missingPhone, 'contact-detail', null)}
        ${issueSection('Stale Contacts (90+ days inactive)', issues.staleContacts, 'contact-detail', item => item.lastActivity ? 'Last active ' + timeAgo(item.lastActivity) : 'Never active')}
        ${dupEmailSection()}
      </div>
      <div class="panel" style="padding:16px">
        <div style="font-size:12px;font-weight:600;color:var(--text);margin-bottom:12px;padding-bottom:8px;border-bottom:1px solid var(--border)">Company &amp; Deal Issues</div>
        ${issueSection('Companies Missing Website', issues.missingWebsite, 'company-detail', null)}
        ${issueSection('Deals Missing Close Date', issues.missingClose, 'deal-detail', null)}
        ${issueSection('Deals Missing Owner', issues.missingOwner, 'deal-detail', null)}
      </div>
    </div>`;
}

