let _p21CommissionRates = [];
let _p21Commissions = [];
let _p21Meetings = [];
let _p21Territories = [];
let _p21SavedReports = [];

async function p21LoadAll() {
  try {
    const [rates, commissions, meetings, territories, savedReports] = await Promise.allSettled([
      apiGet('/commission-rates'),
      apiGet('/commissions'),
      apiGet('/meetings'),
      apiGet('/territories'),
      apiGet('/saved-reports'),
    ]);
    _p21CommissionRates = rates.status === 'fulfilled' ? rates.value : [];
    _p21Commissions = commissions.status === 'fulfilled' ? commissions.value : [];
    _p21Meetings = meetings.status === 'fulfilled' ? meetings.value : [];
    _p21Territories = territories.status === 'fulfilled' ? territories.value : [];
    _p21SavedReports = savedReports.status === 'fulfilled' ? savedReports.value : [];
  } catch(e) { console.warn('p21LoadAll partial:', e.message); }
}

