// ─────────────────────────────────────────────────────────────────────────────

function renderCommissionsSettings() {
  const users = (db.settings && db.settings.users) ? db.settings.users : [];
  const ratesHtml = _p21CommissionRates.length
    ? _p21CommissionRates.map(r => {
        const user = users.find(u => u.id === r.userId);
        const userName = user ? user.name : r.userId;
        return `<div class="p21-rate-row">
          <span style="flex:1;font-size:13px;color:var(--text)">${esc(userName)}</span>
          <span style="font-size:13px;color:var(--text-dim)">${r.ratePercent}% commission</span>
          <button class="btn btn-ghost btn-xs" onclick="p21DeleteCommissionRate('${r.id}','${r.userId}')">Remove</button>
        </div>`;
      }).join('')
    : '<div style="font-size:12px;color:var(--text-muted);padding:8px 0">No commission rates configured.</div>';

  const userOptions = users.map(u => `<option value="${esc(u.id)}">${esc(u.name)}</option>`).join('');

  return `
    <div class="panel settings-card" style="grid-column:span 2" id="settings-commissions-panel">
      <div class="panel-header">
        <div class="panel-title">Commission Rates</div>
      </div>
      <div style="padding:16px">
        <p style="font-size:12px;color:var(--text-muted);margin-bottom:12px">Set commission rates per rep. When a deal is moved to Won, a Pending commission record is auto-created based on the rep's rate and deal value.</p>
        <div id="commission-rates-list" style="display:flex;flex-direction:column;gap:6px;margin-bottom:12px">${ratesHtml}</div>
        <div style="display:flex;gap:8px;align-items:center;flex-wrap:wrap">
          <select class="form-select" id="new-commission-user" style="flex:1;min-width:120px;font-size:12px">
            <option value="">Select rep...</option>
            ${userOptions}
          </select>
          <input type="number" class="form-input" id="new-commission-rate" placeholder="Rate (%)" min="0" max="100" step="0.5" style="width:110px;font-size:12px" />
          <button class="btn btn-primary btn-sm" onclick="p21SaveCommissionRate()">Set Rate</button>
        </div>
      </div>
    </div>`;
}

async function p21SaveCommissionRate() {
  const userId = document.getElementById('new-commission-user').value;
  const rate = parseFloat(document.getElementById('new-commission-rate').value);
  if (!userId || isNaN(rate)) return toast('Select a rep and enter a rate', 'error');
  try {
    await apiPost('/commission-rates', { userId, ratePercent: rate, effectiveFrom: new Date().toISOString().slice(0,10) });
    _p21CommissionRates = await apiGet('/commission-rates');
    toast('Commission rate saved', 'success');
    const panel = document.getElementById('commission-rates-list');
    if (panel) {
      const users = (db.settings && db.settings.users) ? db.settings.users : [];
      panel.innerHTML = _p21CommissionRates.map(r => {
        const user = users.find(u => u.id === r.userId);
        return `<div class="p21-rate-row">
          <span style="flex:1;font-size:13px;color:var(--text)">${esc(user ? user.name : r.userId)}</span>
          <span style="font-size:13px;color:var(--text-dim)">${r.ratePercent}% commission</span>
          <button class="btn btn-ghost btn-xs" onclick="p21DeleteCommissionRate('${r.id}','${r.userId}')">Remove</button>
        </div>`;
      }).join('') || '<div style="font-size:12px;color:var(--text-muted)">No rates configured.</div>';
    }
  } catch(e) { toast(e.message, 'error'); }
}

async function p21DeleteCommissionRate(id, userId) {
  // Remove by userId (server does DELETE then re-insert, but we have no DELETE endpoint for rates)
  // We'll re-save with 0 rate as a workaround — actually we should add a proper delete
  // For now, filter out locally and call set with 0 (server already upserts)
  try {
    await apiPost('/commission-rates', { userId, ratePercent: 0 });
    _p21CommissionRates = await apiGet('/commission-rates');
    toast('Rate removed', 'success');
    if (typeof renderSettings === 'function') renderSettings();
  } catch(e) { toast(e.message, 'error'); }
}

async function renderCommissionsReport() {
  const el = document.getElementById('p21-commissions-report');
  if (!el) return;
  el.innerHTML = '<div style="color:var(--text-muted);font-size:13px;padding:16px">Loading commissions...</div>';
  try {
    const [commissions, summary] = await Promise.all([
      apiGet('/commissions'),
      apiGet('/commissions/summary'),
    ]);
    _p21Commissions = commissions;

    const totalPending = commissions.filter(c=>c.status==='Pending').reduce((s,c)=>s+c.amount,0);
    const totalApproved = commissions.filter(c=>c.status==='Approved').reduce((s,c)=>s+c.amount,0);
    const totalPaid = commissions.filter(c=>c.status==='Paid').reduce((s,c)=>s+c.amount,0);

    el.innerHTML = `
      <div class="stats-grid" style="grid-template-columns:repeat(3,1fr);gap:12px;margin-bottom:16px">
        <div class="stat-card"><div class="stat-label">Pending</div><div class="stat-value">${formatCurrency(totalPending)}</div></div>
        <div class="stat-card"><div class="stat-label">Approved</div><div class="stat-value">${formatCurrency(totalApproved)}</div></div>
        <div class="stat-card"><div class="stat-label">Paid</div><div class="stat-value">${formatCurrency(totalPaid)}</div></div>
      </div>
      <div class="panel" style="margin-bottom:16px">
        <div class="panel-header"><div class="panel-title">Per-Rep Summary</div></div>
        <div style="padding:12px">
          <table style="width:100%;font-size:12px;border-collapse:collapse">
            <thead><tr style="color:var(--text-muted);text-align:left">
              <th style="padding:6px 8px">Rep</th>
              <th style="padding:6px 8px">Pending</th>
              <th style="padding:6px 8px">Approved</th>
              <th style="padding:6px 8px">Paid</th>
              <th style="padding:6px 8px">Total</th>
            </tr></thead>
            <tbody>
              ${summary.map(s => `<tr style="border-top:1px solid var(--border)">
                <td style="padding:6px 8px">${esc(s.userName||s.userId)}</td>
                <td style="padding:6px 8px;color:#eab308">${formatCurrency(s.pending)}</td>
                <td style="padding:6px 8px;color:#3b82f6">${formatCurrency(s.approved)}</td>
                <td style="padding:6px 8px;color:#22c55e">${formatCurrency(s.paid)}</td>
                <td style="padding:6px 8px;font-weight:600">${formatCurrency(s.pending+s.approved+s.paid)}</td>
              </tr>`).join('')}
            </tbody>
          </table>
        </div>
      </div>
      <div class="panel">
        <div class="panel-header"><div class="panel-title">All Commissions</div>
          <div style="display:flex;gap:8px">
            <select class="filter-select" id="comm-filter-status" onchange="filterCommissionsTable()" style="font-size:12px">
              <option value="">All Status</option>
              <option>Pending</option><option>Approved</option><option>Paid</option>
            </select>
          </div>
        </div>
        <div style="padding:12px">
          <table id="commissions-table" style="width:100%;font-size:12px;border-collapse:collapse">
            <thead><tr style="color:var(--text-muted);text-align:left">
              <th style="padding:6px 8px">Deal</th>
              <th style="padding:6px 8px">Rep</th>
              <th style="padding:6px 8px">Deal Value</th>
              <th style="padding:6px 8px">Rate</th>
              <th style="padding:6px 8px">Commission</th>
              <th style="padding:6px 8px">Status</th>
              <th style="padding:6px 8px">Date</th>
              <th style="padding:6px 8px">Actions</th>
            </tr></thead>
            <tbody id="commissions-tbody">
              ${commissions.map(c => renderCommissionRow(c)).join('')}
            </tbody>
          </table>
        </div>
      </div>`;
  } catch(e) { el.innerHTML = `<div style="color:#ef4444;padding:16px">${esc(e.message)}</div>`; }
}

function renderCommissionRow(c) {
  const statusColor = {Pending:'#eab308',Approved:'#3b82f6',Paid:'#22c55e'}[c.status]||'#a1a1aa';
  return `<tr data-status="${c.status}" style="border-top:1px solid var(--border)">
    <td style="padding:6px 8px">${esc(c.dealName||'—')}</td>
    <td style="padding:6px 8px">${esc(c.userName||c.userId)}</td>
    <td style="padding:6px 8px">${formatCurrency(c.dealValue||0)}</td>
    <td style="padding:6px 8px">${c.ratePercent}%</td>
    <td style="padding:6px 8px;font-weight:600">${formatCurrency(c.amount)}</td>
    <td style="padding:6px 8px"><span style="font-size:11px;font-weight:600;color:${statusColor};background:${statusColor}18;padding:2px 8px;border-radius:10px">${c.status}</span></td>
    <td style="padding:6px 8px">${formatDate(c.createdAt)}</td>
    <td style="padding:6px 8px">
      ${c.status==='Pending' ? `<button class="btn btn-ghost btn-xs" onclick="p21ApproveCommission('${c.id}')">Approve</button>` : ''}
      ${c.status==='Approved' ? `<button class="btn btn-ghost btn-xs" onclick="p21MarkCommissionPaid('${c.id}')">Mark Paid</button>` : ''}
      <button class="btn btn-ghost btn-xs" style="color:var(--red)" onclick="p21DeleteCommission('${c.id}')">Delete</button>
    </td>
  </tr>`;
}

function filterCommissionsTable() {
  const status = document.getElementById('comm-filter-status').value;
  document.querySelectorAll('#commissions-tbody tr').forEach(row => {
    row.style.display = (!status || row.dataset.status === status) ? '' : 'none';
  });
}

async function p21ApproveCommission(id) {
  try {
    await apiPut('/commissions/'+id, { status: 'Approved' });
    toast('Commission approved', 'success');
    renderCommissionsReport();
  } catch(e) { toast(e.message, 'error'); }
}

async function p21MarkCommissionPaid(id) {
  try {
    await apiPut('/commissions/'+id, { status: 'Paid', paidAt: Date.now() });
    toast('Commission marked as paid', 'success');
    renderCommissionsReport();
  } catch(e) { toast(e.message, 'error'); }
}

async function p21DeleteCommission(id) {
  if (!confirm('Delete this commission record?')) return;
  try {
    await apiDelete('/commissions/'+id);
    toast('Deleted', 'success');
    renderCommissionsReport();
  } catch(e) { toast(e.message, 'error'); }
}

// ─────────────────────────────────────────────────────────────────────────────
// 21.C  CUSTOM REPORT BUILDER
// ─────────────────────────────────────────────────────────────────────────────

const P21_ENTITY_FIELDS = {
  contacts:   ['name','email','phone','title','stage','owner','lead_source','territory','created_at','tags'],
  deals:      ['name','value','stage','owner','close_date','probability','lead_source','win_reason','loss_reason','currency'],
  companies:  ['name','industry','website','phone','city','territory','notes'],
  activities: ['type','note','date'],
};

function renderReportBuilder(container) {
  if (!container) return;
  container.innerHTML = `
    <div class="panel" style="margin-bottom:16px">
      <div class="panel-header"><div class="panel-title">Report Builder</div></div>
      <div style="padding:16px">
        <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:12px;margin-bottom:12px">
          <div class="form-group">
            <label class="form-label">Entity</label>
            <select class="form-select" id="rb-entity" onchange="p21UpdateFieldOptions()">
              <option value="contacts">Contacts</option>
              <option value="deals">Deals</option>
              <option value="companies">Companies</option>
              <option value="activities">Activities</option>
            </select>
          </div>
          <div class="form-group">
            <label class="form-label">Chart Type</label>
            <select class="form-select" id="rb-chart">
              <option value="table">Table</option>
              <option value="bar">Bar Chart</option>
              <option value="pie">Pie Chart</option>
            </select>
          </div>
          <div class="form-group">
            <label class="form-label">Group By</label>
            <select class="form-select" id="rb-groupby">
              <option value="">No grouping</option>
            </select>
          </div>
        </div>
        <div class="form-group" style="margin-bottom:12px">
          <label class="form-label">Fields to Display</label>
          <div id="rb-fields-checkboxes" style="display:flex;flex-wrap:wrap;gap:8px;padding:8px;background:var(--surface2);border:1px solid var(--border);border-radius:6px"></div>
        </div>
        <div class="form-group" style="margin-bottom:12px">
          <label class="form-label" style="display:flex;align-items:center;justify-content:space-between">
            Filters
            <button class="btn btn-ghost btn-xs" onclick="p21AddFilter()">+ Add Filter</button>
          </label>
          <div id="rb-filters" style="display:flex;flex-direction:column;gap:6px"></div>
        </div>
        <div style="display:flex;gap:8px">
          <button class="btn btn-primary" onclick="p21RunReport()">Preview Report</button>
          <button class="btn btn-secondary" onclick="p21SaveReport()">Save Report</button>
        </div>
      </div>
    </div>
    <div id="rb-preview" style="margin-bottom:16px"></div>`;
  p21UpdateFieldOptions();
}

function p21UpdateFieldOptions() {
  const entity = document.getElementById('rb-entity').value;
  const fields = P21_ENTITY_FIELDS[entity] || [];
  const checkboxes = document.getElementById('rb-fields-checkboxes');
  const groupby = document.getElementById('rb-groupby');
  if (!checkboxes || !groupby) return;

  checkboxes.innerHTML = fields.map(f => `
    <label style="display:flex;align-items:center;gap:4px;font-size:12px;cursor:pointer">
      <input type="checkbox" value="${f}" checked style="cursor:pointer" />
      ${f.replace(/_/g,' ')}
    </label>`).join('');

  groupby.innerHTML = '<option value="">No grouping</option>' +
    fields.map(f => `<option value="${f}">${f.replace(/_/g,' ')}</option>`).join('');
}

function p21AddFilter() {
  const entity = document.getElementById('rb-entity').value;
  const fields = P21_ENTITY_FIELDS[entity] || [];
  const container = document.getElementById('rb-filters');
  const row = document.createElement('div');
  row.style.cssText = 'display:flex;gap:6px;align-items:center';
  row.innerHTML = `
    <select class="form-select" style="flex:1;font-size:12px">
      ${fields.map(f => `<option value="${f}">${f.replace(/_/g,' ')}</option>`).join('')}
    </select>
    <select class="form-select" style="width:80px;font-size:12px">
      <option value="eq">equals</option>
      <option value="neq">not equal</option>
      <option value="like">contains</option>
      <option value="gt">greater than</option>
      <option value="lt">less than</option>
    </select>
    <input type="text" class="form-input" placeholder="Value" style="flex:1;font-size:12px" />
    <button class="btn btn-ghost btn-xs" onclick="this.parentElement.remove()">x</button>`;
  container.appendChild(row);
}

async function p21RunReport() {
  const entity = document.getElementById('rb-entity').value;
  const chartType = document.getElementById('rb-chart').value;
  const groupBy = document.getElementById('rb-groupby').value;
  const fields = [...document.querySelectorAll('#rb-fields-checkboxes input:checked')].map(i => i.value);
  const filterRows = document.querySelectorAll('#rb-filters > div');
  const filters = [...filterRows].map(row => {
    const selects = row.querySelectorAll('select');
    const input = row.querySelector('input');
    return { field: selects[0].value, op: selects[1].value, value: input.value };
  }).filter(f => f.value !== '');

  if (!fields.length) return toast('Select at least one field', 'error');

  const preview = document.getElementById('rb-preview');
  preview.innerHTML = '<div style="color:var(--text-muted);font-size:13px;padding:16px">Running report...</div>';

  try {
    const result = await apiPost('/reports/run', { entity, fields, groupBy, chartType, filters });
    preview.innerHTML = p21RenderReportPreview(result);
    // Store last result for CSV export
    window._p21LastReport = result;
  } catch(e) { preview.innerHTML = `<div style="color:#ef4444;padding:16px">${esc(e.message)}</div>`; }
}

function p21RenderReportPreview(result) {
  const { rows, grouped, fields, entity, groupBy, chartType, total } = result;

  let html = `<div class="panel">
    <div class="panel-header">
      <div class="panel-title">Report Preview — ${esc(entity)} (${total} rows)</div>
      <button class="btn btn-secondary btn-sm" onclick="p21ExportReportCSV()">Export CSV</button>
    </div>
    <div style="padding:12px">`;

  if (grouped && (chartType === 'bar' || chartType === 'pie')) {
    html += `<div style="margin-bottom:16px">
      <div style="font-size:12px;font-weight:600;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.05em;margin-bottom:8px">Grouped by ${esc(groupBy)}</div>`;
    const maxCount = Math.max(...grouped.map(g => g.count), 1);
    grouped.forEach(g => {
      const pct = Math.round((g.count / maxCount) * 100);
      html += `<div style="margin-bottom:8px">
        <div style="display:flex;justify-content:space-between;font-size:12px;margin-bottom:2px">
          <span>${esc(g.key)}</span>
          <span style="color:var(--text-muted)">${g.count} records${g.totalValue ? ' · ' + formatCurrency(g.totalValue) : ''}</span>
        </div>
        <div style="height:6px;background:var(--border);border-radius:3px">
          <div style="height:100%;width:${pct}%;background:var(--accent);border-radius:3px"></div>
        </div>
      </div>`;
    });
    html += `</div>`;
  }

  // Table
  html += `<div style="overflow-x:auto">
    <table style="width:100%;font-size:12px;border-collapse:collapse">
      <thead><tr style="color:var(--text-muted)">
        ${fields.map(f => `<th style="padding:6px 8px;text-align:left;font-weight:500">${esc(f.replace(/_/g,' '))}</th>`).join('')}
      </tr></thead>
      <tbody>
        ${rows.slice(0,100).map(row => `<tr style="border-top:1px solid var(--border)">
          ${fields.map(f => `<td style="padding:6px 8px;color:var(--text-dim)">${esc(String(row[f]||'—'))}</td>`).join('')}
        </tr>`).join('')}
      </tbody>
    </table>
    ${total > 100 ? `<div style="font-size:11px;color:var(--text-muted);padding:8px">Showing first 100 of ${total} rows</div>` : ''}
  </div>`;

  html += '</div></div>';
  return html;
}

function p21ExportReportCSV() {
  const result = window._p21LastReport;
  if (!result) return toast('Run a report first', 'error');
  const { rows, fields } = result;
  const header = fields.join(',');
  const csvRows = rows.map(row => fields.map(f => `"${String(row[f]||'').replace(/"/g,'""')}"`).join(','));
  const csv = [header, ...csvRows].join('\n');
  const blob = new Blob([csv], { type: 'text/csv' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a'); a.href = url; a.download = 'report.csv'; a.click();
  URL.revokeObjectURL(url);
}

async function p21SaveReport() {
  const name = prompt('Report name:');
  if (!name) return;
  const entity = document.getElementById('rb-entity').value;
  const chartType = document.getElementById('rb-chart').value;
  const groupBy = document.getElementById('rb-groupby').value;
  const fields = [...document.querySelectorAll('#rb-fields-checkboxes input:checked')].map(i => i.value);
  const filterRows = document.querySelectorAll('#rb-filters > div');
  const filters = [...filterRows].map(row => {
    const selects = row.querySelectorAll('select');
    const input = row.querySelector('input');
    return { field: selects[0].value, op: selects[1].value, value: input.value };
  }).filter(f => f.value !== '');

  try {
    await apiPost('/saved-reports', { name, config: { entity, fields, groupBy, chartType, filters } });
    _p21SavedReports = await apiGet('/saved-reports');
    toast(`Report "${name}" saved`, 'success');
    const srEl = document.getElementById('p21-saved-reports');
    if (srEl) renderSavedReportsList(srEl);
  } catch(e) { toast(e.message, 'error'); }
}

function renderSavedReportsList(container) {
  if (!_p21SavedReports.length) {
    container.innerHTML = '<div style="font-size:12px;color:var(--text-muted);padding:8px 0">No saved reports yet. Build a report above and click Save Report.</div>';
    return;
  }
  container.innerHTML = _p21SavedReports.map(sr => `
    <div style="display:flex;align-items:center;gap:8px;padding:8px 10px;background:var(--surface2);border:1px solid var(--border);border-radius:6px">
      <div style="flex:1">
        <div style="font-size:13px;font-weight:500;color:var(--text)">${esc(sr.name)}</div>
        <div style="font-size:11px;color:var(--text-muted)">${esc((sr.config.entity||''))} · ${esc((sr.config.fields||[]).length)} fields · ${esc(sr.config.chartType||'table')}</div>
      </div>
      <button class="btn btn-secondary btn-sm" onclick="p21RunSavedReport('${sr.id}')">Run</button>
      <button class="btn btn-ghost btn-xs" onclick="p21ExportSavedReportCSV('${sr.id}')">CSV</button>
      <button class="btn btn-ghost btn-xs" style="color:var(--red)" onclick="p21DeleteSavedReport('${sr.id}')">Delete</button>
    </div>`).join('');
}

async function p21RunSavedReport(id) {
  const sr = _p21SavedReports.find(r => r.id === id);
  if (!sr) return;
  const preview = document.getElementById('rb-preview') || document.getElementById('p21-saved-report-result');
  if (!preview) return;
  preview.innerHTML = '<div style="color:var(--text-muted);font-size:13px;padding:16px">Running report...</div>';
  try {
    const result = await apiPost('/reports/run', sr.config);
    preview.innerHTML = p21RenderReportPreview(result);
    window._p21LastReport = result;
  } catch(e) { preview.innerHTML = `<div style="color:#ef4444;padding:16px">${esc(e.message)}</div>`; }
}

async function p21ExportSavedReportCSV(id) {
  const sr = _p21SavedReports.find(r => r.id === id);
  if (!sr) return;
  try {
    const result = await apiPost('/reports/run', sr.config);
    window._p21LastReport = result;
    p21ExportReportCSV();
  } catch(e) { toast(e.message, 'error'); }
}

async function p21DeleteSavedReport(id) {
  if (!confirm('Delete this saved report?')) return;
  try {
    await apiDelete('/saved-reports/'+id);
    _p21SavedReports = await apiGet('/saved-reports');
    toast('Report deleted', 'success');
    const container = document.getElementById('p21-saved-reports');
    if (container) renderSavedReportsList(container);
  } catch(e) { toast(e.message, 'error'); }
}

// ─────────────────────────────────────────────────────────────────────────────
// 21.D  CLIENT PORTAL V2
// ─────────────────────────────────────────────────────────────────────────────

function renderPortalV2(token) {
  const el = document.getElementById('view-portal');
  if (!el) return;
  el.innerHTML = '<div style="display:flex;align-items:center;justify-content:center;height:100%;color:var(--text-muted);font-size:14px">Loading deal room...</div>';

  fetch('/api/portal-v2/' + token)
    .then(r => r.json())
    .then(data => {
      if (data.error) { el.innerHTML = `<div style="text-align:center;padding:40px;color:#ef4444">${esc(data.error)}</div>`; return; }

      const stageWidth = data.stages.length ? 100 / data.stages.length : 100;
      const progressWidth = data.stageIdx >= 0 ? Math.round((data.stageIdx / Math.max(data.stages.length - 1, 1)) * 100) : 0;

      el.innerHTML = `
        <div style="max-width:760px;margin:0 auto;padding:32px 16px">
          <div style="text-align:center;margin-bottom:32px">
            <div style="width:48px;height:48px;background:var(--accent);border-radius:12px;display:flex;align-items:center;justify-content:center;margin:0 auto 12px">
              <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="white" stroke-width="2" stroke-linecap="round"><rect x="3" y="3" width="7" height="7"/><rect x="14" y="3" width="7" height="7"/><rect x="14" y="14" width="7" height="7"/><rect x="3" y="14" width="7" height="7"/></svg>
            </div>
            <div style="font-size:22px;font-weight:700;color:var(--text)">${esc(data.dealName)}</div>
            <div style="font-size:14px;color:var(--text-muted);margin-top:4px">Deal Room</div>
          </div>

          <div class="panel" style="margin-bottom:16px">
            <div class="panel-header"><div class="panel-title">Deal Summary</div></div>
            <div style="padding:16px">
              <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:16px">
                <div><div style="font-size:11px;color:var(--text-muted);text-transform:uppercase;margin-bottom:2px">Value</div><div style="font-size:20px;font-weight:700;color:var(--text)">${data.value ? formatCurrency(data.value) : 'TBD'}</div></div>
                <div><div style="font-size:11px;color:var(--text-muted);text-transform:uppercase;margin-bottom:2px">Stage</div><div style="font-size:14px;font-weight:600;color:var(--accent)">${esc(data.stage)}</div></div>
                ${data.closeDate ? `<div><div style="font-size:11px;color:var(--text-muted);text-transform:uppercase;margin-bottom:2px">Target Close</div><div style="font-size:13px;color:var(--text)">${formatDate(data.closeDate)}</div></div>` : ''}
              </div>
              ${data.stages.length > 0 ? `
              <div style="margin-top:8px">
                <div style="display:flex;justify-content:space-between;font-size:11px;color:var(--text-muted);margin-bottom:6px">
                  <span>Progress</span><span>${progressWidth}%</span>
                </div>
                <div style="height:6px;background:var(--border);border-radius:3px;margin-bottom:8px">
                  <div style="height:100%;width:${progressWidth}%;background:var(--accent);border-radius:3px;transition:width 0.6s ease"></div>
                </div>
                <div style="display:flex;justify-content:space-between;font-size:10px;color:var(--text-muted)">
                  ${data.stages.map((s,i) => `<span style="${data.stage===s?'color:var(--accent);font-weight:600':''}">${esc(s)}</span>`).join('')}
                </div>
              </div>` : ''}
            </div>
          </div>

          ${data.checklists && data.checklists.length ? `
          <div class="panel" style="margin-bottom:16px">
            <div class="panel-header"><div class="panel-title">Onboarding Progress</div></div>
            <div style="padding:16px">
              ${data.checklists.map(cl => {
                const total = cl.items.length;
                const done = cl.items.filter(i=>i.done).length;
                const pct = total ? Math.round((done/total)*100) : 0;
                return `<div style="margin-bottom:12px">
                  <div style="display:flex;justify-content:space-between;font-size:13px;font-weight:500;margin-bottom:4px">
                    <span>${esc(cl.name)}</span><span style="color:var(--text-muted)">${done}/${total}</span>
                  </div>
                  <div style="height:4px;background:var(--border);border-radius:2px;margin-bottom:8px">
                    <div style="height:100%;width:${pct}%;background:#22c55e;border-radius:2px"></div>
                  </div>
                  ${cl.items.map(item => `<div style="display:flex;align-items:center;gap:8px;padding:4px 0;font-size:12px;color:${item.done?'#22c55e':'var(--text-dim)'}">
                    <span style="width:14px;height:14px;border-radius:3px;border:1.5px solid ${item.done?'#22c55e':'var(--border)'};background:${item.done?'#22c55e':'transparent'};display:inline-flex;align-items:center;justify-content:center;flex-shrink:0">
                      ${item.done ? '<svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="white" stroke-width="3" stroke-linecap="round"><polyline points="20 6 9 17 4 12"/></svg>' : ''}
                    </span>
                    ${esc(item.title)}
                  </div>`).join('')}
                </div>`;
              }).join('')}
            </div>
          </div>` : ''}

          ${data.docs && data.docs.length ? `
          <div class="panel" style="margin-bottom:16px">
            <div class="panel-header"><div class="panel-title">Documents</div></div>
            <div style="padding:12px">
              ${data.docs.map(d => `<div style="display:flex;align-items:center;gap:8px;padding:6px 8px;border-radius:4px;hover:background:var(--surface2)">
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="var(--text-muted)" stroke-width="2" stroke-linecap="round"><path d="M13 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V9z"/><polyline points="13,2 13,9 20,9"/></svg>
                ${d.url ? `<a href="${esc(d.url)}" target="_blank" style="font-size:13px;color:var(--accent);text-decoration:none">${esc(d.title)}</a>` : `<span style="font-size:13px;color:var(--text)">${esc(d.title)}</span>`}
                <span style="font-size:11px;color:var(--text-muted);margin-left:auto">${d.date_added||''}</span>
              </div>`).join('')}
            </div>
          </div>` : ''}

          ${data.proposal ? `
          <div class="panel" style="margin-bottom:16px">
            <div class="panel-header"><div class="panel-title">Proposal</div></div>
            <div style="padding:12px;font-size:13px">
              <div>${esc(data.proposal.title||'Proposal')}</div>
              <div style="color:var(--text-muted);font-size:11px;margin-top:4px">Status: ${esc(data.proposal.status)} ${data.proposal.signed_at ? '· Signed ' + formatDate(data.proposal.signed_at) : ''}</div>
            </div>
          </div>` : ''}

          <div class="panel" style="margin-bottom:16px">
            <div class="panel-header"><div class="panel-title">Upload a File</div></div>
            <div style="padding:16px">
              <input type="text" id="portal-upload-name" placeholder="Your name" class="form-input" style="margin-bottom:8px" />
              <input type="file" id="portal-upload-file" class="form-input" style="margin-bottom:8px" />
              <button class="btn btn-primary btn-sm" onclick="portalV2Upload('${token}')">Upload</button>
              ${data.uploadedDocs && data.uploadedDocs.length ? `
              <div style="margin-top:12px;font-size:12px;color:var(--text-muted)">
                <div style="font-weight:500;margin-bottom:4px">Previously uploaded:</div>
                ${data.uploadedDocs.map(d => `<div style="color:var(--text-dim)">${esc(d.title)} — ${d.date_added||''}</div>`).join('')}
              </div>` : ''}
            </div>
          </div>

          <div class="panel">
            <div class="panel-header"><div class="panel-title">Comments</div></div>
            <div style="padding:16px">
              <div id="portal-comments-list" style="margin-bottom:12px">
                ${(data.comments||[]).length === 0 ? '<div style="font-size:12px;color:var(--text-muted)">No comments yet.</div>' : ''}
                ${(data.comments||[]).map(c => `<div style="margin-bottom:10px;padding:10px;background:var(--surface2);border-radius:6px;border:1px solid var(--border)">
                  <div style="font-size:12px;font-weight:600;color:var(--text);margin-bottom:4px">${esc(c.author_name)}</div>
                  <div style="font-size:13px;color:var(--text-dim)">${esc(c.body)}</div>
                  <div style="font-size:11px;color:var(--text-muted);margin-top:4px">${formatDate(c.created_at)}</div>
                </div>`).join('')}
              </div>
              <div style="display:flex;flex-direction:column;gap:8px">
                <input type="text" id="portal-comment-name" placeholder="Your name" class="form-input" />
                <textarea id="portal-comment-body" placeholder="Leave a comment..." class="form-input" rows="3" style="resize:vertical"></textarea>
                <button class="btn btn-primary btn-sm" onclick="portalV2PostComment('${token}')">Post Comment</button>
              </div>
            </div>
          </div>

        </div>`;
    })
    .catch(err => { el.innerHTML = `<div style="text-align:center;padding:40px;color:#ef4444">${esc(err.message)}</div>`; });
}

async function portalV2PostComment(token) {
  const authorName = document.getElementById('portal-comment-name').value.trim();
  const body = document.getElementById('portal-comment-body').value.trim();
  if (!authorName || !body) return alert('Please enter your name and a comment.');
  try {
    const result = await fetch('/api/portal-v2/' + token + '/comment', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ authorName, body }),
    }).then(r => r.json());
    if (result.error) return alert(result.error);
    const list = document.getElementById('portal-comments-list');
    if (list) {
      list.innerHTML += `<div style="margin-bottom:10px;padding:10px;background:var(--surface2);border-radius:6px;border:1px solid var(--border)">
        <div style="font-size:12px;font-weight:600;color:var(--text);margin-bottom:4px">${esc(authorName)}</div>
        <div style="font-size:13px;color:var(--text-dim)">${esc(body)}</div>
        <div style="font-size:11px;color:var(--text-muted);margin-top:4px">just now</div>
      </div>`;
    }
    document.getElementById('portal-comment-body').value = '';
  } catch(e) { alert('Failed to post comment: ' + e.message); }
}

async function portalV2Upload(token) {
  const fileInput = document.getElementById('portal-upload-file');
  const authorName = document.getElementById('portal-upload-name').value.trim();
  if (!fileInput.files[0]) return alert('Please select a file.');
  const file = fileInput.files[0];
  const reader = new FileReader();
  reader.onload = async (e) => {
    const fileData = e.target.result;
    try {
      const result = await fetch('/api/portal-v2/' + token + '/upload', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ fileName: file.name, fileData, authorName }),
      }).then(r => r.json());
      if (result.error) return alert(result.error);
      alert('File uploaded successfully.');
      fileInput.value = '';
    } catch(e) { alert('Upload failed: ' + e.message); }
  };
  reader.readAsDataURL(file);
}

