function renderMeetings() {
  const el = document.getElementById('view-meetings');
  if (!el) return;
  el.innerHTML = `
    <div class="page-header">
      <div class="page-title">Meetings</div>
      <div class="header-actions">
        <select class="filter-select" id="mtg-status-filter" onchange="renderMeetingsTable()">
          <option value="">All Status</option>
          <option value="Scheduled">Scheduled</option>
          <option value="Completed">Completed</option>
          <option value="Cancelled">Cancelled</option>
        </select>
        <button class="btn btn-primary" onclick="openMeetingModal()">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" width="14" height="14"><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg>
          Schedule Meeting
        </button>
      </div>
    </div>
    <div class="page-content" style="overflow-y:auto">
      <div id="meetings-container"></div>
    </div>`;
  renderMeetingsTable();
}

async function renderMeetingsTable() {
  const container = document.getElementById('meetings-container');
  if (!container) return;
  const status = (document.getElementById('mtg-status-filter') || {}).value || '';
  let meetings = _p21Meetings;
  if (status) meetings = meetings.filter(m => m.status === status);

  if (!meetings.length) {
    container.innerHTML = '<div style="text-align:center;padding:40px;color:var(--text-muted);font-size:14px">No meetings found. Click Schedule Meeting to get started.</div>';
    return;
  }

  const now = new Date().toISOString();
  container.innerHTML = `
    <div style="display:flex;flex-direction:column;gap:8px">
      ${meetings.map(m => {
        const isPast = m.scheduledAt < now;
        const contact = db.contacts ? db.contacts.find(c => c.id === m.contactId) : null;
        const deal = db.deals ? db.deals.find(d => d.id === m.dealId) : null;
        const statusColor = {Scheduled:'#3b82f6',Completed:'#22c55e',Cancelled:'#ef4444'}[m.status]||'#a1a1aa';
        return `<div style="display:flex;align-items:flex-start;gap:12px;padding:14px 16px;background:var(--surface2);border:1px solid var(--border);border-radius:8px">
          <div style="width:48px;height:48px;border-radius:8px;background:${statusColor}18;display:flex;align-items:center;justify-content:center;flex-shrink:0">
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="${statusColor}" stroke-width="2" stroke-linecap="round"><rect x="3" y="4" width="18" height="18" rx="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>
          </div>
          <div style="flex:1;min-width:0">
            <div style="font-size:14px;font-weight:600;color:var(--text)">${esc(m.title)}</div>
            <div style="font-size:12px;color:var(--text-muted);margin-top:2px">
              ${formatDate(m.scheduledAt)} · ${m.durationMin} min${m.location ? ' · ' + esc(m.location) : ''}
            </div>
            ${contact ? `<div style="font-size:12px;color:var(--text-dim);margin-top:2px">Contact: <span style="color:var(--accent);cursor:pointer" onclick="showContactDetail('${contact.id}')">${esc(contact.name)}</span></div>` : ''}
            ${deal ? `<div style="font-size:12px;color:var(--text-dim)">Deal: <span style="color:var(--accent);cursor:pointer" onclick="showDealDetail('${deal.id}')">${esc(deal.name)}</span></div>` : ''}
            ${m.description ? `<div style="font-size:12px;color:var(--text-muted);margin-top:4px">${esc(m.description)}</div>` : ''}
          </div>
          <div style="display:flex;flex-direction:column;align-items:flex-end;gap:6px">
            <span style="font-size:11px;font-weight:600;color:${statusColor};background:${statusColor}18;padding:2px 8px;border-radius:10px">${m.status}</span>
            <div style="display:flex;gap:4px">
              ${m.status==='Scheduled' ? `<button class="btn btn-ghost btn-xs" onclick="p21CompleteMeeting('${m.id}')">Complete</button>` : ''}
              <button class="btn btn-ghost btn-xs" onclick="openMeetingModal('${m.id}')">Edit</button>
              <button class="btn btn-ghost btn-xs" style="color:var(--red)" onclick="p21DeleteMeeting('${m.id}')">Delete</button>
            </div>
          </div>
        </div>`;
      }).join('')}
    </div>`;
}

function openMeetingModal(id, prefillContactId, prefillDealId) {
  const meeting = id ? _p21Meetings.find(m => m.id === id) : null;
  const contacts = db.contacts || [];
  const deals = db.deals || [];

  const modal = document.createElement('div');
  modal.id = 'p21-meeting-modal';
  modal.className = 'modal-overlay open';
  modal.innerHTML = `
    <div class="modal" style="max-width:520px;width:100%">
      <div class="modal-header">
        <div class="modal-title">${id ? 'Edit Meeting' : 'Schedule Meeting'}</div>
        <button class="modal-close" onclick="document.getElementById('p21-meeting-modal').remove()">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="16" height="16"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
        </button>
      </div>
      <div class="modal-body" style="display:flex;flex-direction:column;gap:12px">
        <div class="form-group">
          <label class="form-label">Title *</label>
          <input type="text" class="form-input" id="mtg-title" value="${esc(meeting ? meeting.title : '')}" placeholder="Meeting title" />
        </div>
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px">
          <div class="form-group">
            <label class="form-label">Date & Time *</label>
            <input type="datetime-local" class="form-input" id="mtg-scheduled-at" value="${meeting ? meeting.scheduledAt.slice(0,16) : ''}" />
          </div>
          <div class="form-group">
            <label class="form-label">Duration (minutes)</label>
            <input type="number" class="form-input" id="mtg-duration" value="${meeting ? meeting.durationMin : 30}" min="5" max="480" />
          </div>
        </div>
        <div class="form-group">
          <label class="form-label">Location</label>
          <input type="text" class="form-input" id="mtg-location" value="${esc(meeting ? meeting.location||'' : '')}" placeholder="Office, Zoom, phone..." />
        </div>
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px">
          <div class="form-group">
            <label class="form-label">Contact</label>
            <select class="form-select" id="mtg-contact">
              <option value="">None</option>
              ${contacts.map(c => `<option value="${c.id}" ${((meeting&&meeting.contactId===c.id)||(prefillContactId===c.id))?'selected':''}>${esc(c.name)}</option>`).join('')}
            </select>
          </div>
          <div class="form-group">
            <label class="form-label">Deal</label>
            <select class="form-select" id="mtg-deal">
              <option value="">None</option>
              ${deals.map(d => `<option value="${d.id}" ${((meeting&&meeting.dealId===d.id)||(prefillDealId===d.id))?'selected':''}>${esc(d.name)}</option>`).join('')}
            </select>
          </div>
        </div>
        <div class="form-group">
          <label class="form-label">Status</label>
          <select class="form-select" id="mtg-status">
            <option value="Scheduled" ${!meeting||meeting.status==='Scheduled'?'selected':''}>Scheduled</option>
            <option value="Completed" ${meeting&&meeting.status==='Completed'?'selected':''}>Completed</option>
            <option value="Cancelled" ${meeting&&meeting.status==='Cancelled'?'selected':''}>Cancelled</option>
          </select>
        </div>
        <div class="form-group">
          <label class="form-label">Description</label>
          <textarea class="form-input" id="mtg-description" rows="3" style="resize:vertical" placeholder="Agenda, goals, notes...">${esc(meeting ? meeting.description||'' : '')}</textarea>
        </div>
      </div>
      <div class="modal-footer">
        <button class="btn btn-ghost" onclick="document.getElementById('p21-meeting-modal').remove()">Cancel</button>
        <button class="btn btn-primary" onclick="p21SaveMeeting('${id||''}')">Save Meeting</button>
      </div>
    </div>`;
  document.body.appendChild(modal);
}

async function p21SaveMeeting(id) {
  const title = document.getElementById('mtg-title').value.trim();
  const scheduledAt = document.getElementById('mtg-scheduled-at').value;
  const durationMin = parseInt(document.getElementById('mtg-duration').value) || 30;
  const location = document.getElementById('mtg-location').value.trim();
  const contactId = document.getElementById('mtg-contact').value || null;
  const dealId = document.getElementById('mtg-deal').value || null;
  const status = document.getElementById('mtg-status').value;
  const description = document.getElementById('mtg-description').value.trim();

  if (!title || !scheduledAt) return toast('Title and date/time required', 'error');

  try {
    if (id) {
      await apiPut('/meetings/'+id, { title, scheduledAt, durationMin, location, contactId, dealId, status, description });
    } else {
      await apiPost('/meetings', { title, scheduledAt, durationMin, location, contactId, dealId, status, description });
    }
    _p21Meetings = await apiGet('/meetings');
    toast(id ? 'Meeting updated' : 'Meeting scheduled', 'success');
    document.getElementById('p21-meeting-modal').remove();
    if (currentView === 'meetings') renderMeetingsTable();
    // Re-render detail views if open
    if (currentView === 'contact-detail') { const cid = contactId; if (cid) showContactDetail(cid); }
    if (currentView === 'deal-detail') { const did = dealId; if (did) showDealDetail(did); }
  } catch(e) { toast(e.message, 'error'); }
}

async function p21CompleteMeeting(id) {
  try {
    await apiPut('/meetings/'+id, { ...(_p21Meetings.find(m=>m.id===id)||{}), status: 'Completed' });
    _p21Meetings = await apiGet('/meetings');
    toast('Meeting marked complete', 'success');
    if (currentView === 'meetings') renderMeetingsTable();
  } catch(e) { toast(e.message, 'error'); }
}

async function p21DeleteMeeting(id) {
  if (!confirm('Delete this meeting?')) return;
  try {
    await apiDelete('/meetings/'+id);
    _p21Meetings = _p21Meetings.filter(m => m.id !== id);
    toast('Meeting deleted', 'success');
    if (currentView === 'meetings') renderMeetingsTable();
  } catch(e) { toast(e.message, 'error'); }
}

function renderUpcomingMeetingsPanel(entityType, entityId) {
  const now = new Date().toISOString();
  const upcoming = _p21Meetings.filter(m =>
    m.status === 'Scheduled' &&
    m.scheduledAt >= now &&
    ((entityType === 'contact' && m.contactId === entityId) ||
     (entityType === 'deal' && m.dealId === entityId))
  ).slice(0, 3);

  if (!upcoming.length) return '';
  return `
    <div class="panel">
      <div class="panel-header">
        <div class="panel-title">Upcoming Meetings</div>
        <span class="panel-count">${upcoming.length}</span>
        <button class="btn btn-secondary btn-sm panel-action" onclick="openMeetingModal(null,'${entityType==='contact'?entityId:''}','${entityType==='deal'?entityId:''}')">+ Schedule</button>
      </div>
      <div style="padding:10px 12px;display:flex;flex-direction:column;gap:8px">
        ${upcoming.map(m => `
          <div style="display:flex;align-items:center;gap:10px;padding:8px 10px;background:var(--surface2);border:1px solid var(--border);border-radius:6px">
            <div style="width:8px;height:8px;border-radius:50%;background:#3b82f6;flex-shrink:0"></div>
            <div style="flex:1;min-width:0">
              <div style="font-size:13px;font-weight:500;color:var(--text)">${esc(m.title)}</div>
              <div style="font-size:11px;color:var(--text-muted)">${formatDate(m.scheduledAt)} · ${m.durationMin} min${m.location?' · '+esc(m.location):''}</div>
            </div>
            <button class="btn btn-ghost btn-xs" onclick="openMeetingModal('${m.id}')">Edit</button>
          </div>`).join('')}
      </div>
    </div>`;
}

