function getTerritoryOptions(selectedName) {
  const options = _p21Territories.map(t =>
    `<option value="${esc(t.name)}" ${t.name === selectedName ? 'selected' : ''}>${esc(t.name)}</option>`
  ).join('');
  return `<option value="">None</option>${options}`;
}

function renderTerritoriesSettings() {
  const users = (db.settings && db.settings.users) ? db.settings.users : [];
  const terrHtml = _p21Territories.length
    ? _p21Territories.map(t => {
        const reps = (t.repIds||[]).map(rid => {
          const u = users.find(u => u.id === rid);
          return u ? esc(u.name) : rid;
        }).join(', ');
        return `<div style="display:flex;align-items:flex-start;gap:8px;padding:10px;background:var(--surface2);border:1px solid var(--border);border-radius:6px;margin-bottom:8px">
          <div style="flex:1">
            <div style="font-size:13px;font-weight:600;color:var(--text)">${esc(t.name)}</div>
            ${t.description ? `<div style="font-size:11px;color:var(--text-muted)">${esc(t.description)}</div>` : ''}
            <div style="font-size:11px;color:var(--text-dim);margin-top:4px">Reps: ${reps || 'None assigned'}</div>
          </div>
          <button class="btn btn-ghost btn-xs" onclick="openTerritoryModal('${t.id}')">Edit</button>
          <button class="btn btn-ghost btn-xs" style="color:var(--red)" onclick="p21DeleteTerritory('${t.id}')">Delete</button>
        </div>`;
      }).join('')
    : '<div style="font-size:12px;color:var(--text-muted);padding:8px 0">No territories configured.</div>';

  return `
    <div class="panel settings-card" style="grid-column:span 2" id="settings-territories-panel">
      <div class="panel-header">
        <div class="panel-title">Territory Management</div>
        <button class="btn btn-primary btn-sm" onclick="openTerritoryModal()">Add Territory</button>
      </div>
      <div style="padding:16px">
        <p style="font-size:12px;color:var(--text-muted);margin-bottom:12px">Create named territories and assign reps to them. Contact and company forms will show a dynamic territory dropdown.</p>
        <div id="territories-list">${terrHtml}</div>
      </div>
    </div>`;
}

function openTerritoryModal(id) {
  const territory = id ? _p21Territories.find(t => t.id === id) : null;
  const users = (db.settings && db.settings.users) ? db.settings.users : [];

  const modal = document.createElement('div');
  modal.id = 'p21-territory-modal';
  modal.className = 'modal-overlay open';
  modal.innerHTML = `
    <div class="modal" style="max-width:460px;width:100%">
      <div class="modal-header">
        <div class="modal-title">${id ? 'Edit Territory' : 'New Territory'}</div>
        <button class="modal-close" onclick="document.getElementById('p21-territory-modal').remove()">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="16" height="16"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
        </button>
      </div>
      <div class="modal-body" style="display:flex;flex-direction:column;gap:12px">
        <div class="form-group">
          <label class="form-label">Territory Name *</label>
          <input type="text" class="form-input" id="terr-name" value="${esc(territory ? territory.name : '')}" placeholder="e.g. Midwest, Northeast" />
        </div>
        <div class="form-group">
          <label class="form-label">Description</label>
          <input type="text" class="form-input" id="terr-desc" value="${esc(territory ? territory.description||'' : '')}" placeholder="Optional description" />
        </div>
        <div class="form-group">
          <label class="form-label">Assigned Reps</label>
          <div style="max-height:160px;overflow-y:auto;padding:8px;background:var(--surface2);border:1px solid var(--border);border-radius:6px">
            ${users.map(u => `
              <label style="display:flex;align-items:center;gap:8px;padding:4px 0;font-size:13px;cursor:pointer">
                <input type="checkbox" value="${u.id}" ${territory && (territory.repIds||[]).includes(u.id) ? 'checked' : ''} />
                ${esc(u.name)} <span style="font-size:11px;color:var(--text-muted)">(${u.role})</span>
              </label>`).join('')}
            ${!users.length ? '<div style="font-size:12px;color:var(--text-muted)">No team members found. Add users in Settings > Team Members.</div>' : ''}
          </div>
        </div>
      </div>
      <div class="modal-footer">
        <button class="btn btn-ghost" onclick="document.getElementById('p21-territory-modal').remove()">Cancel</button>
        <button class="btn btn-primary" onclick="p21SaveTerritory('${id||''}')">Save Territory</button>
      </div>
    </div>`;
  document.body.appendChild(modal);
}

async function p21SaveTerritory(id) {
  const name = document.getElementById('terr-name').value.trim();
  const description = document.getElementById('terr-desc').value.trim();
  const repIds = [...document.querySelectorAll('#p21-territory-modal input[type="checkbox"]:checked')].map(i => i.value);

  if (!name) return toast('Territory name required', 'error');
  try {
    if (id) {
      await apiPut('/territories/'+id, { name, description, repIds });
    } else {
      await apiPost('/territories', { name, description, repIds });
    }
    _p21Territories = await apiGet('/territories');
    toast(id ? 'Territory updated' : 'Territory created', 'success');
    document.getElementById('p21-territory-modal').remove();
    // Refresh territories list in settings if visible
    const tList = document.getElementById('territories-list');
    if (tList) {
      const usrs = (db.settings && db.settings.users) ? db.settings.users : [];
      tList.innerHTML = _p21Territories.map(t => {
        const reps = (t.repIds||[]).map(rid => { const u = usrs.find(u=>u.id===rid); return u?esc(u.name):rid; }).join(', ');
        return `<div style="display:flex;align-items:flex-start;gap:8px;padding:10px;background:var(--surface2);border:1px solid var(--border);border-radius:6px;margin-bottom:8px">
          <div style="flex:1"><div style="font-size:13px;font-weight:600;color:var(--text)">${esc(t.name)}</div>${t.description?`<div style="font-size:11px;color:var(--text-muted)">${esc(t.description)}</div>`:''}<div style="font-size:11px;color:var(--text-dim);margin-top:4px">Reps: ${reps||'None assigned'}</div></div>
          <button class="btn btn-ghost btn-xs" onclick="openTerritoryModal('${t.id}')">Edit</button>
          <button class="btn btn-ghost btn-xs" style="color:var(--red)" onclick="p21DeleteTerritory('${t.id}')">Delete</button>
        </div>`;
      }).join('') || '<div style="font-size:12px;color:var(--text-muted)">No territories.</div>';
    }
  } catch(e) { toast(e.message, 'error'); }
}

async function p21DeleteTerritory(id) {
  if (!confirm('Delete this territory?')) return;
  try {
    await apiDelete('/territories/'+id);
    _p21Territories = _p21Territories.filter(t => t.id !== id);
    toast('Territory deleted', 'success');
    const tList = document.getElementById('territories-list');
    if (tList) { const modal = {innerHTML:''}; p21SaveTerritory; }
    if (typeof renderSettings === 'function') renderSettings();
  } catch(e) { toast(e.message, 'error'); }
}

function checkTerritoryWarning(territoryName) {
  if (!territoryName || !_currentUser) return '';
  if (_currentUser.role !== 'rep') return '';
  const territory = _p21Territories.find(t => t.name === territoryName);
  if (!territory) return '';
  if (territory.repIds && territory.repIds.includes(_currentUser.id)) return '';
  return `<div style="font-size:12px;color:#f97316;padding:6px 8px;background:#f9731618;border-radius:4px;border:1px solid #f9731630;margin-top:4px">
    Warning: You are not assigned to the "${esc(territoryName)}" territory.
  </div>`;
}

