// Store portal invoices globally for download function
window._p22PortalInvoices = {};

// Patch renderPortalV2 to include invoices section
(function patchPortalV2ForInvoices() {
  const _orig = window.renderPortalV2;
  window.renderPortalV2 = function(token) {
    // Use original but intercept to add invoices
    const el = document.getElementById('view-portal');
    if (!el) return _orig ? _orig.call(this, token) : null;
    el.innerHTML = '<div style="display:flex;align-items:center;justify-content:center;height:100%;color:var(--text-muted);font-size:14px">Loading deal room...</div>';

    fetch('/api/portal-v2/' + token)
      .then(r => r.json())
      .then(async data => {
        if (data.error) { el.innerHTML = `<div style="text-align:center;padding:40px;color:#ef4444">${esc(data.error)}</div>`; return; }

        // Call original logic by re-invoking with data already fetched
        // We rebuild the HTML with invoices included
        const stageWidth = data.stages.length ? 100 / data.stages.length : 100;
        const progressWidth = data.stageIdx >= 0 ? Math.round((data.stageIdx / Math.max(data.stages.length - 1, 1)) * 100) : 0;
        const invoices = data.invoices || [];
        // Store globally for download function
        invoices.forEach(inv => { window._p22PortalInvoices[inv.id] = inv; });

        el.innerHTML = `
          <div style="max-width:760px;margin:0 auto;padding:32px 16px">
            <div style="text-align:center;margin-bottom:32px">
              <div style="width:48px;height:48px;background:var(--accent);border-radius:12px;display:flex;align-items:center;justify-content:center;margin:0 auto 12px">
                <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="white" stroke-width="2" stroke-linecap="round"><rect x="3" y="3" width="7" height="7"/><rect x="14" y="3" width="7" height="7"/><rect x="14" y="14" width="7" height="7"/><rect x="3" y="14" width="7" height="7"/></svg>
              </div>
              <div style="font-size:22px;font-weight:700;color:var(--text)">${esc(data.dealName)}</div>
              <div style="font-size:14px;color:var(--text-muted);margin-top:4px">Deal Room</div>
            </div>

            <div class="panel" style="margin-bottom:16px">
              <div class="panel-header"><div class="panel-title">Deal Summary</div></div>
              <div style="padding:16px">
                <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:16px">
                  <div><div style="font-size:11px;color:var(--text-muted);text-transform:uppercase;margin-bottom:2px">Value</div><div style="font-size:20px;font-weight:700;color:var(--text)">${data.value ? formatCurrency(data.value) : 'TBD'}</div></div>
                  <div><div style="font-size:11px;color:var(--text-muted);text-transform:uppercase;margin-bottom:2px">Stage</div><div style="font-size:14px;font-weight:600;color:var(--accent)">${esc(data.stage)}</div></div>
                  ${data.closeDate ? `<div><div style="font-size:11px;color:var(--text-muted);text-transform:uppercase;margin-bottom:2px">Target Close</div><div style="font-size:13px;color:var(--text)">${formatDate(data.closeDate)}</div></div>` : ''}
                </div>
                ${data.stages.length > 0 ? `
                <div style="margin-top:8px">
                  <div style="display:flex;justify-content:space-between;font-size:11px;color:var(--text-muted);margin-bottom:6px"><span>Progress</span><span>${progressWidth}%</span></div>
                  <div style="height:6px;background:var(--border);border-radius:3px;margin-bottom:8px">
                    <div style="height:100%;width:${progressWidth}%;background:var(--accent);border-radius:3px;transition:width 0.6s ease"></div>
                  </div>
                  <div style="display:flex;justify-content:space-between;font-size:10px;color:var(--text-muted)">
                    ${data.stages.map(s => `<span style="${data.stage===s?'color:var(--accent);font-weight:600':''}">${esc(s)}</span>`).join('')}
                  </div>
                </div>` : ''}
              </div>
            </div>

            ${invoices.length > 0 ? `
            <div class="panel" style="margin-bottom:16px">
              <div class="panel-header"><div class="panel-title">Invoices</div><span class="panel-count">${invoices.length}</span></div>
              <div style="padding:12px;display:flex;flex-direction:column;gap:8px">
                ${invoices.map(inv => {
                  const statusColor = inv.status === 'Paid' ? '#22c55e' : inv.status === 'Overdue' ? '#ef4444' : '#ca8a04';
                  return `
                  <div style="padding:12px;background:var(--surface2);border-radius:8px;border:1px solid var(--border)" id="portal-inv-${inv.id}">
                    <div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:8px">
                      <div>
                        <div style="font-size:14px;font-weight:600;color:var(--text)">${esc(inv.number)}</div>
                        <div style="font-size:11px;color:var(--text-muted);margin-top:2px">Due: ${inv.dueDate ? formatDate(inv.dueDate) : '—'}</div>
                      </div>
                      <div style="text-align:right">
                        <div style="font-size:18px;font-weight:700;color:var(--text)">$${(inv.total||0).toLocaleString()}</div>
                        <span style="font-size:11px;font-weight:600;padding:2px 8px;border-radius:10px;background:${statusColor}22;color:${statusColor}">${esc(inv.status)}</span>
                      </div>
                    </div>
                    <div style="display:flex;gap:8px;flex-wrap:wrap">
                      ${inv.reviewed ? `<span style="font-size:11px;color:#22c55e;display:flex;align-items:center;gap:3px"><svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round"><polyline points="20 6 9 17 4 12"/></svg>Reviewed</span>` :
                        `<button class="btn btn-secondary btn-sm" style="font-size:11px;padding:3px 10px" onclick="p22PortalMarkReviewed('${token}','${inv.id}')">Mark as Reviewed</button>`}
                      <button class="btn btn-secondary btn-sm" style="font-size:11px;padding:3px 10px" onclick="p22ShowPayNow()">Pay Now</button>
                      <button class="btn btn-secondary btn-sm" style="font-size:11px;padding:3px 10px" onclick="p22DownloadInvoice('${inv.id}')">Download</button>
                    </div>
                  </div>`;
                }).join('')}
              </div>
            </div>` : ''}

            ${data.checklists && data.checklists.length ? `
            <div class="panel" style="margin-bottom:16px">
              <div class="panel-header"><div class="panel-title">Onboarding Progress</div></div>
              <div style="padding:16px">
                ${data.checklists.map(cl => {
                  const total = cl.items.length;
                  const done = cl.items.filter(i=>i.done).length;
                  const pct = total ? Math.round((done/total)*100) : 0;
                  return `<div style="margin-bottom:12px">
                    <div style="display:flex;justify-content:space-between;font-size:13px;font-weight:500;margin-bottom:4px"><span>${esc(cl.name)}</span><span style="color:var(--text-muted)">${done}/${total}</span></div>
                    <div style="height:4px;background:var(--border);border-radius:2px;margin-bottom:8px"><div style="height:100%;width:${pct}%;background:#22c55e;border-radius:2px"></div></div>
                    ${cl.items.map(item => `<div style="display:flex;align-items:center;gap:8px;padding:4px 0;font-size:12px;color:${item.done?'#22c55e':'var(--text-dim)'}">
                      <span style="width:14px;height:14px;border-radius:3px;border:1.5px solid ${item.done?'#22c55e':'var(--border)'};background:${item.done?'#22c55e':'transparent'};display:inline-flex;align-items:center;justify-content:center;flex-shrink:0">
                        ${item.done ? '<svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="white" stroke-width="3" stroke-linecap="round"><polyline points="20 6 9 17 4 12"/></svg>' : ''}
                      </span>${esc(item.title)}
                    </div>`).join('')}
                  </div>`;
                }).join('')}
              </div>
            </div>` : ''}

            ${data.docs && data.docs.length ? `
            <div class="panel" style="margin-bottom:16px">
              <div class="panel-header"><div class="panel-title">Documents</div></div>
              <div style="padding:12px">
                ${data.docs.map(d => `<div style="display:flex;align-items:center;gap:8px;padding:6px 8px">
                  <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="var(--text-muted)" stroke-width="2" stroke-linecap="round"><path d="M13 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V9z"/><polyline points="13,2 13,9 20,9"/></svg>
                  ${d.url ? `<a href="${esc(d.url)}" target="_blank" style="font-size:13px;color:var(--accent);text-decoration:none">${esc(d.title)}</a>` : `<span style="font-size:13px;color:var(--text)">${esc(d.title)}</span>`}
                  <span style="font-size:11px;color:var(--text-muted);margin-left:auto">${d.date_added||''}</span>
                </div>`).join('')}
              </div>
            </div>` : ''}

            ${data.proposal ? `
            <div class="panel" style="margin-bottom:16px">
              <div class="panel-header"><div class="panel-title">Proposal</div></div>
              <div style="padding:12px;font-size:13px">
                <div>${esc(data.proposal.title||'Proposal')}</div>
                <div style="color:var(--text-muted);font-size:11px;margin-top:4px">Status: ${esc(data.proposal.status)} ${data.proposal.signed_at ? '· Signed ' + formatDate(data.proposal.signed_at) : ''}</div>
              </div>
            </div>` : ''}

            <div class="panel" style="margin-bottom:16px">
              <div class="panel-header"><div class="panel-title">Upload a File</div></div>
              <div style="padding:16px">
                <input type="text" id="portal-upload-name" placeholder="Your name" class="form-input" style="margin-bottom:8px" />
                <input type="file" id="portal-upload-file" class="form-input" style="margin-bottom:8px" />
                <button class="btn btn-primary btn-sm" onclick="portalV2Upload('${token}')">Upload</button>
                ${data.uploadedDocs && data.uploadedDocs.length ? `
                <div style="margin-top:12px;font-size:12px;color:var(--text-muted)">
                  <div style="font-weight:500;margin-bottom:4px">Previously uploaded:</div>
                  ${data.uploadedDocs.map(d => `<div style="color:var(--text-dim)">${esc(d.title)} — ${d.date_added||''}</div>`).join('')}
                </div>` : ''}
              </div>
            </div>

            <div class="panel">
              <div class="panel-header"><div class="panel-title">Comments</div></div>
              <div style="padding:16px">
                <div id="portal-comments-list" style="margin-bottom:12px">
                  ${!(data.comments||[]).length ? '<div style="font-size:12px;color:var(--text-muted)">No comments yet.</div>' : ''}
                  ${(data.comments||[]).map(c => `<div style="margin-bottom:10px;padding:10px;background:var(--surface2);border-radius:6px;border:1px solid var(--border)">
                    <div style="font-size:12px;font-weight:600;color:var(--text);margin-bottom:4px">${esc(c.author_name)}</div>
                    <div style="font-size:13px;color:var(--text-dim)">${esc(c.body)}</div>
                    <div style="font-size:11px;color:var(--text-muted);margin-top:4px">${formatDate(c.created_at)}</div>
                  </div>`).join('')}
                </div>
                <div style="display:flex;flex-direction:column;gap:8px">
                  <input type="text" id="portal-comment-name" placeholder="Your name" class="form-input" />
                  <textarea id="portal-comment-body" placeholder="Leave a comment..." class="form-input" rows="3" style="resize:vertical"></textarea>
                  <button class="btn btn-primary btn-sm" onclick="portalV2PostComment('${token}')">Post Comment</button>
                </div>
              </div>
            </div>

            <div id="p22-pay-now-msg" style="display:none;margin-top:12px;padding:16px;background:rgba(99,102,241,0.1);border-radius:8px;border:1px solid var(--accent);text-align:center;font-size:13px;color:var(--accent)">
              Payment processing coming soon. Please contact us to arrange payment.
            </div>

          </div>`;
      })
      .catch(err => { el.innerHTML = `<div style="text-align:center;padding:40px;color:#ef4444">${esc(err.message)}</div>`; });
  };

})();

async function p22PortalMarkReviewed(token, invoiceId) {
  try {
    const btn = document.querySelector(`#portal-inv-${invoiceId} button`);
    if (btn) { btn.textContent = 'Saving...'; btn.disabled = true; }
    const result = await fetch(`/api/portal-v2/${token}/invoice/${invoiceId}/reviewed`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({}),
    }).then(r => r.json());
    if (result.ok || result.alreadyReviewed) {
      const invEl = document.getElementById(`portal-inv-${invoiceId}`);
      if (invEl) {
        const btnArea = invEl.querySelector('[onclick*="p22PortalMarkReviewed"]');
        if (btnArea) btnArea.outerHTML = `<span style="font-size:11px;color:#22c55e;display:flex;align-items:center;gap:3px"><svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round"><polyline points="20 6 9 17 4 12"/></svg>Reviewed</span>`;
      }
      toast('Invoice marked as reviewed', 'success');
    }
  } catch(e) { toast('Failed to mark reviewed', 'error'); }
}

function p22ShowPayNow() {
  const msg = document.getElementById('p22-pay-now-msg');
  if (msg) { msg.style.display = ''; msg.scrollIntoView({ behavior: 'smooth', block: 'center' }); }
}

function p22DownloadInvoice(invOrId) {
  let inv = invOrId;
  if (typeof invOrId === 'string') {
    inv = window._p22PortalInvoices[invOrId];
    if (!inv) { toast('Invoice not found', 'error'); return; }
  }

  const items = (inv.items || []);
  const html = `<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Invoice ${esc(inv.number||'')}</title>
  <style>body{font-family:Arial,sans-serif;max-width:700px;margin:40px auto;padding:0 20px;color:#111}h1{font-size:24px;margin-bottom:4px}table{width:100%;border-collapse:collapse;margin:16px 0}th,td{text-align:left;padding:8px;border-bottom:1px solid #ddd}th{background:#f4f4f4;font-size:12px;text-transform:uppercase}.total{font-size:20px;font-weight:700;text-align:right;margin-top:12px}.meta{font-size:13px;color:#555;margin:4px 0}@media print{button{display:none}}</style>
  </head><body>
  <h1>Invoice ${esc(inv.number||'')}</h1>
  <div class="meta">Status: ${esc(inv.status||'')}</div>
  <div class="meta">Issue Date: ${inv.issueDate ? formatDate(inv.issueDate) : '—'}</div>
  <div class="meta">Due Date: ${inv.dueDate ? formatDate(inv.dueDate) : '—'}</div>
  <table>
    <thead><tr><th>Description</th><th>Qty</th><th>Price</th><th>Total</th></tr></thead>
    <tbody>
      ${items.map(it => `<tr><td>${esc(it.description||it.name||'')}</td><td>${it.qty||1}</td><td>$${(it.price||0).toLocaleString()}</td><td>$${((it.qty||1)*(it.price||0)).toLocaleString()}</td></tr>`).join('')}
    </tbody>
  </table>
  <div class="total">Total: $${(inv.total||0).toLocaleString()}</div>
  ${inv.notes ? `<div style="margin-top:16px;font-size:13px;color:#555">Notes: ${esc(inv.notes)}</div>` : ''}
  <script>window.print();<\/script>
  </body></html>`;

  const w = window.open('', '_blank');
  if (w) { w.document.write(html); w.document.close(); }
  else toast('Pop-up blocked. Please allow pop-ups to download.', 'warning');
}

