// Make saveContact properly persist referredBy to the API
// The Phase 16 deep override of saveContact sends fields but misses referredBy.
// We wrap to inject referredBy into the API call after save.
(function ensureSaveContactPicksUpReferredBy() {
  const _orig = window.saveContact;
  if (!_orig) return;
  window.saveContact = async function() {
    const refEl = document.getElementById('contact-form-referred-by');
    const refId = refEl ? refEl.value : '';
    const formId = document.getElementById('contact-form-id')?.value;

    await _orig.call(this);

    // After save, update referredBy field via API
    if (refEl !== null) {
      // Find the contact that was just saved
      let targetId = formId;
      if (!targetId) {
        // New contact — get the most recently created one
        const allContacts = await apiGet('/contacts').catch(() => []);
        if (allContacts.length) targetId = allContacts[allContacts.length - 1].id;
      }
      if (targetId) {
        try {
          const contact = db.contacts.find(c => c.id === targetId) ||
                          await apiGet('/contacts/' + targetId).catch(() => null);
          if (contact && contact.referredBy !== refId) {
            const updated = await apiPut('/contacts/' + targetId, { ...contact, referredBy: refId || null });
            const idx = db.contacts.findIndex(c => c.id === targetId);
            if (idx >= 0) db.contacts[idx] = updated;
          }
        } catch(e) { /* non-fatal */ }
      }
    }
  };
})();

