// ─────────────────────────────────────────────────────────────────────────────
// 22.I  EMAIL INBOX INTEGRATION
// ─────────────────────────────────────────────────────────────────────────────

let _inboxMessages   = [];
let _inboxUnread     = 0;
let _inboxSearchQ    = '';
let _activeMessageId = null;

// Update the nav badge with unread count
function p22UpdateInboxBadge(count) {
  const badge = document.getElementById('nav-inbox-badge');
  if (!badge) return;
  _inboxUnread = count;
  if (count > 0) {
    badge.textContent = count > 99 ? '99+' : count;
    badge.style.display = 'inline-flex';
  } else {
    badge.style.display = 'none';
  }
}

// Sync inbox — calls /api/email/sync then reloads
async function p22SyncInbox() {
  const btn = document.querySelector('#view-inbox .btn-secondary');
  if (btn) { btn.disabled = true; btn.textContent = 'Syncing...'; }
  try {
    const r = await fetch('/api/email/sync', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + getToken() }
    });
    const data = await r.json();
    if (data.inserted > 0) toast(`Synced ${data.inserted} new message${data.inserted !== 1 ? 's' : ''}`, 'success');
    else toast('Inbox up to date', 'info');
    await p22LoadInboxMessages();
    p22RenderInboxList();
  } catch(e) {
    toast('Sync failed: ' + e.message, 'error');
  } finally {
    if (btn) { btn.disabled = false; btn.textContent = 'Sync'; }
  }
}

// Load all messages from API
async function p22LoadInboxMessages(search) {
  try {
    let url = '/api/email/inbox?limit=100';
    if (search) url += '&search=' + encodeURIComponent(search);
    const data = await apiGet(url.replace('/api/', ''));
    _inboxMessages = data.messages || [];
    p22UpdateInboxBadge(data.unreadCount || 0);
    return _inboxMessages;
  } catch(e) {
    _inboxMessages = [];
    return [];
  }
}

// Search debounce
let _inboxSearchTimer = null;
function p22InboxSearch(q) {
  _inboxSearchQ = q;
  clearTimeout(_inboxSearchTimer);
  _inboxSearchTimer = setTimeout(async () => {
    await p22LoadInboxMessages(q);
    p22RenderInboxList();
  }, 300);
}

function p22FormatDate(ts) {
  if (!ts) return '';
  const d = new Date(ts);
  const now = new Date();
  const diff = now - d;
  if (diff < 86400000 && d.getDate() === now.getDate()) {
    return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  }
  if (diff < 7 * 86400000) {
    return d.toLocaleDateString([], { weekday: 'short' });
  }
  return d.toLocaleDateString([], { month: 'short', day: 'numeric' });
}

function p22RenderInboxList() {
  const container = document.getElementById('inbox-list');
  if (!container) return;

  if (_inboxMessages.length === 0) {
    container.innerHTML = `
      <div style="padding:24px;text-align:center;color:var(--text-muted);font-size:13px">
        No messages. Click Sync to load your inbox.
      </div>`;
    return;
  }

  container.innerHTML = _inboxMessages.map(m => {
    const isUnread = !m.read_at;
    const isActive = m.id === _activeMessageId;
    return `<div class="inbox-row${isActive ? ' active' : ''}" data-id="${m.id}" onclick="p22OpenMessage('${m.id}')" style="padding:12px 14px;border-bottom:1px solid var(--border);cursor:pointer;background:${isActive ? 'var(--hover)' : 'transparent'};${isUnread ? 'border-left:3px solid var(--primary);' : 'border-left:3px solid transparent;'}transition:background .15s">
      <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:8px;margin-bottom:3px">
        <div style="font-size:12px;font-weight:${isUnread ? '700' : '500'};color:var(--text);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;max-width:220px">${escapeHtml(m.from_name || m.from_email)}</div>
        <div style="font-size:11px;color:var(--text-muted);white-space:nowrap;flex-shrink:0">${p22FormatDate(m.received_at)}</div>
      </div>
      <div style="font-size:12px;font-weight:${isUnread ? '600' : '400'};color:var(--text);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;margin-bottom:2px">${escapeHtml(m.subject || '(no subject)')}</div>
      <div style="font-size:11px;color:var(--text-muted);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${escapeHtml((m.body_text || '').substring(0, 80))}</div>
      ${m.contact_name ? `<div style="font-size:10px;color:var(--primary);margin-top:3px">${escapeHtml(m.contact_name)}</div>` : ''}
    </div>`;
  }).join('');
}

async function p22OpenMessage(id) {
  _activeMessageId = id;
  // Re-render list to update active + unread state
  const existing = _inboxMessages.find(m => m.id === id);
  if (existing && !existing.read_at) {
    existing.read_at = Date.now();
    if (_inboxUnread > 0) p22UpdateInboxBadge(_inboxUnread - 1);
  }
  p22RenderInboxList();

  const detail = document.getElementById('inbox-detail');
  if (!detail) return;
  detail.innerHTML = '<div style="padding:24px;color:var(--text-muted);font-size:13px">Loading...</div>';

  try {
    const token = getToken();
    const r = await fetch('/api/email/inbox/' + id, {
      headers: { 'Authorization': 'Bearer ' + token }
    });
    const msg = await r.json();

    // Load contacts for linking
    let contactOptions = '';
    try {
      const contacts = await apiGet('contacts?limit=200');
      const list = contacts.contacts || contacts || [];
      contactOptions = list.map(c => `<option value="${c.id}">${escapeHtml(c.name)}${c.email ? ' — ' + c.email : ''}</option>`).join('');
    } catch(_) {}

    const linkedBadge = msg.contact_name
      ? `<span style="display:inline-block;padding:2px 8px;border-radius:10px;background:var(--primary-dim, rgba(99,102,241,.15));color:var(--primary);font-size:11px;font-weight:600">Linked: ${escapeHtml(msg.contact_name)}</span>`
      : '';

    const activityBadge = msg.activity_logged
      ? `<span style="display:inline-block;padding:2px 8px;border-radius:10px;background:rgba(34,197,94,.12);color:#22c55e;font-size:11px;font-weight:600">Activity Logged</span>`
      : '';

    detail.innerHTML = `
      <div style="padding:20px 24px;border-bottom:1px solid var(--border)">
        <div style="font-size:17px;font-weight:700;color:var(--text);margin-bottom:8px">${escapeHtml(msg.subject || '(no subject)')}</div>
        <div style="font-size:12px;color:var(--text-muted);margin-bottom:6px">
          <strong>From:</strong> ${escapeHtml(msg.from_name || '')} &lt;${escapeHtml(msg.from_email)}&gt;
        </div>
        <div style="font-size:12px;color:var(--text-muted);margin-bottom:10px">
          <strong>Received:</strong> ${new Date(msg.received_at).toLocaleString()}
        </div>
        <div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap">
          ${linkedBadge}
          ${activityBadge}
        </div>
      </div>

      <div style="padding:20px 24px;border-bottom:1px solid var(--border)">
        <div style="font-size:13px;color:var(--text);line-height:1.6;white-space:pre-wrap">${escapeHtml(msg.body_text || '(empty message)')}</div>
      </div>

      <div style="padding:16px 24px">
        <div style="font-size:12px;font-weight:600;color:var(--text);margin-bottom:8px">Link to Contact</div>
        <div style="display:flex;gap:8px;align-items:center;flex-wrap:wrap">
          <select id="inbox-link-contact-sel" style="flex:1;min-width:180px;padding:6px 10px;border-radius:6px;border:1px solid var(--border);background:var(--input-bg);color:var(--text);font-size:12px">
            <option value="">-- Select contact --</option>
            ${contactOptions}
          </select>
          <button class="btn btn-primary btn-sm" style="font-size:12px" onclick="p22LinkMessageToContact('${msg.id}')">Link + Log Activity</button>
        </div>
        <div id="inbox-link-result" style="margin-top:6px;font-size:11px;color:var(--text-muted)"></div>
      </div>`;

    // Pre-select if already linked
    if (msg.linked_contact_id) {
      const sel = document.getElementById('inbox-link-contact-sel');
      if (sel) sel.value = msg.linked_contact_id;
    }
  } catch(e) {
    detail.innerHTML = `<div style="padding:24px;color:var(--danger);font-size:13px">Failed to load message: ${e.message}</div>`;
  }
}

async function p22LinkMessageToContact(msgId) {
  const sel = document.getElementById('inbox-link-contact-sel');
  if (!sel || !sel.value) { toast('Select a contact first', 'error'); return; }
  const contactId = sel.value;
  try {
    const r = await fetch('/api/email/inbox/' + msgId + '/link-contact', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + getToken() },
      body: JSON.stringify({ contactId })
    });
    const data = await r.json();
    if (!r.ok) throw new Error(data.error || 'Failed');
    toast('Contact linked and activity logged', 'success');

    // Update local state
    const m = _inboxMessages.find(x => x.id === msgId);
    if (m && data.message) {
      m.linked_contact_id = data.message.linked_contact_id;
      m.contact_name      = data.message.contact_name;
      m.activity_logged   = data.message.activity_logged;
    }

    const resultEl = document.getElementById('inbox-link-result');
    if (resultEl) resultEl.textContent = 'Linked to ' + (data.message.contact_name || contactId) + ' — activity logged.';

    p22RenderInboxList();
  } catch(e) {
    toast('Link failed: ' + e.message, 'error');
  }
}

// Main render function for the Inbox view
async function p22RenderInbox() {
  const view = document.getElementById('view-inbox');
  if (!view) return;

  // Ensure content containers exist (they're in index.html)
  const listEl   = document.getElementById('inbox-list');
  const detailEl = document.getElementById('inbox-detail');

  if (listEl) listEl.innerHTML = '<div style="padding:24px;text-align:center;color:var(--text-muted);font-size:13px">Loading...</div>';

  await p22LoadInboxMessages(_inboxSearchQ);

  if (_inboxMessages.length === 0) {
    // Auto-sync on first load
    await p22SyncInbox();
  } else {
    p22RenderInboxList();
  }
}

