async function p22RenderEmailIntegrationSettings() {
  const container = document.getElementById('p22-email-integration-body');
  if (!container) return;
  container.innerHTML = '<div style="padding:12px;font-size:12px;color:var(--text-muted)">Loading...</div>';

  let config = null;
  try {
    config = await apiGet('email/config');
  } catch(_) {}

  const isMock = !config || config.mock_mode;

  container.innerHTML = `
    <form id="email-integration-form" onsubmit="p22SaveEmailConfig(event)" style="padding:12px;display:flex;flex-direction:column;gap:10px">
      <div style="display:flex;align-items:center;gap:8px;margin-bottom:4px">
        <label style="font-size:12px;font-weight:600;color:var(--text)">
          <input type="checkbox" id="ei-mock" ${isMock ? 'checked' : ''} onchange="p22ToggleEmailMock(this.checked)" style="margin-right:5px" />
          Mock mode (demo data, no real IMAP connection)
        </label>
      </div>
      <div id="ei-real-fields" style="display:${isMock ? 'none' : 'flex'};flex-direction:column;gap:8px">
        <div style="display:grid;grid-template-columns:1fr 80px;gap:8px">
          <div>
            <label style="font-size:11px;color:var(--text-muted);display:block;margin-bottom:3px">IMAP Host</label>
            <input type="text" id="ei-host" placeholder="imap.gmail.com" value="${config && config.host ? escapeHtml(config.host) : ''}" style="width:100%;padding:6px 10px;border-radius:6px;border:1px solid var(--border);background:var(--input-bg);color:var(--text);font-size:12px" />
          </div>
          <div>
            <label style="font-size:11px;color:var(--text-muted);display:block;margin-bottom:3px">Port</label>
            <input type="number" id="ei-port" placeholder="993" value="${config && config.port ? config.port : 993}" style="width:100%;padding:6px 10px;border-radius:6px;border:1px solid var(--border);background:var(--input-bg);color:var(--text);font-size:12px" />
          </div>
        </div>
        <div>
          <label style="font-size:11px;color:var(--text-muted);display:block;margin-bottom:3px">Email Address</label>
          <input type="email" id="ei-email" placeholder="you@example.com" value="${config && config.email ? escapeHtml(config.email) : ''}" style="width:100%;padding:6px 10px;border-radius:6px;border:1px solid var(--border);background:var(--input-bg);color:var(--text);font-size:12px" />
        </div>
        <div>
          <label style="font-size:11px;color:var(--text-muted);display:block;margin-bottom:3px">App Password / Token</label>
          <input type="password" id="ei-pass" placeholder="Leave blank to keep existing" style="width:100%;padding:6px 10px;border-radius:6px;border:1px solid var(--border);background:var(--input-bg);color:var(--text);font-size:12px" />
        </div>
      </div>
      ${config && config.last_synced ? `<div style="font-size:11px;color:var(--text-muted)">Last synced: ${new Date(config.last_synced).toLocaleString()}</div>` : ''}
      <div style="display:flex;gap:8px">
        <button type="submit" class="btn btn-primary btn-sm" style="font-size:12px">Save Config</button>
        <button type="button" class="btn btn-secondary btn-sm" style="font-size:12px" onclick="p22SyncFromSettings()">Sync Now</button>
      </div>
    </form>`;
}

function p22ToggleEmailMock(isMock) {
  const fields = document.getElementById('ei-real-fields');
  if (fields) fields.style.display = isMock ? 'none' : 'flex';
}

async function p22SaveEmailConfig(e) {
  e.preventDefault();
  const mock_mode = document.getElementById('ei-mock').checked;
  const host      = (document.getElementById('ei-host')  || {}).value || null;
  const port      = parseInt((document.getElementById('ei-port')  || {}).value || '993', 10);
  const email     = (document.getElementById('ei-email') || {}).value || null;
  const password  = (document.getElementById('ei-pass')  || {}).value || null;

  try {
    const r = await fetch('/api/email/connect', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + getToken() },
      body: JSON.stringify({ host, port, email, password, mock_mode })
    });
    const data = await r.json();
    if (!r.ok) throw new Error(data.error || 'Failed');
    toast('Email integration saved', 'success');
    p22RenderEmailIntegrationSettings();
  } catch(err) {
    toast('Save failed: ' + err.message, 'error');
  }
}

async function p22SyncFromSettings() {
  const btn = document.querySelector('#p22-email-integration-body .btn-secondary');
  if (btn) { btn.disabled = true; btn.textContent = 'Syncing...'; }
  try {
    const r = await fetch('/api/email/sync', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + getToken() }
    });
    const data = await r.json();
    toast(`Sync complete — ${data.total} messages in inbox`, 'success');
    p22RenderEmailIntegrationSettings();
  } catch(e) {
    toast('Sync failed: ' + e.message, 'error');
  } finally {
    if (btn) { btn.disabled = false; btn.textContent = 'Sync Now'; }
  }
}

