'use strict';

// ── Shared helpers ───────────────────────────────────────────────────────────

// escapeHtml alias (used in Phase 22+ code)
if (typeof escapeHtml === 'undefined') {
  window.escapeHtml = function(str) {
    if (str === null || str === undefined) return '';
    return String(str)
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#39;');
  };
}

function p23FormatCurrency(amount, code, currencies) {
  const cur = currencies && currencies.find(c => c.code === code);
  const symbol = cur ? cur.symbol : (code === 'USD' ? '$' : code + ' ');
  const num = parseFloat(amount) || 0;
  return symbol + num.toLocaleString('en-US', { minimumFractionDigits: 0, maximumFractionDigits: 2 });
}

// ── Global currency cache ────────────────────────────────────────────────────
let _p23Currencies = null;
async function p23GetCurrencies() {
  if (_p23Currencies) return _p23Currencies;
  try {
    _p23Currencies = await apiGet('/currencies');
  } catch(e) {
    _p23Currencies = [
      { id: 'usd', code: 'USD', symbol: '$', name: 'US Dollar', rate: 1.0, active: true },
    ];
  }
  return _p23Currencies;
}

function p23InvalidateCurrencyCache() { _p23Currencies = null; }

// ══════════════════════════════════════════════════════════════════════════
// 1. PIPELINE AUTOMATION / WORKFLOW TRIGGERS
// ══════════════════════════════════════════════════════════════════════════

let _p23Workflows = [];

async function p23LoadWorkflows() {
  try { _p23Workflows = await apiGet('/workflow-rules'); } catch(e) { _p23Workflows = []; }
}

function p23RenderWorkflowsSettings() {
  const container = document.getElementById('p23-workflows-body');
  if (!container) return;

  p23LoadWorkflows().then(() => {
    container.innerHTML = `
      <div style="padding:12px">
        <button class="btn btn-primary btn-sm" onclick="p23OpenWorkflowModal(null)" style="margin-bottom:12px">+ Add Rule</button>
        ${_p23Workflows.length === 0 ? `<div style="font-size:12px;color:var(--text-muted);padding:8px 0">No workflow rules yet. Add one to automate CRM actions.</div>` : ''}
        <div id="p23-workflow-list">
          ${_p23Workflows.map(rule => `
            <div style="display:flex;align-items:center;gap:8px;padding:8px 10px;background:var(--surface2);border-radius:6px;margin-bottom:6px">
              <div style="flex:1;min-width:0">
                <div style="font-size:13px;font-weight:600;color:var(--text)">${escapeHtml(rule.name)}</div>
                <div style="font-size:11px;color:var(--text-muted)">
                  ${p23TriggerLabel(rule.triggerEvent, rule.triggerCondition)} &rarr; ${(rule.actions || []).length} action(s)
                </div>
              </div>
              <label style="display:flex;align-items:center;gap:4px;cursor:pointer;font-size:11px;color:var(--text-muted)">
                <input type="checkbox" ${rule.active ? 'checked' : ''} onchange="p23ToggleWorkflow('${rule.id}', this.checked)" />
                Active
              </label>
              <button class="btn btn-ghost btn-xs" onclick="p23OpenWorkflowModal('${rule.id}')">Edit</button>
              <button class="btn btn-ghost btn-xs" style="color:var(--red)" onclick="p23DeleteWorkflow('${rule.id}')">Delete</button>
              <button class="btn btn-ghost btn-xs" onclick="p23ViewWorkflowHistory('${rule.id}', '${escapeHtml(rule.name)}')">History</button>
            </div>
          `).join('')}
        </div>
      </div>`;
  });
}

function p23TriggerLabel(event, condition) {
  const labels = {
    deal_stage_change: 'Deal stage changes',
    deal_created: 'Deal is created',
    contact_created: 'Contact is created',
    task_overdue: 'Task is overdue',
  };
  let label = labels[event] || event;
  if (event === 'deal_stage_change' && condition && condition.stage) {
    label += ` to "${condition.stage}"`;
  }
  return label;
}

function p23OpenWorkflowModal(ruleId) {
  const rule = ruleId ? _p23Workflows.find(r => r.id === ruleId) : null;
  const actions = rule ? JSON.parse(JSON.stringify(rule.actions || [])) : [];
  window._p23EditActions = actions;

  const stagesEl = document.querySelector('[data-pipeline-stages]');
  let stages = [];
  try {
    const stagesData = document.querySelector('#pipeline-stage-select');
    // Get stages from existing pipeline settings if available
  } catch(e) {}

  const modal = document.createElement('div');
  modal.className = 'modal-overlay';
  modal.id = 'p23-workflow-modal';
  modal.innerHTML = `
    <div class="modal" style="width:560px;max-height:90vh;overflow-y:auto">
      <div class="modal-header">
        <div class="modal-title">${rule ? 'Edit' : 'New'} Workflow Rule</div>
        <button class="modal-close" onclick="document.getElementById('p23-workflow-modal').remove()">&#x2715;</button>
      </div>
      <div class="modal-body" style="display:flex;flex-direction:column;gap:14px">
        <div>
          <label class="field-label">Rule Name</label>
          <input type="text" id="wf-name" class="field-input" value="${rule ? escapeHtml(rule.name) : ''}" placeholder="e.g. Auto-create follow-up task" />
        </div>
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px">
          <div>
            <label class="field-label">Trigger Event</label>
            <select id="wf-trigger-event" class="field-input" onchange="p23UpdateTriggerConditionUI()">
              <option value="deal_stage_change" ${(!rule || rule.triggerEvent==='deal_stage_change')?'selected':''}>Deal stage changes</option>
              <option value="deal_created" ${rule&&rule.triggerEvent==='deal_created'?'selected':''}>Deal is created</option>
              <option value="contact_created" ${rule&&rule.triggerEvent==='contact_created'?'selected':''}>Contact is created</option>
              <option value="task_overdue" ${rule&&rule.triggerEvent==='task_overdue'?'selected':''}>Task is overdue</option>
            </select>
          </div>
          <div id="wf-condition-container">
            <label class="field-label">Condition (optional)</label>
            <input type="text" id="wf-condition-stage" class="field-input" placeholder="Stage name (e.g. Proposal Sent)" value="${rule&&rule.triggerCondition&&rule.triggerCondition.stage ? escapeHtml(rule.triggerCondition.stage) : ''}" />
          </div>
        </div>

        <div>
          <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:8px">
            <label class="field-label" style="margin:0">Actions</label>
            <select id="wf-add-action-type" class="field-input" style="width:auto;font-size:12px;padding:4px 8px">
              <option value="">Add action...</option>
              <option value="create_task">Auto-create task</option>
              <option value="log_activity">Log activity</option>
              <option value="send_webhook">Send webhook</option>
              <option value="update_deal_field">Update deal field</option>
            </select>
            <button class="btn btn-secondary btn-sm" onclick="p23AddWorkflowAction()">+ Add</button>
          </div>
          <div id="wf-actions-list">
            ${actions.map((a, i) => p23RenderActionRow(a, i)).join('')}
          </div>
          ${actions.length === 0 ? `<div id="wf-no-actions" style="font-size:12px;color:var(--text-muted);padding:6px 0">No actions yet. Add at least one action.</div>` : ''}
        </div>
      </div>
      <div class="modal-footer">
        <button class="btn btn-secondary" onclick="document.getElementById('p23-workflow-modal').remove()">Cancel</button>
        <button class="btn btn-primary" onclick="p23SaveWorkflow('${ruleId || ''}')">Save Rule</button>
      </div>
    </div>`;
  document.body.appendChild(modal);
}

function p23UpdateTriggerConditionUI() {
  const event = document.getElementById('wf-trigger-event')?.value;
  const container = document.getElementById('wf-condition-container');
  if (!container) return;
  if (event === 'deal_stage_change') {
    container.style.display = '';
    container.querySelector('label').textContent = 'To Stage (leave blank for any)';
    container.querySelector('input').placeholder = 'Stage name';
  } else {
    container.style.display = 'none';
  }
}

function p23RenderActionRow(action, idx) {
  const typeLabels = { create_task: 'Create Task', log_activity: 'Log Activity', send_webhook: 'Send Webhook', update_deal_field: 'Update Field' };
  let fields = '';
  if (action.type === 'create_task') {
    fields = `
      <input type="text" placeholder="Task title" value="${escapeHtml(action.title||'')}" oninput="p23UpdateAction(${idx},'title',this.value)" class="field-input" style="margin-bottom:4px" />
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:6px">
        <input type="text" placeholder="Assignee (email or tag)" value="${escapeHtml(action.assignee||'')}" oninput="p23UpdateAction(${idx},'assignee',this.value)" class="field-input" />
        <input type="number" placeholder="Due in N days" value="${action.dueOffset||1}" oninput="p23UpdateAction(${idx},'dueOffset',this.value)" class="field-input" />
      </div>`;
  } else if (action.type === 'log_activity') {
    fields = `
      <select oninput="p23UpdateAction(${idx},'activityType',this.value)" class="field-input" style="margin-bottom:4px">
        ${['Note','Call','Email','Meeting'].map(t => `<option ${action.activityType===t?'selected':''}>${t}</option>`).join('')}
      </select>
      <textarea placeholder="Activity note" rows="2" oninput="p23UpdateAction(${idx},'note',this.value)" class="field-input" style="resize:vertical">${escapeHtml(action.note||'')}</textarea>`;
  } else if (action.type === 'send_webhook') {
    fields = `<input type="url" placeholder="Webhook URL (https://...)" value="${escapeHtml(action.webhookUrl||'')}" oninput="p23UpdateAction(${idx},'webhookUrl',this.value)" class="field-input" />`;
  } else if (action.type === 'update_deal_field') {
    fields = `
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:6px">
        <select oninput="p23UpdateAction(${idx},'field',this.value)" class="field-input">
          ${['stage','owner','close_date','notes'].map(f => `<option value="${f}" ${action.field===f?'selected':''}>${f}</option>`).join('')}
        </select>
        <input type="text" placeholder="New value" value="${escapeHtml(action.value||'')}" oninput="p23UpdateAction(${idx},'value',this.value)" class="field-input" />
      </div>`;
  }
  return `
    <div class="p23-action-row" data-idx="${idx}" style="background:var(--surface3,var(--surface2));border:1px solid var(--border);border-radius:6px;padding:10px;margin-bottom:6px">
      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:8px">
        <span style="font-size:12px;font-weight:600;color:var(--accent)">${typeLabels[action.type] || action.type}</span>
        <button class="btn btn-ghost btn-xs" style="color:var(--red)" onclick="p23RemoveAction(${idx})">Remove</button>
      </div>
      ${fields}
    </div>`;
}

function p23AddWorkflowAction() {
  const type = document.getElementById('wf-add-action-type')?.value;
  if (!type) { toast('Select an action type first', 'error'); return; }
  const action = { type };
  if (type === 'create_task') { action.title = 'Follow-up'; action.assignee = ''; action.dueOffset = 1; }
  if (type === 'log_activity') { action.activityType = 'Note'; action.note = ''; }
  if (type === 'send_webhook') { action.webhookUrl = ''; }
  if (type === 'update_deal_field') { action.field = 'stage'; action.value = ''; }
  window._p23EditActions.push(action);
  p23RefreshActionsUI();
  document.getElementById('wf-add-action-type').value = '';
}

function p23UpdateAction(idx, key, value) {
  if (window._p23EditActions && window._p23EditActions[idx]) {
    window._p23EditActions[idx][key] = value;
  }
}

function p23RemoveAction(idx) {
  if (window._p23EditActions) {
    window._p23EditActions.splice(idx, 1);
    p23RefreshActionsUI();
  }
}

function p23RefreshActionsUI() {
  const list = document.getElementById('wf-actions-list');
  const noAct = document.getElementById('wf-no-actions');
  if (!list) return;
  list.innerHTML = (window._p23EditActions || []).map((a, i) => p23RenderActionRow(a, i)).join('');
  if (noAct) noAct.style.display = (window._p23EditActions || []).length === 0 ? '' : 'none';
}

async function p23SaveWorkflow(ruleId) {
  const name = document.getElementById('wf-name')?.value?.trim();
  const triggerEvent = document.getElementById('wf-trigger-event')?.value;
  const conditionStage = document.getElementById('wf-condition-stage')?.value?.trim();
  const actions = window._p23EditActions || [];
  if (!name) { toast('Rule name is required', 'error'); return; }

  const payload = {
    name, triggerEvent,
    triggerCondition: conditionStage ? { stage: conditionStage } : {},
    actions, active: true,
  };

  try {
    if (ruleId) {
      await apiPut('/workflow-rules/' + ruleId, payload);
      toast('Workflow rule updated', 'success');
    } else {
      await apiPost('/workflow-rules', payload);
      toast('Workflow rule created', 'success');
    }
    document.getElementById('p23-workflow-modal')?.remove();
    await p23LoadWorkflows();
    p23RenderWorkflowsSettings();
  } catch(e) {
    toast('Save failed: ' + e.message, 'error');
  }
}

async function p23ToggleWorkflow(ruleId, active) {
  const rule = _p23Workflows.find(r => r.id === ruleId);
  if (!rule) return;
  try {
    await apiPut('/workflow-rules/' + ruleId, { ...rule, active });
    rule.active = active;
    toast('Workflow ' + (active ? 'enabled' : 'disabled'), 'success');
  } catch(e) {
    toast('Failed: ' + e.message, 'error');
  }
}

async function p23DeleteWorkflow(ruleId) {
  if (!confirm('Delete this workflow rule?')) return;
  try {
    await apiDelete('/workflow-rules/' + ruleId);
    toast('Rule deleted', 'success');
    await p23LoadWorkflows();
    p23RenderWorkflowsSettings();
  } catch(e) {
    toast('Delete failed: ' + e.message, 'error');
  }
}

async function p23ViewWorkflowHistory(ruleId, ruleName) {
  let executions = [];
  try { executions = await apiGet('/workflow-rules/' + ruleId + '/executions'); } catch(e) {}

  const modal = document.createElement('div');
  modal.className = 'modal-overlay';
  modal.id = 'p23-wf-history-modal';
  modal.innerHTML = `
    <div class="modal" style="width:560px">
      <div class="modal-header">
        <div class="modal-title">Execution History: ${escapeHtml(ruleName)}</div>
        <button class="modal-close" onclick="document.getElementById('p23-wf-history-modal').remove()">&#x2715;</button>
      </div>
      <div class="modal-body">
        ${executions.length === 0 ? `<div style="font-size:13px;color:var(--text-muted);padding:16px 0;text-align:center">No executions recorded yet.</div>` : `
          <table style="width:100%;border-collapse:collapse;font-size:12px">
            <thead><tr>
              <th style="text-align:left;padding:6px 8px;border-bottom:1px solid var(--border);color:var(--text-muted)">When</th>
              <th style="text-align:left;padding:6px 8px;border-bottom:1px solid var(--border);color:var(--text-muted)">Entity</th>
              <th style="text-align:left;padding:6px 8px;border-bottom:1px solid var(--border);color:var(--text-muted)">Status</th>
            </tr></thead>
            <tbody>
              ${executions.map(ex => `
                <tr>
                  <td style="padding:6px 8px;border-bottom:1px solid var(--border);color:var(--text-dim)">${new Date(ex.executed_at).toLocaleString()}</td>
                  <td style="padding:6px 8px;border-bottom:1px solid var(--border);color:var(--text)">${escapeHtml(ex.entity_name || ex.entity_id || '-')}</td>
                  <td style="padding:6px 8px;border-bottom:1px solid var(--border)">
                    <span style="color:${ex.status==='success'?'var(--green)':'var(--red)'};">${ex.status}</span>
                    ${ex.error ? `<div style="font-size:10px;color:var(--red)">${escapeHtml(ex.error)}</div>` : ''}
                  </td>
                </tr>`).join('')}
            </tbody>
          </table>`}
      </div>
      <div class="modal-footer">
        <button class="btn btn-secondary" onclick="document.getElementById('p23-wf-history-modal').remove()">Close</button>
      </div>
    </div>`;
  document.body.appendChild(modal);
}

// ══════════════════════════════════════════════════════════════════════════
// 2. CONTACT SCORING AUTOMATION
// ══════════════════════════════════════════════════════════════════════════

let _p23ScoringRules = [];

async function p23LoadScoringRules() {
  try { _p23ScoringRules = await apiGet('/scoring-rules'); } catch(e) { _p23ScoringRules = []; }
}

function p23RenderScoringSettings() {
  const container = document.getElementById('p23-scoring-body');
  if (!container) return;

  p23LoadScoringRules().then(() => {
    const fieldOptions = [
      ['title', 'Job Title'],
      ['stage', 'Contact Stage'],
      ['tags', 'Tags'],
      ['email', 'Email'],
      ['deal_count', 'Deal Count'],
      ['days_since_activity', 'Days Since Activity'],
    ];
    const opOptions = [
      ['equals', 'equals'],
      ['contains', 'contains'],
      ['greater_than', 'greater than'],
      ['less_than', 'less than'],
      ['not_empty', 'is not empty'],
      ['is_empty', 'is empty'],
    ];

    container.innerHTML = `
      <div style="padding:12px">
        <div style="font-size:12px;color:var(--text-muted);margin-bottom:10px">
          Rules are evaluated on contact load and save. Score is clamped to 0-100.
        </div>
        <div id="p23-scoring-rules-list">
          ${_p23ScoringRules.map(rule => `
            <div style="display:flex;align-items:center;gap:6px;padding:7px 8px;background:var(--surface2);border-radius:6px;margin-bottom:5px;flex-wrap:wrap">
              <span style="font-size:12px;color:var(--text);flex:1;min-width:200px">${escapeHtml(rule.label || (rule.field + ' ' + rule.operator + ' "' + rule.value + '"'))}</span>
              <span style="font-size:12px;font-weight:700;color:${rule.points>=0?'var(--green)':'var(--red)'}">${rule.points>=0?'+':''}${rule.points} pts</span>
              <button class="btn btn-ghost btn-xs" onclick="p23DeleteScoringRule('${rule.id}')">Remove</button>
            </div>
          `).join('')}
        </div>

        <div style="background:var(--surface2);border-radius:8px;padding:12px;margin-top:10px">
          <div style="font-size:12px;font-weight:600;color:var(--text);margin-bottom:8px">Add Scoring Rule</div>
          <div style="display:grid;grid-template-columns:1fr 1fr 1fr auto;gap:6px;align-items:end;flex-wrap:wrap">
            <div>
              <label style="font-size:11px;color:var(--text-muted);display:block;margin-bottom:3px">Field</label>
              <select id="sr-field" class="field-input" style="font-size:12px">
                ${fieldOptions.map(([v,l]) => `<option value="${v}">${l}</option>`).join('')}
              </select>
            </div>
            <div>
              <label style="font-size:11px;color:var(--text-muted);display:block;margin-bottom:3px">Operator</label>
              <select id="sr-operator" class="field-input" style="font-size:12px">
                ${opOptions.map(([v,l]) => `<option value="${v}">${l}</option>`).join('')}
              </select>
            </div>
            <div>
              <label style="font-size:11px;color:var(--text-muted);display:block;margin-bottom:3px">Value</label>
              <input type="text" id="sr-value" class="field-input" style="font-size:12px" placeholder='e.g. "CEO" or "30"' />
            </div>
            <div>
              <label style="font-size:11px;color:var(--text-muted);display:block;margin-bottom:3px">Points</label>
              <input type="number" id="sr-points" class="field-input" style="font-size:12px;width:70px" value="10" />
            </div>
          </div>
          <div style="margin-top:8px">
            <label style="font-size:11px;color:var(--text-muted);display:block;margin-bottom:3px">Label (optional description)</label>
            <input type="text" id="sr-label" class="field-input" style="font-size:12px" placeholder='e.g. "Title contains CEO"' />
          </div>
          <div style="display:flex;gap:8px;margin-top:10px">
            <button class="btn btn-primary btn-sm" onclick="p23AddScoringRule()">Add Rule</button>
            <button class="btn btn-secondary btn-sm" onclick="p23RecalculateAllScores()">Recalculate All</button>
          </div>
        </div>
      </div>`;
  });
}

async function p23AddScoringRule() {
  const field    = document.getElementById('sr-field')?.value;
  const operator = document.getElementById('sr-operator')?.value;
  const value    = document.getElementById('sr-value')?.value?.trim();
  const points   = parseInt(document.getElementById('sr-points')?.value) || 0;
  const label    = document.getElementById('sr-label')?.value?.trim();

  if (!field || !operator) { toast('Field and operator required', 'error'); return; }

  try {
    await apiPost('/scoring-rules', { field, operator, value, points, label });
    toast('Scoring rule added', 'success');
    await p23LoadScoringRules();
    p23RenderScoringSettings();
  } catch(e) { toast('Failed: ' + e.message, 'error'); }
}

async function p23DeleteScoringRule(id) {
  try {
    await apiDelete('/scoring-rules/' + id);
    toast('Rule removed', 'success');
    await p23LoadScoringRules();
    p23RenderScoringSettings();
  } catch(e) { toast('Failed: ' + e.message, 'error'); }
}

async function p23RecalculateAllScores() {
  const btn = document.querySelector('#p23-scoring-body .btn-secondary');
  if (btn) { btn.disabled = true; btn.textContent = 'Recalculating...'; }
  try {
    const r = await apiPost('/scoring-rules/recalculate-all', {});
    toast(`Recalculated scores for ${r.updated} contacts`, 'success');
  } catch(e) {
    toast('Failed: ' + e.message, 'error');
  } finally {
    if (btn) { btn.disabled = false; btn.textContent = 'Recalculate All'; }
  }
}

// Score breakdown panel on contact detail
async function p23RenderScoreBreakdown(contactId, containerId) {
  const container = document.getElementById(containerId);
  if (!container) return;
  container.innerHTML = '<div style="font-size:12px;color:var(--text-muted);padding:8px 0">Calculating...</div>';
  try {
    const data = await apiGet('/contacts/' + contactId + '/auto-score');
    if (!data || !data.breakdown) {
      container.innerHTML = '<div style="font-size:12px;color:var(--text-muted);padding:8px 0">No scoring rules configured.</div>';
      return;
    }
    container.innerHTML = `
      <div style="display:flex;align-items:center;gap:12px;margin-bottom:10px">
        <div style="width:52px;height:52px;border-radius:50%;background:${data.score>=70?'#22c55e':data.score>=40?'#f97316':'#ef4444'};display:flex;align-items:center;justify-content:center;color:#fff;font-size:18px;font-weight:700;flex-shrink:0">${data.score}</div>
        <div>
          <div style="font-size:13px;font-weight:600;color:var(--text)">Lead Score</div>
          <div style="font-size:11px;color:var(--text-muted)">${data.breakdown.length} rule(s) applied</div>
        </div>
      </div>
      ${data.breakdown.length === 0 ? `<div style="font-size:12px;color:var(--text-muted)">No rules matched. Add scoring rules in Settings > Lead Scoring.</div>` : `
        <table style="width:100%;border-collapse:collapse;font-size:12px">
          <thead><tr>
            <th style="text-align:left;padding:4px 6px;color:var(--text-muted)">Rule</th>
            <th style="text-align:right;padding:4px 6px;color:var(--text-muted)">Points</th>
          </tr></thead>
          <tbody>
            ${data.breakdown.map(r => `
              <tr>
                <td style="padding:4px 6px;color:var(--text)">${escapeHtml(r.label)}</td>
                <td style="padding:4px 6px;text-align:right;font-weight:600;color:${r.points>=0?'var(--green)':'var(--red)'}">${r.points>=0?'+':''}${r.points}</td>
              </tr>`).join('')}
            <tr style="border-top:1px solid var(--border)">
              <td style="padding:5px 6px;font-weight:600;color:var(--text)">Total</td>
              <td style="padding:5px 6px;text-align:right;font-weight:700;color:var(--accent)">${data.rawScore} (clamped: ${data.score})</td>
            </tr>
          </tbody>
        </table>`}`;
  } catch(e) {
    container.innerHTML = '<div style="font-size:12px;color:var(--text-muted)">Could not load score breakdown.</div>';
  }
}

