function p23RenderCurrencySettings() {
  const container = document.getElementById('p23-currency-body');
  if (!container) return;

  p23GetCurrencies().then(currencies => {
    container.innerHTML = `
      <div style="padding:12px">
        <table style="width:100%;border-collapse:collapse;font-size:12px;margin-bottom:12px">
          <thead><tr>
            <th style="text-align:left;padding:5px 8px;border-bottom:1px solid var(--border);color:var(--text-muted)">Code</th>
            <th style="text-align:left;padding:5px 8px;border-bottom:1px solid var(--border);color:var(--text-muted)">Symbol</th>
            <th style="text-align:left;padding:5px 8px;border-bottom:1px solid var(--border);color:var(--text-muted)">Name</th>
            <th style="text-align:right;padding:5px 8px;border-bottom:1px solid var(--border);color:var(--text-muted)">Rate (to USD)</th>
            <th style="text-align:center;padding:5px 8px;border-bottom:1px solid var(--border);color:var(--text-muted)">Active</th>
            <th style="padding:5px 8px;border-bottom:1px solid var(--border)"></th>
          </tr></thead>
          <tbody id="p23-currency-rows">
            ${currencies.map(c => `
              <tr data-cur-id="${c.id}">
                <td style="padding:5px 8px;border-bottom:1px solid var(--border);font-weight:600;color:var(--text)">${escapeHtml(c.code)}</td>
                <td style="padding:5px 8px;border-bottom:1px solid var(--border);color:var(--text)">${escapeHtml(c.symbol)}</td>
                <td style="padding:5px 8px;border-bottom:1px solid var(--border);color:var(--text-dim)">${escapeHtml(c.name)}</td>
                <td style="padding:5px 8px;border-bottom:1px solid var(--border);text-align:right">
                  <input type="number" step="0.0001" value="${c.rate}" style="width:80px;padding:3px 6px;border-radius:4px;border:1px solid var(--border);background:var(--input-bg);color:var(--text);font-size:12px" onblur="p23SaveCurrencyRate('${c.id}','${c.code}','${c.symbol}','${escapeHtml(c.name)}',this.value,${c.active})" />
                </td>
                <td style="padding:5px 8px;border-bottom:1px solid var(--border);text-align:center">
                  <input type="checkbox" ${c.active?'checked':''} onchange="p23SaveCurrencyRate('${c.id}','${c.code}','${c.symbol}','${escapeHtml(c.name)}',${c.rate},this.checked)" />
                </td>
                <td style="padding:5px 8px;border-bottom:1px solid var(--border)">
                  ${c.code !== 'USD' ? `<button class="btn btn-ghost btn-xs" style="color:var(--red)" onclick="p23DisableCurrency('${c.id}')">Disable</button>` : ''}
                </td>
              </tr>`).join('')}
          </tbody>
        </table>

        <div style="background:var(--surface2);border-radius:8px;padding:12px">
          <div style="font-size:12px;font-weight:600;color:var(--text);margin-bottom:8px">Add Currency</div>
          <div style="display:grid;grid-template-columns:80px 60px 1fr 100px auto;gap:6px;align-items:end">
            <div>
              <label style="font-size:11px;color:var(--text-muted);display:block;margin-bottom:2px">Code</label>
              <input type="text" id="nc-code" class="field-input" style="font-size:12px" placeholder="JPY" maxlength="5" />
            </div>
            <div>
              <label style="font-size:11px;color:var(--text-muted);display:block;margin-bottom:2px">Symbol</label>
              <input type="text" id="nc-symbol" class="field-input" style="font-size:12px" placeholder="&yen;" maxlength="5" />
            </div>
            <div>
              <label style="font-size:11px;color:var(--text-muted);display:block;margin-bottom:2px">Name</label>
              <input type="text" id="nc-name" class="field-input" style="font-size:12px" placeholder="Japanese Yen" />
            </div>
            <div>
              <label style="font-size:11px;color:var(--text-muted);display:block;margin-bottom:2px">Rate (to USD)</label>
              <input type="number" id="nc-rate" class="field-input" style="font-size:12px" value="1.0" step="0.001" />
            </div>
            <button class="btn btn-primary btn-sm" onclick="p23AddCurrency()" style="height:32px">Add</button>
          </div>
        </div>
      </div>`;
  });
}

async function p23SaveCurrencyRate(id, code, symbol, name, rate, active) {
  try {
    await apiPut('/currencies/' + id, { code, symbol, name, rate: parseFloat(rate), active });
    p23InvalidateCurrencyCache();
    toast('Currency updated', 'success');
  } catch(e) { toast('Update failed: ' + e.message, 'error'); }
}

async function p23DisableCurrency(id) {
  try {
    await apiDelete('/currencies/' + id);
    p23InvalidateCurrencyCache();
    toast('Currency disabled', 'success');
    p23RenderCurrencySettings();
  } catch(e) { toast('Failed: ' + e.message, 'error'); }
}

async function p23AddCurrency() {
  const code   = document.getElementById('nc-code')?.value?.trim().toUpperCase();
  const symbol = document.getElementById('nc-symbol')?.value?.trim();
  const name   = document.getElementById('nc-name')?.value?.trim();
  const rate   = parseFloat(document.getElementById('nc-rate')?.value) || 1.0;

  if (!code || !symbol || !name) { toast('Code, symbol, and name required', 'error'); return; }
  try {
    await apiPost('/currencies', { code, symbol, name, rate });
    p23InvalidateCurrencyCache();
    toast('Currency added', 'success');
    p23RenderCurrencySettings();
    document.getElementById('nc-code').value = '';
    document.getElementById('nc-symbol').value = '';
    document.getElementById('nc-name').value = '';
    document.getElementById('nc-rate').value = '1.0';
  } catch(e) { toast('Failed: ' + e.message, 'error'); }
}

// Populate the existing deal-form-currency dropdown with API-backed currencies
async function p23InjectCurrencyIntoModal() {
  const sel = document.getElementById('deal-form-currency');
  if (!sel) return;
  if (sel.dataset.p23Populated) return; // Already refreshed this session

  try {
    const currencies = await p23GetCurrencies();
    const activeCurrencies = currencies.filter(c => c.active);
    if (activeCurrencies.length === 0) return;
    const current = sel.value || 'USD';
    sel.innerHTML = activeCurrencies.map(c => `<option value="${c.code}" ${c.code===current?'selected':''}>${c.code} — ${c.name} (${c.symbol})</option>`).join('');
    sel.dataset.p23Populated = '1';
  } catch(e) { /* non-fatal — keep existing hardcoded options */ }
}

