// 4a. Video Call Panel
async function p23RenderVideoCallPanel(dealId, containerId) {
  const container = document.getElementById(containerId);
  if (!container) return;
  try {
    const data = await apiGet('/deals/' + dealId + '/video-call');
    container.innerHTML = `
      <div class="panel" style="margin-bottom:16px">
        <div class="panel-header">
          <div class="panel-title">Video Call</div>
          <button class="btn btn-secondary btn-sm panel-action" onclick="p23EditVideoCall('${dealId}','${containerId}')">Edit</button>
        </div>
        <div style="padding:14px">
          ${data.videoCallUrl ? `
            <div style="background:var(--surface2);border-radius:8px;padding:12px;display:flex;align-items:center;gap:12px">
              <div style="width:36px;height:36px;background:var(--accent);border-radius:8px;display:flex;align-items:center;justify-content:center;flex-shrink:0">
                <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="white" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polygon points="23 7 16 12 23 17 23 7"/><rect x="1" y="5" width="15" height="14" rx="2" ry="2"/></svg>
              </div>
              <div style="flex:1;min-width:0">
                ${data.videoCallTime ? `<div style="font-size:11px;color:var(--text-muted);margin-bottom:2px">${new Date(data.videoCallTime).toLocaleString()}</div>` : ''}
                <div style="font-size:13px;font-weight:600;color:var(--text);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${escapeHtml(data.videoCallUrl)}</div>
              </div>
              <a href="${escapeHtml(data.videoCallUrl)}" target="_blank" class="btn btn-primary btn-sm" style="flex-shrink:0">Join Call</a>
            </div>` : `
            <div style="text-align:center;padding:16px 0;color:var(--text-muted);font-size:13px">
              No video call scheduled.
              <div style="margin-top:8px"><button class="btn btn-secondary btn-sm" onclick="p23EditVideoCall('${dealId}','${containerId}')">Add Video Call</button></div>
            </div>`}
        </div>
      </div>`;
  } catch(e) {
    container.innerHTML = '';
  }
}

function p23EditVideoCall(dealId, containerId) {
  apiGet('/deals/' + dealId + '/video-call').then(data => {
    const modal = document.createElement('div');
    modal.className = 'modal-overlay';
    modal.id = 'p23-videocall-modal';
    modal.innerHTML = `
      <div class="modal" style="width:440px">
        <div class="modal-header">
          <div class="modal-title">Video Call</div>
          <button class="modal-close" onclick="document.getElementById('p23-videocall-modal').remove()">&#x2715;</button>
        </div>
        <div class="modal-body" style="display:flex;flex-direction:column;gap:12px">
          <div>
            <label class="field-label">Meeting Link (Zoom, Meet, Teams, etc.)</label>
            <input type="url" id="vc-url" class="field-input" placeholder="https://zoom.us/j/..." value="${data.videoCallUrl ? escapeHtml(data.videoCallUrl) : ''}" />
          </div>
          <div>
            <label class="field-label">Scheduled Time</label>
            <input type="datetime-local" id="vc-time" class="field-input" value="${data.videoCallTime ? data.videoCallTime.slice(0,16) : ''}" />
          </div>
        </div>
        <div class="modal-footer">
          <button class="btn btn-secondary" onclick="document.getElementById('p23-videocall-modal').remove()">Cancel</button>
          ${data.videoCallUrl ? `<button class="btn btn-ghost" style="color:var(--red)" onclick="p23SaveVideoCall('${dealId}','${containerId}',null,null)">Remove</button>` : ''}
          <button class="btn btn-primary" onclick="p23SaveVideoCall('${dealId}','${containerId}',document.getElementById('vc-url').value,document.getElementById('vc-time').value)">Save</button>
        </div>
      </div>`;
    document.body.appendChild(modal);
  }).catch(() => {});
}

async function p23SaveVideoCall(dealId, containerId, url, time) {
  try {
    await apiPut('/deals/' + dealId + '/video-call', { videoCallUrl: url || null, videoCallTime: time || null });
    document.getElementById('p23-videocall-modal')?.remove();
    toast('Video call saved', 'success');
    p23RenderVideoCallPanel(dealId, containerId);
  } catch(e) {
    toast('Failed: ' + e.message, 'error');
  }
}

// 4b. E-Signature V2 — typed name support
// We patch the renderSignaturePage function to add Draw/Type radio
const _p23OrigRenderSig = window.renderSignaturePage;
window.renderSignaturePage = function(token) {
  if (_p23OrigRenderSig) _p23OrigRenderSig.call(this, token);
  // After render, patch the sign panel to add typed signature option
  setTimeout(() => p23PatchSignaturePage(token), 200);
};

function p23PatchSignaturePage(token) {
  const signPanel = document.querySelector('#view-sign .panel:last-child .panel-header');
  if (!signPanel) return;
  const titleEl = signPanel.querySelector('.panel-title');
  if (!titleEl || document.getElementById('p23-sig-mode-draw')) return; // already patched

  const sigBody = signPanel.nextElementSibling;
  if (!sigBody) return;

  // Add radio buttons above the canvas
  const modeRow = document.createElement('div');
  modeRow.style.cssText = 'display:flex;gap:16px;margin-bottom:12px;align-items:center';
  modeRow.innerHTML = `
    <label style="display:flex;align-items:center;gap:6px;cursor:pointer;font-size:13px;font-weight:600;color:var(--text)">
      <input type="radio" name="p23-sig-mode" id="p23-sig-mode-draw" value="draw" checked onchange="p23SwitchSigMode('draw')" /> Draw
    </label>
    <label style="display:flex;align-items:center;gap:6px;cursor:pointer;font-size:13px;font-weight:600;color:var(--text)">
      <input type="radio" name="p23-sig-mode" id="p23-sig-mode-type" value="type" onchange="p23SwitchSigMode('type')" /> Type Name
    </label>
    <link rel="stylesheet" href="https://fonts.googleapis.com/css2?family=Pacifico&display=swap" />`;
  sigBody.insertBefore(modeRow, sigBody.firstChild);

  // Add typed signature input (hidden by default)
  const typeInput = document.createElement('div');
  typeInput.id = 'p23-type-sig-container';
  typeInput.style.display = 'none';
  typeInput.innerHTML = `
    <div style="border:2px solid var(--border);border-radius:8px;padding:24px 16px;background:#fff;margin-bottom:12px;text-align:center;min-height:100px;display:flex;align-items:center;justify-content:center">
      <span id="p23-type-sig-preview" style="font-family:'Pacifico',cursive;font-size:36px;color:#111;letter-spacing:1px"></span>
    </div>
    <input type="text" id="p23-type-sig-input" placeholder="Type your full name" style="width:100%;padding:8px 12px;border-radius:6px;border:1px solid var(--border);background:var(--input-bg);color:var(--text);font-size:14px;margin-bottom:8px" oninput="document.getElementById('p23-type-sig-preview').textContent=this.value" />`;

  const canvasWrapper = sigBody.querySelector('div[style*="position:relative"]');
  if (canvasWrapper) {
    sigBody.insertBefore(typeInput, canvasWrapper);
  }
}

function p23SwitchSigMode(mode) {
  const drawWrapper = document.querySelector('#view-sign div[style*="position:relative"]');
  const typeContainer = document.getElementById('p23-type-sig-container');
  if (mode === 'draw') {
    if (drawWrapper) drawWrapper.style.display = '';
    if (typeContainer) typeContainer.style.display = 'none';
  } else {
    if (drawWrapper) drawWrapper.style.display = 'none';
    if (typeContainer) typeContainer.style.display = '';
  }
}

// Patch submitSignature to support typed mode
const _p23OrigSubmitSig = window.submitSignature;
window.submitSignature = async function(token) {
  const typeMode = document.getElementById('p23-sig-mode-type')?.checked;
  if (!typeMode) { return _p23OrigSubmitSig.call(this, token); }

  const name = document.getElementById('p23-type-sig-input')?.value?.trim();
  if (!name) { toast('Please type your name to sign', 'error'); return; }

  // Render the typed name to a canvas for the signature image
  const canvas = document.createElement('canvas');
  canvas.width = 640; canvas.height = 160;
  const ctx = canvas.getContext('2d');
  ctx.fillStyle = '#ffffff';
  ctx.fillRect(0, 0, 640, 160);
  ctx.fillStyle = '#111';
  ctx.font = "56px 'Pacifico', cursive";
  ctx.textAlign = 'center';
  ctx.textBaseline = 'middle';
  ctx.fillText(name, 320, 80);
  const signatureData = canvas.toDataURL('image/png');

  try {
    await fetch(`${API_BASE}/proposals/sign/${token}`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ signatureData }),
    }).then(r => r.json());
    window.renderSignaturePage(token);
    toast('Signature submitted successfully', 'success');
  } catch(err) {
    toast('Failed to submit signature: ' + err.message, 'error');
  }
};

// 4c. Deal Room Analytics — portal view tracking
async function p23RenderPortalAnalytics(dealId, containerId) {
  const container = document.getElementById(containerId);
  if (!container) return;
  container.innerHTML = '<div style="font-size:12px;color:var(--text-muted);padding:8px 0">Loading analytics...</div>';
  try {
    const data = await apiGet('/deals/' + dealId + '/portal-analytics');
    const maxCount = Math.max(1, ...data.trendByDay.map(d => d.count));

    container.innerHTML = `
      <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:10px;margin-bottom:14px">
        <div style="background:var(--surface2);border-radius:6px;padding:10px;text-align:center">
          <div style="font-size:22px;font-weight:700;color:var(--text)">${data.totalViews}</div>
          <div style="font-size:11px;color:var(--text-muted)">Total Views</div>
        </div>
        <div style="background:var(--surface2);border-radius:6px;padding:10px;text-align:center">
          <div style="font-size:22px;font-weight:700;color:var(--text)">${data.uniqueVisitors}</div>
          <div style="font-size:11px;color:var(--text-muted)">Unique Visitors</div>
        </div>
        <div style="background:var(--surface2);border-radius:6px;padding:10px;text-align:center">
          <div style="font-size:13px;font-weight:600;color:var(--text)">${data.lastViewed ? new Date(data.lastViewed).toLocaleDateString() : 'Never'}</div>
          <div style="font-size:11px;color:var(--text-muted)">Last Viewed</div>
        </div>
      </div>
      <div style="font-size:11px;color:var(--text-muted);margin-bottom:6px">Views last 7 days</div>
      <div style="display:flex;align-items:flex-end;gap:4px;height:60px">
        ${data.trendByDay.map(d => `
          <div style="flex:1;display:flex;flex-direction:column;align-items:center;gap:2px">
            <div style="flex:1;display:flex;align-items:flex-end;width:100%">
              <div style="width:100%;background:var(--accent);border-radius:2px 2px 0 0;height:${d.count ? Math.max(4, Math.round((d.count/maxCount)*52)) : 0}px;opacity:${d.count?1:0.2}"></div>
            </div>
            <div style="font-size:9px;color:var(--text-muted)">${d.label.split(' ')[1] || d.label}</div>
          </div>`).join('')}
      </div>`;
  } catch(e) {
    container.innerHTML = '<div style="font-size:12px;color:var(--text-muted)">Analytics not available.</div>';
  }
}

