async function p23RenderHygieneSettings() {
  const container = document.getElementById('p23-hygiene-body');
  if (!container) return;

  container.innerHTML = `
    <div style="padding:12px">
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:12px">
        <button class="btn btn-secondary btn-sm" onclick="p23ScanContactDuplicates()">Scan Contact Duplicates</button>
        <button class="btn btn-secondary btn-sm" onclick="p23ScanCompanyDuplicates()">Scan Company Duplicates</button>
        <button class="btn btn-secondary btn-sm" onclick="p23ShowInactiveContacts()">Inactive Contacts (90+ days)</button>
        <button class="btn btn-secondary btn-sm" onclick="p23ShowInactiveDeals()">Stale Deals (30+ days)</button>
        <button class="btn btn-secondary btn-sm" onclick="p23ShowMissingInfoContacts()">Contacts Missing Email/Phone</button>
      </div>
      <div id="p23-hygiene-results" style="margin-top:8px"></div>
    </div>`;
}

async function p23ScanContactDuplicates() {
  const results = document.getElementById('p23-hygiene-results');
  if (results) results.innerHTML = '<div style="font-size:12px;color:var(--text-muted)">Scanning...</div>';
  try {
    const data = await apiGet('/hygiene/contact-duplicates');
    if (!results) return;
    if (data.length === 0) {
      results.innerHTML = '<div style="font-size:13px;color:var(--green);padding:8px 0">No contact duplicates found.</div>';
      return;
    }
    results.innerHTML = `
      <div style="font-size:13px;font-weight:600;color:var(--text);margin-bottom:8px">${data.length} duplicate set(s) found</div>
      ${data.map((set, si) => `
        <div style="border:1px solid var(--border);border-radius:8px;padding:12px;margin-bottom:10px">
          <div style="font-size:11px;color:var(--text-muted);margin-bottom:8px;text-transform:uppercase;letter-spacing:0.5px">Reason: ${escapeHtml(set.reason)}</div>
          <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px">
            ${set.contacts.map(c => `
              <div style="background:var(--surface2);border-radius:6px;padding:10px">
                <div style="font-size:13px;font-weight:600;color:var(--text)">${escapeHtml(c.name)}</div>
                ${c.email ? `<div style="font-size:11px;color:var(--text-muted)">${escapeHtml(c.email)}</div>` : ''}
                ${c.phone ? `<div style="font-size:11px;color:var(--text-muted)">${escapeHtml(c.phone)}</div>` : ''}
                <div style="font-size:11px;color:var(--text-dim);margin-top:4px">${escapeHtml(c.stage||'')}${c.title?' | '+escapeHtml(c.title):''}</div>
                <button class="btn btn-ghost btn-xs" onclick="navigate('contact-detail','${c.id}')" style="margin-top:6px">View</button>
              </div>`).join('')}
          </div>
          ${set.contacts.length === 2 ? `
            <div style="margin-top:8px;text-align:center">
              <button class="btn btn-secondary btn-sm" onclick="openMergeModal && openMergeModal('${set.contacts[0].id}','${set.contacts[1].id}')">Merge</button>
            </div>` : ''}
        </div>`).join('')}`;
  } catch(e) {
    if (results) results.innerHTML = '<div style="font-size:12px;color:var(--red)">Scan failed: ' + escapeHtml(e.message) + '</div>';
  }
}

