function p23InjectContactScorePanel(contactId) {
  const view = document.getElementById('view-contact-detail');
  if (!view) return;
  if (document.getElementById('p23-score-panel-' + contactId)) return;

  const panel = document.createElement('div');
  panel.id = 'p23-score-panel-' + contactId;
  panel.className = 'panel';
  panel.style.marginBottom = '16px';
  panel.innerHTML = `
    <div class="panel-header">
      <div class="panel-title">Lead Score Breakdown</div>
      <button class="btn btn-ghost btn-xs panel-action" onclick="p23RenderScoreBreakdown('${contactId}','p23-score-breakdown-${contactId}')">Refresh</button>
    </div>
    <div style="padding:14px">
      <div id="p23-score-breakdown-${contactId}"><div style="font-size:12px;color:var(--text-muted)">Loading...</div></div>
    </div>`;

  const panels = view.querySelectorAll('.panel');
  if (panels.length > 0) {
    panels[0].parentNode.insertBefore(panel, panels[0]);
  } else {
    view.appendChild(panel);
  }
  p23RenderScoreBreakdown(contactId, 'p23-score-breakdown-' + contactId);
}

