// PHASE 24 — Email Composer, Win/Loss V2, Engagement Timeline, Task Deps, Assets
// ══════════════════════════════════════════════════════════════════════════

// ─────────────────────────────────────────────────────────────────────────
// 1. EMAIL COMPOSER WITH TEMPLATES
// ─────────────────────────────────────────────────────────────────────────

let _p24ComposeContactId  = null;
let _p24ComposeDealId     = null;
let _p24ComposePreviewOn  = false;

function p24OpenComposeEmail(contactId, dealId) {
  _p24ComposeContactId = contactId || null;
  _p24ComposeDealId    = dealId    || null;

  // Reset form
  document.getElementById('email-compose-contact-id').value = contactId || '';
  document.getElementById('email-compose-deal-id').value    = dealId    || '';
  document.getElementById('email-compose-subject').value    = '';
  document.getElementById('email-compose-body').value       = '';
  document.getElementById('email-compose-to-search').value  = '';
  document.getElementById('email-compose-to-display').innerHTML = '';
  document.getElementById('email-compose-preview').style.display = 'none';
  _p24ComposePreviewOn = false;

  // Pre-fill contact if provided
  if (contactId) {
    const c = db.contacts && db.contacts.find(x => x.id === contactId);
    if (c) {
      document.getElementById('email-compose-to-search').value = c.name + (c.email ? ' <' + c.email + '>' : '');
      document.getElementById('email-compose-to-display').innerHTML =
        '<span style="color:var(--accent)">To: ' + esc(c.name) + (c.email ? ' &lt;' + esc(c.email) + '&gt;' : '') + '</span>';
    }
  }

  // Load templates into picker
  p24LoadEmailTemplatePicker();
  openModal('modal-email-compose');
  setTimeout(() => document.getElementById('email-compose-subject').focus(), 80);
}

function p24LoadEmailTemplatePicker() {
  const sel = document.getElementById('email-compose-template-picker');
  if (!sel) return;
  const templates = (db.settings && db.settings.emailTemplates) || [];
  sel.innerHTML = '<option value="">Insert Template</option>' +
    templates.map(t => `<option value="${esc(t.id)}">${esc(t.name || t.subject || 'Template')}</option>`).join('');
}

function p24InsertEmailTemplate(templateId) {
  if (!templateId) return;
  const templates = (db.settings && db.settings.emailTemplates) || [];
  const t = templates.find(x => x.id === templateId || x.name === templateId);
  if (!t) return;

  // Resolve contact/deal for variable substitution
  const contactId = document.getElementById('email-compose-contact-id').value;
  const dealId    = document.getElementById('email-compose-deal-id').value;
  const contact   = (db.contacts || []).find(c => c.id === contactId);
  const deal      = (db.deals    || []).find(d => d.id === dealId);

  let subject = t.subject || '';
  let body    = t.body    || '';

  // Variable substitution
  const vars = {
    '{{contact.name}}':    contact ? contact.name  : '',
    '{{contact.company}}': contact ? (db.companies || []).find(c => c.id === contact.company)?.name || '' : '',
    '{{deal.name}}':       deal    ? deal.name      : '',
    '{{deal.value}}':      deal    ? '$' + (deal.value || 0).toLocaleString() : '',
    '{{user.name}}':       _currentUser ? _currentUser.name : '',
  };
  Object.entries(vars).forEach(([k, v]) => {
    subject = subject.split(k).join(v);
    body    = body.split(k).join(v);
  });

  if (subject && !document.getElementById('email-compose-subject').value) {
    document.getElementById('email-compose-subject').value = subject;
  }

  const bodyEl = document.getElementById('email-compose-body');
  bodyEl.value = body;

  // Reset picker
  document.getElementById('email-compose-template-picker').value = '';
}

function p24ContactSearchAutocomplete(query) {
  const box = document.getElementById('email-compose-autocomplete');
  if (!query || query.length < 1) { box.style.display = 'none'; return; }
  const q = query.toLowerCase();
  const matches = (db.contacts || [])
    .filter(c => c.name.toLowerCase().includes(q) || (c.email || '').toLowerCase().includes(q))
    .slice(0, 8);
  if (!matches.length) { box.style.display = 'none'; return; }
  box.innerHTML = matches.map(c =>
    `<div style="padding:8px 12px;cursor:pointer;font-size:12px;border-bottom:1px solid var(--border)" onmousedown="p24SelectComposeContact('${c.id}')" onmouseover="this.style.background='var(--surface2)'" onmouseout="this.style.background=''">
      <div style="font-weight:500">${esc(c.name)}</div>
      ${c.email ? `<div style="color:var(--text-muted)">${esc(c.email)}</div>` : ''}
    </div>`
  ).join('');
  box.style.display = 'block';
}

function p24SelectComposeContact(contactId) {
  const c = (db.contacts || []).find(x => x.id === contactId);
  if (!c) return;
  document.getElementById('email-compose-contact-id').value = contactId;
  _p24ComposeContactId = contactId;
  document.getElementById('email-compose-to-search').value  = c.name + (c.email ? ' <' + c.email + '>' : '');
  document.getElementById('email-compose-to-display').innerHTML =
    '<span style="color:var(--accent)">To: ' + esc(c.name) + (c.email ? ' &lt;' + esc(c.email) + '&gt;' : '') + '</span>';
  document.getElementById('email-compose-autocomplete').style.display = 'none';
}

function p24ToggleEmailPreview() {
  _p24ComposePreviewOn = !_p24ComposePreviewOn;
  const previewEl = document.getElementById('email-compose-preview');
  if (_p24ComposePreviewOn) {
    const body = document.getElementById('email-compose-body').value;
    document.getElementById('email-compose-preview-body').textContent = body;
    previewEl.style.display = '';
  } else {
    previewEl.style.display = 'none';
  }
}

async function p24SendEmail() {
  const contactId = document.getElementById('email-compose-contact-id').value;
  const dealId    = document.getElementById('email-compose-deal-id').value;
  const subject   = document.getElementById('email-compose-subject').value.trim();
  const body      = document.getElementById('email-compose-body').value;

  if (!subject) { toast('Subject is required', 'error'); return; }

  const btn = document.querySelector('#modal-email-compose .modal-footer .btn-primary');
  if (btn) { btn.textContent = 'Sending...'; btn.disabled = true; }

  try {
    const result = await apiPost('/email/send', {
      contactId: contactId || null,
      dealId:    dealId    || null,
      subject,
      body,
      to: (() => {
        if (contactId) {
          const c = (db.contacts || []).find(x => x.id === contactId);
          return c && c.email ? c.email : '';
        }
        return document.getElementById('email-compose-to-search').value;
      })(),
    });

    closeModal('modal-email-compose');
    if (result.simulated) {
      toast('Email saved to log (no SMTP configured)', 'info');
    } else if (result.smtpError) {
      toast('Email logged, but SMTP delivery failed', 'warning');
    } else {
      toast('Email sent successfully', 'success');
    }

    // Update contact detail email tab if visible
    if (contactId && document.getElementById('view-contact-detail').classList.contains('active')) {
      setTimeout(() => renderContactDetail(contactId), 200);
    }
  } catch (err) {
    toast('Failed to send: ' + err.message, 'error');
  } finally {
    if (btn) { btn.textContent = 'Send Email'; btn.disabled = false; }
  }
}

// SMTP Settings in Settings page
function p24RenderSmtpSettings(containerId) {
  const el = document.getElementById(containerId);
  if (!el) return;
  el.innerHTML = '<div style="color:var(--text-muted);font-size:12px">Loading SMTP config...</div>';
  apiGet('/settings/smtp').then(cfg => {
    el.innerHTML = `
      <div style="display:flex;flex-direction:column;gap:12px">
        ${cfg.configured ? `<div style="font-size:12px;color:var(--green);font-weight:500">SMTP configured — Host: ${esc(cfg.host || '')}, User: ${esc(cfg.user || '')}</div>` : `<div style="font-size:12px;color:var(--text-muted)">SMTP not configured. Fill in the fields below to enable real email delivery.</div>`}
        <div class="form-group">
          <label class="form-label">SMTP Host</label>
          <input type="text" class="form-input" id="smtp-host" placeholder="smtp.gmail.com" value="${esc(cfg.host || '')}" />
        </div>
        <div class="form-group">
          <label class="form-label">SMTP Port</label>
          <input type="number" class="form-input" id="smtp-port" placeholder="587" value="${cfg.port || 587}" />
        </div>
        <div class="form-group">
          <label class="form-label">SMTP Username</label>
          <input type="text" class="form-input" id="smtp-user" placeholder="you@example.com" value="${esc(cfg.user || '')}" />
        </div>
        <div class="form-group">
          <label class="form-label">SMTP Password</label>
          <input type="password" class="form-input" id="smtp-pass" placeholder="App password or SMTP password" />
        </div>
        <div class="form-group">
          <label class="form-label">From Address</label>
          <input type="text" class="form-input" id="smtp-from" placeholder="CRM &lt;you@example.com&gt;" value="${esc(cfg.from || '')}" />
        </div>
        <div style="display:flex;gap:8px">
          <button class="btn btn-primary btn-sm" onclick="p24SaveSmtp()">Save SMTP</button>
          ${cfg.configured ? `<button class="btn btn-danger btn-sm" onclick="p24DeleteSmtp()">Remove</button>` : ''}
        </div>
      </div>`;
  }).catch(() => { el.innerHTML = '<div style="color:var(--red);font-size:12px">Failed to load SMTP settings</div>'; });
}

async function p24SaveSmtp() {
  const host = document.getElementById('smtp-host').value.trim();
  const port = document.getElementById('smtp-port').value;
  const user = document.getElementById('smtp-user').value.trim();
  const pass = document.getElementById('smtp-pass').value;
  const from = document.getElementById('smtp-from').value.trim();
  if (!host || !user) { toast('Host and username are required', 'error'); return; }
  await apiPost('/settings/smtp', { host, port, user, pass, from });
  toast('SMTP settings saved', 'success');
  p24RenderSmtpSettings('p24-smtp-container');
}

async function p24DeleteSmtp() {
  if (!confirm('Remove SMTP configuration?')) return;
  await apiRequest('DELETE', '/settings/smtp');
  toast('SMTP configuration removed', 'info');
  p24RenderSmtpSettings('p24-smtp-container');
}

// ─────────────────────────────────────────────────────────────────────────
// 2. DEAL WIN/LOSS ANALYTICS V2
// ─────────────────────────────────────────────────────────────────────────

async function p24RenderWinLossV2(containerId) {
  const el = document.getElementById(containerId);
  if (!el) return;
  el.innerHTML = '<div style="color:var(--text-muted);font-size:12px;padding:16px">Loading Win/Loss analytics...</div>';

  try {
    const [trend, lostByStage, lostByRep, characteristics, taxonomy] = await Promise.all([
      apiGet('/reports/winloss-trend'),
      apiGet('/reports/lost-by-stage'),
      apiGet('/reports/lost-by-rep'),
      apiGet('/reports/deal-characteristics'),
      apiGet('/loss-reason-taxonomy'),
    ]);

    el.innerHTML = `
      <div style="display:flex;flex-direction:column;gap:24px">

        <!-- Win Rate Trend -->
        <div>
          <div style="font-size:13px;font-weight:600;color:var(--text);margin-bottom:12px">Win Rate Trend (Last 12 Months)</div>
          <div style="display:flex;align-items:flex-end;gap:4px;height:100px">
            ${trend.map(m => {
              const h = m.winRate !== null ? Math.max(4, m.winRate) : 0;
              const color = m.winRate !== null ? (m.winRate >= 50 ? 'var(--green)' : m.winRate >= 30 ? 'var(--yellow)' : 'var(--red)') : 'var(--border)';
              return `<div style="flex:1;display:flex;flex-direction:column;align-items:center;gap:4px">
                <div style="font-size:10px;color:var(--text-muted)">${m.winRate !== null ? m.winRate + '%' : '-'}</div>
                <div style="width:100%;background:${color};border-radius:3px 3px 0 0;height:${h}px;min-height:4px;transition:height 0.3s" title="${m.label}: ${m.won} won, ${m.lost} lost${m.winRate !== null ? ', ' + m.winRate + '% win rate' : ''}"></div>
                <div style="font-size:9px;color:var(--text-muted);text-align:center;writing-mode:horizontal-tb">${m.label}</div>
              </div>`;
            }).join('')}
          </div>
        </div>

        <!-- Lost by Stage -->
        <div>
          <div style="font-size:13px;font-weight:600;color:var(--text);margin-bottom:10px">Deals Lost by Stage</div>
          ${(() => {
            const grouped = {};
            lostByStage.forEach(r => {
              const stage = r.stage || 'Unknown';
              if (!grouped[stage]) grouped[stage] = { total: 0, reasons: {} };
              grouped[stage].total += r.count;
              if (r.loss_reason) grouped[stage].reasons[r.loss_reason] = (grouped[stage].reasons[r.loss_reason] || 0) + r.count;
            });
            const entries = Object.entries(grouped).sort((a,b) => b[1].total - a[1].total);
            if (!entries.length) return '<div style="color:var(--text-muted);font-size:12px">No lost deals data yet.</div>';
            const maxTotal = Math.max(...entries.map(e => e[1].total));
            return `<div style="display:flex;flex-direction:column;gap:8px">
              ${entries.map(([stage, data]) => `
                <div>
                  <div style="display:flex;justify-content:space-between;margin-bottom:3px">
                    <span style="font-size:12px;font-weight:500">${esc(stage)}</span>
                    <span style="font-size:12px;color:var(--text-muted)">${data.total} deal${data.total !== 1 ? 's' : ''} lost</span>
                  </div>
                  <div style="background:var(--surface2);border-radius:4px;height:16px;overflow:hidden">
                    <div style="height:100%;width:${Math.round((data.total/maxTotal)*100)}%;background:var(--red);border-radius:4px;opacity:0.75"></div>
                  </div>
                  ${Object.keys(data.reasons).length ? `<div style="font-size:10px;color:var(--text-muted);margin-top:2px">${Object.entries(data.reasons).sort((a,b)=>b[1]-a[1]).slice(0,3).map(([r,c]) => `${esc(r)}: ${c}`).join(' · ')}</div>` : ''}
                </div>
              `).join('')}
            </div>`;
          })()}
        </div>

        <!-- Win Rate by Rep -->
        <div>
          <div style="font-size:13px;font-weight:600;color:var(--text);margin-bottom:10px">Win Rate by Rep</div>
          ${lostByRep.length ? `
          <table style="width:100%;border-collapse:collapse;font-size:12px">
            <thead><tr style="border-bottom:1px solid var(--border)">
              <th style="text-align:left;padding:6px 0;color:var(--text-muted)">Rep</th>
              <th style="text-align:right;padding:6px 0;color:var(--text-muted)">Won</th>
              <th style="text-align:right;padding:6px 0;color:var(--text-muted)">Lost</th>
              <th style="text-align:right;padding:6px 0;color:var(--text-muted)">Win Rate</th>
              <th style="text-align:right;padding:6px 0;color:var(--text-muted)">Avg Won Value</th>
            </tr></thead>
            <tbody>
              ${lostByRep.map(r => `<tr style="border-bottom:1px solid var(--border)">
                <td style="padding:6px 0;font-weight:500">${esc(r.owner)}</td>
                <td style="padding:6px 0;text-align:right;color:var(--green)">${r.won}</td>
                <td style="padding:6px 0;text-align:right;color:var(--red)">${r.lost}</td>
                <td style="padding:6px 0;text-align:right;font-weight:600;color:${r.winRate >= 50 ? 'var(--green)' : r.winRate >= 30 ? 'var(--yellow)' : 'var(--red)'}">${r.winRate}%</td>
                <td style="padding:6px 0;text-align:right;color:var(--text-muted)">$${(r.avgWonValue||0).toLocaleString()}</td>
              </tr>`).join('')}
            </tbody>
          </table>` : '<div style="color:var(--text-muted);font-size:12px">No data yet.</div>'}
        </div>

        <!-- Deal Characteristics Comparison -->
        <div>
          <div style="font-size:13px;font-weight:600;color:var(--text);margin-bottom:10px">Won vs. Lost — Deal Characteristics</div>
          <table style="width:100%;border-collapse:collapse;font-size:12px">
            <thead><tr style="border-bottom:1px solid var(--border)">
              <th style="text-align:left;padding:6px 0;color:var(--text-muted)">Metric</th>
              <th style="text-align:right;padding:6px 0;color:var(--green)">Won (${characteristics.won.count})</th>
              <th style="text-align:right;padding:6px 0;color:var(--red)">Lost (${characteristics.lost.count})</th>
            </tr></thead>
            <tbody>
              <tr style="border-bottom:1px solid var(--border)">
                <td style="padding:6px 0">Avg Deal Value</td>
                <td style="padding:6px 0;text-align:right;color:var(--green)">$${(characteristics.won.avgValue||0).toLocaleString()}</td>
                <td style="padding:6px 0;text-align:right;color:var(--red)">$${(characteristics.lost.avgValue||0).toLocaleString()}</td>
              </tr>
              <tr style="border-bottom:1px solid var(--border)">
                <td style="padding:6px 0">Avg Deal Age (days)</td>
                <td style="padding:6px 0;text-align:right;color:var(--green)">${characteristics.won.avgAgeDays || 0}</td>
                <td style="padding:6px 0;text-align:right;color:var(--red)">${characteristics.lost.avgAgeDays || 0}</td>
              </tr>
              <tr>
                <td style="padding:6px 0">Avg Activities</td>
                <td style="padding:6px 0;text-align:right;color:var(--green)">${characteristics.won.avgActivities || 0}</td>
                <td style="padding:6px 0;text-align:right;color:var(--red)">${characteristics.lost.avgActivities || 0}</td>
              </tr>
            </tbody>
          </table>
        </div>

      </div>`;
  } catch (err) {
    el.innerHTML = '<div style="color:var(--red);font-size:12px">Failed to load analytics: ' + esc(err.message) + '</div>';
  }
}

