async function p24RenderAssetsReport(containerId) {
  const el = document.getElementById(containerId);
  if (!el) return;
  try {
    const data = await apiGet('/reports/assets');
    el.innerHTML = `
      <div style="display:flex;flex-direction:column;gap:20px">
        <!-- Value by Type -->
        <div>
          <div style="font-size:13px;font-weight:600;color:var(--text);margin-bottom:10px">Asset Value by Type</div>
          ${data.byType.length ? `
          <table style="width:100%;border-collapse:collapse;font-size:12px">
            <thead><tr style="border-bottom:1px solid var(--border)">
              <th style="text-align:left;padding:6px 0;color:var(--text-muted)">Type</th>
              <th style="text-align:right;padding:6px 0;color:var(--text-muted)">Count</th>
              <th style="text-align:right;padding:6px 0;color:var(--text-muted)">Total Value</th>
            </tr></thead>
            <tbody>
              ${data.byType.map(r => `<tr style="border-bottom:1px solid var(--border)">
                <td style="padding:6px 0;font-weight:500">${esc(r.type)}</td>
                <td style="padding:6px 0;text-align:right">${r.count}</td>
                <td style="padding:6px 0;text-align:right;font-weight:600">$${(r.total_value||0).toLocaleString()}</td>
              </tr>`).join('')}
            </tbody>
          </table>` : '<div style="color:var(--text-muted);font-size:12px">No active assets.</div>'}
        </div>

        <!-- Expiring Assets Table -->
        <div>
          <div style="font-size:13px;font-weight:600;color:var(--text);margin-bottom:10px">Warranties Expiring (Next 90 Days)</div>
          ${data.expiring.length ? `
          <table style="width:100%;border-collapse:collapse;font-size:12px">
            <thead><tr style="border-bottom:1px solid var(--border)">
              <th style="text-align:left;padding:6px 0;color:var(--text-muted)">Asset</th>
              <th style="text-align:left;padding:6px 0;color:var(--text-muted)">Type</th>
              <th style="text-align:left;padding:6px 0;color:var(--text-muted)">Assigned To</th>
              <th style="text-align:right;padding:6px 0;color:var(--text-muted)">Expires</th>
            </tr></thead>
            <tbody>
              ${data.expiring.map(a => {
                const today = new Date().toISOString().slice(0,10);
                const in30  = new Date(Date.now() + 30 * 86400000).toISOString().slice(0,10);
                const urgent = a.warrantyExpiry <= in30;
                return `<tr style="border-bottom:1px solid var(--border)">
                  <td style="padding:6px 0;font-weight:500">${esc(a.name)}</td>
                  <td style="padding:6px 0;color:var(--text-muted)">${esc(a.type)}</td>
                  <td style="padding:6px 0">${esc(a.contactName || '—')}</td>
                  <td style="padding:6px 0;text-align:right;font-weight:${urgent ? '600' : '400'};color:${urgent ? 'var(--yellow)' : 'var(--text)'}">${a.warrantyExpiry}</td>
                </tr>`;
              }).join('')}
            </tbody>
          </table>` : '<div style="color:var(--text-muted);font-size:12px">No assets with warranties expiring in the next 90 days.</div>'}
        </div>
      </div>`;
  } catch (err) {
    el.innerHTML = '<div style="color:var(--red);font-size:12px">Failed to load: ' + esc(err.message) + '</div>';
  }
}

