// ── Phase 24 Task Dep Badge Injection (Post-process DOM) ──────────────────
// Improved version that scans DOM by onclick attributes
async function p24InjectTaskBlockedBadges() {
  if (!document.getElementById('view-tasks')?.classList.contains('active')) return;
  try {
    const rows = await apiGet('/tasks/with-dependencies');
    const blockedIds = new Set(rows.filter(r => r.blocked).map(r => r.id));
    if (!blockedIds.size) return;

    // Find task items by looking at Done buttons' onclick attributes
    const allButtons = document.querySelectorAll('#tasks-list .task-item button[title="Mark done"]');
    allButtons.forEach(btn => {
      const match = btn.getAttribute('onclick').match(/markTaskDone\('([^']+)'\)/);
      if (!match) return;
      const taskId = match[1];
      if (!blockedIds.has(taskId)) return;
      const taskItem = btn.closest('.task-item');
      if (!taskItem || taskItem.querySelector('.dep-blocked-badge')) return;
      const titleEl = taskItem.querySelector('.task-title');
      if (titleEl) {
        const badge = document.createElement('span');
        badge.className = 'dep-blocked-badge';
        badge.style.cssText = 'background:var(--red);color:white;font-size:9px;font-weight:700;padding:1px 5px;border-radius:3px;letter-spacing:0.3px;text-transform:uppercase;margin-left:6px;vertical-align:middle';
        badge.textContent = 'Blocked';
        titleEl.appendChild(badge);
      }
      // Add deps button after title area
      const meta = taskItem.querySelector('.task-meta');
      if (meta && !meta.querySelector('.dep-view-btn')) {
        const depBtn = document.createElement('button');
        depBtn.className = 'btn btn-ghost btn-xs dep-view-btn';
        depBtn.style.cssText = 'font-size:10px;margin-left:6px;color:var(--red)';
        depBtn.textContent = 'Blocked';
        depBtn.onclick = (e) => {
          e.stopPropagation();
          p24ShowTaskDepsModal(taskId);
        };
      }
    });
  } catch {}
}

async function p24ShowTaskDepsModal(taskId) {
  const task = (db.tasks || []).find(t => t.id === taskId);
  const title = task ? task.title : 'Task';
  const data = await p24LoadTaskDeps(taskId);

  const overlay = document.createElement('div');
  overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.5);z-index:9999;display:flex;align-items:center;justify-content:center';
  overlay.innerHTML = `
    <div style="background:var(--surface);border:1px solid var(--border);border-radius:10px;width:500px;max-width:95vw;max-height:80vh;overflow:auto">
      <div style="padding:16px 20px;border-bottom:1px solid var(--border);display:flex;justify-content:space-between;align-items:center">
        <div style="font-size:14px;font-weight:600">Task Dependencies</div>
        <button onclick="this.closest('[style]').remove()" style="background:none;border:none;cursor:pointer;color:var(--text-muted);font-size:18px">&times;</button>
      </div>
      <div style="padding:16px">
        <div style="font-size:13px;font-weight:500;color:var(--text);margin-bottom:16px">${esc(title)}</div>
        <div id="p24-modal-deps-container-${taskId}"></div>
      </div>
    </div>`;
  document.body.appendChild(overlay);
  overlay.addEventListener('click', e => { if (e.target === overlay) overlay.remove(); });
  p24RenderTaskDepsPanel(taskId, 'p24-modal-deps-container-' + taskId);
}

