// ─── 2. CONTACT RELATIONSHIP MAPPING ─────────────────────────────────────

async function p25RenderRelationshipsTab(contactId, containerId) {
  const el = document.getElementById(containerId);
  if (!el) return;
  el.innerHTML = '<div style="padding:20px;color:var(--text-muted);font-size:12px">Loading relationship graph...</div>';

  try {
    const data = await apiGet('/contacts/' + contactId + '/relationships');
    p25DrawGraph(data, el);
  } catch(e) {
    el.innerHTML = '<div style="padding:20px;color:var(--text-muted);font-size:12px">Could not load relationship data.</div>';
  }
}

function p25DrawGraph(data, container) {
  const { nodes, edges } = data;
  if (!nodes.length) {
    container.innerHTML = '<div style="padding:20px;color:var(--text-muted);font-size:12px">No relationship data available. Link a company, deals, or referrals to see a graph.</div>';
    return;
  }

  const W = Math.min(container.offsetWidth || 600, 700);
  const H = 400;
  const cx = W / 2, cy = H / 2;

  // Simple layout: center = primary, others in circles
  const primary = nodes.find(n => n.primary);
  const rest = nodes.filter(n => !n.primary);

  // Position nodes
  const nodePos = {};
  if (primary) nodePos[primary.id] = { x: cx, y: cy };

  const radius = Math.min(W, H) * 0.36;
  rest.forEach((n, i) => {
    const angle = (2 * Math.PI * i) / rest.length - Math.PI / 2;
    nodePos[n.id] = {
      x: cx + Math.cos(angle) * radius,
      y: cy + Math.sin(angle) * radius,
    };
  });

  // Node styling
  const typeColors = {
    contact: '#6366f1',
    company: '#f97316',
    deal:    '#22c55e',
  };
  const typeRadius = {
    contact: 22,
    company: 26,
    deal:    20,
  };

  // Build SVG
  const svgEdges = edges.map(e => {
    const from = nodePos[e.from];
    const to   = nodePos[e.to];
    if (!from || !to) return '';
    const mx = (from.x + to.x) / 2;
    const my = (from.y + to.y) / 2;
    return `
      <line x1="${from.x}" y1="${from.y}" x2="${to.x}" y2="${to.y}" stroke="var(--border)" stroke-width="1.5" />
      <text x="${mx}" y="${my - 4}" font-size="9" fill="var(--text-muted)" text-anchor="middle" dominant-baseline="middle">${esc(e.label)}</text>`;
  }).join('');

  const svgNodes = nodes.map(n => {
    const pos   = nodePos[n.id];
    if (!pos) return '';
    const color = typeColors[n.type] || '#888';
    const r     = typeRadius[n.type] || 20;
    const stroke = n.primary ? '3' : '1.5';
    const label = n.label.length > 14 ? n.label.slice(0, 13) + '…' : n.label;

    // Navigate on click
    let clickFn = '';
    if (n.type === 'contact') clickFn = `showContactDetail('${n.id}')`;
    else if (n.type === 'company') clickFn = `editCompanyModal('${n.id}')`;
    else if (n.type === 'deal') clickFn = `showDealDetail('${n.id}')`;

    return `
      <g class="graph-node" style="cursor:pointer" onclick="${clickFn}">
        <circle cx="${pos.x}" cy="${pos.y}" r="${r}" fill="${color}22" stroke="${color}" stroke-width="${stroke}" />
        <text x="${pos.x}" y="${pos.y - r - 5}" font-size="10" fill="var(--text)" text-anchor="middle">${esc(label)}</text>
        <text x="${pos.x}" y="${pos.y + 4}" font-size="9" fill="${color}" text-anchor="middle" font-weight="600" dominant-baseline="middle">${n.type[0].toUpperCase()}</text>
      </g>`;
  }).join('');

  const legend = ['contact', 'company', 'deal'].map(t => `
    <div style="display:flex;align-items:center;gap:5px">
      <div style="width:10px;height:10px;border-radius:50%;background:${typeColors[t]}22;border:1.5px solid ${typeColors[t]}"></div>
      <span style="font-size:10px;color:var(--text-muted);text-transform:capitalize">${t}</span>
    </div>`).join('');

  container.innerHTML = `
    <div style="padding:12px 0">
      <div style="display:flex;gap:12px;flex-wrap:wrap;margin-bottom:12px;padding:0 4px">
        ${legend}
        <span style="font-size:10px;color:var(--text-muted);margin-left:auto">Click a node to navigate</span>
      </div>
      <svg width="${W}" height="${H}" style="background:var(--surface2);border:1px solid var(--border);border-radius:8px;display:block;max-width:100%">
        ${svgEdges}
        ${svgNodes}
      </svg>
    </div>`;
}

