async function p25RenderCompanyConnections(companyId, containerId) {
  const el = document.getElementById(containerId);
  if (!el) return;
  el.innerHTML = '<div style="padding:12px;color:var(--text-muted);font-size:12px">Loading connections...</div>';

  try {
    const contacts = await apiGet('/companies/' + companyId + '/connections');
    if (!contacts.length) {
      el.innerHTML = '<div style="padding:12px;color:var(--text-muted);font-size:12px">No contacts linked to this company.</div>';
      return;
    }

    const healthColor = (h) => h >= 70 ? 'var(--green)' : h >= 40 ? 'var(--yellow)' : 'var(--red)';

    el.innerHTML = `
      <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(200px,1fr));gap:10px;padding:12px">
        ${contacts.map(c => `
          <div class="p25-conn-card" onclick="showContactDetail('${c.id}')" style="cursor:pointer;padding:12px;background:var(--surface2);border:1px solid var(--border);border-radius:8px;transition:border-color 0.15s" onmouseenter="this.style.borderColor='var(--accent)'" onmouseleave="this.style.borderColor='var(--border)'">
            <div style="display:flex;align-items:center;gap:8px;margin-bottom:8px">
              <div class="avatar" style="width:30px;height:30px;font-size:11px;border-radius:6px;flex-shrink:0">${esc(initials(c.name))}</div>
              <div style="min-width:0">
                <div style="font-size:12px;font-weight:600;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${esc(c.name)}</div>
                ${c.title ? `<div style="font-size:10px;color:var(--text-muted);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${esc(c.title)}</div>` : ''}
              </div>
            </div>
            <div style="display:flex;justify-content:space-between;align-items:center">
              <div style="font-size:10px;color:var(--text-muted)">${c.dealCount} deal${c.dealCount !== 1 ? 's' : ''}</div>
              <div style="display:flex;align-items:center;gap:4px">
                <div style="font-size:10px;font-weight:600;color:${healthColor(c.healthScore)}">${c.healthScore}</div>
                <div style="width:32px;height:4px;background:var(--surface3);border-radius:2px;overflow:hidden">
                  <div style="height:100%;width:${c.healthScore}%;background:${healthColor(c.healthScore)};border-radius:2px"></div>
                </div>
              </div>
            </div>
          </div>`).join('')}
      </div>`;
  } catch(e) {
    el.innerHTML = '<div style="padding:12px;color:var(--text-muted);font-size:12px">Could not load connections.</div>';
  }
}

// Patch renderCompanyDetail to add Connections panel
(function p25PatchCompanyDetail() {
  const _origComp = window.renderCompanyDetail;
  window.renderCompanyDetail = function(id) {
    if (_origComp) _origComp.call(this, id);

    const el = document.getElementById('view-company-detail');
    if (!el || el.querySelector('#p25-company-conn-wrap')) return;

    // Find the page-content or first panel container
    const content = el.querySelector('.page-content') || el.querySelector('.contact-detail-grid');
    if (!content) return;

    const wrap = document.createElement('div');
    wrap.id = 'p25-company-conn-wrap';
    wrap.className = 'panel';
    wrap.style.marginTop = '16px';
    wrap.innerHTML = `
      <div class="panel-header">
        <div class="panel-title">Connections</div>
        <span style="font-size:11px;color:var(--text-muted)">All contacts at this company</span>
      </div>
      <div id="p25-company-conn-inner"></div>`;
    content.appendChild(wrap);

    p25RenderCompanyConnections(id, 'p25-company-conn-inner');
  };
})();

// ─── 4. ADVANCED EMAIL SEQUENCES V2 ──────────────────────────────────────

let _p25Enrollments = [];
let _p25SelectedContacts = new Set();

// Route handler
(function() {
  const _origNavigate = window.navigate;
  window.navigate = function(view, param) {
    if (_origNavigate) _origNavigate.call(this, view, param);
    if (view === 'sequences') {
      setTimeout(() => p25RenderSequencesPage(), 50);
    }
  };
})();

async function p25RenderSequencesPage() {
  const el = document.getElementById('view-sequences-content');
  if (!el) return;
  el.innerHTML = '<div style="padding:20px;color:var(--text-muted)">Loading...</div>';

  try {
    const [seqs, enrollments] = await Promise.all([
      apiGet('/sequences'),
      apiGet('/sequence-enrollments').catch(() => []),
    ]);
    _p25Enrollments = enrollments;
    db.sequences = seqs; // keep in sync

    el.innerHTML = `
      <div style="padding:0 0 24px">

        <!-- Sequences List -->
        <div style="padding:20px">
          <div style="font-size:14px;font-weight:600;margin-bottom:12px">Sequences</div>
          ${seqs.length ? `
            <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(280px,1fr));gap:12px;margin-bottom:24px">
              ${seqs.map(s => {
                const steps = s.steps || [];
                return `
                  <div class="panel" style="padding:14px 16px;cursor:default">
                    <div style="font-size:13px;font-weight:600;margin-bottom:4px">${esc(s.name)}</div>
                    <div style="font-size:11px;color:var(--text-muted);margin-bottom:10px">${steps.length} step${steps.length !== 1 ? 's' : ''}</div>
                    ${steps.map((step, i) => `
                      <div style="display:flex;align-items:flex-start;gap:8px;padding:6px 0;border-top:1px solid var(--border)">
                        <div style="min-width:18px;height:18px;border-radius:50%;background:var(--accent);color:white;font-size:9px;font-weight:700;display:flex;align-items:center;justify-content:center">${i+1}</div>
                        <div style="flex:1">
                          <div style="font-size:11px;font-weight:500">${esc(step.type||'Email')}</div>
                          <div style="font-size:10px;color:var(--text-muted)">${step.delayDays ? `+${step.delayDays}d` : 'Immediate'}${step.condition ? ' · Conditional' : ''}</div>
                          <div style="font-size:10px;color:var(--text-dim);margin-top:1px">${esc((step.note||step.subject||'').slice(0,60))}${(step.note||step.subject||'').length>60?'…':''}</div>
                        </div>
                      </div>`).join('')}
                    <div style="margin-top:10px;display:flex;gap:6px">
                      <button class="btn btn-secondary btn-xs" onclick="p25OpenSequenceModal('${s.id}')">Edit</button>
                      <button class="btn btn-ghost btn-xs" onclick="p25DeleteSequence('${s.id}')">Delete</button>
                    </div>
                  </div>`;
              }).join('')}
            </div>` : `<div style="color:var(--text-muted);font-size:12px;margin-bottom:24px">No sequences yet. Create one to set up drip campaigns.</div>`}
        </div>

        <!-- Enrollment Table -->
        <div style="padding:0 20px">
          <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px">
            <div style="font-size:14px;font-weight:600">Enrollments</div>
            <div style="font-size:11px;color:var(--text-muted)">${enrollments.length} contact${enrollments.length !== 1 ? 's' : ''} enrolled</div>
          </div>
          ${enrollments.length ? `
            <div class="table-wrap">
              <table>
                <thead><tr>
                  <th>Contact</th>
                  <th>Sequence</th>
                  <th>Step</th>
                  <th>Status</th>
                  <th>Enrolled</th>
                  <th>Actions</th>
                </tr></thead>
                <tbody>
                  ${enrollments.map(e => {
                    const seq = seqs.find(s => s.id === e.sequenceId);
                    const stepCount = seq ? (seq.steps||[]).length : 0;
                    const statusColor = e.status === 'Active' ? 'var(--green)' : e.status === 'Completed' ? 'var(--accent)' : 'var(--yellow)';
                    return `
                      <tr>
                        <td>
                          <span style="cursor:pointer;color:var(--accent-hover)" onclick="showContactDetail('${e.contactId}')">${esc(e.contactName)}</span>
                          ${e.contactEmail ? `<div style="font-size:10px;color:var(--text-muted)">${esc(e.contactEmail)}</div>` : ''}
                        </td>
                        <td style="font-size:12px">${esc(seq ? seq.name : e.sequenceId)}</td>
                        <td>
                          <span style="font-size:12px">${e.currentStep + 1} / ${stepCount || '?'}</span>
                          ${stepCount ? `<div style="width:60px;height:3px;background:var(--surface3);border-radius:2px;margin-top:3px;overflow:hidden">
                            <div style="height:100%;width:${Math.round(((e.currentStep)/(stepCount||1))*100)}%;background:var(--accent);border-radius:2px"></div>
                          </div>` : ''}
                        </td>
                        <td><span style="font-size:11px;font-weight:600;color:${statusColor}">${e.status}</span></td>
                        <td style="font-size:11px;color:var(--text-muted)">${formatDate(e.enrolledAt)}</td>
                        <td>
                          <div style="display:flex;gap:4px">
                            ${e.status !== 'Completed' ? `<button class="btn btn-ghost btn-xs" onclick="p25AdvanceStep('${e.id}')">Advance</button>` : ''}
                            ${e.status === 'Active' ? `<button class="btn btn-ghost btn-xs" onclick="p25PauseEnrollment('${e.id}')">Pause</button>` : ''}
                            ${e.status === 'Paused' ? `<button class="btn btn-ghost btn-xs" onclick="p25ResumeEnrollment('${e.id}')">Resume</button>` : ''}
                            <button class="btn btn-ghost btn-xs" style="opacity:0.5" onclick="p25RemoveEnrollment('${e.id}')">Remove</button>
                          </div>
                        </td>
                      </tr>`;
                  }).join('')}
                </tbody>
              </table>
            </div>` : `<div style="color:var(--text-muted);font-size:12px">No contacts enrolled in any sequence. Go to Contacts and select contacts to enroll.</div>`}
        </div>
      </div>`;
  } catch(e) {
    el.innerHTML = '<div style="padding:20px;color:var(--red)">Error loading sequences.</div>';
    console.error(e);
  }
}

async function p25AdvanceStep(enrollmentId) {
  try {
    await apiRequest('PATCH', '/sequence-enrollments/' + enrollmentId + '/advance');
    p25RenderSequencesPage();
  } catch(e) { alert('Error advancing step: ' + e.message); }
}

async function p25PauseEnrollment(enrollmentId) {
  try {
    await apiRequest('PATCH', '/sequence-enrollments/' + enrollmentId + '/pause');
    p25RenderSequencesPage();
  } catch(e) { alert('Error pausing enrollment: ' + e.message); }
}

async function p25ResumeEnrollment(enrollmentId) {
  try {
    await apiRequest('PATCH', '/sequence-enrollments/' + enrollmentId + '/resume');
    p25RenderSequencesPage();
  } catch(e) { alert('Error resuming enrollment: ' + e.message); }
}

async function p25RemoveEnrollment(enrollmentId) {
  if (!confirm('Remove this enrollment?')) return;
  try {
    await apiDelete('/sequence-enrollments/' + enrollmentId);
    p25RenderSequencesPage();
  } catch(e) { alert('Error removing enrollment: ' + e.message); }
}

async function p25DeleteSequence(seqId) {
  if (!confirm('Delete this sequence? Enrolled contacts will remain but the sequence will be gone.')) return;
  try {
    await apiDelete('/sequences/' + seqId);
    p25RenderSequencesPage();
  } catch(e) { alert('Error deleting sequence: ' + e.message); }
}

// Sequence create/edit modal
let _p25EditSeqId = null;
let _p25SeqSteps  = [];

function p25OpenSequenceModal(seqId) {
  _p25EditSeqId = seqId || null;
  _p25SeqSteps = [];

  let name = '';
  if (seqId) {
    const seq = db.sequences.find(s => s.id === seqId);
    if (seq) {
      name = seq.name;
      _p25SeqSteps = JSON.parse(JSON.stringify(seq.steps || []));
    }
  }

  const overlay = document.createElement('div');
  overlay.id = 'p25-seq-modal-overlay';
  overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.6);z-index:9999;display:flex;align-items:center;justify-content:center';
  overlay.innerHTML = `
    <div style="background:var(--surface);border:1px solid var(--border);border-radius:10px;width:560px;max-width:96vw;max-height:85vh;display:flex;flex-direction:column">
      <div style="padding:16px 20px;border-bottom:1px solid var(--border);display:flex;justify-content:space-between;align-items:center">
        <div style="font-size:15px;font-weight:600">${seqId ? 'Edit' : 'New'} Sequence</div>
        <button onclick="document.getElementById('p25-seq-modal-overlay').remove()" style="background:none;border:none;cursor:pointer;color:var(--text-muted);font-size:20px">&times;</button>
      </div>
      <div style="flex:1;overflow-y:auto;padding:16px 20px">
        <div style="margin-bottom:14px">
          <label style="font-size:12px;font-weight:500;color:var(--text-muted);display:block;margin-bottom:5px">Sequence Name</label>
          <input id="p25-seq-name" type="text" class="input-field" value="${esc(name)}" placeholder="e.g. Post-Demo Follow-up" style="width:100%" />
        </div>
        <div style="font-size:12px;font-weight:500;color:var(--text-muted);margin-bottom:8px">Steps</div>
        <div id="p25-seq-steps-list"></div>
        <button class="btn btn-secondary btn-sm" style="margin-top:8px" onclick="p25AddSeqStep()">+ Add Step</button>
      </div>
      <div style="padding:12px 20px;border-top:1px solid var(--border);display:flex;justify-content:flex-end;gap:8px">
        <button class="btn btn-ghost" onclick="document.getElementById('p25-seq-modal-overlay').remove()">Cancel</button>
        <button class="btn btn-primary" onclick="p25SaveSequence()">Save Sequence</button>
      </div>
    </div>`;
  document.body.appendChild(overlay);
  overlay.addEventListener('click', e => { if (e.target === overlay) overlay.remove(); });
  p25RenderSeqStepsList();
}

function p25RenderSeqStepsList() {
  const el = document.getElementById('p25-seq-steps-list');
  if (!el) return;
  if (!_p25SeqSteps.length) {
    el.innerHTML = '<div style="color:var(--text-muted);font-size:12px;padding:8px 0">No steps yet. Add a step below.</div>';
    return;
  }
  el.innerHTML = _p25SeqSteps.map((step, i) => `
    <div style="border:1px solid var(--border);border-radius:8px;padding:12px 14px;margin-bottom:8px;background:var(--surface2)">
      <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px">
        <span style="font-size:11px;font-weight:700;color:var(--text-muted)">Step ${i + 1}</span>
        <button onclick="p25RemoveSeqStep(${i})" style="background:none;border:none;cursor:pointer;color:var(--text-muted);font-size:13px">&times;</button>
      </div>
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:8px">
        <div>
          <label style="font-size:10px;color:var(--text-muted);font-weight:500;display:block;margin-bottom:3px">Type</label>
          <select class="filter-select" style="width:100%" onchange="p25UpdateStep(${i},'type',this.value)">
            ${['Email','Call','Task','LinkedIn','SMS'].map(t => `<option value="${t}" ${step.type===t?'selected':''}>${t}</option>`).join('')}
          </select>
        </div>
        <div>
          <label style="font-size:10px;color:var(--text-muted);font-weight:500;display:block;margin-bottom:3px">Delay (days)</label>
          <input type="number" min="0" class="input-field" value="${step.delayDays||0}" placeholder="0" onchange="p25UpdateStep(${i},'delayDays',parseInt(this.value)||0)" style="width:100%" />
        </div>
      </div>
      <div style="margin-bottom:8px">
        <label style="font-size:10px;color:var(--text-muted);font-weight:500;display:block;margin-bottom:3px">Subject / Topic</label>
        <input type="text" class="input-field" value="${esc(step.subject||step.note||'')}" placeholder="Subject or topic" onchange="p25UpdateStep(${i},'subject',this.value)" style="width:100%" />
      </div>
      <div style="margin-bottom:8px">
        <label style="font-size:10px;color:var(--text-muted);font-weight:500;display:block;margin-bottom:3px">Message / Note</label>
        <textarea class="input-field" rows="2" placeholder="Message body or action note" style="width:100%;resize:vertical" onchange="p25UpdateStep(${i},'note',this.value)">${esc(step.note||'')}</textarea>
      </div>
      <div style="display:flex;align-items:center;gap:6px">
        <input type="checkbox" id="p25-step-cond-${i}" ${step.condition?'checked':''} onchange="p25UpdateStep(${i},'condition',this.checked?'email_opened':null)" />
        <label for="p25-step-cond-${i}" style="font-size:11px;color:var(--text-muted)">Conditional: only proceed if previous email was opened</label>
      </div>
    </div>`).join('');
}

function p25AddSeqStep() {
  _p25SeqSteps.push({ type: 'Email', delayDays: 3, subject: '', note: '', condition: null });
  p25RenderSeqStepsList();
}

function p25RemoveSeqStep(i) {
  _p25SeqSteps.splice(i, 1);
  p25RenderSeqStepsList();
}

function p25UpdateStep(i, key, value) {
  if (!_p25SeqSteps[i]) return;
  _p25SeqSteps[i][key] = value;
}

async function p25SaveSequence() {
  const name = document.getElementById('p25-seq-name')?.value?.trim();
  if (!name) { alert('Please enter a sequence name.'); return; }

  try {
    if (_p25EditSeqId) {
      await apiPut('/sequences/' + _p25EditSeqId, { name, steps: _p25SeqSteps });
    } else {
      await apiPost('/sequences', { name, steps: _p25SeqSteps });
    }
    document.getElementById('p25-seq-modal-overlay')?.remove();
    p25RenderSequencesPage();
  } catch(e) {
    alert('Error saving sequence: ' + e.message);
  }
}

// Enroll contacts from contacts list
let _p25EnrollSelectedIds = [];
let _p25EnrollFromContacts = false;

function p25OpenEnrollModal(contactIds) {
  const ids = contactIds || [..._p25SelectedContacts];
  if (!ids.length) { alert('No contacts selected.'); return; }
  _p25EnrollSelectedIds = ids;

  const seqs = db.sequences || [];
  if (!seqs.length) { alert('No sequences available. Create a sequence first in the Sequences section.'); return; }

  const overlay = document.createElement('div');
  overlay.id = 'p25-enroll-modal-overlay';
  overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.6);z-index:9999;display:flex;align-items:center;justify-content:center';
  overlay.innerHTML = `
    <div style="background:var(--surface);border:1px solid var(--border);border-radius:10px;width:400px;max-width:95vw">
      <div style="padding:16px 20px;border-bottom:1px solid var(--border);display:flex;justify-content:space-between;align-items:center">
        <div style="font-size:14px;font-weight:600">Enroll in Sequence</div>
        <button onclick="document.getElementById('p25-enroll-modal-overlay').remove()" style="background:none;border:none;cursor:pointer;color:var(--text-muted);font-size:20px">&times;</button>
      </div>
      <div style="padding:16px 20px">
        <div style="font-size:12px;color:var(--text-muted);margin-bottom:12px">Enrolling ${ids.length} contact${ids.length !== 1 ? 's' : ''}</div>
        <label style="font-size:12px;font-weight:500;color:var(--text-muted);display:block;margin-bottom:6px">Select Sequence</label>
        <select id="p25-enroll-seq-select" class="filter-select" style="width:100%">
          ${seqs.map(s => `<option value="${s.id}">${esc(s.name)} (${(s.steps||[]).length} steps)</option>`).join('')}
        </select>
      </div>
      <div style="padding:12px 20px;border-top:1px solid var(--border);display:flex;justify-content:flex-end;gap:8px">
        <button class="btn btn-ghost" onclick="document.getElementById('p25-enroll-modal-overlay').remove()">Cancel</button>
        <button class="btn btn-primary" onclick="p25ConfirmEnroll()">Enroll</button>
      </div>
    </div>`;
  document.body.appendChild(overlay);
  overlay.addEventListener('click', e => { if (e.target === overlay) overlay.remove(); });
}

async function p25ConfirmEnroll() {
  const seqId = document.getElementById('p25-enroll-seq-select')?.value;
  if (!seqId) { alert('Please select a sequence.'); return; }
  try {
    const result = await apiPost('/sequence-enrollments', { contactIds: _p25EnrollSelectedIds, sequenceId: seqId });
    document.getElementById('p25-enroll-modal-overlay')?.remove();
    alert(`${result.enrolled} contact${result.enrolled !== 1 ? 's' : ''} enrolled.`);
    // Clear selection
    _p25SelectedContacts.clear();
    const btn = document.getElementById('p25-contacts-enroll-btn');
    if (btn) btn.style.display = 'none';
  } catch(e) {
    alert('Error enrolling: ' + e.message);
  }
}

// Add Enroll button to contacts toolbar (patch renderContacts)
(function p25PatchContactsEnroll() {
  const _origRC = window.renderContacts;
  window.renderContacts = function() {
    if (_origRC) _origRC.call(this);
    setTimeout(() => {
      const toolbar = document.querySelector('#view-contacts .toolbar') ||
                      document.querySelector('#view-contacts .page-header .header-actions');
      if (!toolbar || toolbar.querySelector('#p25-contacts-enroll-btn')) return;

      const btn = document.createElement('button');
      btn.id = 'p25-contacts-enroll-btn';
      btn.className = 'btn btn-secondary';
      btn.textContent = 'Enroll in Sequence';
      btn.style.display = 'none';
      btn.onclick = () => p25OpenEnrollModal([..._p25SelectedContacts]);
      toolbar.appendChild(btn);
    }, 100);
  };
})();

// ─── 5. SALES FORECASTING V2 ─────────────────────────────────────────────

let _p25ForecastSeasonality = 0;
let _p25ForecastData = null;

async function p25LoadForecastV2() {
  const el = document.getElementById('p25-forecast-v2-panel');
  if (!el) return;
  el.innerHTML = '<div style="padding:20px;color:var(--text-muted);font-size:12px">Loading forecast...</div>';

  try {
    const data = await apiGet('/reports/forecast-v2?seasonality=' + _p25ForecastSeasonality);
    _p25ForecastData = data;
    p25RenderForecastV2Panel(data, el);
  } catch(e) {
    el.innerHTML = '<div style="padding:20px;color:var(--red);font-size:12px">Error loading forecast.</div>';
  }
}

function p25RenderForecastV2Panel(data, el) {
  const fmt = (v) => '$' + Math.round(v).toLocaleString();
  const pct = (a, b) => b === 0 ? 'N/A' : ((a - b) / b * 100).toFixed(1) + '%';
  const diff = data.bestCase - (data.lastMonthWon || 0);
  const diffStr = diff >= 0 ? '+' + fmt(diff) : fmt(diff);

  el.innerHTML = `
    <!-- Three Tier Cards -->
    <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:14px;margin-bottom:20px">
      <div style="background:var(--surface2);border:1px solid var(--border);border-radius:10px;padding:18px">
        <div style="font-size:11px;font-weight:600;text-transform:uppercase;letter-spacing:0.07em;color:var(--text-muted);margin-bottom:8px">Commit</div>
        <div style="font-size:24px;font-weight:700;color:var(--green)">${fmt(data.commit)}</div>
        <div style="font-size:10px;color:var(--text-muted);margin-top:4px">${data.commitCount} deal${data.commitCount !== 1 ? 's' : ''} &gt;70% health, closing this month</div>
      </div>
      <div style="background:var(--surface2);border:1px solid var(--border);border-radius:10px;padding:18px">
        <div style="font-size:11px;font-weight:600;text-transform:uppercase;letter-spacing:0.07em;color:var(--text-muted);margin-bottom:8px">Best Case</div>
        <div style="font-size:24px;font-weight:700;color:var(--accent)">${fmt(data.bestCase)}</div>
        <div style="font-size:10px;color:var(--text-muted);margin-top:4px">${data.bestCaseCount} deal${data.bestCaseCount !== 1 ? 's' : ''} closing this month x health probability</div>
        <div style="font-size:10px;margin-top:6px;color:${diff >= 0 ? 'var(--green)' : 'var(--red)'}">${diffStr} vs last month (${fmt(data.lastMonthWon)} won)</div>
      </div>
      <div style="background:var(--surface2);border:1px solid var(--border);border-radius:10px;padding:18px">
        <div style="font-size:11px;font-weight:600;text-transform:uppercase;letter-spacing:0.07em;color:var(--text-muted);margin-bottom:8px">Pipeline</div>
        <div style="font-size:24px;font-weight:700;color:var(--yellow)">${fmt(data.pipeline)}</div>
        <div style="font-size:10px;color:var(--text-muted);margin-top:4px">${data.pipelineCount} deal${data.pipelineCount !== 1 ? 's' : ''} closing this quarter x 50%</div>
        <div style="font-size:10px;color:var(--text-muted);margin-top:2px">Seasonality: ${_p25ForecastSeasonality >= 0 ? '+' : ''}${(_p25ForecastSeasonality * 100).toFixed(0)}%</div>
      </div>
    </div>

    <!-- Seasonality Slider -->
    <div style="background:var(--surface2);border:1px solid var(--border);border-radius:8px;padding:14px;margin-bottom:20px;display:flex;align-items:center;gap:14px">
      <span style="font-size:12px;font-weight:500;white-space:nowrap">Seasonality Adjustment</span>
      <input type="range" id="p25-seasonality-slider" min="-20" max="20" step="1" value="${Math.round(_p25ForecastSeasonality * 100)}"
        oninput="p25UpdateSeasonality(this.value)" style="flex:1;accent-color:var(--accent)" />
      <span id="p25-seasonality-value" style="font-size:12px;font-weight:600;min-width:36px;text-align:right">${_p25ForecastSeasonality >= 0 ? '+' : ''}${(_p25ForecastSeasonality * 100).toFixed(0)}%</span>
    </div>

    <!-- 6-Month Forecast Table -->
    <div style="background:var(--surface2);border:1px solid var(--border);border-radius:8px;overflow:hidden;margin-bottom:14px">
      <div style="padding:12px 14px;border-bottom:1px solid var(--border);display:flex;justify-content:space-between;align-items:center">
        <div style="font-size:13px;font-weight:600">6-Month Forecast</div>
        <button class="btn btn-secondary btn-xs" onclick="p25ExportForecastCSV()">Export CSV</button>
      </div>
      <div style="overflow-x:auto">
        <table style="width:100%;border-collapse:collapse">
          <thead>
            <tr style="background:var(--surface3)">
              <th style="padding:8px 12px;text-align:left;font-size:11px;font-weight:600;color:var(--text-muted)">Month</th>
              <th style="padding:8px 12px;text-align:right;font-size:11px;font-weight:600;color:var(--text-muted)">Committed</th>
              <th style="padding:8px 12px;text-align:right;font-size:11px;font-weight:600;color:var(--text-muted)">Best Case</th>
              <th style="padding:8px 12px;text-align:right;font-size:11px;font-weight:600;color:var(--text-muted)">Pipeline</th>
              <th style="padding:8px 12px;text-align:right;font-size:11px;font-weight:600;color:var(--text-muted)">Deals Closing</th>
              <th style="padding:8px 12px;text-align:right;font-size:11px;font-weight:600;color:var(--text-muted)">Won Revenue</th>
            </tr>
          </thead>
          <tbody>
            ${(data.forecastTable || []).map((row, i) => `
              <tr style="border-top:1px solid var(--border);${i === 0 ? 'background:var(--surface3)' : ''}">
                <td style="padding:8px 12px;font-size:12px;font-weight:${i===0?'600':'400'}">${row.month}</td>
                <td style="padding:8px 12px;text-align:right;font-size:12px;color:var(--green)">${fmt(row.committed)}</td>
                <td style="padding:8px 12px;text-align:right;font-size:12px;color:var(--accent)">${fmt(row.bestCase)}</td>
                <td style="padding:8px 12px;text-align:right;font-size:12px;color:var(--yellow)">${fmt(row.pipeline)}</td>
                <td style="padding:8px 12px;text-align:right;font-size:12px">${row.dealsClosing}</td>
                <td style="padding:8px 12px;text-align:right;font-size:12px;color:var(--text-muted)">${fmt(row.wonRevenue)}</td>
              </tr>`).join('')}
          </tbody>
        </table>
      </div>
    </div>`;
}

let _p25SeasonalityTimer = null;
function p25UpdateSeasonality(pctInt) {
  const val = parseInt(pctInt) / 100;
  _p25ForecastSeasonality = val;
  const el = document.getElementById('p25-seasonality-value');
  if (el) el.textContent = (val >= 0 ? '+' : '') + (val * 100).toFixed(0) + '%';

  clearTimeout(_p25SeasonalityTimer);
  _p25SeasonalityTimer = setTimeout(() => p25LoadForecastV2(), 500);
}

function p25ExportForecastCSV() {
  const s = Math.round(_p25ForecastSeasonality * 100);
  window.open(`${API_BASE}/reports/forecast-v2/csv?seasonality=${_p25ForecastSeasonality}`, '_blank');
}

