async function p25LoadSlackSettings() {
  try {
    const data = await apiGet('/settings/slack');
    const urlInput = document.getElementById('p25-slack-webhook-url');
    if (urlInput) urlInput.value = data.webhookUrl || '';

    const events = data.enabledEvents || [];
    document.querySelectorAll('.p25-slack-event-cb').forEach(cb => {
      cb.checked = events.includes(cb.value);
    });
  } catch(e) {
    console.warn('Could not load Slack settings', e);
  }
}

async function p25SaveSlackSettings() {
  const url = document.getElementById('p25-slack-webhook-url')?.value?.trim();
  const events = [...document.querySelectorAll('.p25-slack-event-cb:checked')].map(cb => cb.value);

  try {
    await apiPut('/settings/slack', { webhookUrl: url, enabledEvents: events });
    const el = document.getElementById('p25-slack-save-result');
    if (el) { el.textContent = 'Saved'; el.style.color = 'var(--green)'; setTimeout(() => { el.textContent = ''; }, 2000); }
  } catch(e) {
    alert('Error saving Slack settings: ' + e.message);
  }
}

async function p25TestSlackWebhook() {
  const btn = document.getElementById('p25-slack-test-btn');
  const result = document.getElementById('p25-slack-test-result');
  if (btn) btn.disabled = true;
  if (result) { result.textContent = 'Sending...'; result.style.color = 'var(--text-muted)'; }

  try {
    // Save first
    const url = document.getElementById('p25-slack-webhook-url')?.value?.trim();
    const events = [...document.querySelectorAll('.p25-slack-event-cb:checked')].map(cb => cb.value);
    await apiPut('/settings/slack', { webhookUrl: url, enabledEvents: events });
    await apiPost('/settings/slack/test', {});
    if (result) { result.textContent = 'Test message sent successfully'; result.style.color = 'var(--green)'; }
  } catch(e) {
    if (result) { result.textContent = 'Error: ' + e.message; result.style.color = 'var(--red)'; }
  } finally {
    if (btn) btn.disabled = false;
  }
}

