// Patch renderContacts to add checkboxes and enroll button
(function p25AddContactEnrollCheckboxes() {
  // After renderContacts runs and builds the table, inject checkboxes
  const _origRenderContactsTable = window.renderContactsTable;
  // We'll intercept by watching DOM mutations on contacts list
  // Instead, patch at a higher level via renderContacts wrapper
  const _origRC = window.renderContacts;
  window.renderContacts = function() {
    if (_origRC) _origRC.call(this);
    _p25SelectedContacts.clear();
    setTimeout(p25InjectContactCheckboxes, 150);
  };
})();

function p25InjectContactCheckboxes() {
  const table = document.querySelector('#view-contacts table') || document.querySelector('#contacts-list');
  if (!table) return;
  if (table.querySelector('.p25-enroll-cb')) return; // already injected

  // Add header checkbox
  const thead = table.querySelector('thead tr');
  if (thead && !thead.querySelector('.p25-select-all-th')) {
    const th = document.createElement('th');
    th.className = 'p25-select-all-th';
    th.style.width = '32px';
    th.innerHTML = '<input type="checkbox" id="p25-select-all-cb" onchange="p25SelectAllContacts(this.checked)" style="accent-color:var(--accent)" title="Select all" />';
    thead.insertBefore(th, thead.firstChild);
  }

  // Add row checkboxes
  const rows = table.querySelectorAll('tbody tr[onclick]');
  rows.forEach(row => {
    if (row.querySelector('.p25-enroll-cb')) return;
    // Extract contact ID from row's onclick
    const onclickStr = row.getAttribute('onclick') || '';
    const match = onclickStr.match(/showContactDetail\('([^']+)'\)/);
    if (!match) return;
    const cid = match[1];

    const td = document.createElement('td');
    td.style.padding = '0 8px';
    td.onclick = (e) => e.stopPropagation();
    td.innerHTML = `<input type="checkbox" class="p25-enroll-cb" data-cid="${cid}" onchange="p25ToggleContactSelect('${cid}',this.checked)" style="accent-color:var(--accent)" />`;
    row.insertBefore(td, row.firstChild);
  });

  // Show/hide enroll button in header
  p25UpdateEnrollBtn();
}

function p25SelectAllContacts(checked) {
  document.querySelectorAll('.p25-enroll-cb').forEach(cb => {
    cb.checked = checked;
    const cid = cb.dataset.cid;
    if (cid) {
      if (checked) _p25SelectedContacts.add(cid);
      else _p25SelectedContacts.delete(cid);
    }
  });
  p25UpdateEnrollBtn();
}

function p25ToggleContactSelect(cid, checked) {
  if (checked) _p25SelectedContacts.add(cid);
  else _p25SelectedContacts.delete(cid);
  p25UpdateEnrollBtn();
}

function p25UpdateEnrollBtn() {
  const count = _p25SelectedContacts.size;
  const btn = document.getElementById('p25-contacts-enroll-btn');
  if (!btn) {
    // Create it
    const toolbar = document.querySelector('#view-contacts .toolbar') ||
                    document.querySelector('#view-contacts .page-header .header-actions');
    if (!toolbar) return;
    const newBtn = document.createElement('button');
    newBtn.id = 'p25-contacts-enroll-btn';
    newBtn.className = 'btn btn-secondary';
    newBtn.style.display = count > 0 ? '' : 'none';
    newBtn.onclick = () => p25OpenEnrollModal([..._p25SelectedContacts]);
    toolbar.appendChild(newBtn);
    const b2 = document.getElementById('p25-contacts-enroll-btn');
    if (b2) b2.textContent = `Enroll ${count} in Sequence`;
    return;
  }
  btn.style.display = count > 0 ? '' : 'none';
  btn.textContent = count > 0 ? `Enroll ${count} in Sequence` : 'Enroll in Sequence';
}

// ─── 8. SLACK: FIRE OVERDUE NOTIFICATIONS ON APP LOAD ───────────────────

async function p25CheckOverdueSlackNotifications() {
  try {
    const slackCfg = await apiGet('/settings/slack');
    if (!slackCfg.webhookUrl || !slackCfg.enabledEvents?.length) return;

    // Task overdue
    if (slackCfg.enabledEvents.includes('task_overdue')) {
      const overdueTasks = (db.tasks || []).filter(t =>
        t.status === 'Open' && t.dueDate && t.dueDate < new Date().toISOString().slice(0,10)
      );
      if (overdueTasks.length) {
        const taskList = overdueTasks.slice(0, 3).map(t => `- ${t.title} (due ${t.dueDate})`).join('\n');
        const msg = `*Overdue Tasks*\n${taskList}${overdueTasks.length > 3 ? `\n... and ${overdueTasks.length - 3} more` : ''}`;
        apiPost('/settings/slack/notify', { event: 'task_overdue', message: msg }).catch(() => {});
      }
    }

    // Invoice overdue
    if (slackCfg.enabledEvents.includes('invoice_overdue')) {
      const overdueInv = (db.invoices || []).filter(inv =>
        inv.status !== 'Paid' && inv.dueDate && inv.dueDate < new Date().toISOString().slice(0,10)
      );
      if (overdueInv.length) {
        const invList = overdueInv.slice(0, 3).map(i => `- ${i.number||'Invoice'}: $${(i.total||0).toLocaleString()} (due ${i.dueDate})`).join('\n');
        const msg = `*Overdue Invoices*\n${invList}${overdueInv.length > 3 ? `\n... and ${overdueInv.length - 3} more` : ''}`;
        apiPost('/settings/slack/notify', { event: 'invoice_overdue', message: msg }).catch(() => {});
      }
    }
  } catch(e) {
    // Non-fatal
  }
}

// Run overdue checks 30 seconds after app loads (to let DB populate)
setTimeout(p25CheckOverdueSlackNotifications, 30000);

