function p26MobileNav(view) {
  p26CloseMobileMenu();
  navigate(view);
  // Update active tab
  document.querySelectorAll('.mobile-tab').forEach(btn => {
    btn.classList.toggle('active', btn.dataset.view === view);
  });
}

function p26ToggleMobileMenu() {
  const menu = document.getElementById('mobile-more-menu');
  if (!menu) return;
  menu.style.display = menu.style.display === 'none' ? 'flex' : 'none';
}

function p26CloseMobileMenu() {
  const menu = document.getElementById('mobile-more-menu');
  if (menu) menu.style.display = 'none';
}

// Swipe-to-dismiss modals
(function p26AddSwipeToDismiss() {
  let touchStartX = 0;
  let touchStartY = 0;

  document.addEventListener('touchstart', (e) => {
    touchStartX = e.changedTouches[0].clientX;
    touchStartY = e.changedTouches[0].clientY;
  }, { passive: true });

  document.addEventListener('touchend', (e) => {
    const dx = e.changedTouches[0].clientX - touchStartX;
    const dy = e.changedTouches[0].clientY - touchStartY;

    // Detect downward swipe > 80px on a modal
    if (dy > 80 && Math.abs(dx) < 60) {
      const openModal = document.querySelector('.modal-overlay.open, .modal-overlay[style*="flex"]');
      if (openModal) {
        const id = openModal.id;
        if (id) closeModal(id);
      }
    }
  }, { passive: true });
})();

// Update mobile tab active state when navigating
(function p26WatchNavForMobileTabs() {
  const _origNav = window.navigate;
  if (typeof _origNav !== 'function') return;
  window.navigate = function(view, param) {
    _origNav(view, param);
    const tabViews = ['dashboard', 'contacts', 'pipeline', 'activities'];
    document.querySelectorAll('.mobile-tab').forEach(btn => {
      if (btn.dataset.view === view || (!tabViews.includes(view) && btn.dataset.view === 'more')) {
        btn.classList.add('active');
      } else {
        btn.classList.remove('active');
      }
    });
  };
})();

// Set initial mobile tab on DOMContentLoaded
document.addEventListener('DOMContentLoaded', () => {
  const firstTab = document.querySelector('.mobile-tab[data-view="dashboard"]');
  if (firstTab) firstTab.classList.add('active');
});

