async function p26DraftEmail(contactId, dealId) {
  try {
    // Fetch context from server
    const ctx = await apiGet(`/contacts/${contactId}/email-context`);
    const contact = ctx.contact;
    const deal = dealId ? ctx.openDeals.find(d => d.id === dealId) : (ctx.openDeals[0] || null);
    const company = ctx.company;
    const lastActivity = ctx.lastActivity;

    // Determine stage
    const stage = deal ? deal.stage : null;

    // Pick template
    const template = P26_EMAIL_TEMPLATES[stage] || P26_EMAIL_TEMPLATES['default'];

    // Build variables
    const firstName = (contact.name || '').split(' ')[0] || contact.name;
    const companyName = company ? company.name : (contact.company || 'your company');
    const dealName = deal ? deal.name : companyName;
    const senderName = (_currentUser && _currentUser.name) || 'The BoredRoom Team';

    let lastActivityNote = '';
    if (lastActivity && lastActivity.note) {
      const topic = lastActivity.note.slice(0, 120);
      lastActivityNote = `Following our last ${(lastActivity.type || 'conversation').toLowerCase()} — ${topic}${lastActivity.note.length > 120 ? '...' : ''}`;
    } else if (ctx.daysSinceActivity !== null) {
      lastActivityNote = `It has been ${ctx.daysSinceActivity} day${ctx.daysSinceActivity !== 1 ? 's' : ''} since our last contact.`;
    }

    let titlePlural = 'professionals';
    const title = contact.title || '';
    if (title.toLowerCase().includes('vp') || title.toLowerCase().includes('vice')) titlePlural = 'VPs';
    else if (title.toLowerCase().includes('cto') || title.toLowerCase().includes('ceo') || title.toLowerCase().includes('c-') || title.toLowerCase().includes('chief')) titlePlural = 'executives';
    else if (title.toLowerCase().includes('director')) titlePlural = 'directors';
    else if (title.toLowerCase().includes('manager')) titlePlural = 'managers';
    else if (title.toLowerCase().includes('founder')) titlePlural = 'founders';

    function fill(str) {
      return str
        .replace(/\{firstName\}/g, firstName)
        .replace(/\{company\}/g, companyName)
        .replace(/\{dealName\}/g, dealName)
        .replace(/\{senderName\}/g, senderName)
        .replace(/\{lastActivityNote\}/g, lastActivityNote)
        .replace(/\{title\.plural\}/g, titlePlural);
    }

    const subject = fill(template.subject);
    const body = fill(template.body);

    // Open the compose modal (using Phase 24's p24OpenComposeEmail)
    if (typeof p24OpenComposeEmail === 'function') {
      p24OpenComposeEmail(contactId, dealId);

      // Wait a tick for the modal to render, then fill in the values
      setTimeout(() => {
        const subjectEl = document.getElementById('compose-subject');
        const bodyEl = document.getElementById('compose-body');
        const draftLabelId = 'compose-draft-label';

        if (subjectEl) subjectEl.value = subject;
        if (bodyEl) bodyEl.value = body;

        // Add "Generated Draft" label if not already there
        const modalHeader = document.querySelector('#modal-compose-email .modal-header');
        if (modalHeader && !document.getElementById(draftLabelId)) {
          const label = document.createElement('span');
          label.id = draftLabelId;
          label.style.cssText = 'font-size:11px;background:#22c55e22;color:#22c55e;padding:2px 8px;border-radius:10px;font-weight:500;margin-left:8px;';
          label.textContent = 'Generated Draft';
          const title = modalHeader.querySelector('.modal-title');
          if (title) title.appendChild(label);
        }
      }, 150);
    } else {
      toast('Compose modal not available', 'error');
    }
  } catch(e) {
    console.error('AI Email Writer error:', e);
    toast('Could not load email context', 'error');
  }
}

// Inject "Draft Email" button into contact detail header
(function p26InjectContactDraftEmailBtn() {
  const _origRenderContactDetail = window.renderContactDetail;
  if (typeof _origRenderContactDetail !== 'function') return;

  window.renderContactDetail = function(id) {
    _origRenderContactDetail(id);
    setTimeout(() => {
      const header = document.querySelector('#view-contact-detail .header-actions');
      if (!header || header.querySelector('.p26-draft-email-btn')) return;
      const btn = document.createElement('button');
      btn.className = 'btn btn-secondary btn-sm p26-draft-email-btn';
      btn.title = 'Draft AI Email';
      btn.textContent = 'Draft Email';
      btn.onclick = () => p26DraftEmail(id, null);
      header.insertBefore(btn, header.firstChild);
    }, 200);
  };
})();

// Inject "Draft Email" button into deal detail header
(function p26InjectDealDraftEmailBtn() {
  const _origRenderDealDetail = window.renderDealDetail;
  if (typeof _origRenderDealDetail !== 'function') return;

  window.renderDealDetail = function(id) {
    _origRenderDealDetail(id);
    setTimeout(() => {
      const header = document.querySelector('#view-deal-detail .header-actions');
      if (!header || header.querySelector('.p26-draft-email-btn')) return;
      // Need the deal's contact
      const deal = (window.db && window.db.deals) ? window.db.deals.find(d => d.id === id) : null;
      const contactId = deal ? deal.contact : null;
      if (!contactId) return;
      const btn = document.createElement('button');
      btn.className = 'btn btn-secondary btn-sm p26-draft-email-btn';
      btn.title = 'Draft AI Email for this deal';
      btn.textContent = 'Draft Email';
      btn.onclick = () => p26DraftEmail(contactId, id);
      header.insertBefore(btn, header.firstChild);
    }, 200);
  };
})();

