async function p26LoadPipelineDeepDive() {
  const container = document.getElementById('p26-deep-dive-container');
  if (!container) return;

  container.innerHTML = '<div style="color:var(--text-muted);font-size:13px;padding:24px;text-align:center">Loading...</div>';

  try {
    const data = await apiGet('/reports/pipeline-deep-dive');
    p26RenderDeepDive(container, data);
  } catch(e) {
    container.innerHTML = '<div style="color:#ef4444;font-size:13px;padding:24px;text-align:center">Could not load deep dive data.</div>';
  }
}

function p26RenderDeepDive(container, data) {
  const { conversionRates, avgDaysPerStage, stuckDeals, bottleneck, velocityComparison } = data;

  // Find bottleneck stage for callout
  const bottleneckStuck = stuckDeals ? stuckDeals.find(s => s.stuckCount > 0 && s.stuckCount === Math.max(...stuckDeals.map(x => x.stuckCount))) : null;
  const bottleneckCallout = bottleneck && bottleneck.avgDays > 0
    ? `Deals take the longest in <strong>${esc(bottleneck.stage)}</strong> (avg ${bottleneck.avgDays}d). ${bottleneckStuck ? `${bottleneckStuck.stuckCount} deal${bottleneckStuck.stuckCount !== 1 ? 's' : ''} stuck there for >14 days.` : ''}`
    : 'Not enough data to determine bottleneck.';

  const maxConv = 100;

  container.innerHTML = `
    <div style="display:flex;flex-direction:column;gap:20px;padding:16px">

      <!-- Stage Conversion Funnel -->
      <div class="panel">
        <div class="panel-header">
          <div class="panel-title">Stage Conversion Funnel</div>
          <span style="font-size:11px;color:var(--text-muted)">% of deals that reached each stage</span>
        </div>
        <div style="padding:16px;display:flex;flex-direction:column;gap:10px">
          ${(conversionRates || []).map((item, i) => `
            <div style="display:flex;align-items:center;gap:12px">
              <div style="min-width:120px;font-size:12px;color:var(--text-dim);font-weight:500">${esc(item.stage)}</div>
              <div style="flex:1;height:22px;background:var(--surface2);border-radius:4px;overflow:hidden;position:relative">
                <div style="height:100%;width:${item.conversionRate}%;background:${i === 0 ? 'var(--accent)' : '#3b82f6'};border-radius:4px;transition:width 0.6s ease;min-width:2px"></div>
              </div>
              <div style="min-width:80px;text-align:right;font-size:12px;font-weight:600;color:var(--text)">${item.conversionRate}%</div>
              <div style="min-width:50px;text-align:right;font-size:11px;color:var(--text-muted)">${item.count} deals</div>
            </div>
          `).join('')}
        </div>
      </div>

      <!-- Bottleneck Callout -->
      ${bottleneck ? `
      <div style="background:rgba(239,68,68,0.08);border:1px solid rgba(239,68,68,0.25);border-radius:8px;padding:14px 16px;font-size:13px;color:var(--text)">
        <strong style="color:#ef4444">Bottleneck Detected:</strong> ${bottleneckCallout}
      </div>` : ''}

      <!-- Average Days per Stage -->
      <div class="panel">
        <div class="panel-header">
          <div class="panel-title">Average Days per Stage</div>
        </div>
        <div style="padding:16px">
          ${(avgDaysPerStage || []).length ? (() => {
            const maxDays = Math.max(...avgDaysPerStage.map(s => s.avgDays), 1);
            return avgDaysPerStage.map(item => `
              <div style="display:flex;align-items:center;gap:12px;margin-bottom:10px">
                <div style="min-width:120px;font-size:12px;color:var(--text-dim);font-weight:500">${esc(item.stage)}</div>
                <div style="flex:1;height:18px;background:var(--surface2);border-radius:4px;overflow:hidden">
                  <div style="height:100%;width:${maxDays > 0 ? Math.round((item.avgDays / maxDays) * 100) : 0}%;background:#f97316;border-radius:4px;transition:width 0.6s ease;min-width:${item.avgDays > 0 ? 2 : 0}px"></div>
                </div>
                <div style="min-width:60px;text-align:right;font-size:12px;font-weight:600;color:var(--text)">${item.avgDays}d</div>
              </div>
            `).join('');
          })() : '<div style="color:var(--text-muted);font-size:12px;text-align:center;padding:12px">No stage log data yet. Data populates as deals move through stages.</div>'}
        </div>
      </div>

      <!-- Stuck Deals -->
      ${(stuckDeals || []).some(s => s.stuckCount > 0) ? `
      <div class="panel">
        <div class="panel-header">
          <div class="panel-title">Deals Stuck > 14 Days</div>
        </div>
        <div style="padding:12px;display:flex;flex-wrap:wrap;gap:10px">
          ${stuckDeals.filter(s => s.stuckCount > 0).map(s => `
            <div style="background:rgba(239,68,68,0.08);border:1px solid rgba(239,68,68,0.2);border-radius:6px;padding:10px 16px;text-align:center">
              <div style="font-size:22px;font-weight:700;color:#ef4444">${s.stuckCount}</div>
              <div style="font-size:11px;color:var(--text-muted)">${esc(s.stage)}</div>
            </div>
          `).join('')}
        </div>
      </div>` : ''}

      <!-- Stage Velocity Trend -->
      <div class="panel">
        <div class="panel-header">
          <div class="panel-title">Stage Velocity Trend</div>
          <span style="font-size:11px;color:var(--text-muted)">This quarter vs last quarter (avg days)</span>
        </div>
        <div style="padding:0 16px 12px">
          <table style="width:100%;border-collapse:collapse;font-size:12px">
            <thead>
              <tr style="border-bottom:1px solid var(--border)">
                <th style="text-align:left;padding:8px 0;color:var(--text-muted);font-weight:500">Stage</th>
                <th style="text-align:right;padding:8px 0;color:var(--text-muted);font-weight:500">This Qtr</th>
                <th style="text-align:right;padding:8px 0;color:var(--text-muted);font-weight:500">Last Qtr</th>
                <th style="text-align:right;padding:8px 0;color:var(--text-muted);font-weight:500">Delta</th>
              </tr>
            </thead>
            <tbody>
              ${(velocityComparison || []).map(row => {
                const delta = row.delta;
                const arrow = delta === null ? '' : delta > 0 ? '<span style="color:#ef4444">+' + delta + 'd ↑</span>' : delta < 0 ? '<span style="color:#22c55e">' + delta + 'd ↓</span>' : '<span style="color:var(--text-muted)">—</span>';
                return `<tr style="border-bottom:1px solid var(--border)">
                  <td style="padding:8px 0;color:var(--text)">${esc(row.stage)}</td>
                  <td style="padding:8px 0;text-align:right;color:var(--text)">${row.thisQ !== null ? row.thisQ + 'd' : '—'}</td>
                  <td style="padding:8px 0;text-align:right;color:var(--text-muted)">${row.lastQ !== null ? row.lastQ + 'd' : '—'}</td>
                  <td style="padding:8px 0;text-align:right">${arrow}</td>
                </tr>`;
              }).join('')}
            </tbody>
          </table>
        </div>
      </div>

    </div>
  `;
}

// Patch renderReports to inject the Deep Dive section
(function p26PatchReports() {
  const _orig = window.renderReports;
  if (typeof _orig !== 'function') return;

  window.renderReports = function() {
    _orig();
    setTimeout(() => {
      const content = document.querySelector('#view-reports .page-content');
      if (!content) return;
      if (content.querySelector('#p26-deep-dive-container')) return;

      const section = document.createElement('div');
      section.style.cssText = 'margin-top:24px';
      section.innerHTML = `
        <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:12px">
          <div style="font-size:16px;font-weight:700;color:var(--text)">Pipeline Deep Dive</div>
          <button class="btn btn-ghost btn-sm" onclick="p26LoadPipelineDeepDive()">Refresh</button>
        </div>
        <div id="p26-deep-dive-container">
          <div style="color:var(--text-muted);font-size:13px;padding:24px;text-align:center">Click Refresh to load pipeline analytics.</div>
        </div>
      `;
      content.appendChild(section);
      p26LoadPipelineDeepDive();
    }, 300);
  };
})();

