async function p26LoadCustomers() {
  const grid = document.getElementById('customers-grid');
  const countEl = document.getElementById('customers-count');
  if (!grid) return;

  grid.innerHTML = '<div style="color:var(--text-muted);font-size:13px;text-align:center;padding:32px;grid-column:1/-1">Loading...</div>';

  try {
    const customers = await apiGet('/customers');
    if (countEl) countEl.textContent = `${customers.length} customer${customers.length !== 1 ? 's' : ''}`;

    if (!customers.length) {
      grid.innerHTML = '<div style="color:var(--text-muted);font-size:13px;text-align:center;padding:32px;grid-column:1/-1">No won deals found. Won deals appear here as customer records.</div>';
      return;
    }

    grid.innerHTML = customers.map(c => {
      const health = c.healthScore || 0;
      const healthColor = health >= 70 ? '#22c55e' : health >= 40 ? '#f97316' : '#ef4444';
      const healthLabel = health >= 70 ? 'Healthy' : health >= 40 ? 'At Risk' : 'Critical';

      const daysSinceClose = c.closeDate ? Math.floor((Date.now() - new Date(c.closeDate).getTime()) / 86400000) : null;

      let renewalBadge = '';
      if (c.renewalDate) {
        const daysToRenewal = Math.floor((new Date(c.renewalDate).getTime() - Date.now()) / 86400000);
        if (daysToRenewal <= 30) {
          renewalBadge = `<span style="background:#fef08a22;border:1px solid #eab308;color:#eab308;font-size:10px;padding:1px 6px;border-radius:10px;font-weight:600">Renewal in ${daysToRenewal}d</span>`;
        }
      }

      return `
        <div class="panel p26-customer-card" onclick="p26RenderCustomerDetail('${c.dealId}')" style="cursor:pointer;transition:border-color 0.15s">
          <div style="padding:16px">
            <div style="display:flex;align-items:flex-start;justify-content:space-between;margin-bottom:12px">
              <div>
                <div style="font-size:15px;font-weight:700;color:var(--text)">${esc(c.companyName || c.dealName)}</div>
                ${c.contactName ? `<div style="font-size:12px;color:var(--text-muted);margin-top:2px">${esc(c.contactName)}</div>` : ''}
              </div>
              <div style="text-align:right">
                <div style="font-size:16px;font-weight:700;color:var(--accent)">${c.dealValue ? formatCurrency(c.dealValue) : '—'}</div>
                ${renewalBadge}
              </div>
            </div>

            <!-- Health Score -->
            <div style="display:flex;align-items:center;gap:8px;margin-bottom:10px">
              <div style="width:32px;height:32px;border-radius:50%;border:2.5px solid ${healthColor};display:flex;align-items:center;justify-content:center;font-size:11px;font-weight:700;color:${healthColor};flex-shrink:0">${health}</div>
              <div>
                <div style="font-size:11px;font-weight:600;color:${healthColor}">${healthLabel}</div>
                <div style="font-size:10px;color:var(--text-muted)">Health Score</div>
              </div>
            </div>

            <!-- Stats row -->
            <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:8px;font-size:11px">
              <div>
                <div style="color:var(--text-muted)">Open Tasks</div>
                <div style="font-weight:600;color:${c.openTasks > 0 ? '#f97316' : 'var(--text)'}">${c.openTasks}</div>
              </div>
              <div>
                <div style="color:var(--text-muted)">Since Close</div>
                <div style="font-weight:600;color:var(--text)">${daysSinceClose !== null ? daysSinceClose + 'd' : '—'}</div>
              </div>
              <div>
                <div style="color:var(--text-muted)">Last Activity</div>
                <div style="font-weight:600;color:var(--text)">${c.lastActivityDate ? formatDate(c.lastActivityDate) : '—'}</div>
              </div>
            </div>

            ${c.lastInvoice ? `
            <div style="margin-top:10px;padding-top:10px;border-top:1px solid var(--border);font-size:11px;display:flex;justify-content:space-between">
              <span style="color:var(--text-muted)">Last Invoice: ${esc(c.lastInvoice.number)}</span>
              <span style="color:${c.lastInvoice.status === 'Paid' ? '#22c55e' : c.lastInvoice.status === 'Overdue' ? '#ef4444' : 'var(--text-muted)'}">${esc(c.lastInvoice.status)}</span>
            </div>` : ''}
          </div>
        </div>
      `;
    }).join('');
  } catch(e) {
    grid.innerHTML = `<div style="color:#ef4444;font-size:13px;text-align:center;padding:32px;grid-column:1/-1">Error loading customers: ${esc(e.message)}</div>`;
  }
}

async function p26RenderCustomerDetail(dealId) {
  navigate('customer-detail', dealId);
  const body = document.getElementById('p26-customer-detail-body');
  if (!body) return;

  body.innerHTML = `
    <div class="page-header">
      <button class="btn btn-ghost btn-sm" onclick="navigate('customers')">← Back to Customers</button>
    </div>
    <div style="color:var(--text-muted);font-size:13px;text-align:center;padding:40px">Loading...</div>
  `;

  try {
    const data = await apiGet(`/customers/${dealId}`);
    const { deal, contact, company, renewal, tasks, activities, invoices, npsScores, scoreHistory } = data;

    const health = p26ComputeCustomerHealth(data);
    const healthColor = health >= 70 ? '#22c55e' : health >= 40 ? '#f97316' : '#ef4444';
    const healthLabel = health >= 70 ? 'Healthy' : health >= 40 ? 'At Risk' : 'Critical';

    body.innerHTML = `
      <div class="page-header">
        <div>
          <button class="btn btn-ghost btn-sm" onclick="navigate('customers')" style="margin-bottom:6px">← Back to Customers</button>
          <div class="page-title">${esc((company && company.name) || (contact && contact.name) || deal.name)}</div>
          ${contact ? `<div style="font-size:13px;color:var(--text-muted)">${esc(contact.name)}${contact.title ? ' · ' + esc(contact.title) : ''}</div>` : ''}
        </div>
        <div class="header-actions">
          <button class="btn btn-secondary btn-sm" onclick="p26RenderCustomerDetail('${dealId}')">Refresh</button>
          ${contact ? `<button class="btn btn-secondary btn-sm" onclick="p26DraftEmail('${contact.id}', '${dealId}')">Draft Email</button>` : ''}
        </div>
      </div>
      <div class="page-content" style="overflow-y:auto;padding:16px">
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:16px;margin-bottom:16px">
          <!-- Health Score Panel -->
          <div class="panel">
            <div class="panel-header"><div class="panel-title">Health Score</div></div>
            <div style="padding:16px;text-align:center">
              <div style="font-size:48px;font-weight:800;color:${healthColor}">${health}</div>
              <div style="font-size:13px;font-weight:600;color:${healthColor};margin-bottom:8px">${healthLabel}</div>
              ${scoreHistory.length > 1 ? p26RenderScoreHistoryMini(scoreHistory) : '<div style="font-size:11px;color:var(--text-muted)">Score history builds over time</div>'}
            </div>
          </div>

          <!-- Deal Info -->
          <div class="panel">
            <div class="panel-header"><div class="panel-title">Account Overview</div></div>
            <div style="padding:16px;display:flex;flex-direction:column;gap:8px;font-size:13px">
              <div style="display:flex;justify-content:space-between"><span style="color:var(--text-muted)">Deal Value</span><span style="font-weight:600">${deal.value ? formatCurrency(deal.value) : '—'}</span></div>
              <div style="display:flex;justify-content:space-between"><span style="color:var(--text-muted)">Close Date</span><span>${deal.closeDate ? formatDate(deal.closeDate) : '—'}</span></div>
              ${renewal ? `<div style="display:flex;justify-content:space-between"><span style="color:var(--text-muted)">Renewal</span><span style="color:#eab308;font-weight:500">${esc(renewal.renewal_date)}</span></div>` : ''}
              ${renewal ? `<div style="display:flex;justify-content:space-between"><span style="color:var(--text-muted)">Service</span><span>${esc(renewal.service_name)}</span></div>` : ''}
              <div style="display:flex;justify-content:space-between"><span style="color:var(--text-muted)">Open Tasks</span><span style="color:${tasks.length > 0 ? '#f97316' : '#22c55e'};font-weight:600">${tasks.length}</span></div>
            </div>
          </div>
        </div>

        <!-- NPS Panel -->
        <div class="panel" style="margin-bottom:16px">
          <div class="panel-header">
            <div class="panel-title">Net Promoter Score (NPS)</div>
            ${npsScores.length ? `<span style="font-size:12px;color:var(--text-muted)">Latest: ${npsScores[0].score}/10</span>` : ''}
          </div>
          <div style="padding:16px">
            <div style="margin-bottom:12px;font-size:12px;color:var(--text-muted)">How likely is the customer to recommend you? (0 = Not at all, 10 = Extremely likely)</div>
            <div style="display:flex;gap:6px;flex-wrap:wrap;margin-bottom:12px" id="nps-score-buttons-${dealId}">
              ${Array.from({length: 11}, (_, i) => `
                <button onclick="p26SetNPSScore(${i}, '${dealId}')" class="nps-score-btn" data-score="${i}"
                  style="width:36px;height:36px;border-radius:6px;border:1.5px solid var(--border);background:var(--surface2);color:var(--text);font-size:13px;font-weight:600;cursor:pointer;transition:all 0.15s">${i}</button>
              `).join('')}
            </div>
            <div style="display:flex;gap:8px;align-items:flex-end">
              <textarea class="form-textarea" id="nps-comment-${dealId}" placeholder="Optional comment..." style="flex:1;height:60px;font-size:12px" rows="2"></textarea>
              <button class="btn btn-primary btn-sm" onclick="p26SubmitNPS('${dealId}', '${contact ? contact.id : ''}')">Submit NPS</button>
            </div>
            ${npsScores.length ? `
            <div style="margin-top:16px;border-top:1px solid var(--border);padding-top:12px">
              <div style="font-size:12px;font-weight:600;color:var(--text-dim);margin-bottom:8px">NPS History</div>
              ${npsScores.map(n => `
                <div style="display:flex;align-items:center;gap:8px;padding:4px 0;font-size:12px">
                  <span style="font-size:18px;font-weight:700;color:${n.score >= 9 ? '#22c55e' : n.score >= 7 ? '#f97316' : '#ef4444'}">${n.score}</span>
                  <span style="color:var(--text-muted)">${n.submitted_at}</span>
                  ${n.comment ? `<span style="color:var(--text)">${esc(n.comment)}</span>` : ''}
                </div>
              `).join('')}
            </div>` : ''}
          </div>
        </div>

        <!-- Tasks Panel -->
        ${tasks.length ? `
        <div class="panel" style="margin-bottom:16px">
          <div class="panel-header"><div class="panel-title">Open Tasks</div></div>
          <div style="padding:12px">
            ${tasks.map(t => `
              <div style="display:flex;align-items:center;gap:8px;padding:6px 0;border-bottom:1px solid var(--border);font-size:13px">
                <span style="font-size:10px;padding:2px 6px;border-radius:10px;background:${t.priority === 'High' ? 'rgba(239,68,68,0.1)' : 'var(--surface2)'};color:${t.priority === 'High' ? '#ef4444' : 'var(--text-muted)'}">${esc(t.priority)}</span>
                <span style="flex:1;color:var(--text)">${esc(t.title)}</span>
                <span style="color:${t.dueDate && t.dueDate < new Date().toISOString().slice(0,10) ? '#ef4444' : 'var(--text-muted)'};font-size:11px">${t.dueDate || '—'}</span>
              </div>
            `).join('')}
          </div>
        </div>` : ''}

        <!-- Recent Activities -->
        ${activities.length ? `
        <div class="panel" style="margin-bottom:16px">
          <div class="panel-header"><div class="panel-title">Recent Activities</div></div>
          <div style="padding:12px" class="activity-timeline">
            ${activities.slice(0,8).map(a => `
              <div class="activity-item">
                <div class="activity-icon">${p26ActivityIcon(a.type)}</div>
                <div class="activity-content">
                  <div class="activity-type">${esc(a.type)}</div>
                  <div class="activity-note">${esc(a.note || '')}</div>
                  <div class="activity-date">${a.date ? formatDate(a.date) : ''}</div>
                </div>
              </div>
            `).join('')}
          </div>
        </div>` : ''}

        <!-- Invoices -->
        ${invoices.length ? `
        <div class="panel" style="margin-bottom:16px">
          <div class="panel-header"><div class="panel-title">Invoices</div></div>
          <div style="padding:0">
            <table style="width:100%;border-collapse:collapse;font-size:12px">
              <thead>
                <tr style="border-bottom:1px solid var(--border)">
                  <th style="padding:8px 12px;text-align:left;color:var(--text-muted);font-weight:500">Invoice</th>
                  <th style="padding:8px 12px;text-align:right;color:var(--text-muted);font-weight:500">Amount</th>
                  <th style="padding:8px 12px;text-align:left;color:var(--text-muted);font-weight:500">Status</th>
                  <th style="padding:8px 12px;text-align:left;color:var(--text-muted);font-weight:500">Due</th>
                </tr>
              </thead>
              <tbody>
                ${invoices.map(inv => `
                  <tr style="border-bottom:1px solid var(--border)">
                    <td style="padding:8px 12px;color:var(--text)">${esc(inv.number)}</td>
                    <td style="padding:8px 12px;text-align:right;font-weight:600">${formatCurrency(inv.total || 0)}</td>
                    <td style="padding:8px 12px"><span style="padding:2px 6px;border-radius:10px;font-size:10px;font-weight:600;background:${inv.status === 'Paid' ? '#22c55e22' : inv.status === 'Overdue' ? '#ef444422' : 'var(--surface2)'};color:${inv.status === 'Paid' ? '#22c55e' : inv.status === 'Overdue' ? '#ef4444' : 'var(--text-muted)'}">${esc(inv.status)}</span></td>
                    <td style="padding:8px 12px;color:var(--text-muted)">${inv.dueDate || '—'}</td>
                  </tr>
                `).join('')}
              </tbody>
            </table>
          </div>
        </div>` : ''}

      </div>
    `;

    // Restore NPS selected score if any
    window._p26NPSSelected = null;

  } catch(e) {
    body.innerHTML = `
      <div class="page-header">
        <button class="btn btn-ghost btn-sm" onclick="navigate('customers')">← Back to Customers</button>
      </div>
      <div style="color:#ef4444;font-size:13px;text-align:center;padding:40px">Error loading customer: ${esc(e.message)}</div>
    `;
  }
}

function p26ComputeCustomerHealth(data) {
  const { deal, tasks, activities, npsScores, scoreHistory } = data;
  let health = 70;
  const now = Date.now();

  if (activities && activities.length > 0) {
    const lastAct = activities[0];
    if (lastAct.date) {
      const daysSince = (now - new Date(lastAct.date).getTime()) / 86400000;
      if (daysSince < 30) health += 15;
      else if (daysSince > 90) health -= 20;
    }
  }
  if (tasks && tasks.length > 3) health -= 10;
  if (npsScores && npsScores.length > 0) {
    const latest = npsScores[0].score;
    if (latest >= 9) health += 10;
    else if (latest <= 6) health -= 15;
  }
  if (scoreHistory && scoreHistory.length > 0) {
    const latestScore = scoreHistory[scoreHistory.length - 1].score;
    health = Math.round((health + latestScore) / 2);
  }
  return Math.max(0, Math.min(100, health));
}

function p26RenderScoreHistoryMini(history) {
  const max = Math.max(...history.map(h => h.score), 100);
  const H = 40;
  const W = 120;
  const pts = history.map((h, i) => {
    const x = (i / (history.length - 1)) * W;
    const y = H - (h.score / max) * H;
    return `${x},${y}`;
  }).join(' ');
  return `<svg width="${W}" height="${H}" style="display:block;margin:8px auto">
    <polyline points="${pts}" fill="none" stroke="#6366f1" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>
  </svg>`;
}

function p26ActivityIcon(type) {
  const icons = {
    'Call': '<svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round"><path d="M22 16.92v3a2 2 0 0 1-2.18 2 19.79 19.79 0 0 1-8.63-3.07A19.5 19.5 0 0 1 4.18 11.91a19.79 19.79 0 0 1-3.07-8.67A2 2 0 0 1 3.11 1h3a2 2 0 0 1 2 1.72c.127.96.361 1.903.7 2.81a2 2 0 0 1-.45 2.11L7.09 8.91a16 16 0 0 0 6 6l1.27-1.27a2 2 0 0 1 2.11-.45c.907.339 1.85.573 2.81.7A2 2 0 0 1 21 16.92z"/></svg>',
    'Email': '<svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round"><path d="M4 4h16c1.1 0 2 .9 2 2v12c0 1.1-.9 2-2 2H4c-1.1 0-2-.9-2-2V6c0-1.1.9-2 2-2z"/><polyline points="22,6 12,13 2,6"/></svg>',
    'Meeting': '<svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>',
    'Note': '<svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14,2 14,8 20,8"/></svg>',
    'Task': '<svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round"><polyline points="9 11 12 14 22 4"/><path d="M21 12v7a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11"/></svg>',
  };
  return icons[type] || icons['Note'];
}

let _p26NPSSelected = null;

function p26SetNPSScore(score, dealId) {
  _p26NPSSelected = score;
  const btns = document.querySelectorAll(`#nps-score-buttons-${dealId} .nps-score-btn`);
  btns.forEach(btn => {
    const s = parseInt(btn.dataset.score, 10);
    btn.style.background = s === score ? 'var(--accent)' : 'var(--surface2)';
    btn.style.color = s === score ? '#fff' : 'var(--text)';
    btn.style.borderColor = s === score ? 'var(--accent)' : 'var(--border)';
  });
}

async function p26SubmitNPS(dealId, contactId) {
  if (_p26NPSSelected === null) { toast('Select a score (0-10) first', 'error'); return; }
  const commentEl = document.getElementById(`nps-comment-${dealId}`);
  const comment = commentEl ? commentEl.value.trim() : '';
  try {
    await apiPost(`/customers/${dealId}/nps`, { contactId, score: _p26NPSSelected, comment });
    toast('NPS score saved');
    _p26NPSSelected = null;
    p26RenderCustomerDetail(dealId);
  } catch(e) {
    toast('Error saving NPS: ' + e.message, 'error');
  }
}

