// Threaded comment reply
function p26ReplyToComment(parentId, parentAuthor, token) {
  window._p26CurrentToken = token;
  const indicator = document.getElementById('p26-reply-indicator');
  const nameEl = document.getElementById('p26-reply-to-name');
  const parentInput = document.getElementById('p26-reply-parent-id');
  if (indicator) indicator.style.display = 'block';
  if (nameEl) nameEl.textContent = parentAuthor;
  if (parentInput) parentInput.value = parentId;
  // Scroll to comment input
  const commentBody = document.getElementById('portal-comment-body');
  if (commentBody) { commentBody.focus(); commentBody.scrollIntoView({ behavior: 'smooth', block: 'center' }); }
}

function p26CancelReply() {
  const indicator = document.getElementById('p26-reply-indicator');
  const parentInput = document.getElementById('p26-reply-parent-id');
  if (indicator) indicator.style.display = 'none';
  if (parentInput) parentInput.value = '';
}

async function portalV2PostCommentV26(token) {
  const nameEl = document.getElementById('portal-comment-name');
  const bodyEl = document.getElementById('portal-comment-body');
  const parentInput = document.getElementById('p26-reply-parent-id');

  const authorName = nameEl ? nameEl.value.trim() : '';
  const body = bodyEl ? bodyEl.value.trim() : '';
  const parentCommentId = parentInput ? parentInput.value.trim() : '';

  if (!authorName) { toast('Enter your name', 'error'); return; }
  if (!body) { toast('Write a comment', 'error'); return; }

  try {
    const result = await fetch(`/api/portal-v2-v26/${token}/comment`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ authorName, body, parentCommentId: parentCommentId || null })
    }).then(r => r.json());

    if (result.error) { toast(result.error, 'error'); return; }

    if (bodyEl) bodyEl.value = '';
    p26CancelReply();
    toast('Comment posted');
    // Reload portal
    renderPortalV2(token);
  } catch(e) {
    toast('Error posting comment', 'error');
  }
}

// Client checklist toggle
async function portalV2ToggleClientChecklist(token, itemId, checked) {
  const nameInput = document.getElementById('portal-checklist-name');
  const checkedByName = nameInput ? nameInput.value.trim() : '';
  if (!checkedByName) {
    toast('Enter your name above before checking items', 'error');
    // Revert the checkbox
    setTimeout(() => renderPortalV2(token), 100);
    return;
  }

  try {
    await fetch(`/api/portal-v2-v26/${token}/client-checklist`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ itemId, checkedByName, checked })
    });
    toast(checked ? 'Item marked complete' : 'Item unchecked');
    // Reload in bg
    setTimeout(() => renderPortalV2(token), 500);
  } catch(e) {
    toast('Error updating checklist', 'error');
  }
}

// Download Package
function portalV2DownloadPackage(token) {
  const a = document.createElement('a');
  a.href = `/api/portal-v2-v26/${token}/download-package`;
  a.download = 'document-package.txt';
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
}

